function workflowSuiteVersion(): string {
  try {
    const version = readFileSync(WORKFLOW_SUITE_VERSION_FILE, "utf8").trim();
    return /^v\d+\.\d+\.\d+$/.test(version) ? version : "v0.0.0";
  } catch {
    return "v0.0.0";
  }
}

function workflowSuitePackageVersion(): string {
  return workflowSuiteVersion().replace(/^v/, "");
}

