type PiCompactionApi = {
  compact: typeof piCompact;
  estimateTokens: typeof piEstimateTokens;
  findCutPoint: typeof piFindCutPoint;
};
type PiCompactionPreparation = Parameters<PiCompactionApi["compact"]>[0];
type PiCompactionModel = Parameters<PiCompactionApi["compact"]>[1];
type PiSessionEntry = SessionEntry;

const DEFAULT_PI_COMPACTION_RESERVE_TOKENS = 16_384;
const DEFAULT_PI_COMPACTION_KEEP_RECENT_TOKENS = 20_000;
const CUSTOM_COMPACTION_PROMPT_OVERHEAD_TOKENS = 8_192;
const PI_SETTINGS_FILE = join(AGENT_DIR, "settings.json");

type PiNativeCompactionSettings = {
  enabled: boolean;
  reserveTokens: number;
  keepRecentTokens: number;
  source: "default" | "global" | "project";
  file?: string;
};

function loadPiCompactionApi(): PiCompactionApi {
  return {
    compact: piCompact,
    estimateTokens: piEstimateTokens,
    findCutPoint: piFindCutPoint,
  };
}

function readJsonObject(path: string): Record<string, unknown> | undefined {
  try {
    const parsed = JSON.parse(readFileSync(path, "utf8")) as unknown;
    return parsed && typeof parsed === "object" && !Array.isArray(parsed) ? parsed as Record<string, unknown> : undefined;
  } catch {
    return undefined;
  }
}

function findProjectPiSettings(cwd: string): string | undefined {
  let dir = cwd;
  for (let i = 0; i < 40; i += 1) {
    const candidate = join(dir, ".pi", "settings.json");
    if (existsSync(candidate)) return candidate;
    const parent = dirname(dir);
    if (parent === dir) break;
    dir = parent;
  }
  return undefined;
}

function coercePiCompactionSettings(raw: unknown): Partial<PiNativeCompactionSettings> | undefined {
  if (!raw || typeof raw !== "object" || Array.isArray(raw)) return undefined;
  const compaction = raw as Record<string, unknown>;
  const settings: Partial<PiNativeCompactionSettings> = {};
  if (typeof compaction.enabled === "boolean") settings.enabled = compaction.enabled;
  const reserveTokens = Number(compaction.reserveTokens);
  if (Number.isFinite(reserveTokens) && reserveTokens > 0) settings.reserveTokens = Math.round(reserveTokens);
  const keepRecentTokens = Number(compaction.keepRecentTokens);
  if (Number.isFinite(keepRecentTokens) && keepRecentTokens > 0) settings.keepRecentTokens = Math.round(keepRecentTokens);
  return settings;
}

function loadPiNativeCompactionSettings(cwd?: string): PiNativeCompactionSettings {
  let settings: PiNativeCompactionSettings = {
    enabled: true,
    reserveTokens: DEFAULT_PI_COMPACTION_RESERVE_TOKENS,
    keepRecentTokens: DEFAULT_PI_COMPACTION_KEEP_RECENT_TOKENS,
    source: "default",
  };
  const globalSettings = existsSync(PI_SETTINGS_FILE) ? coercePiCompactionSettings(readJsonObject(PI_SETTINGS_FILE)?.compaction) : undefined;
  if (globalSettings) settings = { ...settings, ...globalSettings, source: "global", file: PI_SETTINGS_FILE };

  const projectFile = cwd ? findProjectPiSettings(cwd) : undefined;
  const projectSettings = projectFile ? coercePiCompactionSettings(readJsonObject(projectFile)?.compaction) : undefined;
  if (projectSettings) settings = { ...settings, ...projectSettings, source: "project", file: projectFile };
  return settings;
}

function contextWindowFrom(ctx?: ExtensionContext, usage?: { contextWindow?: number }): number | undefined {
  const contextWindow = Number(usage?.contextWindow ?? ctx?.getContextUsage?.()?.contextWindow ?? ctx?.model?.contextWindow);
  return Number.isFinite(contextWindow) && contextWindow > 0 ? contextWindow : undefined;
}

function piNativeCompactionThreshold(cwd: string | undefined, contextWindow: number | undefined): { settings: PiNativeCompactionSettings; triggerTokens?: number; triggerPercent?: number } {
  const settings = loadPiNativeCompactionSettings(cwd);
  if (!settings.enabled || !contextWindow) return { settings };
  const threshold = compactionThresholdForReserve(contextWindow, settings.reserveTokens);
  return { settings, ...threshold };
}

function compactionThresholdForReserve(contextWindow: number, reserveTokens: number): { triggerTokens: number; triggerPercent: number } {
  const triggerTokens = Math.max(0, contextWindow - reserveTokens);
  return { triggerTokens, triggerPercent: (triggerTokens / contextWindow) * 100 };
}

function formatPiNativeCompactionThreshold(cwd: string | undefined, contextWindow: number | undefined): string {
  const threshold = piNativeCompactionThreshold(cwd, contextWindow);
  if (!threshold.settings.enabled) return "disabled";
  return "Pi default";
}

function formatSharedCompactionTrigger(settings: ReturnType<typeof loadWorkflowSettings>, ctx?: ExtensionContext): string {
  if (settings.context.compactionMode === "disabled" || settings.context.autoCompactionEnabled === false) return "disabled";
  const override = compactionTriggerPercentOverride(settings);
  if (override != null) return `custom, ${override}%`;
  return formatPiNativeCompactionThreshold(ctx?.cwd, contextWindowFrom(ctx));
}

function createWorkflowCompactionFileOps(): FileOperations {
  return { read: new Set<string>(), written: new Set<string>(), edited: new Set<string>() };
}

function extractWorkflowCompactionFileOps(message: AgentMessage, fileOps: FileOperations): void {
  if (!isAssistantMessage(message)) return;
  for (const block of message.content) {
    if (block.type !== "toolCall") continue;
    const args = block.arguments as { path?: unknown } | undefined;
    const toolPath = typeof args?.path === "string" ? args.path : undefined;
    if (!toolPath) continue;
    if (block.name === "read") fileOps.read.add(toolPath);
    else if (block.name === "write") fileOps.written.add(toolPath);
    else if (block.name === "edit") fileOps.edited.add(toolPath);
  }
}

function workflowEntryTimestampMs(timestamp: unknown): number {
  const parsed = new Date(String(timestamp ?? "")).getTime();
  return Number.isFinite(parsed) ? parsed : Date.now();
}

function workflowMessageFromEntryForCompaction(entry: PiSessionEntry): AgentMessage | undefined {
  if (entry.type === "message") return entry.message;
  if (entry.type === "branch_summary") {
    return { role: "branchSummary", summary: entry.summary, fromId: entry.fromId, timestamp: workflowEntryTimestampMs(entry.timestamp) } as unknown as AgentMessage;
  }
  if (entry.type === "custom_message") {
    return { role: "custom", customType: entry.customType, content: entry.content, display: entry.display, details: entry.details, timestamp: workflowEntryTimestampMs(entry.timestamp) } as unknown as AgentMessage;
  }
  return undefined;
}

function workflowCompactionMessages(entries: PiSessionEntry[], startIndex: number, endIndex: number): AgentMessage[] {
  const messages: AgentMessage[] = [];
  for (let index = startIndex; index < endIndex; index += 1) {
    const message = workflowMessageFromEntryForCompaction(entries[index]);
    if (message) messages.push(message);
  }
  return messages;
}

function prepareWorkflowCompaction(branchEntries: PiSessionEntry[], settings: PiCompactionPreparation["settings"], tokensBefore: number, api: PiCompactionApi): PiCompactionPreparation | undefined {
  if (branchEntries.length > 0 && branchEntries[branchEntries.length - 1].type === "compaction") return undefined;

  let prevCompactionIndex = -1;
  for (let index = branchEntries.length - 1; index >= 0; index -= 1) {
    if (branchEntries[index].type === "compaction") {
      prevCompactionIndex = index;
      break;
    }
  }

  let previousSummary: string | undefined;
  let boundaryStart = 0;
  const fileOps = createWorkflowCompactionFileOps();
  if (prevCompactionIndex >= 0) {
    const prevCompaction = branchEntries[prevCompactionIndex];
    if (prevCompaction.type === "compaction") {
      previousSummary = prevCompaction.summary;
      const firstKeptEntryIndex = branchEntries.findIndex((entry) => entry.id === prevCompaction.firstKeptEntryId);
      boundaryStart = firstKeptEntryIndex >= 0 ? firstKeptEntryIndex : prevCompactionIndex + 1;
      if (!prevCompaction.fromHook && prevCompaction.details && typeof prevCompaction.details === "object") {
        const details = prevCompaction.details as { readFiles?: unknown; modifiedFiles?: unknown };
        if (Array.isArray(details.readFiles)) for (const file of details.readFiles) if (typeof file === "string") fileOps.read.add(file);
        if (Array.isArray(details.modifiedFiles)) for (const file of details.modifiedFiles) if (typeof file === "string") fileOps.edited.add(file);
      }
    }
  }

  const boundaryEnd = branchEntries.length;
  const cutPoint = api.findCutPoint(branchEntries, boundaryStart, boundaryEnd, settings.keepRecentTokens);
  const firstKeptEntry = branchEntries[cutPoint.firstKeptEntryIndex];
  if (!firstKeptEntry?.id) return undefined;

  const historyEnd = cutPoint.isSplitTurn ? cutPoint.turnStartIndex : cutPoint.firstKeptEntryIndex;
  const messagesToSummarize = workflowCompactionMessages(branchEntries, boundaryStart, historyEnd);
  const turnPrefixMessages = cutPoint.isSplitTurn ? workflowCompactionMessages(branchEntries, cutPoint.turnStartIndex, cutPoint.firstKeptEntryIndex) : [];
  for (const message of [...messagesToSummarize, ...turnPrefixMessages]) extractWorkflowCompactionFileOps(message, fileOps);

  return {
    firstKeptEntryId: firstKeptEntry.id,
    messagesToSummarize,
    turnPrefixMessages,
    isSplitTurn: cutPoint.isSplitTurn,
    tokensBefore,
    previousSummary,
    fileOps,
    settings,
  };
}

function customCompactionSafeInputTokens(model: PiCompactionModel, reserveTokens = DEFAULT_PI_COMPACTION_RESERVE_TOKENS): number | undefined {
  const contextWindow = Number((model as { contextWindow?: unknown }).contextWindow);
  if (!Number.isFinite(contextWindow) || contextWindow <= 0) return undefined;
  const outputBudget = Math.max(4_096, Math.floor(0.8 * reserveTokens));
  return Math.max(4_096, Math.floor(contextWindow - outputBudget - CUSTOM_COMPACTION_PROMPT_OVERHEAD_TOKENS));
}

function estimateCompactionInputTokens(preparation: PiCompactionPreparation, estimateTokens: PiCompactionApi["estimateTokens"]): number {
  const messages = [...preparation.messagesToSummarize, ...preparation.turnPrefixMessages];
  const messageTokens = messages.reduce((sum, message) => sum + estimateTokens(message), 0);
  const previousSummaryTokens = Math.ceil((preparation.previousSummary?.length ?? 0) / 4);
  return messageTokens + previousSummaryTokens + CUSTOM_COMPACTION_PROMPT_OVERHEAD_TOKENS;
}

function fitCompactionPreparationToCustomModel(
  preparation: PiCompactionPreparation,
  branchEntries: PiSessionEntry[],
  model: PiCompactionModel,
  api: PiCompactionApi,
): { preparation: PiCompactionPreparation; adjusted: boolean; inputTokens: number; safeInputTokens?: number } {
  const safeInputTokens = customCompactionSafeInputTokens(model, preparation.settings?.reserveTokens ?? DEFAULT_PI_COMPACTION_RESERVE_TOKENS);
  let inputTokens = estimateCompactionInputTokens(preparation, api.estimateTokens);
  if (!safeInputTokens || inputTokens <= safeInputTokens) return { preparation, adjusted: false, inputTokens, safeInputTokens };

  const tokensBefore = Number(preparation.tokensBefore);
  if (!Number.isFinite(tokensBefore) || tokensBefore <= 0) return { preparation, adjusted: false, inputTokens, safeInputTokens };

  const currentKeepRecent = Math.max(DEFAULT_PI_COMPACTION_KEEP_RECENT_TOKENS, Number(preparation.settings?.keepRecentTokens ?? DEFAULT_PI_COMPACTION_KEEP_RECENT_TOKENS));
  const maxKeepRecent = Math.max(currentKeepRecent, Math.ceil(tokensBefore - 1_000));
  let keepRecentTokens = Math.min(maxKeepRecent, Math.max(currentKeepRecent, Math.ceil(tokensBefore - safeInputTokens)));
  let fitted = preparation;
  let adjusted = false;

  for (let attempt = 0; attempt < 8; attempt += 1) {
    const candidate = prepareWorkflowCompaction(branchEntries, { ...preparation.settings, keepRecentTokens }, tokensBefore, api);
    if (!candidate) break;
    const candidateInputTokens = estimateCompactionInputTokens(candidate, api.estimateTokens);
    const candidateHasContent = candidate.messagesToSummarize.length > 0 || candidate.turnPrefixMessages.length > 0;
    if (candidateHasContent) {
      fitted = candidate;
      inputTokens = candidateInputTokens;
      adjusted = true;
    }
    if (candidateInputTokens <= safeInputTokens || keepRecentTokens >= maxKeepRecent) break;
    const excessTokens = candidateInputTokens - safeInputTokens;
    keepRecentTokens = Math.min(maxKeepRecent, Math.max(keepRecentTokens + 1_000, keepRecentTokens + Math.ceil(excessTokens * 1.25)));
  }

  return { preparation: fitted, adjusted, inputTokens, safeInputTokens };
}

type PiTuiUtils = {
  truncateToWidth(text: string, maxWidth: number, ellipsis?: string, pad?: boolean): string;
  visibleWidth(text: string): number;
};

let cachedPiTuiUtils: PiTuiUtils | undefined;

function fallbackVisibleWidth(text: string): number {
  return String(text ?? "").replace(/\x1b\[[0-9;]*m/g, "").length;
}

function fallbackTruncateToWidth(text: string, maxWidth: number, ellipsis = "…", pad = false): string {
  const raw = String(text ?? "");
  const width = Math.max(0, maxWidth);
  const plainWidth = fallbackVisibleWidth(raw);
  const clipped = plainWidth <= width ? raw : raw.replace(/\x1b\[[0-9;]*m/g, "").slice(0, Math.max(0, width - fallbackVisibleWidth(ellipsis))) + ellipsis;
  return pad ? clipped + " ".repeat(Math.max(0, width - fallbackVisibleWidth(clipped))) : clipped;
}

function fallbackPiTuiUtils(): PiTuiUtils {
  return { truncateToWidth: fallbackTruncateToWidth, visibleWidth: fallbackVisibleWidth };
}

function tryLoadPiTuiUtils(specifier: string): PiTuiUtils | undefined {
  try { return requireFromExtension(specifier) as PiTuiUtils; } catch { return undefined; }
}

function loadPiTuiUtils(): PiTuiUtils {
  if (cachedPiTuiUtils) return cachedPiTuiUtils;
  cachedPiTuiUtils = tryLoadPiTuiUtils("@earendil-works/pi-tui");
  if (cachedPiTuiUtils) return cachedPiTuiUtils;
  const piEntry = process.argv[1];
  if (piEntry) {
    try {
      const piRequire = createRequire(realpathSync(piEntry));
      try { cachedPiTuiUtils = piRequire("@earendil-works/pi-tui") as PiTuiUtils; } catch { /* fall back to local width helpers */ }
      if (cachedPiTuiUtils) return cachedPiTuiUtils;
    } catch { /* fall back to local width helpers */ }
  }
  cachedPiTuiUtils = tryLoadPiTuiUtils("/usr/local/lib/node_modules/@earendil-works/pi-coding-agent/node_modules/@earendil-works/pi-tui/dist/index.js")
    ?? fallbackPiTuiUtils();
  return cachedPiTuiUtils;
}

// ── Agent discovery ──────────────────────────────────────────────

interface AgentInfo {
  name: string;
  description: string;
  file: string;
  source: "package" | "global" | "project";
  tools?: string[];
}

function listAgentsFromDir(dir: string, source: "package" | "global" | "project"): AgentInfo[] {
  if (!existsSync(dir)) return [];
  const agents: AgentInfo[] = [];
  try {
    for (const entry of readdirSync(dir, { withFileTypes: true })) {
      if (!entry.name.endsWith(".md") || (!entry.isFile() && !entry.isSymbolicLink())) continue;
      const filePath = join(dir, entry.name);
      try {
        const content = readFileSync(filePath, "utf-8");
        const fm = content.match(/^---[\s\S]*?---/)?.[0];
        if (!fm) continue;
        const name = fm.match(/name:\s*(.+)/)?.[1]?.trim();
        const desc = fm.match(/description:\s*(.+)/)?.[1]?.trim();
        const rawTools = fm.match(/tools:\s*(.+)/)?.[1]?.trim();
        const tools = rawTools?.split(",").map((tool) => tool.trim()).filter(Boolean);
        if (name && desc) agents.push({ name, description: desc, file: filePath, source, tools: tools?.length ? tools : undefined });
      } catch { /* skip */ }
    }
  } catch { /* skip */ }
  return agents;
}

function listPackageAgents(): AgentInfo[] { return listAgentsFromDir(PACKAGE_AGENTS_DIR, "package"); }
function listUserAgents(): AgentInfo[] { return listAgentsFromDir(USER_AGENTS_DIR, "global"); }

function findProjectAgentsDir(cwd: string): string | undefined {
  let dir = cwd;
  for (let i = 0; i < 40; i++) {
    const candidate = join(dir, ".pi", "agents");
    if (existsSync(candidate)) return candidate;
    const parent = dirname(dir);
    if (parent === dir) break;
    dir = parent;
  }
  return undefined;
}

function listProjectAgents(cwd: string): AgentInfo[] {
  const dir = findProjectAgentsDir(cwd);
  if (!dir) return [];
  return listAgentsFromDir(dir, "project");
}

function listEffectiveAgents(cwd: string): AgentInfo[] {
  const bundled = listPackageAgents();
  const global = listUserAgents();
  const project = listProjectAgents(cwd);
  const map = new Map<string, AgentInfo>();
  for (const a of bundled) map.set(a.name, a);
  for (const a of global) map.set(a.name, a);
  for (const a of project) map.set(a.name, a);
  return Array.from(map.values());
}

function detectProjectInstructions(cwd: string): { detected: boolean; files: string[] } {
  const files: string[] = [];
  const candidates = ["AGENTS.md", "SYSTEM.md", "CLAUDE.md", join(".cursor", "rules"), join(".factory", "rules"), join(".factory", "memories.md")];
  for (const rel of candidates) {
    if (existsSync(join(cwd, rel))) files.push(rel);
  }
  return { detected: files.length > 0, files };
}

// ── Message helpers ──────────────────────────────────────────────

function isAssistantMessage(m: AgentMessage): m is AssistantMessage {
  return m.role === "assistant" && Array.isArray(m.content);
}

function assistantText(message: AssistantMessage): string {
  return message.content.filter((block): block is TextContent => block.type === "text").map((block) => block.text).join("\n").trim();
}

function lastAssistantText(messages: AgentMessage[]): string | undefined {
  const last = [...messages].reverse().find(isAssistantMessage);
  return last ? assistantText(last) : undefined;
}


function show(pi: ExtensionAPI, content: string): void {
  pi.sendMessage({ customType: "workflow-suite", content, display: true }, { triggerTurn: false });
}

function showInternal(pi: ExtensionAPI, content: string): void {
  pi.sendMessage({ customType: "workflow-suite", content, display: false }, { triggerTurn: false });
}

function stripWorkflowEmoji(text: string): string {
  return text.replace(/[\p{Emoji_Presentation}\p{Extended_Pictographic}\uFE0F]/gu, "");
}

function stripStandardAutoChecksBlock(text: string): string {
  const lines = text.replace(/\r\n/g, "\n").split("\n");
  const output: string[] = [];
  const autoCheckLine = /^\s*(?:CLARIFICATION_DECISION|CLARIFICATION_REASON|TODO_DECISION|TODO_REASON)\s*:/i;
  for (let index = 0; index < lines.length; index += 1) {
    if (/^\s*#{0,3}\s*Standard Auto Checks:?\s*$/i.test(lines[index].trim())) {
      index += 1;
      while (index < lines.length && autoCheckLine.test(lines[index].trim())) index += 1;
      while (index < lines.length && !lines[index].trim()) index += 1;
      index -= 1;
      continue;
    }
    if (autoCheckLine.test(lines[index].trim())) continue;
    output.push(lines[index]);
  }
  return output.join("\n");
}

function stripPlanMissionMarkers(text: string): string {
  const lines = text.replace(/\r\n/g, "\n").split("\n");
  const output: string[] = [];
  const markerLine = /^\s*(?:PLAN_DECISION|MISSION_DECISION|CLARIFICATION_DECISION|CLARIFICATION_REASON)\s*:/i;
  for (const line of lines) {
    if (markerLine.test(line.trim())) continue;
    if (/^\s*#{0,3}\s*(?:Standard Auto Checks|Plan Auto Checks|Mission Auto Checks):?\s*$/i.test(line.trim())) continue;
    output.push(line);
  }
  return output.join("\n");
}

function stripVisibleWorkflowMarkdown(text: string, options: { preserveHeadings?: boolean } = {}): string {
  const headingReplacement = options.preserveHeadings ? "$1 $2" : "$2";
  let cleaned = stripStandardAutoChecksBlock(stripPlanMissionMarkers(text))
    .replace(/\r\n/g, "\n")
    .replace(/^\s*```[a-zA-Z0-9_-]*\s*$/gm, "")
    .replace(/^(\s{0,3}#{1,6})\s+(.+)$/gm, headingReplacement)
    .replace(/^\s{0,3}[-*+]\s+\[[ xX-]\]\s+/gm, "- ")
    .replace(/^\s{0,3}[-*+]\s+/gm, "- ")
    .replace(/`([^`]+)`/g, "$1")
    .replace(/\*\*([^*]+)\*\*/g, "$1")
    .replace(/__([^_]+)__/g, "$1");
  if (!options.preserveHeadings) cleaned = cleaned.replace(/^\s*#{1,6}\s*/gm, "");
  return stripWorkflowEmoji(cleaned.replace(/\n{4,}/g, "\n\n\n")).trim();
}

function professionalOutputGuidance(context: string): string {
  return `Professional user-facing output guidance for ${context}:
- Do not use emoji, pictographs, medal icons, warning icons, decorative symbols, Markdown tables, or box-art tables in user-facing prose.
- Prefer concise section titles and labeled lines. Simple Markdown section headings are allowed for final user-facing summaries so the terminal can render styled headings without showing raw hashtag markers. Do not use decorative Markdown headings or dash-bullet lists except where an exact parser-safe legacy fallback contract requires them.
- Typed handoff tools are the primary control plane. If an Output exactly or legacy fallback section specifies headings, preserve that parser-safe format exactly.`;
}

function professionalWorkflowText(text: string | undefined, options: { preserveHeadings?: boolean } = {}): string {
  if (!text?.trim()) return "(none recorded)";
  const lines = stripWorkflowEmoji(text)
    .replace(/\r\n/g, "\n")
    .replace(/^\s*```[a-zA-Z0-9_-]*\s*$/gm, "")
    .replace(/`([^`]+)`/g, "$1")
    .replace(/\*\*([^*]+)\*\*/g, "$1")
    .replace(/__([^_]+)__/g, "$1")
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, "$1 ($2)")
    .replace(/[┌┬┐├┼┤└┴┘─│]/g, " ")
    .split("\n");
  const output: string[] = [];
  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed) {
      if (output.length && output[output.length - 1] !== "") output.push("");
      continue;
    }
    const heading = trimmed.match(/^(#{1,6})\s+(.+)$/);
    if (heading) {
      if (output.length && output[output.length - 1] !== "") output.push("");
      const level = heading[1].length <= 2 ? "##" : "###";
      output.push(options.preserveHeadings ? `${level} ${heading[2].trim()}` : heading[2].trim());
      continue;
    }
    const checkbox = trimmed.match(/^[-*+]\s+\[[ xX-]\]\s+(.+)$/);
    if (checkbox) {
      output.push(`  ${checkbox[1].trim()}`);
      continue;
    }
    const bullet = trimmed.match(/^[-*+]\s+(.+)$/);
    if (bullet) {
      output.push(`  ${bullet[1].trim()}`);
      continue;
    }
    const numbered = trimmed.match(/^(\d{1,3})[.)]\s+(.+)$/);
    if (numbered) {
      output.push(`  ${numbered[1]}. ${numbered[2].trim()}`);
      continue;
    }
    output.push(line.replace(/\s+$/g, ""));
  }
  return output.join("\n")
    .replace(/[ \t]+([,.;:])/g, "$1")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function professionalFinalSummaryMarkdown(text: string | undefined): string {
  return professionalWorkflowText(text, { preserveHeadings: true });
}

function standardVisibleOptionLabel(option: string): string {
  return stripVisibleWorkflowMarkdown(option)
    .replace(/^([A-D])\.\s+/i, "$1) ")
    .replace(/^D\)\s*(?:Other|Other\s*\/\s*custom answer).*$/i, "D) Something else")
    .trim();
}

function renderStandardClarificationQuestionsForDisplay(questions: ClarificationQuestion[]): string {
  return questions.map((question, index) => {
    const label = `Question ${question.index || index + 1}`;
    const prompt = stripVisibleWorkflowMarkdown(question.question).replace(/^Question\s+\d+\s*[:.)-]?\s*/i, "").trim();
    const options = question.options.map(standardVisibleOptionLabel).filter(Boolean);
    return [label, prompt, ...options].filter(Boolean).join("\n");
  }).join("\n\n").trim();
}

function standardLooksLikeStandaloneTitle(line: string): boolean {
  const trimmed = line.trim();
  if (!trimmed || trimmed.length > 120) return false;
  if (/^(?:[-*+]\s+|\d{1,3}[.)]\s+|[A-D][.)]\s+)/.test(trimmed)) return false;
  if (/^(?:done|mode|model|status|current|next|standard|clarification|todo|question)\s*:/i.test(trimmed)) return false;
  if (/^#{1,6}\s+/.test(trimmed)) return false;
  if (/^(?:here is|here's|now let me|sure|absolutely|i(?:'|’)ll|let me)\b/i.test(trimmed)) return false;
  const words = trimmed.split(/\s+/).filter(Boolean);
  if (words.length < 3 || words.length > 16) return false;
  return /[A-Za-z]/.test(trimmed) && !/[.!?]$/.test(trimmed);
}

function standardPresentationText(text: string): string {
  const lines = text
    .split("\n")
    .filter((line) => !/^\s*[─━]{8,}\s*$/.test(line.trim()));
  const nonEmpty = lines.map((line, index) => ({ line, index })).filter((entry) => entry.line.trim());
  if (nonEmpty.length < 3 || text.length < 220 || /^\s*#{1,2}\s+/m.test(text)) return lines.join("\n").replace(/\n{3,}/g, "\n\n").trim();
  if (/^\s*(?:Question\s+\d+|[A-D][)]\s+)/im.test(text)) return lines.join("\n").replace(/\n{3,}/g, "\n\n").trim();
  const first = nonEmpty[0];
  const second = nonEmpty[1];
  const title = standardLooksLikeStandaloneTitle(first.line) ? first : /^\s*(?:here is|here's|now let me|sure|absolutely)\b[\s\S]{0,140}:\s*$/i.test(first.line.trim()) && standardLooksLikeStandaloneTitle(second?.line ?? "") ? second : undefined;
  if (!title) return lines.join("\n").replace(/\n{3,}/g, "\n\n").trim();
  const next = [...lines];
  next[title.index] = `## ${title.line.trim()}`;
  return next.join("\n").replace(/\n{3,}/g, "\n\n").trim();
}

function standardVisibleText(text: string): string {
  const cleaned = stripVisibleWorkflowMarkdown(text, { preserveHeadings: true })
    .split("\n")
    .filter((line) => !/^\s*(?:analysis|reasoning|internal notes?|debug notes?)\s*:/i.test(line.trim()))
    .join("\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
  return standardPresentationText(cleaned);
}

function standardVisibleAssistantText(rawText: string, state: WorkflowState, settings: ReturnType<typeof loadWorkflowSettings>): string {
  const autoDecision = parseStandardAutoCheckDecision(rawText);
  // When the typed tool already set up clarification with an interactive menu,
  // hide the text-based questions so they don't appear twice.
  if (state.standardClarificationStage === "awaiting_answer") {
    return standardVisibleText(rawText);
  }
  const clarificationDrafting = state.standardClarificationStage === "drafting" || autoDecision.clarificationDecision === "ask";
  if (clarificationDrafting) {
    const maxQuestions = Math.max(1, Math.min(2, settings.standard.maxClarificationQuestions ?? 1));
    const task = state.standardClarificationTask ?? state.task ?? state.originalTask ?? "this Standard Mode task";
    const reason = state.standardClarificationRequirementReason ?? autoDecision.clarificationReason ?? "Standard Mode clarification requested.";
    const questions = parseClarifyingQuestions(rawText).slice(0, maxQuestions);
    return renderStandardClarificationQuestionsForDisplay(questions.length ? questions : fallbackStandardClarificationQuestions(task, reason).slice(0, maxQuestions));
  }
  return standardVisibleText(rawText);
}

function workflowDisplaySummaryLabel(value: string | undefined, maxWidth = 56): string {
  const raw = stripVisibleWorkflowMarkdown(value ?? "")
    .replace(/\x1b\[[0-9;]*m/g, "")
    .replace(/^\s*(?:[-*+]\s+|\d{1,3}[.)\-:]\s+)/, "")
    .replace(/^\s*\[[ xX-]\]\s+/, "")
    .replace(/^\s*(?:current|next|step|milestone|todo)\s*[:\-]\s*/i, "")
    .replace(/\s+/g, " ")
    .replace(/\s+([,.;:])/g, "$1")
    .trim();
  return truncateSummaryWithoutEllipsis(raw || "none", maxWidth);
}

function visiblePlanCompletionReport(summary: NonNullable<WorkflowState["lastCompletedPlanSummary"]>): string {
  return [
    "Plan Complete",
    "",
    `Status: ${summary.status}`,
    `Validation: ${summary.validationResult}`,
    `Steps: ${summary.stepsCompleted}/${summary.stepsTotal}`,
    `Repairs: ${summary.repairRetries}/${summary.maxRepairRetries}; status: ${summary.repairStatus ?? "none"}`,
    `Runtime: ${formatDurationMs(summary.activeRuntimeMs)} active / ${formatDurationMs(summary.elapsedMs)} elapsed`,
    `Saved record: /workflow plans show ${summary.planHistoryId ?? "latest"}`,
    `Next: ${workflowDisplaySummaryLabel(summary.nextAction, 80)}`,
  ].join("\n").trim();
}

function nativePlanFinalDeliverableSummary(summary: NonNullable<WorkflowState["lastCompletedPlanSummary"]>): string {
  return professionalFinalSummaryMarkdown(summary.finalReport?.trim() || visiblePlanCompletionReport(summary));
}

function visibleMissionCompletionReport(summary: NonNullable<WorkflowState["lastCompletedMissionSummary"]>): string {
  return [
    "Mission Complete",
    "",
    `Status: ${summary.status}`,
    `Validation: ${summary.validationResult}`,
    `Milestones: ${summary.milestonesCompleted}/${summary.milestonesTotal}`,
    `Repairs: ${summary.repairRetries}/${summary.maxRepairRetries}; status: ${summary.repairStatus ?? "none"}`,
    `Runtime: ${formatDurationMs(summary.activeRuntimeMs)} active / ${formatDurationMs(summary.elapsedMs)} elapsed`,
    `Details: /mission status or /workflow summary`,
    `Next: ${workflowDisplaySummaryLabel(summary.nextAction, 80)}`,
  ].join("\n").trim();
}

function nativeMissionFinalDeliverableSummary(summary: NonNullable<WorkflowState["lastCompletedMissionSummary"]>): string {
  return professionalFinalSummaryMarkdown(summary.finalReport?.trim() || visibleMissionCompletionReport(summary));
}

let workflowTraceWriteCount = 0;

function recordWorkflowInternalEvent(ctx: ExtensionContext | undefined, content: string): void {
  try {
    const cwd = ctx?.cwd ?? process.cwd();
    const traceDir = join(cwd, ".pi");
    const traceFile = join(traceDir, "workflow-suite-trace.log");
    const ts = new Date().toISOString();
    const line = `[${ts}] ${content}\n`;
    if (!existsSync(traceDir)) mkdirSync(traceDir, { recursive: true });
    writeFileSync(traceFile, line, { flag: "a" });
    workflowTraceWriteCount += 1;
    if (workflowTraceWriteCount % 50 === 0) {
      const lines = readFileSync(traceFile, "utf8").split("\n").filter(Boolean);
      if (lines.length > 500) {
        writeFileSync(traceFile, lines.slice(-200).join("\n") + "\n", "utf8");
      }
    }
  } catch {
    // trace file write failure must never affect workflow behavior
  }
}

function showStartupCard(pi: ExtensionAPI, content: string): void {
  try {
    pi.sendMessage({ customType: "workflow-startup-card", content, display: true }, { triggerTurn: false });
  } catch { /* startup cards must never crash Pi */ }
}

function beginWorkflowPreflightUi(ctx: ExtensionContext, _label: string, _activeSubagents: ActiveSubagent[]): void {
  if (!ctx.hasUI) return;
  try { ctx.ui.setStatus("workflow-subagent-activity", undefined); } catch { /* status updates must never break workflow control */ }
}

function updateWorkflowPreflightUi(ctx: ExtensionContext, _label: string, _activeSubagents: ActiveSubagent[]): void {
  if (!ctx.hasUI) return;
  try { ctx.ui.setStatus("workflow-subagent-activity", undefined); } catch { /* status updates must never break workflow control */ }
}

function endWorkflowPreflightUi(ctx: ExtensionContext): void {
  if (!ctx.hasUI) return;
  try { ctx.ui.setStatus("workflow-subagent-activity", undefined); } catch { /* status updates must never break workflow control */ }
}

function queueWorkflowPrompt(pi: ExtensionAPI, content: string, options?: WorkflowQueuedTurnOptions): void {
  workflowScheduledAgentTurns += 1;
  queueGuardedAgentTurn(pi, content, "workflow-suite-instructions", 0, 0, 0, options);
}

function modelLabel(model: RoleModelSettings): string {
  return roleIsConfigured(model) ? `${model.provider}/${model.model}, thinking: ${model.thinkingLevel}` : `not configured, thinking: ${model.thinkingLevel}`;
}

function effectiveStandardModelRole(settings: ReturnType<typeof loadWorkflowSettings>): StandardModelRole {
  return settings.standard.useSharedExecutorModel === false ? "current" : settings.standard.modelRole ?? "executor";
}

let workflowScheduledAgentTurns = 0;

const WORKFLOW_AGENT_TURN_RETRY_DELAYS_MS = [250, 750, 1500, 3000, 5000, 8000, 13000] as const;

function workflowTurnSendErrorMessage(error: unknown): string {
  return error instanceof Error ? error.message : String(error ?? "");
}

function workflowTurnSendErrorIsBusy(error: unknown): boolean {
  return /already processing|currently processing|wait for completion/i.test(workflowTurnSendErrorMessage(error));
}

function workflowTurnSendErrorIsConnection(error: unknown): boolean {
  return /websocket|connection[_\s-]*(?:error|lost|closed|dropped|refused|reset)|network[_\s-]*error|failed to fetch|econnrefused|econnreset|etimedout|enotfound|eai_again/i.test(workflowTurnSendErrorMessage(error));
}

const WORKFLOW_CONNECTION_RETRY_DELAYS_MS = [750, 3000] as const;

type WorkflowQueuedTurnFailure = {
  customType: string;
  message: string;
  error: unknown;
  attempt: number;
  connectionAttempt: number;
  idleAttempt: number;
};

type WorkflowQueuedTurnOptions = {
  initialDelayMs?: number;
  requireIdle?: boolean;
  isIdle?: () => boolean;
  onBeforeSend?: (customType: string) => void | Promise<void>;
  onFinalFailure?: (failure: WorkflowQueuedTurnFailure) => void;
};

class WorkflowToolSurfaceAbort extends Error {
  constructor(message: string) {
    super(message);
    this.name = "WorkflowToolSurfaceAbort";
  }
}

function workflowToolSurfaceAbort(error: unknown): boolean {
  return error instanceof WorkflowToolSurfaceAbort;
}

const WORKFLOW_IDLE_RETRY_DELAYS_MS = [50, 100, 250, 500, 1000, 1500, 2000, 3000, 5000] as const;

function queueGuardedAgentTurn(pi: ExtensionAPI, content: string, customType: string, attempt = 0, connectionAttempt = 0, idleAttempt = 0, options: WorkflowQueuedTurnOptions = {}): void {
  const delay = connectionAttempt > 0
    ? WORKFLOW_CONNECTION_RETRY_DELAYS_MS[Math.min(connectionAttempt - 1, WORKFLOW_CONNECTION_RETRY_DELAYS_MS.length - 1)]
    : attempt === 0 ? options.initialDelayMs ?? WORKFLOW_AGENT_TURN_RETRY_DELAYS_MS[0] : WORKFLOW_AGENT_TURN_RETRY_DELAYS_MS[Math.min(attempt, WORKFLOW_AGENT_TURN_RETRY_DELAYS_MS.length - 1)];
  setTimeout(async () => {
    try {
      if (options.requireIdle && options.isIdle && !options.isIdle()) {
        if (idleAttempt < WORKFLOW_IDLE_RETRY_DELAYS_MS.length - 1) {
          recordWorkflowInternalEvent(undefined, `Workflow agent turn waiting for idle runtime before phase trigger: ${customType}`);
          const idleDelay = WORKFLOW_IDLE_RETRY_DELAYS_MS[Math.min(idleAttempt, WORKFLOW_IDLE_RETRY_DELAYS_MS.length - 1)];
          setTimeout(() => queueGuardedAgentTurn(pi, content, customType, attempt, connectionAttempt, idleAttempt + 1, options), idleDelay);
          return;
        }
        recordWorkflowInternalEvent(undefined, `Workflow agent turn idle wait exhausted; attempting phase trigger delivery: ${customType}`);
      }
      await options.onBeforeSend?.(customType);
      pi.sendMessage({ customType, content, display: false }, { triggerTurn: true, deliverAs: "followUp" });
      workflowScheduledAgentTurns = Math.max(0, workflowScheduledAgentTurns - 1);
    } catch (error) {
      if (workflowToolSurfaceAbort(error)) {
        workflowScheduledAgentTurns = Math.max(0, workflowScheduledAgentTurns - 1);
        recordWorkflowInternalEvent(undefined, `Workflow agent turn blocked by tool-surface verification: ${customType}: ${workflowTurnSendErrorMessage(error)}`);
        return;
      }
      if (workflowTurnSendErrorIsBusy(error) && attempt < WORKFLOW_AGENT_TURN_RETRY_DELAYS_MS.length - 1) {
        recordWorkflowInternalEvent(undefined, `Workflow agent turn delayed because Pi is still processing: ${customType}`);
        queueGuardedAgentTurn(pi, content, customType, attempt + 1, connectionAttempt, idleAttempt, options);
        return;
      }
      if (workflowTurnSendErrorIsConnection(error) && connectionAttempt < WORKFLOW_CONNECTION_RETRY_DELAYS_MS.length) {
        recordWorkflowInternalEvent(undefined, `Workflow agent turn retrying after connection error: ${customType} (retry ${connectionAttempt + 1}/${WORKFLOW_CONNECTION_RETRY_DELAYS_MS.length})`);
        queueGuardedAgentTurn(pi, content, customType, attempt, connectionAttempt + 1, idleAttempt, options);
        return;
      }
      workflowScheduledAgentTurns = Math.max(0, workflowScheduledAgentTurns - 1);
      const message = workflowTurnSendErrorMessage(error);
      recordWorkflowInternalEvent(undefined, `Workflow agent turn failed: ${customType}: ${message}`);
      try { options.onFinalFailure?.({ customType, message, error, attempt, connectionAttempt, idleAttempt }); } catch (hookError) {
        recordWorkflowInternalEvent(undefined, `Workflow agent turn failure recovery failed: ${customType}: ${workflowTurnSendErrorMessage(hookError)}`);
      }
    }
  }, delay);
}

function queueAgentTurn(pi: ExtensionAPI, content: string, customType: string, options?: WorkflowQueuedTurnOptions): void {
  workflowScheduledAgentTurns += 1;
  queueGuardedAgentTurn(pi, content, customType, 0, 0, 0, options);
}

function sendAgentTurnNowOrQueue(pi: ExtensionAPI, content: string, customType: string, options?: WorkflowQueuedTurnOptions): void {
  workflowScheduledAgentTurns += 1;
  void (async () => {
    try {
      await options?.onBeforeSend?.(customType);
      pi.sendMessage({ customType, content, display: false }, { triggerTurn: true, deliverAs: "followUp" });
      workflowScheduledAgentTurns = Math.max(0, workflowScheduledAgentTurns - 1);
    } catch (error) {
      workflowScheduledAgentTurns = Math.max(0, workflowScheduledAgentTurns - 1);
      if (workflowToolSurfaceAbort(error)) {
        recordWorkflowInternalEvent(undefined, `Workflow agent turn immediate send blocked by tool-surface verification: ${customType}: ${workflowTurnSendErrorMessage(error)}`);
        return;
      }
      queueAgentTurn(pi, content, customType, options);
      recordWorkflowInternalEvent(undefined, `Workflow agent turn immediate send fell back to queued delivery: ${customType}: ${workflowTurnSendErrorMessage(error)}`);
    }
  })();
}

function queueNativeFinalSummary(pi: ExtensionAPI, summary: string, customType: "workflow-plan-final-summary" | "workflow-mission-final-summary"): void {
  try {
    pi.sendMessage({ customType, content: professionalFinalSummaryMarkdown(summary), display: true }, { triggerTurn: false });
  } catch (error) {
    recordWorkflowInternalEvent(undefined, `Workflow final summary display failed (state already persisted): ${workflowTurnSendErrorMessage(error)}`);
  }
}

function visibleDeferredHandoffFailure(label: string): boolean {
  return /\b(handoff|repair|revalidation|execution|phase|approval|mission)\b/i.test(label);
}

type WorkflowDeferredActionOptions = {
  onFailure?: (error: unknown) => void;
  onSettled?: () => void;
  countsAsWorkflowWork?: boolean;
  timeoutMs?: number;
  disableTimeout?: boolean;
};

function workflowDeferredPhaseTimeoutMs(ctx: ExtensionContext, phase?: WorkflowPendingToolPhase): number {
  if (!phase) return 30_000;
  try {
    const settings = loadWorkflowSettings(ctx.cwd);
    const policy = phasePolicy(settings, phase);
    if (!subagentPolicyRequiresRequiredEvidence(policy)) return 30_000;
    const limits = settings.subagents as typeof settings.subagents & { subagentTimeoutMinutes?: number };
    const timeoutMinutes = Math.max(1, Math.min(240, Number(limits.subagentTimeoutMinutes ?? 20)));
    return timeoutMinutes * 60_000 + 60_000;
  } catch {
    return 30_000;
  }
}

function deferWorkflowAction(pi: ExtensionAPI, label: string, action: () => Promise<void> | void, options: WorkflowDeferredActionOptions = {}): void {
  const countsAsWorkflowWork = options.countsAsWorkflowWork === true;
  if (countsAsWorkflowWork) workflowScheduledAgentTurns += 1;
  const ACTION_TIMEOUT_MS = options.timeoutMs ?? 30_000;
  setTimeout(() => {
    const actionPromise = Promise.resolve(action());
    const deferredPromise = options.disableTimeout === true
      ? actionPromise
      : Promise.race([
        actionPromise,
        new Promise<never>((_, reject) =>
          setTimeout(() => reject(new Error(`Deferred workflow action timed out after ${ACTION_TIMEOUT_MS / 1000}s`)), ACTION_TIMEOUT_MS)
        ),
      ]);
    deferredPromise
      .catch((error) => {
        const message = `Workflow handoff failed: ${label}: ${error instanceof Error ? error.message : String(error)}`;
        if (visibleDeferredHandoffFailure(label)) show(pi, `# Workflow Handoff Failed\n\n${message}\n\nUse the visible workflow commands to continue, revise, or cancel.`);
        else recordWorkflowInternalEvent(undefined, message);
        try { options.onFailure?.(error); } catch (hookError) {
          recordWorkflowInternalEvent(undefined, `Workflow handoff failure recovery failed: ${label}: ${hookError instanceof Error ? hookError.message : String(hookError)}`);
        }
      })
      .finally(() => {
        setTimeout(() => {
          if (countsAsWorkflowWork) workflowScheduledAgentTurns = Math.max(0, workflowScheduledAgentTurns - 1);
          try { options.onSettled?.(); } catch (hookError) {
            recordWorkflowInternalEvent(undefined, `Workflow handoff settle recovery failed: ${label}: ${hookError instanceof Error ? hookError.message : String(hookError)}`);
          }
        }, 0);
      });
  }, 0);
}

function deferWorkflowMenuAction(pi: ExtensionAPI, label: string, action: () => Promise<void> | void, options: WorkflowDeferredActionOptions = {}): void {
  deferWorkflowAction(pi, label, action, { ...options, disableTimeout: true });
}

type WorkflowHandoffSnapshot = {
  kind: "plan_clarification_menu" | "plan_approval_menu" | "mission_clarification_menu" | "mission_plan_menu" | "workflow_menu";
  expectedMode?: string;
  activePlanId?: string;
  activeMissionId?: string;
  missionUpdatedAt?: string;
  missionPlanFingerprint?: string;
  draftPlan?: string;
  task?: string;
  questions?: ClarificationQuestion[];
  fallback: string;
};

function scheduleWorkflowHandoff(pi: ExtensionAPI, snapshot: WorkflowHandoffSnapshot, action: () => Promise<void> | void): void {
  deferWorkflowMenuAction(pi, snapshot.kind, action);
}

function missionPlanMenuFingerprint(mission: MissionState): string {
  const milestones = mission.milestones.map((m) => `${m.id}:${m.title}:${m.steps.join("|")}`).join("\n");
  return createHash("sha256").update(`${mission.planText ?? ""}\n${milestones}`).digest("hex").slice(0, 12);
}

