type WorkflowMarkdownSegment = { type: "markdown"; text: string } | { type: "mermaid"; source: string; diagramType: string; index: number };
type WorkflowMermaidRenderStatus = "rendered" | "fallback";
type WorkflowMermaidDiagramArtifact = { path: string; mimeType: "image/svg+xml" | "image/png" };
type WorkflowMermaidDiagramDetails = {
  title: string;
  source: string;
  diagramType: string;
  status: WorkflowMermaidRenderStatus;
  terminalDiagram: string;
  artifact?: WorkflowMermaidDiagramArtifact;
  image?: { data: string; mimeType: "image/png"; widthPx: number; heightPx: number };
  error?: string;
};

type WorkflowMermaidAsciiRenderer = typeof import("beautiful-mermaid")["renderMermaidASCII"];
type WorkflowMermaidEdge = { from: string; to: string; label?: string };
type WorkflowMermaidSequenceMessage = { from: string; to: string; label: string };
type WorkflowMermaidParsedGraph = { nodes: Map<string, string>; edges: WorkflowMermaidEdge[] };

function normalizeMermaidSource(source: string): string {
  const lines = source.replace(/\r\n/g, "\n").replace(/\r/g, "\n").split("\n");
  while (lines.length && !lines[0].trim()) lines.shift();
  while (lines.length && !lines[lines.length - 1].trim()) lines.pop();
  const nonEmpty = lines.filter((line) => line.trim().length > 0);
  const minIndent = nonEmpty.reduce((min, line) => {
    const indent = line.match(/^\s*/)?.[0].length ?? 0;
    return Math.min(min, indent);
  }, Number.POSITIVE_INFINITY);
  const trimBy = Number.isFinite(minIndent) ? minIndent : 0;
  return lines.map((line) => line.slice(Math.min(trimBy, line.length))).join("\n").trim();
}

function workflowMermaidDiagramType(source: string): string | undefined {
  const first = source.split(/\n/).map((line) => line.trim()).find((line) => line && !line.startsWith("%%"));
  if (!first) return undefined;
  const token = first.split(/\s+/)[0];
  return WORKFLOW_MERMAID_SUPPORTED_TYPES.has(token) ? token : undefined;
}

function parseWorkflowMermaidSegments(markdown: string): WorkflowMarkdownSegment[] {
  const segments: WorkflowMarkdownSegment[] = [];
  const pattern = /```mermaid\s*\n([\s\S]*?)```/gi;
  let lastIndex = 0;
  let diagramIndex = 0;
  for (const match of markdown.matchAll(pattern)) {
    const start = match.index ?? 0;
    if (start > lastIndex) segments.push({ type: "markdown", text: markdown.slice(lastIndex, start) });
    const source = normalizeMermaidSource(match[1] ?? "");
    const diagramType = workflowMermaidDiagramType(source);
    if (source && diagramType && source.length <= WORKFLOW_MERMAID_MAX_SOURCE_CHARS) {
      diagramIndex += 1;
      segments.push({ type: "mermaid", source, diagramType, index: diagramIndex });
    } else {
      segments.push({ type: "markdown", text: match[0] });
    }
    lastIndex = start + match[0].length;
  }
  if (lastIndex < markdown.length) segments.push({ type: "markdown", text: markdown.slice(lastIndex) });
  return segments;
}

function workflowMermaidSegmentsHaveDiagram(markdown: string): boolean {
  return parseWorkflowMermaidSegments(markdown).some((segment) => segment.type === "mermaid");
}

function markdownWithoutWorkflowMermaidBlocks(markdown: string): string {
  return parseWorkflowMermaidSegments(markdown).map((segment) => {
    if (segment.type === "markdown") return segment.text;
    return "";
  }).join("").replace(/\n{4,}/g, "\n\n\n").trim();
}

function workflowDiagramTitle(source: string, index = 1): string {
  const type = workflowMermaidDiagramType(source) ?? "Mermaid";
  return index > 1 ? `Workflow diagram ${index} (${type})` : `Workflow diagram (${type})`;
}

function workflowMermaidSlug(text: string): string {
  return text.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "").slice(0, 48) || "workflow-diagram";
}

function workflowMermaidArtifactPath(source: string, title: string, ext: "svg" | "png"): string {
  const hash = createHash("sha256").update(normalizeMermaidSource(source)).digest("hex").slice(0, 12);
  return join(WORKFLOW_MERMAID_ARTIFACT_DIR, `${workflowMermaidSlug(title)}-${hash}.${ext}`);
}

function writeWorkflowMermaidArtifact(source: string, title: string, data: Buffer | string, mimeType: "image/svg+xml" | "image/png"): WorkflowMermaidDiagramArtifact | undefined {
  try {
    mkdirSync(WORKFLOW_MERMAID_ARTIFACT_DIR, { recursive: true });
    const ext = mimeType === "image/svg+xml" ? "svg" : "png";
    const path = workflowMermaidArtifactPath(source, title, ext);
    writeFileSync(path, data);
    return { path, mimeType };
  } catch {
    return undefined;
  }
}

function workflowMermaidPlainWidth(line: string): number {
  return line.replace(/\x1b\[[0-9;]*m/g, "").length;
}

function workflowMermaidAsciiFits(text: string): boolean {
  const lines = text.split("\n");
  if (!lines.length || lines.length > WORKFLOW_MERMAID_ASCII_MAX_HEIGHT_LINES) return false;
  return lines.every((line) => workflowMermaidPlainWidth(line) <= WORKFLOW_MERMAID_ASCII_MAX_WIDTH_CELLS);
}

function workflowMermaidCleanLine(line: string): string {
  return line.replace(/%%.*$/, "").trim();
}

function workflowMermaidCleanLabel(label: string): string {
  return label
    .replace(/<br\s*\/?>(?![^<]*>)/gi, " ")
    .replace(/<[^>]+>/g, " ")
    .replace(/[`"']/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function workflowMermaidNodeLabel(raw: string): string {
  const trimmed = workflowMermaidCleanLabel(raw);
  const match = trimmed.match(/^[A-Za-z0-9_.$:-]+\s*(?:\[([^\]]+)\]|\(([^)]+)\)|\{([^}]+)\}|>\s*([^\]]+))$/);
  return workflowMermaidCleanLabel(match?.[1] ?? match?.[2] ?? match?.[3] ?? match?.[4] ?? trimmed);
}

function workflowMermaidNodeId(raw: string): string {
  return workflowMermaidCleanLabel(raw).replace(/(?:\[[^\]]+\]|\([^)]*\)|\{[^}]*\}|>.*)$/g, "").trim() || workflowMermaidNodeLabel(raw);
}

function workflowMermaidSetNode(nodes: Map<string, string>, raw: string): string {
  const id = workflowMermaidNodeId(raw);
  const label = workflowMermaidNodeLabel(raw);
  if (id && label && !nodes.has(id)) nodes.set(id, label);
  return id;
}

function workflowMermaidWrapWords(text: string, width: number): string[] {
  const words = workflowMermaidCleanLabel(text).split(/\s+/).filter(Boolean);
  const lines: string[] = [];
  let current = "";
  for (const word of words.length ? words : ["diagram"]) {
    if (!current) current = word;
    else if ((current.length + word.length + 1) <= width) current += ` ${word}`;
    else {
      lines.push(current);
      current = word;
    }
  }
  if (current) lines.push(current);
  return lines.flatMap((line) => line.length <= width ? [line] : line.match(new RegExp(`.{1,${width}}`, "g")) ?? [line]);
}

function workflowMermaidBox(label: string, width = 18): string[] {
  const contentWidth = Math.max(8, Math.min(width, Math.max(...workflowMermaidWrapWords(label, width).map((line) => line.length), 8)));
  const wrapped = workflowMermaidWrapWords(label, contentWidth);
  const border = `+${"-".repeat(contentWidth + 2)}+`;
  return [border, ...wrapped.map((line) => `| ${line.padEnd(contentWidth)} |`), border];
}

function workflowMermaidPadBox(box: string[], height: number): string[] {
  const width = Math.max(...box.map((line) => line.length));
  return Array.from({ length: height }, (_, index) => (box[index] ?? "").padEnd(width));
}

function workflowMermaidJoinBoxes(boxes: string[][]): string[] {
  const height = Math.max(...boxes.map((box) => box.length));
  const padded = boxes.map((box) => workflowMermaidPadBox(box, height));
  return Array.from({ length: height }, (_, row) => padded.map((box) => box[row]).join("     ").trimEnd());
}

function workflowMermaidParseGraph(source: string): WorkflowMermaidParsedGraph {
  const nodes = new Map<string, string>();
  const edges: WorkflowMermaidEdge[] = [];
  for (const rawLine of source.split("\n")) {
    const line = workflowMermaidCleanLine(rawLine).replace(/;$/, "");
    if (!line || /^(flowchart|graph|stateDiagram|stateDiagram-v2)\b/.test(line) || /^(subgraph|end\b|direction\b|classDef\b|class\b|style\b|linkStyle\b)/.test(line)) continue;
    const edgeMatch = line.match(/^(.+?)\s*(?:--\s*([^>|-]+?)\s*)?(-->|---|==>|-.->|->)\s*(?:\|([^|]+)\|\s*)?(.+)$/);
    if (edgeMatch) {
      const from = workflowMermaidSetNode(nodes, edgeMatch[1]);
      const label = workflowMermaidCleanLabel(edgeMatch[2] ?? edgeMatch[4] ?? "") || undefined;
      const targets = edgeMatch[5].split(/\s*&\s*/).map((target) => target.trim()).filter(Boolean);
      for (const target of targets) {
        const to = workflowMermaidSetNode(nodes, target);
        if (from && to) edges.push({ from, to, label });
      }
      continue;
    }
    const stateMatch = line.match(/^(.+?)\s*:\s*(.+)$/);
    if (stateMatch && !line.includes("http")) {
      const id = workflowMermaidCleanLabel(stateMatch[1]);
      const label = workflowMermaidCleanLabel(stateMatch[2]);
      if (id && label) nodes.set(id, label);
      continue;
    }
    workflowMermaidSetNode(nodes, line);
  }
  return { nodes, edges };
}

function workflowMermaidEdgeKey(edge: WorkflowMermaidEdge): string {
  return `${edge.from}->${edge.to}`;
}

function workflowMermaidShortLabel(label?: string): string | undefined {
  const clean = workflowMermaidCleanLabel(label ?? "");
  return clean && clean.length <= 28 ? clean : undefined;
}

function workflowMermaidRoots(graph: WorkflowMermaidParsedGraph): string[] {
  const targets = new Set(graph.edges.map((edge) => edge.to));
  const roots = [...graph.nodes.keys()].filter((id) => !targets.has(id));
  return roots.length ? roots : [...graph.nodes.keys()].slice(0, 1);
}

function workflowMermaidLayerGraph(graph: WorkflowMermaidParsedGraph): string[][] {
  const layers: string[][] = [];
  const seen = new Set<string>();
  let current = workflowMermaidRoots(graph).slice(0, 4);
  while (current.length && layers.length < 10) {
    const layer = current.filter((id) => !seen.has(id));
    if (!layer.length) break;
    layers.push(layer);
    layer.forEach((id) => seen.add(id));
    current = graph.edges.filter((edge) => layer.includes(edge.from) && !seen.has(edge.to)).map((edge) => edge.to).filter((id, index, list) => list.indexOf(id) === index).slice(0, 4);
  }
  const remaining = [...graph.nodes.keys()].filter((id) => !seen.has(id)).slice(0, 12);
  for (let i = 0; i < remaining.length; i += 4) layers.push(remaining.slice(i, i + 4));
  return layers;
}

function workflowMermaidLayerEdges(graph: WorkflowMermaidParsedGraph, fromLayer: string[], toLayer: string[]): WorkflowMermaidEdge[] {
  return graph.edges.filter((edge) => fromLayer.includes(edge.from) && toLayer.includes(edge.to));
}

function workflowMermaidRenderLayerConnector(edges: WorkflowMermaidEdge[], fromLayer: string[], toLayer: string[], represented: Set<string>): string[] {
  if (!edges.length) return [];
  edges.forEach((edge) => represented.add(workflowMermaidEdgeKey(edge)));
  if (fromLayer.length === 1 && toLayer.length === 1) {
    const label = workflowMermaidShortLabel(edges[0]?.label);
    return label ? ["         |", `         | ${label}`, "         v"] : ["         |", "         v"];
  }
  if (fromLayer.length === 1 && toLayer.length > 1) {
    const width = Math.max(12, toLayer.length * 18);
    return ["         |", `         +${"-".repeat(Math.min(width, 72))}`, toLayer.map(() => "    v    ").join("     ")];
  }
  if (fromLayer.length > 1 && toLayer.length === 1) return [fromLayer.map(() => "    |    ").join("     "), fromLayer.map(() => "    v    ").join("     "), "         +-------->"];
  return [fromLayer.map(() => "    |    ").join("     "), toLayer.map(() => "    v    ").join("     ")];
}

function workflowMermaidArrowTipIndexes(line: string): Set<number> {
  const indexes = new Set<number>();
  const trimmed = line.trim();
  if (!trimmed || /^\+[-+]+\+$/.test(trimmed) || /^\|.*\|$/.test(trimmed)) return indexes;
  if (/^[v^\s]+$/.test(line)) {
    line.split("").forEach((char, index) => {
      if (char === "v" || char === "^") indexes.add(index);
    });
    return indexes;
  }
  for (let index = 0; index < line.length; index += 1) {
    const char = line[index];
    if (char === ">") {
      const previous = line.slice(0, index).match(/\S(?=\s*$)/)?.[0];
      const next = line.slice(index + 1).match(/\S/)?.[0];
      if ((previous === "-" || previous === "+") && next !== "-" && next !== "+") indexes.add(index);
    } else if (char === "<") {
      const previous = line.slice(0, index).match(/\S(?=\s*$)/)?.[0];
      const next = line.slice(index + 1).match(/\S/)?.[0];
      if (previous !== "-" && previous !== "+" && (next === "-" || next === "+")) indexes.add(index);
    }
  }
  return indexes;
}

function workflowMermaidAccentConnectorLine(line: string, base: (text: string) => string, accent: (text: string) => string): string {
  const arrowTips = workflowMermaidArrowTipIndexes(line);
  if (!arrowTips.size) return base(line);
  let rendered = "";
  let baseStart = 0;
  for (const index of [...arrowTips].sort((left, right) => left - right)) {
    if (index > baseStart) rendered += base(line.slice(baseStart, index));
    rendered += accent(line[index]);
    baseStart = index + 1;
  }
  return `${rendered}${base(line.slice(baseStart))}`;
}

function workflowMermaidAccentConnectorText(text: string, base: (text: string) => string, accent: (text: string) => string): string {
  return text.split("\n").map((line) => workflowMermaidAccentConnectorLine(line, base, accent)).join("\n");
}

function workflowMermaidRenderRelationshipPanels(graph: WorkflowMermaidParsedGraph, edges: WorkflowMermaidEdge[]): string[] {
  const lines: string[] = [];
  const bySource = new Map<string, WorkflowMermaidEdge[]>();
  for (const edge of edges) bySource.set(edge.from, [...(bySource.get(edge.from) ?? []), edge]);
  for (const [source, sourceEdges] of bySource) {
    if (lines.length) lines.push("");
    lines.push(...workflowMermaidBox(graph.nodes.get(source) ?? source));
    const firstLabel = sourceEdges.length === 1 ? workflowMermaidShortLabel(sourceEdges[0].label) : undefined;
    lines.push("         |");
    if (firstLabel) lines.push(`         | ${firstLabel}`);
    lines.push("         v");
    const targetBoxes = sourceEdges.slice(0, 4).map((edge) => workflowMermaidBox(graph.nodes.get(edge.to) ?? edge.to));
    lines.push(...workflowMermaidJoinBoxes(targetBoxes));
  }
  return lines;
}

function workflowMermaidRenderGraphDiagram(source: string, diagramType: string): string | undefined {
  const graph = workflowMermaidParseGraph(source);
  if (!graph.nodes.size) return undefined;
  const layers = workflowMermaidLayerGraph(graph);
  const represented = new Set<string>();
  const lines = [`mermaid (${diagramType})`];
  layers.forEach((layer, index) => {
    const boxes = layer.map((id) => workflowMermaidBox(graph.nodes.get(id) ?? id));
    lines.push(...workflowMermaidJoinBoxes(boxes));
    const nextLayer = layers[index + 1];
    if (nextLayer) lines.push(...workflowMermaidRenderLayerConnector(workflowMermaidLayerEdges(graph, layer, nextLayer), layer, nextLayer, represented));
  });
  const unrepresented = graph.edges.filter((edge) => !represented.has(workflowMermaidEdgeKey(edge)));
  if (unrepresented.length) {
    if (lines.length > 1) lines.push("");
    lines.push(...workflowMermaidRenderRelationshipPanels(graph, unrepresented));
  }
  return lines.join("\n").trimEnd();
}

function workflowMermaidParseSequence(source: string): WorkflowMermaidSequenceMessage[] {
  const messages: WorkflowMermaidSequenceMessage[] = [];
  for (const rawLine of source.split("\n")) {
    const line = workflowMermaidCleanLine(rawLine).replace(/;$/, "");
    const match = line.match(/^([^\-:]+?)\s*(?:-+>>\+?|-+>\+?)\s*([^:]+?)\s*:\s*(.+)$/);
    if (match) messages.push({ from: workflowMermaidCleanLabel(match[1]), to: workflowMermaidCleanLabel(match[2]), label: workflowMermaidCleanLabel(match[3]) });
  }
  return messages;
}

function workflowMermaidRenderSequenceDiagram(source: string): string | undefined {
  const messages = workflowMermaidParseSequence(source);
  if (!messages.length) return undefined;
  const lines = ["mermaid (sequenceDiagram)"];
  for (const message of messages.slice(0, 18)) {
    const boxes = [workflowMermaidBox(message.from, 16), workflowMermaidBox(message.to, 16)];
    lines.push(...workflowMermaidJoinBoxes(boxes));
    lines.push(`        ${"-".repeat(14)}> ${message.label}`);
  }
  return lines.join("\n").trimEnd();
}

function workflowMermaidRenderStructuredSource(source: string, diagramType: string): string {
  const lines = [`mermaid (${diagramType})`, ...source.split("\n").map(workflowMermaidCleanLine).filter(Boolean).slice(0, 24)];
  const width = Math.min(72, Math.max(...lines.map((line) => Math.min(line.length, 72)), 18));
  const border = `+${"-".repeat(width + 2)}+`;
  return [border, ...lines.flatMap((line) => workflowMermaidWrapWords(line, width).map((part) => `| ${part.padEnd(width)} |`)), border].join("\n");
}

function workflowMermaidFallbackTerminalDiagram(source: string, diagramType: string): string {
  if (["flowchart", "graph", "stateDiagram", "stateDiagram-v2"].includes(diagramType)) return workflowMermaidRenderGraphDiagram(source, diagramType) ?? workflowMermaidRenderStructuredSource(source, diagramType);
  if (diagramType === "sequenceDiagram") return workflowMermaidRenderSequenceDiagram(source) ?? workflowMermaidRenderStructuredSource(source, diagramType);
  return workflowMermaidRenderStructuredSource(source, diagramType);
}

function renderWorkflowMermaidTerminalDiagram(source: string, diagramType: string): string {
  try {
    const { renderMermaidASCII } = requireFromExtension("beautiful-mermaid") as { renderMermaidASCII: WorkflowMermaidAsciiRenderer };
    const ascii = renderMermaidASCII(source, {
      useAscii: true,
      colorMode: "none",
      paddingX: 3,
      paddingY: 2,
      boxBorderPadding: 1,
    }).trimEnd();
    if (ascii.trim() && workflowMermaidAsciiFits(ascii)) return `mermaid\n${ascii}`;
  } catch {
  }
  return workflowMermaidFallbackTerminalDiagram(source, diagramType);
}
function pngDimensionsFromBase64(base64: string): { widthPx: number; heightPx: number } | undefined {
  try {
    const buffer = Buffer.from(base64, "base64");
    if (buffer.length < 24 || buffer[0] !== 0x89 || buffer[1] !== 0x50 || buffer[2] !== 0x4e || buffer[3] !== 0x47) return undefined;
    return { widthPx: buffer.readUInt32BE(16), heightPx: buffer.readUInt32BE(20) };
  } catch {
    return undefined;
  }
}

async function renderWorkflowMermaidPng(source: string, title: string): Promise<WorkflowMermaidDiagramDetails> {
  const diagramType = workflowMermaidDiagramType(source) ?? "mermaid";
  const terminalDiagram = renderWorkflowMermaidTerminalDiagram(source, diagramType);
  try {
    const puppeteer = (await import("puppeteer")).default as typeof import("puppeteer");
    const { renderMermaid } = await import("@mermaid-js/mermaid-cli") as typeof import("@mermaid-js/mermaid-cli");
    const browser = await puppeteer.launch({ headless: "shell", args: ["--no-sandbox"] });
    try {
      const renderOptions = {
        backgroundColor: WORKFLOW_MERMAID_DARK_BACKGROUND,
        viewport: { width: WORKFLOW_MERMAID_RENDER_WIDTH_PX, height: WORKFLOW_MERMAID_RENDER_HEIGHT_PX },
        mermaidConfig: WORKFLOW_MERMAID_DARK_THEME_CONFIG,
      } as const;
      const svgResult = await renderMermaid(browser, source, "svg", renderOptions);
      const artifact = writeWorkflowMermaidArtifact(source, title, Buffer.from(svgResult.data).toString("utf-8"), "image/svg+xml");
      const result = await renderMermaid(browser, source, "png", renderOptions);
      const png = Buffer.from(result.data);
      const data = png.toString("base64");
      const dims = pngDimensionsFromBase64(data) ?? { widthPx: WORKFLOW_MERMAID_RENDER_WIDTH_PX, heightPx: WORKFLOW_MERMAID_RENDER_HEIGHT_PX };
      return { title, source, diagramType: workflowMermaidDiagramType(source) ?? "mermaid", status: "rendered", terminalDiagram, artifact, image: { data, mimeType: "image/png", ...dims } };
    } finally {
      await browser.close();
    }
  } catch (error) {
    try {
      const sharp = requireFromExtension("sharp") as typeof import("sharp");
      const escapedTitle = title.replace(/[&<>]/g, (char) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;" }[char] ?? char));
      const escaped = source.replace(/[&<>]/g, (char) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;" }[char] ?? char));
      const widthPx = WORKFLOW_MERMAID_RENDER_WIDTH_PX;
      const heightPx = WORKFLOW_MERMAID_RENDER_HEIGHT_PX;
      const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${widthPx}" height="${heightPx}" viewBox="0 0 ${widthPx} ${heightPx}"><rect width="100%" height="100%" rx="22" fill="${WORKFLOW_MERMAID_DARK_BACKGROUND}"/><rect x="24" y="24" width="${widthPx - 48}" height="${heightPx - 48}" rx="18" fill="${WORKFLOW_MERMAID_DARK_SURFACE_ALT}" stroke="${WORKFLOW_MERMAID_DARK_ACCENT}" stroke-width="3"/><text x="52" y="72" font-family="Arial, sans-serif" font-size="30" font-weight="700" fill="${WORKFLOW_MERMAID_DARK_TEXT}">${escapedTitle}</text><text x="52" y="114" font-family="Arial, sans-serif" font-size="20" fill="${WORKFLOW_MERMAID_DARK_MUTED_TEXT}">Mermaid render failed; source preserved below.</text><foreignObject x="52" y="148" width="${widthPx - 104}" height="${heightPx - 182}"><pre xmlns="http://www.w3.org/1999/xhtml" style="font-family: monospace; font-size: 26px; line-height: 1.4; color: ${WORKFLOW_MERMAID_DARK_TEXT}; white-space: pre-wrap; margin: 0;">${escaped}</pre></foreignObject></svg>`;
      const artifact = writeWorkflowMermaidArtifact(source, title, svg, "image/svg+xml");
      const buffer = await sharp(Buffer.from(svg)).png().toBuffer();
      const data = buffer.toString("base64");
      const dims = pngDimensionsFromBase64(data) ?? { widthPx, heightPx };
      return { title, source, diagramType: workflowMermaidDiagramType(source) ?? "mermaid", status: "fallback", terminalDiagram, artifact, image: { data, mimeType: "image/png", ...dims }, error: error instanceof Error ? error.message : String(error) };
    } catch (fallbackError) {
      return { title, source, diagramType: workflowMermaidDiagramType(source) ?? "mermaid", status: "fallback", terminalDiagram, error: fallbackError instanceof Error ? fallbackError.message : String(fallbackError) };
    }
  }
}

function workflowMermaidCardBg(text: string): string {
  return `\x1b[48;2;5;7;13m${text}\x1b[0m`;
}

function workflowMermaidArtifactTarget(path: string): string {
  return path.startsWith("/") ? `file://${path}` : path;
}

function workflowMermaidArtifactLink(text: string, path: string): string {
  return hyperlink(text, workflowMermaidArtifactTarget(path));
}

function workflowMermaidRenderer(message: { content: unknown; details?: unknown }, options: { expanded: boolean }, theme: { fg(color: string, text: string): string; bg(color: string, text: string): string; bold(text: string): string }): Component {
  const details = message.details as WorkflowMermaidDiagramDetails | undefined;
  const box = new Box(1, 1, workflowMermaidCardBg);
  box.addChild(new Text(theme.fg("toolTitle", theme.bold(details?.title ?? "Workflow diagram")), 0, 0));
  box.addChild(new Spacer(1));
  const terminalDiagram = details?.terminalDiagram ? workflowMermaidAccentConnectorText(details.terminalDiagram, (text) => theme.fg("customMessageText", text), (text) => theme.fg("warning", text)) : theme.fg("customMessageText", "Diagram preview unavailable.");
  box.addChild(new Text(terminalDiagram, 0, 0));
  if (details?.artifact?.path) {
    const instruction = theme.fg("accent", theme.bold(workflowMermaidArtifactLink("Command click to open SVG diagram:", details.artifact.path)));
    const artifactPath = theme.fg("muted", workflowMermaidArtifactLink(details.artifact.path, details.artifact.path));
    box.addChild(new Spacer(1));
    box.addChild(new Text(`${instruction}\n${artifactPath}`, 0, 0));
  }
  if (options.expanded) {
    box.addChild(new Spacer(1));
    if (details?.error) box.addChild(new Text(theme.fg("warning", `Render fallback: ${details.error}`), 0, 0));
    box.addChild(new Markdown(`\`\`\`mermaid\n${details?.source ?? ""}\n\`\`\``, 0, 0, getMarkdownTheme(), { color: (text) => theme.fg("customMessageText", text) }));
  }
  return box;
}

function workflowSuiteMarkdownRenderer(message: { content: unknown }, _options: { expanded: boolean }, theme: { fg(color: string, text: string): string; bg(color: string, text: string): string }): Component | undefined {
  const content = typeof message.content === "string" ? message.content : "";
  if (!workflowMermaidSegmentsHaveDiagram(content)) return undefined;
  const box = new Box(1, 1, workflowMermaidCardBg);
  box.addChild(new Markdown(markdownWithoutWorkflowMermaidBlocks(content), 0, 0, getMarkdownTheme(), { color: (text) => theme.fg("customMessageText", text) }));
  return box;
}

// requiredSubagentPreflightSection, hasRequiredSubagentPreflight,
// forcedSubagentPolicySatisfiedGuidance imported from workflow-subagent-policy.ts
// Do not call the visible subagent tool just to satisfy forced policy

function planPrompt(task: string, priorPlan?: string, feedback?: string, settings = loadWorkflowSettings(), options: { forceClarification?: boolean; forceReason?: string; qualityGateFeedback?: string; feedbackKind?: "clarification" | "revision" | "repair" | "resume"; preflightBlock?: string } = {}): string {
  const planning = settings.planning;
  const subagents = settings.subagents;
  const maxQuestions = Math.max(1, Math.min(5, planning.maxClarificationQuestions ?? 3));
  const clarificationInstruction = planning.clarificationMode === "never"
    ? "Do not ask clarification questions. State necessary assumptions instead."
    : planning.clarificationMode === "always_for_nontrivial"
      ? "For non-trivial work, perform initial task analysis first, then use PLAN_DECISION: clarify only when missing scope, validation, risk, target-environment, permission, or follow-through choices would materially change the final plan. The clarification questions must be targeted to this task."
      : "Perform initial task analysis first. Use PLAN_DECISION: clarify when the task is ambiguous, risky, underspecified, broad, has multiple implementation paths, or needs scope/validation/permission/target-environment choices that would materially change the plan.";
  const subagentPolicy = subagents.planningPolicy ?? "auto";
  const depth = planning.depth ?? "standard";
  const analysisInstruction = clarificationAnalysisRequired(settings, "plan")
    ? "Before choosing PLAN_DECISION, do lightweight task analysis: identify likely files/systems, project rules to read, runtime vs repo target, scope ambiguity, risk, validation needs, permission boundaries, and whether sub-agents would improve the plan. Do not expose long chain-of-thought; only expose the decision reason when asking clarification."
    : "You may decide clarification immediately, but questions must still be task-specific and useful.";
  const subagentsBeforeClarification = useSubagentsBeforeClarification(settings, "plan");
  const planningOrchestrationPolicy = (subagents as typeof subagents & { planningOrchestrationPolicy?: string }).planningOrchestrationPolicy ?? "orchestrator_first";
  const preflightSatisfied = hasRequiredSubagentPreflight(options.preflightBlock);
  const forcedPlanningEvidenceRequired = subagentPolicyRequiresRequiredEvidence(subagentPolicy) && !preflightSatisfied;
  const orchestratorGuidance = preflightSatisfied
    ? "Planning orchestration required by forced policy has already been handled by Workflow Suite preflight. Do not call workflow-orchestrator again unless there is genuinely new targeted orchestration work beyond the preflight findings."
    : forcedPlanningEvidenceRequired && planningNeedsOrchestrator(settings, "plan")
      ? planningOrchestrationPolicy === "forced_orchestrated"
        ? "ORCHESTRATION REQUIRED: include workflow-orchestrator as one task inside the required forced Planning parallel subagent call. Do not call workflow-orchestrator separately before the worker batch."
        : "Planning orchestration is available for this turn. If it is useful, include workflow-orchestrator as one task inside the required forced Planning parallel subagent call; do not call workflow-orchestrator separately before the worker batch."
    : planningNeedsOrchestrator(settings, "plan")
      ? "ORCHESTRATION REQUIRED: call workflow-orchestrator before launching parallel planning/research workers or producing the final plan. The orchestrator must scope worker tasks, identify capability gaps, and decide whether live docs/API access is available before workers run."
      : "Orchestrator is optional for this planning turn. Use workflow-orchestrator if the task is broad, multi-pass, or needs coordinated workers.";
  const subagentGuidance = !planningSubagentsAllowed(settings)
    ? "Sub-agent use is disabled by settings. Do not call subagent."
    : preflightSatisfied && subagentPolicyRequiresRequiredEvidence(subagentPolicy)
      ? forcedSubagentPolicySatisfiedGuidance("planning")
      : subagentPolicy === "forced"
        ? `FORCED SUB-AGENT POLICY: before producing the final plan, you MUST call the subagent tool with at least ${Math.max(1, subagents.minPlanningWorkersForMaximum ?? 2)} planning/research worker(s). Use read-only agents such as implementation-planning, codebase-research, quality-validation, workflow-orchestrator, or general-worker. If subagent execution fails, stop and report the exact blocker. Do not use or recommend parallel editing.`
        : subagentPolicy === "maximum"
        ? `For non-trivial codebase work, use multiple read-only sub-agents before finalizing the plan. Strongly target at least ${subagents.minPlanningWorkersForMaximum ?? 2} workers, such as implementation-planning plus codebase-research or quality-validation. Internally decide delegate or skip; skip only for truly trivial work or unavailable sub-agent execution, and give only the concise skip reason in Sub-Agent Usage Summary. Do not print internal policy deliberation. Do not use or recommend parallel editing.`
        : subagentPolicy === "deep"
          ? `For non-trivial codebase work, use at least ${subagents.minPlanningWorkersForDeep ?? 1} read-only planning sub-agent before finalizing the plan. Prefer implementation-planning or codebase-research for safe read-only plan refinement. Internally decide delegate or skip; give only the concise skip reason in Sub-Agent Usage Summary. Do not print internal policy deliberation. Do not use or recommend parallel editing.`
          : "Sub-agents are strongly encouraged for speed and quality. Internally decide delegate or skip. Use them for file discovery, project-rule audit, ambiguity reduction, risk checks, or validation planning; skip only for trivial one-file/doc tasks or no useful parallel work, and give only the concise skip reason in Sub-Agent Usage Summary. Do not print internal policy deliberation.";
  const feedbackKind = options.feedbackKind ?? (feedback ? "revision" : undefined);
  const feedbackBlock = feedbackKind === "clarification" && feedback
    ? `Clarification answers from user:\n${feedback}\n\nCLARIFICATION HAS BEEN RESOLVED. Produce the final approval-ready plan now. Do not ask more clarification questions. Do not execute. Do not call tools, inspect files, generate diagrams, or create artifacts after this point. If more facts are needed, list files to inspect in the plan instead of exhaustively investigating them now.\n\n`
    : feedback
      ? `Plan revision instructions from user/workflow:\n${feedback}\n\nRevise the current draft/approved plan only. Do not call this clarification unless the text explicitly answers pending clarification questions. Do not execute.\n\n`
      : "";
  const forceClarificationPolicy = options.forceClarification
    ? "This is a forced clarification turn. You must ask high-value task-specific clarification questions. Do not produce the final implementation plan in this turn."
    : "If you can produce an approval-ready plan without materially risky assumptions, use PLAN_DECISION: plan.";
  const forcedQuestionRule = options.forceClarification
    ? `Ask at least one focused question and at most ${maxQuestions} questions. If no useful question exists, ask the best approval/scope/validation boundary question for this non-trivial request.`
    : "Prefer zero questions if a safe approval-ready plan can be made with assumptions.";

  return `You are in PI WORKFLOW PLAN MODE.

${professionalOutputGuidance("Plan Mode")}

Diagram guidance:
- ${workflowMermaidGuidance()}

Task:
${task}

Planning settings:
- clarificationMode: ${planning.clarificationMode}
- maxClarificationQuestions: ${maxQuestions}
- depth: ${depth}
- clarificationTiming: ${planning.clarificationTiming ?? "after_initial_analysis"}
- clarificationQualityGate: ${planning.clarificationQualityGate !== false}
- allowClarificationWithoutAnalysis: ${planning.allowClarificationWithoutAnalysis === true}
- useSubagentsBeforeClarification: ${planning.useSubagentsBeforeClarification !== false}
- subagents.enabled: ${subagents.enabled}
- subagents.planningPolicy: ${subagentPolicy}
- subagents.requireApprovalBeforeRun: ${subagents.requireApprovalBeforeRun === true}
- planningOrchestrationPolicy: ${planningOrchestrationPolicy}
- allowParallelReadOnly: ${subagents.allowParallelReadOnly !== false}
- allowParallelPlanning: ${subagents.allowParallelPlanning !== false}
- allowParallelValidation: ${subagents.allowParallelValidation !== false}
- allowParallelExecution: ${subagents.allowParallelExecution !== false}
- allowParallelEdits: ${subagents.allowParallelEdits === true}
- editConcurrencyMode: ${subagents.editConcurrencyMode ?? "sequential"}
${requiredSubagentPreflightSection(options.preflightBlock)}

${subagentCapabilityTable()}

${priorPlan ? `Current draft/approved plan to revise:\n${priorPlan}\n\n` : ""}${feedbackBlock}${options.forceClarification ? `CLARIFICATION IS REQUIRED BEFORE FINAL PLANNING. Reason: ${options.forceReason ?? "always_for_nontrivial classified this as non-trivial"}\nYour job in this turn is to perform lightweight task analysis, then generate only high-value clarification questions from the actual task. Do not produce an implementation plan in this turn. ${subagentsBeforeClarification ? "If planning depth/policy calls for it and sub-agent use is available, use read-only planning/research sub-agents before asking clarification so the questions are context-aware." : "Do not call sub-agents in this clarification-generation turn unless forced by sub-agent policy."} Do not use generic reusable workflow boilerplate questions.\n\n` : ""}${options.qualityGateFeedback ? `The previous clarification output failed the clarification quality gate: ${options.qualityGateFeedback}\nRegenerate better task-specific clarification questions${options.forceClarification ? ". Do not produce a final plan in this retry." : ", or use PLAN_DECISION: plan if no high-value question exists."}\n\n` : ""}MANDATORY STRUCTURED HANDOFF: Before your final response, call workflow_plan_result with decision=clarify, plan, or blocked. The tool payload is the primary control plane. After workflow_plan_result returns, print the user-facing markdown for that decision and stop: the approval-ready # Implementation Plan for decision=plan, the clarification questions for decision=clarify, or the blocker summary for decision=blocked. If workflow_plan_result is unavailable, output the parser-safe PLAN_DECISION fallback once and STOP immediately; do not call subagent as an acknowledgement, do not retry invalid tool names, and do not continue analysis after the fallback.

LEGACY FALLBACK: Your VERY FIRST LINE must be exactly one of:
${options.forceClarification ? "PLAN_DECISION: clarify" : "PLAN_DECISION: clarify\nPLAN_DECISION: plan"}

No preamble. No visible chain-of-thought. No "I see that..." No "Let me think about..." Start directly with one of those two lines.

Initial analysis requirement:
- ${analysisInstruction}

Web research guidance:
${workflowRuntimeWebResearchGuidance()}

Clarification decision policy:
- ${clarificationInstruction}
- Include a concise decision line after PLAN_DECISION: CLARIFICATION_DECISION: ask, CLARIFICATION_DECISION: skip, or CLARIFICATION_DECISION: optional.
- Include Reason: <brief human-readable reason> after CLARIFICATION_DECISION.
- Clarification questions are only valid because a real task is present.
- Never ask clarification for an empty task.
- If the user explicitly asks to be consulted before deciding validation level, scope, risk, or aggressiveness, use PLAN_DECISION: clarify.
- ${forceClarificationPolicy}

If you cannot call workflow_plan_result and PLAN_DECISION: clarify, follow with this exact parser-safe legacy fallback format. The extension will turn these into a guided interactive UI:
## Clarifying Questions

## Q1. <task-specific short question>
A. <option specific to this task>
B. <option specific to this task>
C. <option specific to this task>
D. Other: type your own answer
Skip this question

Rules for questions:
- Generate questions from the actual task after initial analysis.
- Clarification is not a survey. Ask only when the answer genuinely changes the implementation plan.
- ${forcedQuestionRule}
- Prefer one focused question when possible. Maximum ${maxQuestions} questions.
- Each question must resolve at least one real ambiguity, risk, scope decision, validation decision, target-environment choice, permission boundary, sub-agent need, diagnostic-vs-implementation choice, acceptance criterion, or forbidden-file concern.
- Each question must be specific and actionable.
- Each option must be a concrete choice, not "yes/no".
- Always include D. Other as last option.
- Do not ask product-roadmap or strategy questions unless the user explicitly requested product strategy planning.
- Do not ask the user how to work around Pi/tool limitations, shell limitations, or preflight limitations; state the limitation and include safe preflight checks in the plan.
- Never ask "Should I clarify more?" or "What do you want me to do?"

${options.forceClarification ? "Call workflow_plan_result with decision=clarify. Do not output PLAN_DECISION: plan in this forced clarification turn. The plan format below applies only after clarification answers are recorded." : "If PLAN_DECISION: plan, call workflow_plan_result with decision=plan and structured steps, then follow with:"}
# Implementation Plan
## Objective
## Current State Assumptions
## Project Rules Applied
## Files To Inspect
## Files Likely To Modify
## Allowed New File Locations
## Files That Must Not Be Touched
## Risk Assessment
## Acceptance Criteria
## Validation Evidence Required
## Implementation Steps
## Validation Steps
## Rollback Plan
## Sub-Agent Usage Summary
## Open Questions
## Approval Gate
Status: READY FOR APPROVAL

Plan quality requirements:
- Mandatory workflow structure overrides user-requested output sections: every final plan must include a parser-safe ## Implementation Steps section with numbered steps.
- Be specific and execution-ready.
- Include concrete files to inspect before edits.
- Identify likely modified files, allowed new file locations, and off-limits files.
- ${artifactSafetyPolicyBlock("planning").replace(/\n/g, "\n- ")}
- Include risks, validation, rollback, and approval gate.
- Acceptance Criteria must be observable and testable, not generic intent.
- Validation Evidence Required must state exact evidence the validator should look for, including changed-file inventory, safe commands to run when applicable, commands to skip with reasons, and manual QA evidence if needed.
- Do not start execution. The plan must wait for user approval.
- After writing Status: READY FOR APPROVAL, stop immediately. Do not call tools, inspect files, generate diagrams, create artifacts, or continue with implementation before approval.

Implementation step sizing:
- The ## Implementation Steps section is required in every Plan Mode plan, including simple/fast/custom preset plans.
- Choose the number of implementation steps dynamically from actual task complexity, research findings, risk, and execution boundaries.
- Do not pad the plan to any fixed number and do not create steps just to fill space.
- Use a numbered list for trackable implementation steps.
- Each numbered implementation step must be a meaningful execution unit the executor can track with workflow_progress.
- Keep the ## Implementation Steps list focused on trackable execution units; put supporting commands, checks, files, or notes inline within the step or in other plan sections rather than as separate implementation-step bullets.
- Small/simple tasks may need only 2-4 steps; standard tasks may need around 4-8 steps; complex/risky/multi-area tasks may need more.
- If many details exist, group them into coherent execution phases instead of exploding every detail into separate tracked steps.

Project instruction priority:
- Project rules (AGENTS.md, .factory/rules, .cursor/rules) override global defaults.
- Inspect project rule files before planning.
- Never ignore project safety constraints.

Sub-agent planning policy:
- planning.depth controls planner effort; subagents.planningPolicy controls planning sub-agent aggressiveness.
- ${subagentGuidance}
- ${orchestratorGuidance}
- Parallel read-only, planning, execution, review, and validation agents are separate from parallel file editing.
- allowParallelEdits=false does not mean no multiple agents; it means simultaneous conflicting file writes are not allowed.
- Parallel editing is unsafe and must remain blocked or serialized unless conflict protection exists.
- When useSubagentsBeforeClarification=true and planning depth/policy is deep, maximum, or forced, use read-only codebase-research, implementation-planning, quality-validation, or general-worker before asking clarification if that analysis would make the questions more specific.
- In Sub-Agent Usage Summary, list each sub-agent used and what it checked; if none ran, give the exact trivial/unavailable reason.
- If sub-agents are not used when subagents.planningPolicy is auto, deep, or maximum, explain why in Sub-Agent Usage Summary.
- ${preflightSatisfied && subagentPolicyRequiresRequiredEvidence(subagentPolicy) ? "Forced planning policy was satisfied by Workflow Suite preflight or an internal trivial-work exemption; do not rerun required workers solely for policy compliance." : "If subagents.planningPolicy is forced, you must use the required sub-agents before the final plan unless Workflow Suite supplied an internal trivial-work exemption, or stop with: Sub-agent policy is forced, but sub-agent execution is unavailable because <reason>."}`;
}

// SubagentPhase and SubagentPolicyValue imported from workflow-subagent-policy.ts

// workerCount, activeWorkerTargetLabel, workerTargetForPolicy, subagentPhaseSettingKeys,
// repairPolicySource, fileWriteModeLabel, phasePolicy, phaseAutoUseAllowed,
// phaseParallelAllowed, forcedSubagentUnavailableReason, forcedSubagentMessage
// imported from workflow-subagent-policy.ts

function repairWorkerCount(settings: ReturnType<typeof loadWorkflowSettings>): { deep: number; maximum: number } {
  return workerCount(settings, "Repair");
}

function phaseWorkerSettingsLine(settings: ReturnType<typeof loadWorkflowSettings>, label: string, phase: SubagentPhase, sourceLabel = "shared"): string {
  const keys = subagentPhaseSettingKeys(phase);
  const subagents = settings.subagents as typeof settings.subagents & Record<string, boolean | number | string | undefined>;
  const rawPolicy = phase === "Repair" ? (subagents[keys.policyKey] ?? settings.subagents.executionPolicy) : subagents[keys.policyKey];
  const policy = (rawPolicy as SubagentPolicyValue | undefined) ?? "auto";
  const counts = phase === "Repair" ? repairWorkerCount(settings) : workerCount(settings, phase);
  const deep = phase === "Repair" ? counts.deep : subagents[keys.deepKey] ?? counts.deep;
  const maximum = phase === "Repair" ? counts.maximum : subagents[keys.maximumKey] ?? counts.maximum;
  const source = phase === "Repair" ? repairPolicySource(settings) : sourceLabel;
  return `${label} Policy: ${policy} (${source})\n${effectiveWorkerRequirementLine(label, policy, { deep: Number(deep), maximum: Number(maximum) })}\n${label} Workers When Policy Is Deep: ${deep}\n${label} Workers When Policy Is Maximum Or Forced: ${maximum}`;
}

function standardPhaseWorkerSettingsLine(settings: ReturnType<typeof loadWorkflowSettings>, label: string, phase: SubagentPhase): string {
  const policy = standardPhasePolicy(settings, phase);
  const workers = standardWorkerCount(settings, phase);
  return `${label} Policy: ${policy} (standard effective)\n${effectiveWorkerRequirementLine(label, policy, workers)}\n${label} Workers When Policy Is Deep: ${workers.deep}\n${label} Workers When Policy Is Maximum Or Forced: ${workers.maximum}`;
}

function missionPlanningWorkerCount(settings: ReturnType<typeof loadWorkflowSettings>): { deep: number; maximum: number } {
  return {
    deep: settings.missions.minWorkersForDeep ?? settings.subagents.minPlanningWorkersForDeep ?? 1,
    maximum: settings.missions.minWorkersForMaximum ?? settings.subagents.minPlanningWorkersForMaximum ?? 2,
  };
}

function missionPlanningWorkerSettingsLine(settings: ReturnType<typeof loadWorkflowSettings>): string {
  const workers = missionPlanningWorkerCount(settings);
  return `Mission Planning Policy: ${missionSubagentPolicy(settings)} (mission-specific)\nMission Planning Workers When Policy Is Deep: ${workers.deep}\nMission Planning Workers When Policy Is Maximum Or Forced: ${workers.maximum}`;
}

// fileWriteModeLabel, phasePolicy, phaseAutoUseAllowed, phaseParallelAllowed,
// forcedSubagentUnavailableReason, forcedSubagentMessage
// imported from workflow-subagent-policy.ts

type ArtifactSafetyAudience = "general" | "planning" | "execution" | "review" | "validation" | "repair" | "subagent";

function artifactSafetyPolicyBlock(audience: ArtifactSafetyAudience = "general"): string {
  const shared = `Artifact placement and preservation policy:
- Do not create arbitrary repository-root files. A new root-level file is allowed only when the approved plan, explicit user request, or validator finding names that exact root path.
- Before creating any file, inspect existing project conventions and place it in the established source, test, docs, config, script, or feature-local directory that matches the project.
- Treat untracked, unexpected, or ambiguous files as possibly user-owned. Do not delete, overwrite, move, or clean them unless the user explicitly approved that exact file disposition.
- If a current-task-created file is in the wrong location but contains recoverable work, preserve the content and move/rename it to the correct approved location when safe; never delete it merely to clean the root.
- If ownership, destination, or safety is unclear, stop and report the path, evidence, and proposed disposition instead of guessing.`;
  const role = audience === "planning"
    ? `Planning requirement: list allowed new file locations and call out any legitimate root-level files by exact path; otherwise assume root output is forbidden.`
    : audience === "execution"
      ? `Execution requirement: the main executor owns file placement. Create files only in approved or conventionally correct locations, and relocate current-task misplaced files instead of deleting them.`
      : audience === "review"
        ? `Review requirement: flag missing path constraints, arbitrary root artifacts, unsafe cleanup-by-deletion, and plans that do not preserve recoverable misplaced files.`
        : audience === "validation"
          ? `Validation requirement: remain read-only. Prefer text evidence over temporary files; if evidence files are unavoidable, do not write them at repository root and never repair or relocate files during validation.`
          : audience === "repair"
            ? `Repair requirement: keep repairing concrete in-scope failures until revalidation is ready. Repair may move only current-task-created misplaced recoverable files when safe and in scope. Disclose moved, preserved, deleted, root, and possibly user-owned files in workflow_repair_result; set needsUserApproval only when a concrete hard-safety action or artifact disposition must stop automatic revalidation. Advisory follow-up, credential rotation recommendations, preserved ambiguous files, manual QA still needed, and pre-existing debt belong in summary/safety notes, not needsUserApproval. Deletion requires explicit safety evidence or approval.`
            : audience === "subagent"
              ? `Sub-agent requirement: support workers default to read-only inspection. They must not create, delete, move, or clean files unless explicitly authorized with path-approved scope by the parent workflow.`
              : `General requirement: keep artifact placement explicit, preserve recoverable content, and report uncertain cleanup for user approval.`;
  return `${shared}\n- ${role}`;
}

function repairArtifactDispositionOutput(): string {
  return `## Artifact Disposition
List movedFiles, preservedFiles, deletedFiles, rootArtifacts, possiblyUserOwnedFiles, and needsUserApproval. State "none" for empty categories. Set needsUserApproval only for a concrete disposition/action that should block automatic revalidation. Do not set it for advisory-only follow-up, credential rotation recommendations, preserved ambiguous files, manual QA still needed, or pre-existing debt. Deletion is acceptable only when explicitly approved or clearly current-task-generated, unrecoverable, and non-user-owned; otherwise preserve or request approval.`;
}

function forcedSubagentCallShape(phase: SubagentPhase, required: number): string {
  const workflowPhase = phase.toLowerCase();
  const preferred = phase === "Planning"
    ? ["implementation-planning", "codebase-research", "general-worker", "quality-validation"]
    : phase === "Execution"
      ? ["general-worker", "implementation-planning", "codebase-research", "quality-validation"]
      : phase === "Repair"
        ? ["general-worker", "implementation-planning", "quality-validation", "codebase-research"]
        : phase === "Review"
          ? ["quality-validation", "implementation-planning", "general-worker", "codebase-research"]
          : ["quality-validation", "general-worker", "codebase-research", "implementation-planning"];
  const agents = preferred.slice(0, Math.max(1, required));
  const tasks = agents.map((agent) => `{ agent: "${agent}", task: "<focused ${workflowPhase} support task>" }`).join(", ");
  return `Use one visible parallel call with this shape: subagent({ workflowPhase: "${workflowPhase}", tasks: [${tasks}] }). Provide at least ${Math.max(1, required)} worker task entr${Math.max(1, required) === 1 ? "y" : "ies"} in that single parallel tasks array. Worker count means task entries, not unique agent names. The agents shown are examples only; choose phase-suitable workers by task fit. Duplicate suitable agent roles are valid when useful, and distinct role names are not required. Do not add irrelevant filler roles. Do not use subagent chain for forced multi-worker evidence; chain is sequential and will be blocked. Every task must be separate, focused, useful, and phase-suitable.`;
}

function phasePromptPolicyBlock(settings: ReturnType<typeof loadWorkflowSettings>, phase: SubagentPhase, label: string = phase, preflightBlock?: string): string {
  const policy = phasePolicy(settings, phase);
  const workers = workerCount(settings, phase);
  const required = Math.max(1, workers.maximum);
  const phaseName = phase === "Repair" ? "repair-mode sub-agent workers" : `${phase.toLowerCase()} sub-agent workers`;
  const preflightSatisfied = hasRequiredSubagentPreflight(preflightBlock);
  const guidance = !phaseAutoUseAllowed(settings, phase) || policy === "off"
    ? `${label} sub-agent use is disabled by settings. Do not call subagent.`
    : preflightSatisfied && subagentPolicyRequiresRequiredEvidence(policy)
      ? forcedSubagentPolicySatisfiedGuidance(label)
      : policy === "forced"
        ? `FORCED SUB-AGENT POLICY: you MUST call the subagent tool with at least ${required} ${phaseName}, or stop with: Sub-agent policy is forced, but sub-agent execution is unavailable because <reason>. ${forcedSubagentCallShape(phase, required)} Do not continue this phase or write files until the required workers have reported.`
        : policy === "maximum"
        ? `Strongly target ${Math.max(1, workers.maximum)} ${phaseName}; internally decide delegate or skip, skip only when the work is truly trivial or sub-agents are unavailable, and give only the concise skip reason. Do not print internal policy deliberation.`
        : policy === "deep"
          ? `Use ${Math.max(1, workers.deep)} ${phaseName} for non-trivial work; internally decide delegate or skip and give a concrete skip reason if no worker is useful or available. Do not print internal policy deliberation.`
          : `${label} sub-agent use is strongly encouraged; internally decide delegate or skip, strongly consider up to ${Math.max(1, workers.deep)} worker${Math.max(1, workers.deep) === 1 ? "" : "s"} for non-trivial work, use workers for speed, file inspection, risk discovery, validation prep, or evidence-heavy work, and give a concrete skip reason only when none run. Do not print internal policy deliberation.`;
  return `Sub-agent policy for ${label}:
- policy: ${policy}
- workers: ${activeWorkerTargetLabel(policy, workers)}
- requireApprovalBeforeRun: ${settings.subagents.requireApprovalBeforeRun === true ? "enabled" : "disabled"}
- parallel ${phase.toLowerCase()} agents: ${phaseParallelAllowed(settings, phase) ? "enabled" : "disabled"}
- parallel read-only agents: ${settings.subagents.allowParallelReadOnly !== false ? "enabled" : "disabled"}
- parallel file writes: ${fileWriteModeLabel(settings)}
- editConcurrencyMode: ${settings.subagents.editConcurrencyMode ?? "sequential"}
- conflict protection required for parallel edits: ${settings.subagents.requireParallelEditConflictProtection !== false ? "yes" : "no"}
- ${guidance}
- Parallel agents are for isolated support work. Parallel File Writes controls simultaneous file writes only. File writes remain serialized through the main Executor unless scoped conflict protection is explicitly enabled.
- ${artifactSafetyPolicyBlock("subagent").replace(/\n/g, "\n- ")}`;
}

// Duplicated pure policy functions removed; now imported from workflow-subagent-policy.ts

// Local convenience wrappers that delegate to imported policy functions
function effectiveWorkerRequirementLine(label: string, policy: SubagentPolicyValue | undefined, workers: { deep: number; maximum: number }): string {
  const effectivePolicy = policy ?? "auto";
  if (effectivePolicy === "off") return `${label} Effective Requirement: off; no sub-agents should run for this phase.`;
  if (effectivePolicy === "auto") return `${label} Effective Target: sub-agents are strongly encouraged; skip only with a concrete trivial/unavailable reason.`;
  if (effectivePolicy === "deep") return `${label} Effective Target: use ${Math.max(1, workers.deep)} worker${Math.max(1, workers.deep) === 1 ? "" : "s"} for non-trivial work.`;
  if (effectivePolicy === "maximum") return `${label} Effective Target: strongly prefer ${Math.max(1, workers.maximum)} worker${Math.max(1, workers.maximum) === 1 ? "" : "s"}; skip only if trivial or unavailable with explanation.`;
  return `${label} Effective Requirement: must use ${Math.max(1, workers.maximum)} worker${Math.max(1, workers.maximum) === 1 ? "" : "s"} or stop/block.`;
}

function phaseWorkerLine(settings: ReturnType<typeof loadWorkflowSettings>, phase: SubagentPhase, policy: SubagentPolicyValue | undefined): string {
  return `${phase} Workers: ${activeWorkerTargetLabel(policy, workerCount(settings, phase))}`;
}

function subagentCapabilityTable(): string {
  return `## Available Sub-Agent Types

Use only these exact installed agent names when calling the subagent tool. Do not call general-purpose; it is not an installed agent. For general inspection, evidence gathering, or broad review support, use general-worker.

| Agent | Tools | Best For |
|---|---|---|
| general-worker | read, grep, find, ls, bash | Focused inspection, command evidence, scoped analysis |
| implementation-planning | read, grep, find, ls | Pure analysis, step breakdown, implementation strategy (no bash) |
| codebase-research | read, grep, find, ls, bash | Code inspection, dependency tracing, architecture review |
| quality-validation | read, grep, find, ls, bash | Regression checks, build verification, independent review |
| workflow-orchestrator | read, grep, find, ls, bash, subagent | Fan-out research coordination, multi-worker orchestration |

Sub-agents are support workers by default. They may inspect, run safe evidence commands, and propose patches, but the parent workflow/main executor owns final file creation, deletion, movement, and integration unless an approved phase explicitly grants path-scoped mutation.
${artifactSafetyPolicyBlock("subagent")}
Prefer general-worker or codebase-research for inspection and command evidence. Use implementation-planning only for pure read-only analysis tasks.`;
}

function planStepStatusDisplay(state: WorkflowState): string {
  const steps = state.planProgress?.steps;
  if (!steps?.length) return "";
  const lines = steps.map((step, i) => {
    const explicitActive = state.planProgressLastToolStatus === "active" && state.planProgressLastToolStep === i + 1;
    const statusLabel = step.status === "active" ? (explicitActive ? "ACTIVE" : "ACTIVE (workflow_progress required)")
      : step.status === "completed" ? "completed"
      : step.status === "failed" ? "FAILED"
      : step.status === "skipped" ? "skipped"
      : step.status === "blocked" ? "BLOCKED"
      : "pending";
    return `  ${i + 1}. ${step.title} — ${statusLabel}`;
  });
  return `Current Plan Step Status:\n${lines.join("\n")}`;
}

function executePrompt(state: WorkflowState, settings = loadWorkflowSettings(), preflightBlock?: string): string {
  const policy = settings.subagents.executionPolicy ?? "auto";
  const workers = workerCount(settings, "Execution");
  const stepValidationEnabled = settings.workflow.validateAfterEachStep === true;
  const stepApprovalEnabled = settings.workflow.requireApprovalPerStep === true;
  const currentStepIndex = state.planProgress?.currentStepIndex ?? 0;
  const currentStep = state.planProgress?.steps?.[currentStepIndex];
  const stepExecutionGuidance = (stepValidationEnabled || stepApprovalEnabled) && currentStep
    ? `Per-step gating is enabled. Execute only current step ${currentStepIndex + 1}: ${currentStep.title}. Stop after that step and summarize only that step. Do not continue to later steps until ${stepValidationEnabled ? "the validator passes this step" : "the user approves continuing"}.`
    : "Per-step gating is disabled. Execute the whole approved plan in this executor turn unless a safety gate blocks you.";
  const reviewerFindings = state.reviewerReport?.trim();
  const reviewContextParts = [
    state.reviewerVerdict ? `Reviewer verdict: ${state.reviewerVerdict}` : undefined,
    reviewerFindings ? `Reviewer report:\n${compact(reviewerFindings, 2400)}` : undefined,
    state.lastReviewFailure ? `Last review failure/blocker:\n${compact(state.lastReviewFailure, 1200)}` : undefined,
  ].filter((part): part is string => Boolean(part));
  const reviewerFindingsBlock = reviewContextParts.length
    ? `Reviewer findings are part of the execution contract. Address or explicitly account for each reviewer note before broad delegation. If reviewer notes say a step is already complete or should be skipped, call workflow_progress for that step before launching workers to redo it. If reviewer findings identify a blocker or repair need, do not execute unrelated Plan steps; stop or route to repair unless the state already shows the issue was repaired.\n\n${reviewContextParts.join("\n\n")}`
    : "";
  const preflightSatisfied = hasRequiredSubagentPreflight(preflightBlock);
  const subagentGuidance = !executionSubagentsAllowed(settings)
    ? "Execution sub-agents are disabled by settings. Do not call subagent."
    : preflightSatisfied && subagentPolicyRequiresRequiredEvidence(policy)
      ? forcedSubagentPolicySatisfiedGuidance("execution")
      : policy === "forced"
        ? `FORCED SUB-AGENT POLICY: first call workflow_progress({ step: N, status: "active" }) for the current approved Plan step. Then call the subagent tool with at least ${Math.max(1, workers.maximum)} execution/preparation worker(s) before any other executor work, file write, bash command, or final execution summary. ${forcedSubagentCallShape("Execution", Math.max(1, workers.maximum))} Use them in parallel where safe for file inspection, implementation strategy, scoped implementation help, patch planning, regression search, and validation preparation. If subagent execution fails, stop and report the exact blocker. Do not apply simultaneous conflicting edits.`
        : policy === "maximum"
        ? `For non-trivial implementation, use execution sub-agents before editing for analysis, implementation preparation, scoped implementation help, patch planning, regression search, and validation preparation. Strongly target at least ${workers.maximum} execution workers; internally decide delegate or skip, skip only for trivial work or unavailable sub-agent execution, and give only the concise skip reason. Do not print internal policy deliberation. Do not apply simultaneous conflicting edits.`
        : policy === "deep"
          ? `For non-trivial implementation, use at least ${workers.deep} execution sub-agent before editing for analysis, implementation preparation, scoped implementation help, patch planning, or validation preparation. Internally decide delegate or skip and give only the concise skip reason. Do not print internal policy deliberation. Do not apply simultaneous conflicting edits.`
          : `Execution sub-agents are strongly encouraged for speed and quality. Internally decide delegate or skip. Strongly consider up to ${Math.max(1, workers.deep)} execution worker${Math.max(1, workers.deep) === 1 ? "" : "s"} for non-trivial work. Use them for file inspection, implementation prep, scoped implementation help, risk discovery, patch planning, or validation prep; skip only for trivial changes or no useful parallel work and give only the concise skip reason. Do not print internal policy deliberation.`;
  const automatableEvidenceGuidance = `Automatable evidence contract:
- Before calling workflow_execution_result, you MUST gather all automatable validation evidence that the approved plan requires.
- For web/app projects (React, Vite, Next.js, Vue, Svelte, etc.): run build and test commands; when the plan requires runtime/browser/localStorage behavior, start a bounded dev or preview server and verify the behavior with available commands (curl, node scripts, or the platform's built-in tools), then stop/cleanup the server.
- For API/backend projects: run build, test, lint, typecheck; verify server startup, endpoint responses, and persistence where required by the plan.
- For library/CLI projects: run build, test, lint, typecheck; verify CLI output or module exports where required.
- Your execution summary must distinguish "Automated Evidence Completed" from "Truly Manual Evidence Remaining". Do not label automatable runtime checks as "manual verification needed".
- "Manual verification needed" is only valid for genuinely non-automatable human judgment (visual design approval, subjective UX assessment, external service accounts you cannot access). If a check can be automated with available tools and settings, you must perform it.`;

  return `You are in PI WORKFLOW EXECUTE MODE.

YOUR TOOLS: edit, write, bash, workflow_progress, workflow_diagram, workflow_execution_result. You, the main executor, own all file writes, edits, and bash commands directly. Sub-agents are supplementary analysis only — they do not own file creation, and their read-only reports do not mean you are read-only. Even when sub-agents report they cannot write files, you must proceed with your own file writes, edits, and bash commands. For straightforward implementation steps, create files directly yourself without launching sub-agents.

CRITICAL: Use write and edit to create and modify files on disk. Do NOT output file contents as markdown code blocks in your chat response. If you find yourself typing a code block of file contents, STOP and use the write tool instead.

${professionalOutputGuidance("Plan execution")}

Diagram guidance:
${workflowMermaidGuidance()}

Approved plan is the execution contract. Do only this plan. No unrelated refactors. Do not commit. Do not push. Do not switch branches.

${artifactSafetyPolicyBlock("execution")}

${reviewerFindingsBlock ? `Reviewer findings:\n${reviewerFindingsBlock}\n\n` : ""}When the task is complex or you need research before editing, launch sub-agents for analysis and inspection. Run them before writing files when their findings would change your implementation. Otherwise, proceed directly with file creation. After implementation, gather all automatable validation evidence, summarize changed files, sub-agent work/findings used, and recommend validation.

${automatableEvidenceGuidance}

Plan Step Progress — the guard REQUIRES workflow_progress calls for EVERY step:

Tool-surface mismatch stop condition: if workflow_progress is not visible in your callable tool list, STOP immediately. Do not call read, grep, find, ls, subagent, edit, write, bash, workflow_plan_result, or workflow_execution_result. Report: "Tool-surface mismatch: workflow_progress is unavailable in the executor turn."

Step activation: workflow_progress({ step: N, status: "active" })
  REQUIRED before any executor work tool for step N, including read, grep, find, ls, subagent, edit, write, and meaningful bash. The guard blocks executor work without it.

Step completion: workflow_progress({ step: N, status: "completed" })
  REQUIRED after finishing step N. This advances the widget to the next step. Without it, the widget stays stuck.

Failed/blocked step: workflow_progress({ step: N, status: "failed" }) with reason in details.

Multi-step pattern — repeat for EVERY step, in order:
  Step 1: activate → do step 1 work → complete step 1
  Step 2: activate → do step 2 work → complete step 2
  Step 3: activate → do step 3 work → complete step 3

After you complete a step, the guard will require workflow_progress({ step: N+1, status: "active" }) before read, grep, find, ls, subagent, edit, write, or meaningful bash for the next step. Listen to the guard — it tells you exactly which step needs activation.

${planStepStatusDisplay(state)}

- Before any executor work, activate the current step with workflow_progress. If forced execution workers are required, the required ordering is: activate current step with workflow_progress, launch required workers, then do work.
- Respect reviewer findings before launching broad sub-agents. If review says a step is already complete or should be skipped, call workflow_progress for that step first instead of sending workers to redo it.
- Scope execution sub-agent prompts to the current active/open Plan step or current phase question. Even on Maximum, do not fan out workers across future unrelated steps unless those steps are explicitly ready for this turn.
- If you delegate step work to a sub-agent, you still own the parent workflow_progress calls. Start the sub-agent task with Plan step N: and require it to report Plan Step N Progress: completed | blocked | incomplete with evidence. After the sub-agent finishes, YOU must call workflow_progress to complete the step.
- If you accidentally call workflow_plan_result during execution, do not retry it; continue with workflow_progress, write/edit/bash, and workflow_execution_result.
workflow_progress is the ONLY supported mechanism for step tracking. You MUST call workflow_progress({ step: N, status: "active" }) before any read, grep, find, ls, subagent, edit, write, or meaningful bash for step N and workflow_progress({ step: N, status: "completed" }) after finishing step N. Do not use text markers.
- For per-step gated execution, track only the current allowed step and stop after that step.

Before your final execution summary, call workflow_execution_result with status, completedSteps, changedFiles, commands, blockers, and summary. completedSteps should list every approved Plan step completed in this execution turn. The typed tool result is the primary handoff control plane. Your final execution summary must be validator-grade evidence, not just prose. Include Acceptance criteria coverage, exact files changed, Commands run with exit status, Checks skipped with reason, Automated Evidence Completed (list what was verified automatically), Truly Manual Evidence Remaining (only genuinely non-automatable checks), and any evidence from execution sub-agents.

Execution scope:
- ${stepExecutionGuidance}

Sub-agent execution policy:
- executionPolicy: ${policy}
- Execution Workers: ${activeWorkerTargetLabel(policy, workers)}
- Sub-Agent Approval Gate: ${settings.subagents.requireApprovalBeforeRun === true ? "enabled" : "disabled"}
- Parallel Execution Agents: ${settings.subagents.allowParallelExecution !== false ? "enabled" : "disabled"}
- Parallel File Writes: ${fileWriteModeLabel(settings)}
- ${subagentGuidance}
${requiredSubagentPreflightSection(preflightBlock)}
- Parallel File Edits controls simultaneous file writes only; it must not disable multiple execution agents.
- Execution agents may run in parallel for analysis, file inspection, implementation preparation, scoped implementation help, patch planning, regression search, and validation preparation.
- Execution agents may perform work allowed by their configured tools and agent contract, but must stay inside the approved Plan scope and current per-step boundary when per-step gates are enabled.
- Main executor owns final integration, validation-ready summary, and workflow_execution_result. Sub-agent file writes must follow editConcurrencyMode=${settings.subagents.editConcurrencyMode ?? "sequential"}; with sequential mode, serialize writes and avoid conflicting parallel edits.
- ${preflightSatisfied && subagentPolicyRequiresRequiredEvidence(policy) ? "Forced execution policy was satisfied by Workflow Suite preflight; do not rerun required workers solely for policy compliance." : "If executionPolicy is forced, activate the current step with workflow_progress first, then required sub-agents must run before edit/write/meaningful bash/final summary. Local read/grep/find/ls probes may run only to orient the parent or form the required sub-agent call; they do not satisfy the worker requirement. If sub-agent execution is unavailable, stop with: Sub-agent policy is forced, but sub-agent execution is unavailable because <reason>."}
- Final execution summary must include Sub-Agent Usage Summary with agents used and findings applied, or a forced-policy blocker.

${subagentCapabilityTable()}

Web research guidance:
${workflowRuntimeWebResearchGuidance()}

Approved plan:
${state.approvedPlan}`;
}

function validatePrompt(state: WorkflowState, settings = loadWorkflowSettings(), preflightBlock?: string): string {
  const policy = settings.subagents.validationPolicy ?? "auto";
  const workers = workerCount(settings, "Validation");
  const stepValidationEnabled = settings.workflow.validateAfterEachStep === true && typeof state.planStepValidationIndex === "number";
  const stepIndex = Math.max(0, state.planStepValidationIndex ?? 0);
  const step = state.planProgress?.steps?.[stepIndex];
  const validationScope = stepValidationEnabled && step
    ? `Validate only Plan step ${stepIndex + 1}: ${step.title}. Do not require later approved steps to be complete yet.`
    : "Validate the completed execution against the full approved plan.";
  const preflightSatisfied = hasRequiredSubagentPreflight(preflightBlock);
  const subagentGuidance = !validationSubagentsAllowed(settings)
    ? "Validation sub-agents are disabled by settings. Do not call subagent."
    : preflightSatisfied && subagentPolicyRequiresRequiredEvidence(policy)
      ? forcedSubagentPolicySatisfiedGuidance("validation")
      : policy === "forced"
        ? `FORCED SUB-AGENT POLICY: you are the parent validator turn. Before final validation verdict or any substantive validation work, you MUST call the subagent tool with at least ${Math.max(1, workers.maximum)} validation worker(s), preferably quality-validation, general-worker, codebase-research, or implementation-planning. ${forcedSubagentCallShape("Validation", Math.max(1, workers.maximum))} Do not call workflow-orchestrator for this forced Plan Validation requirement; the validator is already the parent controller. If subagent execution fails, stop and report the exact blocker.`
        : policy === "maximum"
        ? `For non-trivial validation, use validation sub-agents for independent checks, regression review, and risk analysis. Strongly target at least ${workers.maximum} validation workers, preferably quality-validation plus focused reviewers; internally decide delegate or skip, skip only for trivial validation or unavailable sub-agent execution, and give only the concise skip reason. Do not print internal policy deliberation.`
        : policy === "deep"
          ? `For non-trivial validation, use at least ${workers.deep} validation sub-agent for independent checks, regression review, or risk analysis. Prefer quality-validation. Internally decide delegate or skip and give only the concise skip reason. Do not print internal policy deliberation.`
          : `Validation sub-agents are strongly encouraged for independent review. Internally decide delegate or skip. Strongly consider up to ${Math.max(1, workers.deep)} validation worker${Math.max(1, workers.deep) === 1 ? "" : "s"} for non-trivial work. Use them for plan compliance, diff review, regression risk, build/test review, or manual-QA classification; skip only for trivial validation or no useful parallel work and give only the concise skip reason. Do not print internal policy deliberation.`;
  const automatableEvidenceVerifierGuidance = `Automatable evidence verification:
- Before marking Manual Verification Required: yes, verify that the missing evidence is genuinely non-automatable.
- If the plan required dev server, browser, localStorage, runtime, or endpoint checks that were not attempted by the executor, and those checks can be performed with safe read-only bash or parent runtime tools such as workflow_browser_check, mark Concrete Repairable Issue: yes and Evidence Gap: yes, then return FAIL rather than PARTIAL PASS.
- PARTIAL PASS with Manual Verification Required: yes is valid only after you confirm the remaining check is truly human-only (visual design approval, subjective UX, external service credentials you cannot access, etc.).
- Validation pass-with-notes is PARTIAL PASS with Concrete Repairable Issue: no and Evidence Gap: no. Use it for advisory improvements, future hardening, style concerns, optional cleanup, non-blocking risk, and already-mitigated concerns.
- Concrete Repairable Issue: yes means a blocking current-scope defect that must be repaired before advancement.

To verify web app runtime behavior:
- For projects with npm dev server: npm run dev -- --port 3017 &
- For static HTML/CSS/JS projects (no package.json scripts): python3 -m http.server 8017 &
- Wait for the server: sleep 2
- Query endpoints: curl -fsS http://localhost:PORT/path
- Check the process: ps aux | grep "server"
- Stop the server when done: workflow_stop_server({ port: PORT })
- Discard unwanted output: >/dev/null 2>&1
Use single-line bash calls for each step from the current project cwd. Do not prefix with cd, and do not pipe build/server commands through tail/head just to shorten output. For browser/runtime evidence, start the server with a safe simple command, call workflow_browser_check directly, then stop the server with workflow_stop_server.

CRITICAL: You MUST exhaust all automatable checks before returning PARTIAL PASS.
DO NOT mark evidence as "could not verify" without actually trying to verify it.
Start a server, curl the endpoints, check file accessibility — THEN report what you
could and could not confirm. "No browser available" is not a reason to skip
server-side checks that ARE automatable.

Headless browser verification: use the workflow_browser_check tool with the dev server URL to verify console errors, page errors, DOM elements, and localStorage behavior. This tool uses Puppeteer from the Pi runtime and works regardless of the target project's dependencies.

${validationRuntimeToolOwnershipGuidance()}

You MUST fill in EVERY structured output field, especially:
- Concrete Repairable Issue: yes/no (with reason)
- Evidence Gap: yes/no (with exact missing evidence)
- Manual Verification Required: yes/no (with exact manual check)
- Automated Evidence Completed: list everything verified automatically (not "none" or "n/a")`;

  return `You are in PI WORKFLOW VALIDATOR MODE.

${professionalOutputGuidance("Plan validation")}

Do not edit or write project source files. Prefer text evidence over temporary evidence files; if a temporary evidence file is unavoidable, it must be in an approved temp/evidence location and never at repository root. You may run safe bash evidence commands such as git status, git diff, git log, package-script discovery, and existing typecheck/test/build commands when they are appropriate and safe. Do not run mutating, install, deploy, push, reset, clean, database, secret, or settings/state commands. You are the independent validator, not the executor. Do not repair, do not move files, do not re-grade your own repair, and do not accept executor claims without evidence. Compare the implementation against the approved plan. Inspect changed files, diffs, and commands run with exit status when available.

${artifactSafetyPolicyBlock("validation")}

${automatableEvidenceVerifierGuidance}

${workflowValidationContextBlock(state)}

Before your final validation report, call workflow_validation_result with scope=plan, validationRunId, planId, projectCwd, verdict, concreteRepairableIssue, evidenceGap, manualVerificationRequired, issues, and summary. The typed tool result is the primary handoff control plane; markdown verdict text is legacy fallback only. After calling workflow_validation_result, print a concise validation summary for the user before stopping.

Validation scope:
- ${validationScope}

Sub-agent validation policy:
- validationPolicy: ${policy}
- Validation Workers: ${activeWorkerTargetLabel(policy, workers)}
- Sub-Agent Approval Gate: ${settings.subagents.requireApprovalBeforeRun === true ? "enabled" : "disabled"}
- Parallel Validation Agents: ${settings.subagents.allowParallelValidation !== false ? "enabled" : "disabled"}
- ${subagentGuidance}
${requiredSubagentPreflightSection(preflightBlock)}

${subagentCapabilityTable()}

- When validationPolicy is auto, deep, or maximum, validation sub-agents are expected for non-trivial work; prefer quality-validation for independent diff/risk/build-test review.
- ${preflightSatisfied && subagentPolicyRequiresRequiredEvidence(policy) ? "Forced validation policy was satisfied by Workflow Suite preflight; do not rerun required workers solely for policy compliance." : "If validationPolicy is forced, required sub-agents must run before verdict, or stop with: Sub-agent policy is forced, but sub-agent execution is unavailable because <reason>."}
- PASS only when the approved plan is fully satisfied with no blocking unresolved risk.
- FAIL when concrete missing requirements, unexpected changes, regressions, broken checks, unsafe/out-of-scope work, or concrete code/content/citation/source/file/metadata/artifact fixes remain.
- FAIL when automatable runtime evidence (build, test, dev server, browser, localStorage, API response) was not gathered and the checks are performable with available tools. Missing automatable evidence is a concrete repairable issue, not a manual-only caveat.
- PARTIAL PASS with Concrete Repairable Issue: no is the validation pass-with-notes path. Use it only after all required automatable evidence has been gathered and no blocking current-scope defect remains.
- Advisory improvements, future hardening, style concerns, optional cleanup, non-blocking risk, already-mitigated concerns, and genuinely human-only verification are notes, not repair blockers.
- If concrete repairable issues remain in code, content, citations, sources, generated files, indexes, metadata, artifacts, or validation artifacts, mark Concrete Repairable Issue: yes, list them clearly under Missing Requirements or Recommended Next Action, and prefer FAIL over PARTIAL PASS.
- Evidence gaps are not repairable defects unless you identify a concrete missing requirement or artifact. Mark Evidence Gap: yes and Concrete Repairable Issue: no when the correct next action is evidence collection or revalidation rather than repair.

Project rules priority:
- If the project has AGENTS.md, .factory/rules, .cursor/rules, or similar instruction files, read and obey them first.
- Project rules override global defaults.

Diagram guidance:
${workflowMermaidGuidance()}

Web research guidance:
${workflowRuntimeWebResearchGuidance()}

Approved plan:
${state.approvedPlan}

Execution summary:
${state.executionSummary ?? "(none recorded)"}

${state.reviewerReport ? `Reviewer notes:\n${state.reviewerReport}\n\n` : ""}Models used:
- Planner: ${state.modelsUsed?.planner ?? "(not recorded)"}
- Executor: ${state.modelsUsed?.executor ?? "(not recorded)"}
- Reviewer: ${state.modelsUsed?.reviewer ?? "(not run)"}

Output exactly:
# Validation Report
## Verdict
PASS, PARTIAL PASS, or FAIL
## Reason
## Approved Plan Coverage
## Changed Files Reviewed
## Commands Run With Exit Status
## Checks Skipped With Reason
## Concrete Repairable Issue
yes/no and short reason
## Evidence Gap
yes/no and exact missing evidence
## Manual Verification Required
yes/no and exact manual check
## Automated Evidence Completed
What runtime/browser/build/test evidence was verified automatically.
## Truly Manual Evidence Remaining
Only genuinely non-automatable human-only checks, not checks that could have been automated.
## Missing Requirements
## Unexpected Changes
## Regression Risks
## Test And Build Status
## Recommended Next Action`;
}

function workflowRepairPrompt(state: WorkflowState, settings = loadWorkflowSettings(), preflightBlock?: string): string {
  const repairPrompt = readPromptFile("workflow-repair.md", "Repair only the approved Plan Mode validation failure safely, then summarize for revalidation.");
  const policy = phasePolicy(settings, "Repair");
  const workers = workerCount(settings, "Repair");
  const repairRetry = repairRetryGateConfig(settings, "validation");
  const preflightSatisfied = hasRequiredSubagentPreflight(preflightBlock);
  const subagentGuidance = !phaseAutoUseAllowed(settings, "Repair") || policy === "off"
    ? "Repair sub-agents are disabled by settings. Do not call subagent."
    : preflightSatisfied && subagentPolicyRequiresRequiredEvidence(policy)
      ? forcedSubagentPolicySatisfiedGuidance("repair")
      : policy === "forced"
        ? `FORCED SUB-AGENT POLICY: before any repair edit or final Workflow Repair Summary, you MUST call the subagent tool with at least ${Math.max(1, workers.maximum)} repair/execution worker(s). ${forcedSubagentCallShape("Repair", Math.max(1, workers.maximum))} Use them for read-only repair verification, missing-file inspection, patch planning, and validation preparation. If subagent execution fails, stop and report the exact blocker.`
        : policy === "maximum"
        ? `For non-trivial repair, strongly target ${Math.max(1, workers.maximum)} repair/execution worker(s) before edits; internally decide delegate or skip, and continue if skipped only with a concise reason. Do not print internal policy deliberation.`
        : policy === "deep"
          ? `For non-trivial repair, use ${Math.max(1, workers.deep)} repair/execution worker(s) before edits when useful. Internally decide delegate or skip and give only the concise skip reason. Do not print internal policy deliberation.`
          : `Repair sub-agents are strongly encouraged. Internally decide delegate or skip. Strongly consider up to ${Math.max(1, workers.deep)} repair worker${Math.max(1, workers.deep) === 1 ? "" : "s"} for non-trivial work. Use them for failure triage, missing-file inspection, patch planning, and validation prep; skip only with a concrete reason. Do not print internal policy deliberation.`;
  return `${repairPrompt}

You are in PI WORKFLOW REPAIR MODE.

${professionalOutputGuidance("Plan repair")}

Diagram guidance:
${workflowMermaidGuidance()}

Approved plan remains the execution contract. Repair concrete validator-identified failures below and keep going while fixes are in-scope and non-destructive. Do not expand scope. Do not commit. Do not push. Do not deploy. Do not change secrets, auth/session files, database schema/data, or environment files unless the user explicitly approved that exact repair. Repair mode cannot declare the work PASS; only a subsequent validator/revalidator can do that. If no safe concrete edit is appropriate because the finding involves only manual/visual/browser verification or an evidence gap, produce a no-op repair summary recommending revalidation. Do not make unsafe or out-of-scope edits solely to produce file changes. Do not mark advisory-only follow-up as needsUserApproval; preserve it in the summary and allow revalidation.

${artifactSafetyPolicyBlock("repair")}

Repair retry: ${state.currentValidationRetry ?? 0}/${workflowMaxValidationRetries(state, settings)} per plan
Workflow repair retry: ${workflowValidationRetryCount(state)}/${workflowMaxValidationRetriesTotal(state, settings)} total
Repair/Retry gate: validation
Repair/Retry mode: ${repairRetry.retryMode}
Auto revalidate after accepted repair: ${repairRetry.autoRepairFailures && !repairRetry.pauseAfterFailure ? "enabled" : "not automatic with current settings"}

Sub-agent repair policy:
- repairPolicy: ${policy} (${repairPolicySource(settings)})
- Repair Workers: ${activeWorkerTargetLabel(policy, workers)}
- Sub-Agent Approval Gate: ${settings.subagents.requireApprovalBeforeRun === true ? "enabled" : "disabled"}
- Parallel Repair Agents: ${phaseParallelAllowed(settings, "Repair") ? "enabled" : "disabled"}
- Parallel File Writes: ${fileWriteModeLabel(settings)}
- ${subagentGuidance}
${requiredSubagentPreflightSection(preflightBlock)}
- Repair-mode sub-agent workers may inspect, triage, and plan safely. File writes must remain serialized through the Executor in repair mode unless scoped conflict protection is explicitly enabled.
- You, the main repair executor, own all file writes, edits, and bash commands. Even when forced sub-agent policy is active and sub-agents report they cannot write files, you must proceed with your own file writes, edits, and bash commands after sub-agent inspection completes. Sub-agents are read-only by design; their inability to write does not mean you cannot write.
- ${preflightSatisfied && subagentPolicyRequiresRequiredEvidence(policy) ? "Forced repair policy was satisfied by Workflow Suite preflight; do not rerun required workers solely for policy compliance." : "If repairPolicy is forced, required sub-agents must run before any repair edit or final repair summary, or stop with: Sub-agent policy is forced, but sub-agent execution is unavailable because <reason>."}
- Do not re-grade validation. Do not claim PASS/FAIL for repaired work; recommend revalidation.
- If no concrete repairable issue exists, perform no-op repair summary and recommend manual verification or /plan revalidate.

${subagentCapabilityTable()}

Web research guidance:
${workflowRuntimeWebResearchGuidance()}

Approved plan:
${state.approvedPlan ?? "(none recorded)"}

Execution summary:
${state.executionSummary ?? "(none recorded)"}

Validation failure:
${state.lastValidationFailure || state.validationReport || "(none recorded)"}

Before your final repair summary, call workflow_repair_result with status, changedFiles, movedFiles, preservedFiles, deletedFiles, rootArtifacts, possiblyUserOwnedFiles, needsUserApproval, safetyFlags, and summary. The typed tool result is the primary repair handoff control plane.

Output exactly:
# Workflow Repair Summary
## Repair Scope
## Files Changed
${repairArtifactDispositionOutput()}
## Validation Failure Addressed
## Safety Notes
## Recommended Revalidation`;
}

function reviewerPrompt(state: WorkflowState, settings = loadWorkflowSettings(), preflightBlock?: string): string {
  const policy = settings.subagents.reviewPolicy ?? "auto";
  const workers = workerCount(settings, "Review");
  const preflightSatisfied = hasRequiredSubagentPreflight(preflightBlock);
  const subagentGuidance = !reviewSubagentsAllowed(settings)
    ? "Reviewer sub-agents are disabled by settings. Do not call subagent."
    : preflightSatisfied && subagentPolicyRequiresRequiredEvidence(policy)
      ? forcedSubagentPolicySatisfiedGuidance("review")
      : policy === "forced"
        ? `FORCED SUB-AGENT POLICY: before final reviewer report or your own review analysis, you MUST call the subagent tool with at least ${Math.max(1, workers.maximum)} review worker(s) for independent read-only challenge review. ${forcedSubagentCallShape("Review", Math.max(1, workers.maximum))} If subagent execution fails, stop and report the exact blocker.`
        : policy === "maximum"
        ? `For non-trivial review, use multiple reviewer sub-agents for independent risk review, regression review, implementation-scope review, and validation-plan review. Strongly target at least ${workers.maximum} review workers; internally decide delegate or skip, skip only for trivial review or unavailable sub-agent execution, and give only the concise skip reason. Do not print internal policy deliberation.`
        : policy === "deep"
          ? `For non-trivial review, use at least ${workers.deep} reviewer sub-agent for independent risk review, regression review, implementation-scope review, or validation-plan review. Internally decide delegate or skip and give only the concise skip reason. Do not print internal policy deliberation.`
          : `Reviewer sub-agents are strongly encouraged. Internally decide delegate or skip. Strongly consider up to ${Math.max(1, workers.deep)} review worker${Math.max(1, workers.deep) === 1 ? "" : "s"} for non-trivial work. Use them to challenge scope, files, risk, and validation plan; skip only for trivial review or no useful parallel work and give only the concise skip reason. Do not print internal policy deliberation.`;
  return `You are in PI WORKFLOW REVIEWER MODE.

CRITICAL: If forced review sub-agents are required by policy, call the subagent tool FIRST — before your own review analysis. Sub-agent findings must inform your review, not validate it after the fact. Once sub-agents complete (or if no sub-agents are required), perform your read-only review and call workflow_review_result with your verdict, issues, summary, and safety flags. After workflow_review_result returns its control-verdict tool result, STOP IMMEDIATELY. Do not call any more tools, do not call subagent again, do not create diagrams, and do not continue prose analysis. Workflow Suite owns the next handoff to execution or review retry. Do not do your own review analysis before dispatching required sub-agents.

${professionalOutputGuidance("Plan review")}

Use read-only tools only. Do not edit, write, or run bash. Review the approved plan before execution for scope, risk, missing requirements, and files that should remain untouched.

${artifactSafetyPolicyBlock("review")}

Reviewer is not validation. Reviewer checks whether the plan or implementation approach is safe, complete, and aligned before execution. Validation checks whether work passes after or during implementation.

Sub-agent review policy:
- reviewPolicy: ${policy}
- Review Workers: ${activeWorkerTargetLabel(policy, workers)}
- Sub-Agent Approval Gate: ${settings.subagents.requireApprovalBeforeRun === true ? "enabled" : "disabled"}
- Parallel Review Agents: ${settings.subagents.allowParallelReview !== false ? "enabled" : "disabled"}
- Parallel File Writes: ${fileWriteModeLabel(settings)}
- editConcurrencyMode: ${settings.subagents.editConcurrencyMode ?? "sequential"}
- ${subagentGuidance}
${requiredSubagentPreflightSection(preflightBlock)}

${subagentCapabilityTable()}

- When reviewPolicy is auto, deep, or maximum, reviewer sub-agents are expected for non-trivial plans to challenge scope, files, risk, and validation plan.
- Reviewer sub-agents must not perform direct file edits.
- ${preflightSatisfied && subagentPolicyRequiresRequiredEvidence(policy) ? "Forced review policy was satisfied by Workflow Suite preflight; do not rerun required workers solely for policy compliance." : "If reviewPolicy is forced, required sub-agents must run before the report, or stop with: Sub-agent policy is forced, but sub-agent execution is unavailable because <reason>."}
- The reviewer must not rubber-stamp execution; surface missing requirements before the executor starts.
- Plan Review is notes-first for control flow. Use NOTES for nearly all actionable advice, including severe executor-correctable findings. Use NEEDS REPAIR only when the Plan text is structurally unusable for execution, such as having no executable implementation steps.
- Validation command additions, rollback wording fixes, selector/test-hook refinements, off-limits/out-of-scope lists, instruction text updates, implementation parameter suggestions, game-rule details, impossible browser/test move sequences, missing draw/test data sequences, dev-server readiness, AI/settings/accessibility details, localStorage keys, icon choices, and executor cautions are executor notes, not repair blockers.

Diagram guidance:
${workflowMermaidGuidance()}

Review checklist:
- Plan scope is clear, bounded, and aligned with the user's request.
- Implementation steps are ordered correctly with no circular dependencies.
- Required files are identified and files to avoid are listed.
- Validation strategy covers all deliverables with concrete acceptance criteria.
- Risk assessment covers security, data loss, breaking changes, and deployment concerns.
- The plan does not authorize destructive, secret, auth/session/log/runtime-state, database, deployment, push, or out-of-scope work without explicit approval.
- New file destinations are explicit; arbitrary root artifacts and cleanup-by-deletion are not authorized.
- Test and build verification is included where applicable.

Approved plan:
${state.approvedPlan}

Output exactly:
# Reviewer Report
## Verdict
PASS — plan is complete, safe, properly scoped, and ready for execution.
NOTES — plan is safe to execute with non-blocking observations for the executor.
NEEDS REPAIR — structurally unusable plan only: no executable steps or no approval-ready implementation plan to repair.
FAIL — plan has serious hard-stop blockers such as unauthorized protected work, wrong target, or unavailable dependencies.
BLOCKED — plan cannot proceed without external resolution.

Do not write APPROVED, APPROVE, OK, or PROCEED as the verdict label.

Verdict criteria:
- PASS when: all checklist items are satisfied and the plan is ready for execution.
- NOTES when: the plan is executable but has non-blocking advice, including selector refinements, validation/test improvements, rollback wording, out-of-scope/off-limits enumeration, instruction text updates, implementation parameter suggestions, test-hook suggestions, implementation sequencing notes, or optional executor cautions.
- NEEDS REPAIR when: the Plan text is structurally unusable for execution because no executable implementation steps or no approval-ready implementation plan exists. Do not use NEEDS REPAIR for severe wording, likely test failures, contradictory/impossible browser or test steps, missing draw/test data sequences, localStorage/readiness details, missing implementation details, omitted validation refinements, stale steps, partially missing desired work, wrong-target concerns, protected-work concerns, or implementation-contract details the executor can resolve from the Plan plus reviewer notes.
- FAIL when: safety/security violations, wrong target, protected work, unavailable dependencies, or work that exceeds approved scope without authorization create a hard stop.
- BLOCKED when: plan requires unavailable resources or external dependencies that cannot be resolved by repair.
## Reason
## Scope Risks
## Missing Information
## Files To Be Careful With
## Required Plan Revisions
## Recommended Execution Notes`;
}

