type WorkflowStartupLogoGlyphLayout = { grid: boolean[][]; letterByCol: number[]; letterCount: number };

function workflowStartupLogoGlyphLayout(text: string): WorkflowStartupLogoGlyphLayout {
  const grid: boolean[][] = Array.from({ length: 5 }, () => []);
  const letterByCol: number[] = [];
  let letterIndex = 0;
  for (const char of text) {
    const glyph = WORKFLOW_STARTUP_LOGO_GLYPHS[char];
    if (!glyph) continue;
    if (letterIndex > 0) {
      for (const row of grid) row.push(false);
      letterByCol.push(-1);
    }
    for (let col = 0; col < glyph[0].length; col += 1) {
      letterByCol.push(letterIndex);
      for (let row = 0; row < 5; row += 1) grid[row].push(glyph[row][col] === "1");
    }
    letterIndex += 1;
  }
  return { grid, letterByCol, letterCount: letterIndex };
}

function workflowStartupLogoShadowOffset(direction: WorkflowStartupLogoShadowDirection): { row: number; col: number } {
  if (direction === "down") return { row: 1, col: 0 };
  if (direction === "up") return { row: -1, col: 0 };
  if (direction === "left") return { row: 0, col: -1 };
  if (direction === "right") return { row: 0, col: 1 };
  return { row: 1, col: 1 };
}

function workflowStartupLogoScaledLayout(layout: WorkflowStartupLogoGlyphLayout, rowScale: number, colScale: number): WorkflowStartupLogoGlyphLayout {
  if (rowScale <= 1 && colScale <= 1) return layout;
  const grid: boolean[][] = [];
  const letterByCol: number[] = [];
  for (let col = 0; col < layout.letterByCol.length; col += 1) for (let c = 0; c < colScale; c += 1) letterByCol.push(layout.letterByCol[col]);
  for (const sourceRow of layout.grid) {
    const expandedRow: boolean[] = [];
    for (const filled of sourceRow) for (let c = 0; c < colScale; c += 1) expandedRow.push(filled);
    for (let r = 0; r < rowScale; r += 1) grid.push([...expandedRow]);
  }
  return { grid, letterByCol, letterCount: layout.letterCount };
}

function workflowStartupLogoCellText(font: WorkflowStartupLogoFont, shadow = false): string {
  if (shadow) return font === "three_d" ? "▓▓" : "░";
  if (font === "wide" || font === "three_d") return "██";
  if (font === "double") return "▓▓";
  if (font === "solid") return "▓";
  return "█";
}

function workflowStartupLogoBlank(font: WorkflowStartupLogoFont): string {
  return font === "wide" || font === "double" || font === "three_d" ? "  " : " ";
}

function workflowStartupLogoColor(settings: ReturnType<typeof loadWorkflowSettings>, letterIndex: number, totalLetters: number, col: number, totalCols: number, shadow = false): WorkflowRgb {
  const palette = workflowVisualPalette(settings);
  const colorStyle = startupLogoColorStyleOrDefault(settings);
  if (shadow || letterIndex < 0) return palette.muted;
  if (colorStyle === "primary") return palette.primary;
  if (colorStyle === "split") return col < Math.ceil(Math.max(1, totalCols) / 2) ? palette.primary : palette.secondary;
  return letterIndex % 2 === 0 ? palette.primary : palette.secondary;
}

function workflowStartupLogoCell(settings: ReturnType<typeof loadWorkflowSettings>, letterIndex: number, totalLetters: number, col: number, totalCols: number, font: WorkflowStartupLogoFont, shadow = false): string {
  return workflowRgb(workflowStartupLogoColor(settings, letterIndex, totalLetters, col, totalCols, shadow), workflowStartupLogoCellText(font, shadow));
}

function workflowStartupLogoOutlineEdge(layout: WorkflowStartupLogoGlyphLayout, row: number, col: number): boolean {
  if (layout.grid[row]?.[col] !== true) return false;
  return layout.grid[row - 1]?.[col] !== true || layout.grid[row + 1]?.[col] !== true || layout.grid[row]?.[col - 1] !== true || layout.grid[row]?.[col + 1] !== true;
}

function workflowCustomStartupLogoLines(settings: ReturnType<typeof loadWorkflowSettings>, width: number): string[] {
  const text = startupLogoText(settings);
  if (!text) return workflowPiMarkLines(settings, width);
  const font = startupLogoFontOrDefault(settings);
  const baseLayout = workflowStartupLogoGlyphLayout(text);
  const baseCols = Math.max(0, ...baseLayout.grid.map((row) => row.length));
  if (!baseCols || baseLayout.letterCount <= 0) return workflowPiMarkLines(settings, width);
  const outlineScale = font === "outline" && baseCols * 2 <= Math.max(24, width) ? 2 : 1;
  const layout = font === "outline" ? workflowStartupLogoScaledLayout(baseLayout, outlineScale, outlineScale) : baseLayout;
  const totalCols = Math.max(0, ...layout.grid.map((row) => row.length));

  const shadowFont = font === "shadow" || font === "three_d";
  const shadowOffset = workflowStartupLogoShadowOffset(startupLogoShadowDirectionOrDefault(settings));
  const minRow = shadowFont ? Math.min(0, shadowOffset.row) : 0;
  const maxRow = layout.grid.length - 1 + (shadowFont ? Math.max(0, shadowOffset.row) : 0);
  const minCol = shadowFont ? Math.min(0, shadowOffset.col) : 0;
  const maxCol = totalCols - 1 + (shadowFont ? Math.max(0, shadowOffset.col) : 0);
  const lines: string[] = [];

  for (let row = minRow; row <= maxRow; row += 1) {
    let line = "";
    for (let col = minCol; col <= maxCol; col += 1) {
      const filled = layout.grid[row]?.[col] === true;
      const filledLetter = layout.letterByCol[col] ?? -1;
      if (font === "outline") {
        line += workflowStartupLogoOutlineEdge(layout, row, col)
          ? workflowStartupLogoCell(settings, filledLetter, layout.letterCount, col, totalCols, font)
          : workflowStartupLogoBlank(font);
        continue;
      }
      const shadowSourceCol = col - shadowOffset.col;
      const shadow = shadowFont && layout.grid[row - shadowOffset.row]?.[shadowSourceCol] === true;
      const shadowLetter = layout.letterByCol[shadowSourceCol] ?? -1;
      line += filled
        ? workflowStartupLogoCell(settings, filledLetter, layout.letterCount, col, totalCols, font)
        : shadow
          ? workflowStartupLogoCell(settings, shadowLetter, layout.letterCount, shadowSourceCol, totalCols, font, true)
          : workflowStartupLogoBlank(font);
    }
    lines.push(line.replace(/\s+$/g, ""));
  }
  return workflowCenterBlockLines(lines, width);
}

function workflowStartupLogoLines(settings: ReturnType<typeof loadWorkflowSettings>, width: number): string[] {
  const logo = startupLogoOrDefault(settings);
  if (logo === "none") return [];
  if (logo === "custom") return workflowCustomStartupLogoLines(settings, width);
  return workflowPiMarkLines(settings, width);
}

