function workflowStartupVisualBoxWidth(lines: string[]): number {
  const { visibleWidth } = loadPiTuiUtils();
  const border = lines.find((line) => line.includes("╭") && line.includes("╮"));
  return visibleWidth(border ?? lines[0] ?? "");
}

function workflowStartupVisualLines(settings: ReturnType<typeof loadWorkflowSettings>, _frame: number, force = false, ctx?: ExtensionContext): string[] | undefined {
  const visual = startupVisualOrDefault(settings, force);
  const startup = { ctx, facts: workflowStartupFacts(ctx, settings) };
  let lines: string[] | undefined;
  if (visual === "none") return undefined;
  if (visual === "minimal") lines = workflowMinimalLines(settings, startup);
  else if (visual === "workflow_duo") lines = workflowDuoLines(settings, startup);
  else if (visual === "mission_control") lines = workflowMissionControlLines(settings, startup);
  else if (visual === "diagnostic_center") lines = workflowDiagnosticLines(settings, startup);
  else if (visual === "data_stream") lines = workflowDataStreamLines(settings, startup);
  else if (visual === "neural_grid") lines = workflowNeuralGridLines(settings, startup);
  else if (visual === "custom_brand") lines = workflowCustomBrandLines(settings, startup);
  else lines = workflowMissionControlLines(settings, startup);
  const width = workflowStartupVisualBoxWidth(lines);
  const logoLines = workflowStartupLogoLines(settings, width);
  return logoLines.length ? [...logoLines, "", ...lines] : lines;
}

function renderSafeStartupBanner(settings: ReturnType<typeof loadWorkflowSettings>, force = false, ctx?: ExtensionContext): string | undefined {
  try {
    const lines = workflowStartupVisualLines(settings, 18, force, ctx);
    return lines?.join("\n");
  } catch {
    return undefined;
  }
}

function renderStartupVisualPresetPreview(settings: ReturnType<typeof loadWorkflowSettings>, visual: WorkflowStartupVisual, ctx?: ExtensionContext): string {
  if (visual === "none") return "(startup visual disabled)";
  const preview = renderSafeStartupBanner({ ...settings, ui: { ...settings.ui, startupVisual: visual } }, true, ctx);
  return preview ?? "(startup visual unavailable)";
}

function renderAllStartupVisualPresetPreviews(settings: ReturnType<typeof loadWorkflowSettings>, ctx?: ExtensionContext): string {
  return WORKFLOW_STARTUP_VISUALS.map((visual) => `## ${visual}\n${renderStartupVisualPresetPreview(settings, visual, ctx)}`).join("\n\n");
}

function workflowStatusThemeSlot(state: WorkflowState): WorkflowThemeSlot {
  if (state.mode === "idle" || state.mode === "cancelled") return "idle";
  if (state.mode === "standard") {
    const todo = state.standardTodo;
    if (todo?.status === "completed") return "validatedPass";
    if (todo?.status === "blocked") return "validatedFail";
    if (todo?.status === "paused") return "idle";
    return "executing";
  }
  if (state.mode === "awaiting_plan_input" || state.mode === "awaiting_clarification") return "plan";
  if (state.mode === "awaiting_mission_input" || state.mode === "mission_awaiting_clarification") return "mission";
  if (state.mode === "plan_draft" || state.mode === "mission_plan_ready") return "awaitingApproval";
  if (state.mode === "plan_approved" || state.mode === "reviewed") return "approved";
  if (state.mode === "executing" || state.mode === "repairing" || state.mode === "mission_running" || state.mode === "mission_repairing") return "executing";
  if (state.mode === "reviewing") return "reviewing";
  if (state.mode === "validating" || state.mode === "revalidating" || state.mode === "mission_validating" || state.mode === "mission_revalidating" || state.mode === "mission_final_validating") return "validating";
  if (state.mode === "validated") return state.validationVerdict === "PASS" ? "validatedPass" : "validatedFail";
  if (isMissionWorkflowMode(state)) return "mission";
  if (isPlanWorkflowUiMode(state)) return "plan";
  return "idle";
}

function workflowSegmentedStatusText(_theme: any, settings: ReturnType<typeof loadWorkflowSettings>, _state: WorkflowState, label: string, detail?: string): string {
  return detail ? `${workflowWidgetRgb(settings, "title", label)}${workflowWidgetSeparator(settings)}${workflowWidgetRgb(settings, "progress", detail)}` : workflowWidgetRgb(settings, "title", label);
}


function startupVisualDisabledHint(settings: ReturnType<typeof loadWorkflowSettings>): string {
  const palette = workflowVisualPalette(settings);
  return [
    workflowRgb(palette.muted, "(startup visual disabled)"),
    workflowRgb(palette.secondary, "Turn it back on with /workflow-settings theme startup mission_control or choose Startup Visual in settings."),
  ].join("\n");
}

