  pi.registerTool({
    name: WORKFLOW_DIAGRAM_TOOL,
    label: "Workflow Diagram",
    description: "Create and render a Mermaid diagram inline with your prose. Call this tool at the point in your response where the diagram should appear -- not batched at the end.",
    promptSnippet: "workflow_diagram({ title, source }) — render a Mermaid flowchart, sequenceDiagram, stateDiagram, classDiagram, erDiagram, or xychart-beta inline",
    promptGuidelines: [
      "Place workflow_diagram calls inline with the paragraph that introduces the concept rather than batching at start or end.",
      "Inline placement is strongly preferred — readers should see the diagram alongside its explanation. Avoid batching diagrams at the beginning or end of your response.",
      "Workflow Suite renders diagrams with a uniform dark-mode visual standard. Do not include random Mermaid style/classDef/light-theme overrides unless the user explicitly asks.",
      "Use meaningful, concise labels and the correct Mermaid type. Keep diagrams readable in the rendered card; split crowded flows instead of shrinking labels.",
      "Do not generate the same diagram more than once per conversation. Reference prior diagrams by concept name instead of re-calling workflow_diagram with identical source.",
    ],
    parameters: WorkflowDiagramParams,
    executionMode: "sequential",
    async execute(_toolCallId, params, _signal, _onUpdate, _ctx): Promise<AgentToolResult<WorkflowMermaidDiagramDetails>> {
      const source = normalizeMermaidSource(String((params as { source?: unknown }).source ?? ""));
      const diagramType = workflowMermaidDiagramType(source);
      const title = typeof (params as { title?: unknown }).title === "string" && (params as { title?: string }).title?.trim()
        ? (params as { title: string }).title.trim()
        : workflowDiagramTitle(source);
      if (!source || !diagramType) {
        return { content: [{ type: "text", text: "Invalid or unsupported Mermaid diagram. Use flowchart, graph, sequenceDiagram, stateDiagram, classDiagram, erDiagram, or xychart-beta." }], details: { title, source, diagramType: diagramType ?? "unsupported", status: "fallback", terminalDiagram: workflowMermaidFallbackTerminalDiagram(source, diagramType ?? "unsupported"), error: "unsupported diagram type" } };
      }
      const details = await renderWorkflowMermaidPng(source, title);
      return { content: [{ type: "text", text: details.status === "rendered" ? title : `Diagram fallback: ${title}` }], details };
    },
    renderResult(result, _options, theme) {
      return workflowMermaidRenderer({ content: result.content, details: result.details }, { expanded: false }, theme);
    },
  } as ToolDefinition<typeof WorkflowDiagramParams, WorkflowMermaidDiagramDetails>);

  pi.registerTool({
    name: "workflow_progress",
    label: "Workflow Progress",
    description: "Update Plan Mode implementation step progress for the approved workflow plan.",
    promptSnippet: "workflow_progress({ step, status }) — update Plan Mode step progress",
    parameters: WorkflowProgressParams,
    executionMode: "sequential",
    async execute(_toolCallId, params, _signal, _onUpdate, ctx) {
      const progressParams = params as { step?: unknown; status?: unknown };
      const step = Number(progressParams.step);
      const status = progressParams.status as PlanStepStatus;
      if (!Number.isFinite(step) || step < 1) {
        return { content: [{ type: "text", text: "Invalid workflow progress step." }], details: { step, status, tracked: false }, isError: true };
      }
      const result = markPlanStep(ctx, step, status, "workflow_progress");
      if (!result.tracked) {
        return { content: [{ type: "text", text: "No Plan Mode progress steps are active. Progress not tracked." }], details: { step, status, tracked: false, reason: result.reason } };
      }
      const item = result.step;
      return { content: [{ type: "text", text: `Step ${step}: ${item?.title ?? "unknown"} → ${status}` }], details: { step, status, text: item?.title, tracked: true, currentStepIndex: result.progress?.currentStepIndex } };
    },
  } as ToolDefinition);

  // ── Standard To-Do status transition validation ─────────────────
  const VALID_STANDARD_TODO_TRANSITIONS: Record<string, string[]> = {
    pending: ["active", "blocked", "skipped"],
    active: ["completed", "skipped", "blocked", "pending"],
    completed: ["active", "skipped"],
    skipped: ["active", "pending"],
    blocked: ["active", "pending", "skipped"],
  };

  function isValidStandardTodoTransition(from: string, to: string): boolean {
    if (from === to) return true;
    const allowed = VALID_STANDARD_TODO_TRANSITIONS[from];
    return allowed ? allowed.includes(to) : false;
  }

  pi.registerTool({
    name: "standard_todo",
    label: "Standard To Do",
    description: "Initialize or update Standard Mode dynamic To Do progress.",
    promptSnippet: "standard_todo({ action: \"set\", task, items }) initializes a task-sized dynamic item list; choose the count from task complexity, not a default of three; standard_todo({ action: \"update\", item, status }) updates progress",
    parameters: StandardTodoParams,
    executionMode: "sequential",
    async execute(_toolCallId, params, _signal, _onUpdate, ctx) {
      const input = params && typeof params === "object" && !Array.isArray(params)
        ? params as { action?: unknown; item?: unknown; status?: unknown; items?: unknown; itemsText?: unknown; task?: unknown }
        : undefined;
      if (!input) {
        return { content: [{ type: "text", text: standardTodoUsageText() }], details: { action: "missing", tracked: false }, isError: true };
      }
      const rawAction = typeof input.action === "string" ? input.action.trim().toLowerCase() : undefined;
      const hasItems = Array.isArray(input.items) || typeof input.itemsText === "string";
      const action = rawAction === "set" || rawAction === "clear" || rawAction === "update" ? rawAction : (!rawAction && hasItems ? "set" : undefined);
      if (!action) {
        return { content: [{ type: "text", text: standardTodoUsageText() }], details: { action: rawAction ?? "missing", tracked: false }, isError: true };
      }
      if (state.mode !== "standard") {
        return { content: [{ type: "text", text: "Standard Mode To Do is only available while Standard Mode is active." }], details: { action, tracked: false }, isError: true };
      }
      const settings = loadWorkflowSettings(ctx.cwd);
      if (action === "set" && (settings.standard.autoTodoEnabled === false || settings.standard.todoTriggerMode === "off")) {
        return { content: [{ type: "text", text: "Standard Mode To Do tracking is disabled by settings." }], details: { action, tracked: false }, isError: true };
      }
      if (action === "clear") {
        updateState({ standardTodo: undefined }, ctx);
        return { content: [{ type: "text", text: "Standard Mode To Do cleared." }], details: { action, tracked: true } };
      }
      if (action === "set") {
        const titles = standardTodoTitlesFromInput(input.items, input.itemsText);
        const task = typeof input.task === "string" && input.task.trim() ? input.task.trim() : state.task ?? state.originalTask;
        const nextTodo = createStandardTodoFromTitles(task, titles);
        if (!nextTodo) {
          const required = standardTodoMode(settings) === "required";
          return { content: [{ type: "text", text: required ? `Required To Do tracking needs at least one concrete task-specific item before substantive Standard Mode work can continue. ${standardTodoUsageText()}` : "Standard Mode To Do needs at least one concrete task-specific item. Keep working without a To Do list or provide more specific items." }], details: { action, tracked: false, acceptedItems: titles.length }, isError: true };
        }
        updateState({ standardTodo: nextTodo, task, originalTask: state.originalTask ?? task }, ctx);
        standardTodoCreatedThisTurn = true;
        return { content: [{ type: "text", text: `Standard Mode To Do initialized with ${nextTodo.items.length} item${nextTodo.items.length === 1 ? "" : "s"}.` }], details: { action, tracked: true, items: nextTodo.items.length } };
      }
      const itemNumber = Number(input.item);
      const rawStatus = typeof input.status === "string" ? input.status.trim().toLowerCase() : undefined;
      const status = rawStatus === "active" || rawStatus === "completed" || rawStatus === "skipped" || rawStatus === "blocked" || rawStatus === "pending" ? rawStatus as StandardTodoItemStatus : undefined;
      if (!Number.isFinite(itemNumber) || !status) {
        return { content: [{ type: "text", text: standardTodoUsageText() }], details: { action, item: input.item, status: rawStatus, tracked: false }, isError: true };
      }
      const todo = state.standardTodo;
      if (!todo?.items.length) {
        return { content: [{ type: "text", text: "No Standard Mode To Do list is active." }], details: { action, item: itemNumber, status, tracked: false }, isError: true };
      }
      const index = Math.floor(itemNumber) - 1;
      if (!Number.isFinite(itemNumber) || index < 0 || index >= todo.items.length) {
        return { content: [{ type: "text", text: "Invalid Standard Mode To Do item." }], details: { action, item: itemNumber, status, tracked: false }, isError: true };
      }
      const currentItemStatus = todo.items[index].status;
      if (!isValidStandardTodoTransition(currentItemStatus, status)) {
        const allowed = VALID_STANDARD_TODO_TRANSITIONS[currentItemStatus]?.join(", ") ?? "none";
        return { content: [{ type: "text", text: `Invalid status transition for To Do ${itemNumber}: ${currentItemStatus} → ${status}. Allowed from ${currentItemStatus}: ${allowed}.` }], details: { action, item: itemNumber, status, currentStatus: currentItemStatus, tracked: false }, isError: true };
      }
      const items = todo.items.map((entry, i) => i === index ? { ...entry, status } : entry);
      const nextActive = status === "completed" || status === "skipped" ? items.findIndex((entry, i) => i > index && entry.status === "pending") : index;
      if (nextActive >= 0 && (status === "completed" || status === "skipped")) items[nextActive] = { ...items[nextActive], status: "active" };
      const done = items.filter((entry) => entry.status === "completed" || entry.status === "skipped").length;
      const blocked = items.some((entry) => entry.status === "blocked");
      const nextStatus: StandardTodoState["status"] = blocked ? "blocked" : done >= items.length ? "completed" : "active";
      updateState({ standardTodo: { ...todo, items, status: nextStatus, currentItemIndex: Math.max(0, nextActive >= 0 ? nextActive : index), updatedAt: new Date().toISOString() } }, ctx);
      const updated = state.standardTodo?.items[index];
      return { content: [{ type: "text", text: `To Do ${itemNumber}: ${updated?.title ?? "unknown"} → ${status}` }], details: { action, item: itemNumber, status, text: updated?.title, tracked: true } };
    },
  } as ToolDefinition);

  const activeModelDiagnostic = (ctx: ExtensionContext): string => {
    const active = ctx.model ? `${ctx.model.provider}/${ctx.model.id}` : "(none)";
    return `Active Pi Model: ${active}\nActive Pi Thinking: ${pi.getThinkingLevel()}`;
  };

  const activePlanModelRole = (): WorkflowRole | undefined => {
    if (state.mode === "awaiting_plan_input" || state.mode === "awaiting_clarification" || state.mode === "planning" || state.mode === "plan_draft") return "planner";
    if (state.mode === "reviewing") return "reviewer";
    if (state.mode === "executing" || state.mode === "repairing") return "executor";
    if (state.mode === "validating" || state.mode === "revalidating") return "validator";
    return undefined;
  };

  const planRoutePendingMessage = (role: WorkflowRole, activeRole: WorkflowRole | undefined): string =>
    activeRole
      ? `Plan ${role} route saved. Current Plan phase uses the ${activeRole} route; ${role} will apply when Plan Mode reaches that phase.`
      : `Plan ${role} route saved. It will apply when Plan Mode reaches the ${role} phase.`;

  const reapplyPlanRouteForRole = async (ctx: ExtensionContext, role: WorkflowRole, showNotice = false, options: { requireEnabled?: boolean } = {}): Promise<RoleModelSettings | undefined> => {
    const route = await applyPlanModelForRole(pi, ctx, role, { cwd: ctx.cwd, requireEnabled: options.requireEnabled });
    if (!route) return undefined;
    updateState({ modelsUsed: { ...(state.modelsUsed ?? {}), [role]: modelLabel(route) } }, ctx);
    if (showNotice) workflowUiNotify(ctx, `Active Plan Mode ${role} route applied: ${modelLabel(route)}\n${activeModelDiagnostic(ctx)}`, "info");
    return route;
  };

  const reapplyPlanRouteForRoleIfActive = async (ctx: ExtensionContext, role: WorkflowRole, showNotice = false, options: { requireEnabled?: boolean } = {}): Promise<boolean> => {
    if (!isPlanWorkflowUiMode(state)) return false;
    const activeRole = activePlanModelRole();
    if (activeRole !== role) {
      if (showNotice) workflowUiNotify(ctx, planRoutePendingMessage(role, activeRole), "info");
      return false;
    }
    const route = await reapplyPlanRouteForRole(ctx, role, showNotice, options);
    return Boolean(route);
  };

  const planRouteSavedFeedback = async (ctx: ExtensionContext, role: WorkflowRole, options: { requireEnabled?: boolean } = {}): Promise<string> => {
    const activeRole = activePlanModelRole();
    const reapplied = await reapplyPlanRouteForRoleIfActive(ctx, role, false, options);
    if (reapplied) return `\n\nActive Plan Mode ${role} route applied.\n${activeModelDiagnostic(ctx)}`;
    if (isPlanWorkflowUiMode(state)) return `\n\n${planRoutePendingMessage(role, activeRole)}`;
    return "";
  };

  const reapplyPlannerRouteIfPlanMode = async (ctx: ExtensionContext, showNotice = false): Promise<boolean> => {
    return reapplyPlanRouteForRoleIfActive(ctx, "planner", showNotice);
  };

  const planRoutingFailurePrompt = (role: WorkflowRole, phase: string): string => {
    return `PI WORKFLOW PLAN MODE ROUTING FAILED: the configured ${role} model could not be applied before ${phase}. Do not continue on the current model. Explain the routing error and ask the user to check /workflow-settings list, provider availability, and credentials.`;
  };

  const reapplyStandardRouteIfStandardMode = async (ctx: ExtensionContext, showNotice = false): Promise<boolean> => {
    if (!isStandardWorkflowMode(state)) return false;
    const settings = loadWorkflowSettings(ctx.cwd);
    const standardRole = effectiveStandardModelRole(settings);
    if (standardRole === "current") {
      if (showNotice) workflowUiNotify(ctx, `Standard Mode keeps the current Pi model.\n${activeModelDiagnostic(ctx)}`, "info");
      return false;
    }
    const route = await applyStandardModelForRole(pi, ctx, standardRole, { cwd: ctx.cwd });
    if (!route) return false;
    updateState({ modelsUsed: { ...(state.modelsUsed ?? {}), [standardRole]: modelLabel(route) } }, ctx);
    if (showNotice) workflowUiNotify(ctx, `Active Standard Mode ${standardRole} route applied: ${modelLabel(route)}\n${activeModelDiagnostic(ctx)}`, "info");
    return true;
  };

  const activeTopWidgetSlot = (): WorkflowWidgetSlot | undefined => {
    if (isPlanWorkflowUiMode(state)) return "planTop";
    if (isMissionWorkflowMode(state)) return "missionTop";
    if (isStandardWorkflowMode(state)) return "standardTop";
    return undefined;
  };

  const renderWorkflowWidgetsStatus = (ctx: ExtensionContext): string => {
    const settings = loadWorkflowSettings(ctx.cwd);
    const globalUi = workflowWidgetUi(loadGlobalSettings());
    const ui = workflowWidgetUi(settings);
    const common = `Active Mode: ${state.mode}\nShortcuts: ${globalUi.enableWidgetShortcuts !== false ? "enabled" : "disabled"}\nRemember Visibility: ${globalUi.rememberWidgetVisibility !== false ? "enabled" : "disabled"}\nStorage: ${globalUi.rememberWidgetVisibility !== false ? "global settings" : "current Pi session"}\nEditor Hints: idle entry ${ui.showIdleWorkflowEntryHint !== false ? "visible" : "hidden"}, active switch ${ui.showActiveWorkflowSwitchHint !== false ? "visible" : "hidden"}, widgets ${ui.showWidgetShortcutHint !== false ? "visible" : "hidden"}, preset ${ui.showPresetShortcutHint !== false ? "visible" : "hidden"}, contrast ${workflowEditorHintContrastLabel(workflowEditorHintContrast(settings))}`;
    if (isPlanWorkflowUiMode(state)) {
      const bottom = planBottomRelevant(state) ? widgetVisibilityLabel(settings, "planBottom") : "not applicable";
      return `# Workflow Widgets\n\nPlan Top Widget: ${widgetVisibilityLabel(settings, "planTop")}\nPlan Bottom Widget: ${bottom}\nStatus Line: ${widgetVisibilityStatus(state, settings) ?? "none"}\n${common}`;
    }
    if (isMissionWorkflowMode(state)) {
      const mission = activeMissionForUi(state);
      const bottom = missionBottomRelevant(state, mission) ? widgetVisibilityLabel(settings, "missionBottom") : "not applicable";
      return `# Workflow Widgets\n\nMission Top Widget: ${widgetVisibilityLabel(settings, "missionTop")}\nMission Bottom Widget: ${bottom}\nStatus Line: ${widgetVisibilityStatus(state, settings) ?? "none"}\n${common}`;
    }
    if (isStandardWorkflowMode(state)) {
      return `# Workflow Widgets\n\nStandard Top Widget: ${widgetVisibilityLabel(settings, "standardTop")}\nStandard To Do Widget: ${widgetVisibilityLabel(settings, "standardBottom")}\nStatus Line: ${widgetVisibilityStatus(state, settings) ?? "none"}\n${common}`;
    }
    return `# Workflow Widgets\n\nNo active Plan/Mission/Standard widget is currently visible.\nStatus Line: ${widgetVisibilityStatus(state, settings) ?? "none"}\n\nEntry Shortcuts:\n- ${workflowEntryShortcutLabel("standard")}\n- ${workflowEntryShortcutLabel("plan")}\n- ${workflowEntryShortcutLabel("mission")}\n\nActive-mode editor hints use compact text such as: ${workflowWidgetShortcutLabel(true)} Preset:${activeWorkflowPresetLabel(settings)} ${workflowPresetCycleShortcutLabel()} ${workflowEntryShortcutLabel("standard")} ${workflowEntryShortcutLabel("mission")}\nWidget toggles and preset cycling are visible only while Plan/Mission/Standard Mode is active.\n\n${common}`;
  };

  const renderEditorHintsSettings = (ctx: ExtensionContext): string => {
    const settings = loadWorkflowSettings(ctx.cwd);
    const ui = workflowWidgetUi(settings);
    return `# Editor Hints\n\nThese hints render inline in the editor/input box.\n\nIdle Entry Hint: ${ui.showIdleWorkflowEntryHint !== false ? "visible" : "hidden"}\nActive Switch Hint: ${ui.showActiveWorkflowSwitchHint !== false ? "visible" : "hidden"}\nWidget Shortcut Hint: ${ui.showWidgetShortcutHint !== false ? "visible" : "hidden"}\nPreset Shortcut Hint: ${ui.showPresetShortcutHint !== false ? "visible" : "hidden"}\nHint Contrast: ${workflowEditorHintContrastLabel(workflowEditorHintContrast(settings))}`;
  };

  const setWorkflowWidgetVisibility = (ctx: ExtensionContext, slot: WorkflowWidgetSlot, visible: boolean): string => {
    const globalUi = workflowWidgetUi(loadGlobalSettings());
    let storage = "current Pi session";
    if (globalUi.rememberWidgetVisibility === false) {
      widgetVisibilityOverrides[slot] = visible;
    } else {
      delete widgetVisibilityOverrides[slot];
      updateSettings(ctx.cwd, "global", (s) => {
        if (slot === "standardTop") s.standard.statusWidgetVisible = visible;
        else if (slot === "standardBottom") s.standard.todoProgressVisible = visible;
        else workflowWidgetUi(s)[widgetSettingKey[slot]] = visible;
      });
      storage = "global settings";
    }
    setWorkflowUi(ctx, state, activeSubagents);
    return `${widgetSlotLabel(slot)} ${visible ? "visible" : "hidden"} (${storage}).`;
  };

  const toggleWorkflowWidget = (ctx: ExtensionContext, slot: WorkflowWidgetSlot): string => {
    const visible = workflowWidgetVisible(loadWorkflowSettings(ctx.cwd), slot);
    return setWorkflowWidgetVisibility(ctx, slot, !visible);
  };

  const setWorkflowWidgetShortcutStatus = (ctx: ExtensionContext, _slot: WorkflowWidgetSlot, _visible?: boolean): void => {
    const settings = loadWorkflowSettings(ctx.cwd);
    workflowEditorHintText = workflowEditorHintTextFor(state, settings);
  };

  const handleWorkflowWidgetsCommand = async (args: string, ctx: ExtensionContext): Promise<void> => {
    const parts = args.trim().split(/\s+/).filter(Boolean);
    const action = parts[0] ?? "list";
    const target = parts[1] ?? "";
    if (action === "list" || action === "status" || action === "show-status") return show(pi, renderWorkflowWidgetsStatus(ctx));
    if (action === "configure") return showUiWidgetsSettingsMenu(ctx);
    if (action === "top" || (action === "toggle" && target === "top")) {
      const slot = activeTopWidgetSlot();
      if (!slot) return show(pi, `# Workflow Widgets\n\nNo active Plan/Mission/Standard top widget for mode: ${state.mode}`);
      return show(pi, `# Workflow Widgets\n\n${toggleWorkflowWidget(ctx, slot)}\n\n${renderWorkflowWidgetsStatus(ctx)}`);
    }
    if (action === "bottom" || (action === "toggle" && target === "bottom")) {
      if (isPlanWorkflowUiMode(state) && planBottomRelevant(state)) return show(pi, `# Workflow Widgets\n\n${toggleWorkflowWidget(ctx, "planBottom")}\n\n${renderWorkflowWidgetsStatus(ctx)}`);
      if (isMissionWorkflowMode(state) && missionBottomRelevant(state, activeMissionForUi(state))) return show(pi, `# Workflow Widgets\n\n${toggleWorkflowWidget(ctx, "missionBottom")}\n\n${renderWorkflowWidgetsStatus(ctx)}`);
      if (isStandardWorkflowMode(state)) return show(pi, `# Workflow Widgets\n\n${toggleWorkflowWidget(ctx, "standardBottom")}\n\n${renderWorkflowWidgetsStatus(ctx)}`);
      return show(pi, `# Workflow Widgets\n\nNo applicable Plan/Mission/Standard bottom widget for mode: ${state.mode}`);
    }
    if (action === "on" || action === "off" || ((action === "show" || action === "hide") && target === "all")) {
      const visible = action === "on" || action === "show";
      const messages = (["planTop", "planBottom", "missionTop", "missionBottom", "standardTop", "standardBottom"] as WorkflowWidgetSlot[]).map((slot) => setWorkflowWidgetVisibility(ctx, slot, visible));
      return show(pi, `# Workflow Widgets\n\n${messages.join("\n")}\n\n${renderWorkflowWidgetsStatus(ctx)}`);
    }
    return show(pi, "# Workflow Widgets\n\nUsage:\n- /workflow widgets status\n- /workflow widgets list\n- /workflow widgets configure\n- /workflow widgets toggle top\n- /workflow widgets toggle bottom\n- /workflow widgets on\n- /workflow widgets off\n\nEditor hint behavior:\n- Idle: Plan/Mission entry shortcuts only\n- Active modes: compact widget/preset hints plus Plan/Mission switch hints by default\n- Active switch hints can be configured in /workflow-settings configure widgets -> Editor Hints");
  };

  const persistCurrentPlan = (ctx: ExtensionContext, approvalStatus: "draft" | "approved" | "revised" | "completed" | "archived", saveReason: string, handoff: { executionSummary?: string; reviewerReport?: string; validationReport?: string; repairAttempt?: string; finalReport?: string } = {}): string | undefined => {
    const settings = loadWorkflowSettings(ctx.cwd);
    const workflow = settings.workflow as typeof settings.workflow & { savePlans?: boolean; savePlanHistory?: boolean; planHistoryLimit?: number };
    if (workflow.savePlans === false) return undefined;
    const record = saveWorkflowPlan(state, {
      cwd: ctx.cwd,
      approvalStatus,
      saveReason,
      planningDepth: settings.planning.depth,
      clarificationMode: settings.planning.clarificationMode,
      savePlanHistory: workflow.savePlanHistory !== false,
      planHistoryLimit: workflow.planHistoryLimit ?? 50,
      ...handoff,
      subagents: {
        planningPolicy: settings.subagents.planningPolicy ?? "auto",
        executionPolicy: settings.subagents.executionPolicy ?? "auto",
        reviewPolicy: settings.subagents.reviewPolicy ?? "auto",
        validationPolicy: settings.subagents.validationPolicy ?? "auto",
      },
    });
    if (record) updateState({ planHistoryId: record.id, approvedPlanHistoryId: approvalStatus === "approved" || approvalStatus === "completed" ? record.id : state.approvedPlanHistoryId }, ctx);
    return record?.id;
  };

  const buildCompletedPlanSummary = (ctx: ExtensionContext, planHistoryId: string | undefined, verdict: NonNullable<WorkflowState["validationVerdict"]>, repairRetries: number, handoff: Pick<NonNullable<WorkflowState["lastCompletedPlanSummary"]>, "executionSummary" | "validationReport" | "repairSummary" | "reviewerSummary"> = {}): NonNullable<WorkflowState["lastCompletedPlanSummary"]> => {
    const progress = state.planProgress;
    const total = progress?.steps.length ?? 0;
    const countedCompleted = progress?.steps.filter((step) => step.status === "completed" || step.status === "skipped").length ?? 0;
    const stepsCompleted = verdict === "PASS" && total > 0 ? total : countedCompleted;
    return {
      completedAt: new Date().toISOString(),
      planHistoryId,
      status: "completed",
      stepsCompleted,
      stepsTotal: total,
      validationResult: verdict,
      repairRetries,
      maxRepairRetries: workflowMaxValidationRetries(state, loadWorkflowSettings(ctx.cwd)),
      repairStatus: state.lastRepairStatus === "running" ? "completed" : (state.lastRepairStatus ?? "none"),
      activeRuntimeMs: planActiveRuntimeMs(state),
      elapsedMs: planWallClockAgeMs(state),
      nextAction: "ready for new plan",
      ...handoff,
    };
  };

  const reportExcerpt = (text: string | undefined, max = 1800): string => text?.trim() ? compact(text, max) : "(none recorded)";

  const finalPlanHandoffReport = (summary: NonNullable<WorkflowState["lastCompletedPlanSummary"]>, verdict: WorkflowState["validationVerdict"], archivedPlanId?: string, cwd?: string): string => {
    const validation = summary.validationReport ?? "";
    const caveatMatch = validation.match(/(?:^|\n)#{1,6}\s*(?:Remaining Caveat|Remaining Caveats|Caveats?|Risks?|Remaining Risks)\s*\n([\s\S]*?)(?=\n#{1,6}\s+|$)/i);
    const nextMatch = validation.match(/(?:^|\n)#{1,6}\s*(?:Next Action|Recommended Next Action)\s*\n([\s\S]*?)(?=\n#{1,6}\s+|$)/i);
    const stepLines = state.planProgress?.steps.map((step, index) => `- ${index + 1}. ${step.title} — ${step.status}`).join("\n") || "- step details not recorded";
    const reviewHistoryLines = state.reviewHistory?.slice(-5).map((entry) => `- ${entry.timestamp}: retry ${entry.retry}, ${entry.status}; ${compact(entry.reviewFailure ?? entry.repairSummary ?? entry.nextAction, 220)}`).join("\n") || "- none recorded";
    const repairHistoryLines = state.repairHistory?.slice(-5).map((entry) => `- ${entry.timestamp}: retry ${entry.retry}, ${entry.status}; ${compact(entry.validationFailure ?? entry.repairSummary ?? entry.nextAction, 220)}`).join("\n") || "- none recorded";
    const validationMode = state.planStepValidationIndex !== undefined || state.planProgress?.lastValidationStatus ? "step/final validation tracked" : "final validation";
    return professionalFinalSummaryMarkdown(`## Final Plan Conclusion
- Plan ID: ${archivedPlanId ?? summary.planHistoryId ?? "this completed plan record"}
- Final status: completed
- Task: ${compact(state.originalTask ?? state.task, 500)}
- Steps completed: ${summary.stepsCompleted}/${summary.stepsTotal}
- Plan review: ${state.reviewerVerdict ?? "not run"}
- Review repairs/retries: ${state.workflowReviewRetryCount ?? 0}/${state.maxReviewRetriesPerWorkflow ?? repairRetryGateConfig(loadWorkflowSettings(cwd), "review").maxRetriesPerWorkflow}; status: ${state.lastReviewRepairStatus ?? "none"}
- Validation mode: ${validationMode}
- Validation result: ${verdict ?? summary.validationResult}
- Validation repairs/retries: ${summary.repairRetries}/${summary.maxRepairRetries}; status: ${summary.repairStatus}
- Runtime: ${formatDurationMs(summary.activeRuntimeMs)} active / ${formatDurationMs(summary.elapsedMs)} elapsed
- Saved plan record: ${archivedPlanId ?? summary.planHistoryId ?? "this completed plan record"}
- Final conclusion: Plan completed its recorded workflow steps and is ready for the next planning request unless the caveats below require manual follow-up.
- Next: ${summary.nextAction}

${renderHandoffProjectContext(cwd)}

### Step Outcomes
${stepLines}

### Plan Review Summary
Reviewer verdict: ${state.reviewerVerdict ?? "not run"}
Latest reviewer report:
${reportExcerpt(summary.reviewerSummary ?? state.reviewerReport, 1600)}

Review History
${reviewHistoryLines}

### Execution Summary
${reportExcerpt(summary.executionSummary, 2200)}

### Repair Summary
${reportExcerpt(summary.repairSummary, 1600)}

Repair History
${repairHistoryLines}

### Validation Report
${reportExcerpt(summary.validationReport, 2400)}

### Remaining Caveats
${caveatMatch?.[1]?.trim() ? compact(caveatMatch[1], 1000) : "None reported by final validation."}

### Recommended Next Action
${nextMatch?.[1]?.trim() ? compact(nextMatch[1], 1000) : summary.nextAction}

### Exact Resume Instructions
- Review this completed record with: /workflow plans show ${archivedPlanId ?? summary.planHistoryId ?? "latest"}
- Re-check current workflow state with: /workflow status
- Before continuing implementation, verify the target repo branch/status and re-read detected project instructions.

Review later with: /workflow plans show ${archivedPlanId ?? summary.planHistoryId ?? "latest"}`);
  };

  const finalStepSummaryText = (summary: NonNullable<WorkflowState["lastCompletedPlanSummary"]>, verdict: WorkflowState["validationVerdict"]): string => {
    return `## Final Step Summary\n- Steps completed: ${summary.stepsCompleted}/${summary.stepsTotal}\n- Validation result: ${verdict ?? summary.validationResult}\n- Repairs attempted: ${summary.repairRetries}\n- Runtime: ${formatDurationMs(summary.activeRuntimeMs)} active\n- Deliverables: final workflow handoff saved in the completed plan record\n- Next: ready for new plan`;
  };

  const buildPlanStopSummary = (ctx: ExtensionContext, status: "completed" | "blocked", title: string, options: { validationText?: string; verdict?: WorkflowState["validationVerdict"]; reason?: string } = {}): NonNullable<WorkflowState["lastPlanStopSummary"]> => {
    const progress = state.planProgress;
    const total = progress?.steps.length ?? extractApprovedPlanSteps(state.approvedPlan ?? state.draftPlan).length;
    const completed = status === "completed" && total > 0 ? total : progress?.steps.filter((step) => step.status === "completed" || step.status === "skipped").length ?? 0;
    const validation = options.validationText ?? state.validationReport;
    const verdict = options.verdict ?? state.validationVerdict ?? "UNKNOWN";
    const repair = state.lastRepairAttempt ?? state.repairHistory?.filter((entry) => entry.status === "completed").slice(-1)[0]?.repairSummary;
    const summaryRepairStatus = nonRunningRepairStatus(state.lastRepairStatus);
    const summaryProgress = nonRunningPlanProgress(progress, summaryRepairStatus);
    const next = status === "completed" ? "ready for new plan" : (options.reason ?? state.lastValidationFailure ?? state.lastRepairAttempt ?? "review blocker, then repair, revalidate, revise, or cancel");
    const summary = professionalFinalSummaryMarkdown(`## Final Plan Stop Summary
- Final status: ${status}
- Steps completed: ${completed}/${total}
- Validation result: ${verdict}
- Repairs attempted: ${state.currentValidationRetry ?? 0}/${workflowMaxValidationRetries(state, loadWorkflowSettings(ctx.cwd))}
- Repair status: ${summaryRepairStatus ?? "none"}
- Runtime: ${formatDurationMs(planActiveRuntimeMs(state))} active
- Next: ${next}

${renderHandoffProjectContext(ctx.cwd)}

### Original Task
${reportExcerpt(state.task ?? state.originalTask, 1200)}

### Approved Plan
${reportExcerpt(state.approvedPlan ?? state.draftPlan, 2200)}

### Execution Summary
${reportExcerpt(state.executionSummary, 2200)}

### Repair Summary
${reportExcerpt(repair, 1600)}

### Validation Report
${reportExcerpt(validation, 2400)}

### Exact Resume Instructions
- Run /workflow status to confirm the final state.
- If blocked, inspect the reason above, then use /plan repair, /plan revalidate, /plan revise <feedback>, or /plan cancel as appropriate.
- If completed, start the next request with /plan or review the saved record with /workflow plans show ${state.planHistoryId ?? "latest"}.`);
    const snapshot: NonNullable<WorkflowState["lastPlanStopSummary"]>["blockedPlanSnapshot"] = status === "blocked" && state.approvedPlan?.trim()
      ? {
          task: state.task,
          originalTask: state.originalTask,
          approvedPlan: state.approvedPlan,
          planHistoryId: state.planHistoryId,
          approvedPlanHistoryId: state.approvedPlanHistoryId,
          executionSummary: state.executionSummary,
          validationReport: state.validationReport,
          validationVerdict: state.validationVerdict,
          lastValidationFailure: state.lastValidationFailure,
          lastRepairAttempt: state.lastRepairAttempt,
          repairHistory: state.repairHistory,
          lastRepairStatus: summaryRepairStatus,
          currentValidationRetry: state.currentValidationRetry,
          workflowValidationRetryCount: state.workflowValidationRetryCount,
          planRuntime: state.planRuntime,
          planProgress: summaryProgress,
          reviewerReport: state.reviewerReport,
          reviewerVerdict: state.reviewerVerdict,
          reviewHistory: state.reviewHistory,
          currentReviewRetry: state.currentReviewRetry,
          workflowReviewRetryCount: state.workflowReviewRetryCount,
          lastReviewFailure: state.lastReviewFailure,
          lastReviewAttempt: state.lastReviewAttempt,
          lastReviewRepairStatus: state.lastReviewRepairStatus,
          reviewRepairInProgress: state.reviewRepairInProgress,
          repairRetryState: state.repairRetryState,
          concreteRepairableIssue: state.concreteRepairableIssue,
          manualVerificationRequired: state.manualVerificationRequired,
          evidenceGap: state.evidenceGap,
          planTokensUsed: state.planTokensUsed,
          modelsUsed: state.modelsUsed,
        }
      : undefined;
    return { stoppedAt: new Date().toISOString(), kind: "plan", status, title, summary, blockedPlanSnapshot: snapshot };
  };

  const queuePlanTerminalSummary = (ctx: ExtensionContext, status: "completed" | "blocked", title: string, options: { validationText?: string; verdict?: WorkflowState["validationVerdict"]; reason?: string } = {}): NonNullable<WorkflowState["lastPlanStopSummary"]> => {
    const summary = buildPlanStopSummary(ctx, status, title, options);
    updateState({ lastPlanStopSummary: summary }, ctx);
    queueNativeFinalSummary(pi, summary.summary, "workflow-plan-final-summary");
    return summary;
  };

  const buildMissionStopSummary = (ctx: ExtensionContext, mission: MissionState, status: "completed" | "blocked", title: string, options: { validationText?: string; verdict?: string; reason?: string } = {}): NonNullable<WorkflowState["lastMissionStopSummary"]> => {
    const completed = mission.milestones.filter((milestone) => milestone.status === "completed" || milestone.status === "skipped").length;
    const total = mission.milestones.length;
    const validation = options.validationText ?? state.validationReport ?? mission.lastFinalValidationFailure ?? mission.lastValidationFailure;
    const verdict = options.verdict ?? mission.lastFinalValidationResult ?? mission.lastValidationResult ?? state.validationVerdict ?? "UNKNOWN";
    const repair = mission.lastRepairAttempt ?? mission.repairHistory?.filter((entry) => entry.status === "completed").slice(-1)[0]?.repairSummary;
    const summaryRepairStatus = mission.lastRepairStatus === "running" ? "failed" : (mission.lastRepairStatus ?? "none");
    const next = status === "completed" ? "ready for new mission" : (options.reason ?? mission.lastBlockReason ?? mission.lastValidationFailure ?? "review blocker, then repair, revalidate, continue, or stop");
    const milestoneLines = mission.milestones.map((milestone, index) => `- ${milestone.id || `M${index + 1}`}: ${milestone.title || "Untitled"} — ${milestone.status}`).join("\n") || "- none recorded";
    const summary = professionalFinalSummaryMarkdown(`## Final Mission Stop Summary
- Final status: ${status}
- Mission ID: ${mission.id}
- Milestones completed: ${status === "completed" && total > 0 ? total : completed}/${total}
- Validation result: ${verdict}
- Repairs attempted: ${mission.missionValidationRetryCount ?? mission.currentValidationRetry ?? 0}/${maxMissionValidationRetries(mission, loadWorkflowSettings(ctx.cwd))}
- Repair status: ${summaryRepairStatus}
- Runtime: ${formatDurationMs(missionActiveRuntimeMs(mission))} active
- Next: ${next}

${renderHandoffProjectContext(ctx.cwd)}

### Mission Goal
${reportExcerpt(mission.goal, 1200)}

### Milestone Outcomes
${milestoneLines}

### Execution Summary
${reportExcerpt(state.executionSummary ?? mission.lastSummary, 2200)}

### Repair Summary
${reportExcerpt(repair, 1600)}

### Validation Report
${reportExcerpt(validation, 2400)}

### Exact Resume Instructions
- Run /mission status or /workflow status to confirm the final state.
- If blocked, inspect the reason above, then use /mission repair, /mission revalidate, /mission continue, or /mission stop as appropriate.
- If completed, start the next mission with /mission start <goal>.`);
    return { stoppedAt: new Date().toISOString(), kind: "mission", status, title, summary };
  };

  const queueMissionTerminalSummary = (ctx: ExtensionContext, mission: MissionState, status: "completed" | "blocked", title: string, options: { validationText?: string; verdict?: string; reason?: string } = {}): NonNullable<WorkflowState["lastMissionStopSummary"]> => {
    const summary = buildMissionStopSummary(ctx, mission, status, title, options);
    updateState({ lastMissionStopSummary: summary }, ctx);
    queueNativeFinalSummary(pi, summary.summary, "workflow-mission-final-summary");
    return summary;
  };

  const completePlanWorkflow = async (ctx: ExtensionContext, validationText?: string, verdict: WorkflowState["validationVerdict"] = "PASS") => {
    const settings = loadWorkflowSettings(ctx.cwd);
    const preserveMissionPointer = isMissionWorkflowMode(state);
    const repairRetriesBeforeCompletion = state.currentValidationRetry ?? 0;
    const executionSummaryForHandoff = state.executionSummary;
    const validationReportForHandoff = validationText ?? state.validationReport;
    const completedRepairEntries = state.repairHistory?.filter((entry) => entry.status === "completed") ?? [];
    const repairSummaryForHandoff = state.lastRepairAttempt ?? completedRepairEntries[completedRepairEntries.length - 1]?.repairSummary;
    const reviewerSummaryForHandoff = state.reviewerReport;
    const finalValidationStatus = planValidationStatusForVerdict(verdict);
    updateState({
      mode: "validated",
      validationReport: validationText ?? state.validationReport,
      validationVerdict: verdict,
      currentValidationRetry: 0,
      lastValidationFailure: "",
      lastRepairStatus: state.lastRepairStatus === "running" ? "completed" : (state.lastRepairStatus ?? "none"),
      planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "validated", validationVerdict: verdict }, settings, { lifecycleStatus: "completed", validationStatus: finalValidationStatus, lastValidationStatus: finalValidationStatus, repairRetry: 0, repairStatus: state.lastRepairStatus === "running" ? "completed" : (state.lastRepairStatus ?? "none"), nextAction: "new planning request", steps: planCompletionSteps(state.planProgress, extractApprovedPlanSteps(state.approvedPlan ?? state.draftPlan)) }) : state.planProgress,
    }, ctx);
    const initialCompletedPlanSummary = buildCompletedPlanSummary(ctx, state.planHistoryId, verdict ?? "UNKNOWN", repairRetriesBeforeCompletion, {
      executionSummary: reportExcerpt(executionSummaryForHandoff, 2400),
      validationReport: reportExcerpt(validationReportForHandoff, 2600),
      repairSummary: reportExcerpt(repairSummaryForHandoff, 1800),
      reviewerSummary: reportExcerpt(reviewerSummaryForHandoff, 1400),
    });
    const initialFinalReport = finalPlanHandoffReport(initialCompletedPlanSummary, verdict, undefined, ctx.cwd);
    const completedPlanId = persistCurrentPlan(ctx, "completed", "plan workflow completed successfully", { executionSummary: executionSummaryForHandoff, reviewerReport: reviewerSummaryForHandoff, validationReport: validationReportForHandoff, repairAttempt: repairSummaryForHandoff, finalReport: initialFinalReport });
    const completedPlanSummary = { ...initialCompletedPlanSummary, planHistoryId: completedPlanId ?? state.planHistoryId, finalReport: finalPlanHandoffReport({ ...initialCompletedPlanSummary, planHistoryId: completedPlanId ?? state.planHistoryId }, verdict, completedPlanId ?? state.planHistoryId, ctx.cwd) };
    if (!preserveMissionPointer) activeMission = undefined;
    pi.setActiveTools(planToolsFor(settings));
    updateState({
      mode: "awaiting_plan_input",
      activeMissionId: preserveMissionPointer ? state.activeMissionId : undefined,
      task: undefined,
      originalTask: undefined,
      draftPlan: undefined,
      approvedPlan: undefined,
      reviewerReport: undefined,
      reviewerVerdict: undefined,
      currentReviewRetry: 0,
      workflowReviewRetryCount: 0,
      maxReviewRetriesPerPlan: undefined,
      maxReviewRetriesPerWorkflow: undefined,
      lastReviewFailure: undefined,
      lastReviewAttempt: undefined,
      lastReviewRepairStatus: "none",
      reviewHistory: undefined,
      reviewRepairInProgress: undefined,
      repairRetryState: undefined,
      executionSummary: undefined,
      validationReport: undefined,
      validationVerdict: undefined,
      clarifyingQuestions: undefined,
      clarifyingAnswers: undefined,
      clarificationAlreadyAsked: undefined,
      clarificationRequiredBeforePlan: undefined,
      clarificationRequirementReason: undefined,
      clarificationSkipReason: undefined,
      clarificationQualityRetryCount: undefined,
      currentValidationRetry: 0,
      workflowValidationRetryCount: 0,
      maxValidationRetriesPerPlan: undefined,
      maxValidationRetriesPerWorkflow: undefined,
      lastValidationFailure: undefined,
      lastRepairAttempt: undefined,
      repairHistory: undefined,
      lastRepairStatus: "none",
      planStepValidationIndex: undefined,
      planExecutionStepIndex: undefined,
      planRuntime: undefined,
      planProgress: undefined,
      lastCompletedPlanSummary: completedPlanSummary,
      lastPlanStopSummary: { stoppedAt: completedPlanSummary.completedAt, kind: "plan", status: "completed", title: "Plan completed", summary: completedPlanSummary.finalReport ?? initialFinalReport },
      planHistoryId: completedPlanId ?? state.planHistoryId,
      approvedPlanHistoryId: completedPlanId ?? state.approvedPlanHistoryId,
      modelsUsed: undefined,
    }, ctx);
    queueNativeFinalSummary(pi, nativePlanFinalDeliverableSummary(completedPlanSummary), "workflow-plan-final-summary");
  };

  const completePlanWithoutValidation = async (ctx: ExtensionContext, reason: string, options: { showMenu?: boolean } = {}) => {
    const settings = loadWorkflowSettings(ctx.cwd);
    const returnToPlan = (settings.workflow as typeof settings.workflow & { returnToPlanModeAfterWorkflow?: boolean }).returnToPlanModeAfterWorkflow !== false;
    if (returnToPlan) {
      await completePlanWorkflow(ctx, reason, "UNKNOWN");
      return;
    }
    updateState({
      mode: "validated",
      validationReport: reason,
      validationVerdict: "UNKNOWN",
      currentValidationRetry: 0,
      lastValidationFailure: "",
      lastRepairStatus: state.lastRepairStatus === "running" ? "completed" : (state.lastRepairStatus ?? "none"),
      planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "validated", validationVerdict: "UNKNOWN" }, settings, { lifecycleStatus: "completed", validationStatus: "unknown", lastValidationStatus: "unknown", repairRetry: 0, repairStatus: state.lastRepairStatus === "running" ? "completed" : (state.lastRepairStatus ?? "none"), nextAction: "list summary or start new plan", steps: planCompletionSteps(state.planProgress, extractApprovedPlanSteps(state.approvedPlan ?? state.draftPlan)) }) : state.planProgress,
    }, ctx);
    recordWorkflowInternalEvent(ctx, "Internal workflow lifecycle event suppressed.");
    if (options.showMenu !== false) await showPostExecutionMenu(ctx);
  };

  const touchMissionHeartbeat = (mission: MissionState, progress = true): MissionState => {
    const settings = loadWorkflowSettings(mission.cwd);
    if (!missionHeartbeatEnabled(settings)) return mission;
    const now = new Date().toISOString();
    return {
      ...mission,
      lastHeartbeatAt: now,
      lastProgressAt: progress ? now : mission.lastProgressAt,
      heartbeatCount: (mission.heartbeatCount ?? 0) + 1,
    };
  };

  const saveActiveMission = (mission: MissionState, progress = true): MissionState => {
    const settings = loadWorkflowSettings(mission.cwd);
    activeMission = saveMissionState(touchMissionHeartbeat(mission, progress), { missionHistoryLimit: settings.missions.missionHistoryLimit ?? 50 });
    state = persistWorkflowState({ ...state, activeMissionId: activeMission.id });
    return activeMission;
  };

  const currentMissionMilestoneId = (mission: MissionState): string | undefined => mission.milestones[mission.currentMilestoneIndex]?.id;

  const missionMilestoneExecutionRecord = (mission: MissionState, summary: string, evidence?: unknown): MissionState["currentMilestoneExecution"] => {
    const items = Array.isArray(evidence) ? evidence.map((item) => String(item ?? "").trim()).filter(Boolean) : undefined;
    return {
      milestoneId: currentMissionMilestoneId(mission),
      summary: summary.trim(),
      evidence: items?.length ? items : undefined,
      completedAt: new Date().toISOString(),
    };
  };

  const missionExecutionSummaryFromCheckpoint = (mission: MissionState): string | undefined => {
    const milestoneId = currentMissionMilestoneId(mission);
    const checkpoint = [...mission.checkpoints].reverse().find((item) =>
      (!milestoneId || item.milestoneId === milestoneId)
      && /(?:execution completed|typed mission milestone result completed|milestone result completed|validation queued)/i.test(item.summary),
    );
    return checkpoint?.summary?.trim();
  };

  const missionExecutionSummaryForValidation = (mission: MissionState): string | undefined => {
    const milestoneId = currentMissionMilestoneId(mission);
    const record = mission.currentMilestoneExecution;
    const persisted = record?.summary?.trim() && (!record.milestoneId || !milestoneId || record.milestoneId === milestoneId)
      ? record.summary.trim()
      : missionExecutionSummaryFromCheckpoint(mission);
    const active = state.executionSummary?.trim();
    if (persisted && active && active !== persisted) return `${persisted}\n\nLatest repair/recovery summary:\n${active}`;
    return persisted || active || undefined;
  };

  const planValidationContextPatch = (ctx: ExtensionContext): Partial<WorkflowState> => ({
    validationRunId: createWorkflowValidationRunId("plan", ctx.cwd, state.activePlanId ?? state.approvedPlanHistoryId),
    validationScope: "plan",
    validationPlanId: state.activePlanId ?? state.approvedPlanHistoryId,
    validationMissionId: undefined,
    validationMilestoneId: undefined,
    validationProjectCwd: ctx.cwd,
  });

  const missionValidationContextPatch = (ctx: ExtensionContext, mission: MissionState, final = false): Partial<WorkflowState> => ({
    validationRunId: createWorkflowValidationRunId(final ? "mission_final" : "mission", ctx.cwd, mission.id),
    validationScope: final ? "mission_final" : "mission",
    validationPlanId: undefined,
    validationMissionId: mission.id,
    validationMilestoneId: final ? undefined : currentMissionMilestoneId(mission),
    validationProjectCwd: ctx.cwd,
  });

  const expectedValidationScopeForMode = (): WorkflowState["validationScope"] | undefined => {
    if (state.mode === "validating" || state.mode === "revalidating") return "plan";
    if (state.mode === "mission_validating" || state.mode === "mission_revalidating") return "mission";
    if (state.mode === "mission_final_validating") return "mission_final";
    return undefined;
  };

  const validationResultContextMismatch = (ctx: ExtensionContext, params: Record<string, unknown>): string | undefined => {
    const expectedScope = state.validationScope ?? expectedValidationScopeForMode();
    const scope = String(params.scope ?? "");
    if (expectedScope && scope !== expectedScope) return `wrong validation scope: expected ${expectedScope}, got ${scope || "missing"}`;
    if (expectedScope && !state.validationRunId) return "missing active validationRunId; re-enter validation";
    if (state.validationRunId && params.validationRunId !== state.validationRunId) return "stale or missing validationRunId";
    if (state.validationPlanId && params.planId !== state.validationPlanId) return "wrong or missing planId";
    if (state.validationMissionId && params.missionId !== state.validationMissionId) return "wrong or missing missionId";
    if (state.validationMilestoneId && params.milestoneId !== state.validationMilestoneId) return "wrong or missing milestoneId";
    if (state.validationProjectCwd && params.projectCwd !== state.validationProjectCwd) return "wrong or missing projectCwd";
    if (scope === "mission" || scope === "mission_final") {
      const mission = state.activeMissionId ? loadMissionState(state.activeMissionId) : undefined;
      if (!mission) return "active mission context unavailable";
      if (params.missionId && params.missionId !== mission.id) return "validation result belongs to a different mission";
      if (mission.cwd && mission.cwd !== ctx.cwd) return "active mission belongs to a different project cwd";
    }
    return undefined;
  };

  const validationTextLooksWrongMissionContext = (ctx: ExtensionContext, mission: MissionState, text?: string): boolean => {
    const body = text ?? "";
    if (!body.trim()) return false;
    const missionIds = Array.from(body.matchAll(/\bmission-\d{8}-\d{6}-[A-Za-z0-9_-]+\b/g)).map((match) => match[0]);
    if (missionIds.some((id) => id !== mission.id)) return true;
    const project = mission.projectLabel ?? (mission.cwd ? basename(mission.cwd) : undefined);
    if (project && /\bSalesForceExports\b/i.test(body) && !/SalesForceExports/i.test(project)) return true;
    if (mission.cwd && body.includes("/MediaDataFusion/") && !body.includes(mission.cwd) && !body.includes(basename(ctx.cwd))) return true;
    return false;
  };

  const withWorkflowCommandLock = async <T>(ctx: ExtensionContext, family: "plan" | "mission", action: string, run: () => Promise<T>): Promise<T> => {
    const lock = { family, action, startedAt: new Date().toISOString() };
    updateState({ workflowCommandLock: lock }, ctx);
    try {
      return await run();
    } finally {
      if (state.workflowCommandLock?.startedAt === lock.startedAt) updateState({ workflowCommandLock: undefined }, ctx);
    }
  };

  type TransientPlanFailureKind = "planning" | "review" | "execution" | "validation" | "revalidation" | "repair" | "repair_revalidation";
  type TransientMissionFailureKind = "planning" | "review" | "run" | "validation" | "revalidation" | "repair" | "final_validation" | "final_repair" | "repair_revalidation";

  const transientFailureReason = (label: string, detail?: string): string => {
    const raw = compact(detail ?? "", 500);
    return raw ? `${label}: ${raw}` : label;
  };

  const retryableInterruptionText = (reason: string): string => `Transient handoff interruption. ${reason}`;

  const nonRunningRepairStatus = (status: WorkflowState["lastRepairStatus"] | undefined): WorkflowState["lastRepairStatus"] => status === "running" ? "failed" : (status ?? "none");

  /*
   * Handoff recovery policy:
   * - queued delivery owns busy/connection retries before a turn is sent;
   * - read-only/control-plane phases may requeue a bounded parent handoff retry;
   * - mutating execution/repair phases are not replayed generically, because a
   *   late typed result or partial edits may still be valid.
   */

  const nonRunningPlanProgress = (progress: WorkflowState["planProgress"] | undefined, repairStatus: NonNullable<WorkflowState["lastRepairStatus"]>): WorkflowState["planProgress"] | undefined => {
    if (!progress) return progress;
    return {
      ...progress,
      repairStatus: progress.repairStatus === "running" ? repairStatus : progress.repairStatus,
      nextAction: /retry|revalidate|resume|continue/i.test(progress.nextAction ?? "") ? progress.nextAction : "retry interrupted workflow handoff",
    };
  };

  const clearTransientPendingPhase = (ctx: ExtensionContext, phase: WorkflowPendingToolPhase | undefined, reason: string): void => {
    if (phase) clearPendingWorkflowToolPhase(ctx, phase, reason);
    else syncWorkflowRuntimeForActivity(ctx, reason);
  };

  const recoverStandardTransientHandoffFailure = (ctx: ExtensionContext, reason: string, phase?: WorkflowPendingToolPhase): void => {
    clearTransientPendingPhase(ctx, phase, "standard transient handoff failure");
    if (state.mode === "standard") setStandardRuntimeActive(ctx, false);
    pi.setActiveTools(standardToolsFor(loadWorkflowSettings(ctx.cwd)));
    show(pi, `# Standard Workflow Interrupted\n\nA transient connection or model handoff failure interrupted Standard Mode. This is not a workflow blocker.\n\nReason: ${workflowDisplayText(reason)}\n\nRetry the request, run /standard status, or continue from the current Standard Mode state.`);
  };

  const recoverPlanTransientHandoffFailure = (ctx: ExtensionContext, kind: TransientPlanFailureKind, reason: string, options: { phase?: WorkflowPendingToolPhase; preserveRetry?: boolean; completedRepair?: boolean } = {}): void => {
    clearTransientPendingPhase(ctx, options.phase, `plan ${kind} transient handoff failure`);
    const settings = loadWorkflowSettings(ctx.cwd);
    const planText = state.approvedPlan ?? state.draftPlan;
    const currentRetry = options.preserveRetry ? Math.max(0, (state.currentValidationRetry ?? 1) - 1) : state.currentValidationRetry;
    const workflowRetry = options.preserveRetry ? Math.max(0, (state.workflowValidationRetryCount ?? 1) - 1) : state.workflowValidationRetryCount;
    const targetMode: WorkflowState["mode"] = kind === "planning"
      ? "plan_draft"
      : kind === "review" ? "reviewed"
        : kind === "execution" ? (state.reviewerReport ? "reviewed" : "plan_approved")
          : kind === "validation" ? "executed"
            : "validated";
    const repairStatus: WorkflowState["lastRepairStatus"] = options.completedRepair ? "completed" : (kind === "repair" || kind === "repair_revalidation" ? "failed" : nonRunningRepairStatus(state.lastRepairStatus));
    const validationStatus = state.validationVerdict ? planValidationStatusForVerdict(state.validationVerdict) : state.planProgress?.validationStatus ?? "unknown";
    const nextAction = kind === "repair" ? "retry /plan repair or run /plan revalidate if edits landed"
      : kind === "repair_revalidation" ? "run /plan revalidate"
        : kind === "validation" || kind === "revalidation" ? "run /plan revalidate"
          : kind === "execution" ? "run /plan continue"
            : kind === "review" ? "rerun reviewer or run /plan continue"
              : "retry planning request";
    const progress = workflowPlanProgressEnabled(settings) && planText?.trim()
      ? mergePlanProgress({ ...state, mode: targetMode, lastRepairStatus: repairStatus }, settings, {
          lifecycleStatus: kind === "planning" ? "plan_ready" : kind === "review" ? "reviewed" : "approved",
          validationStatus,
          lastValidationStatus: state.planProgress?.lastValidationStatus ?? validationStatus,
          repairStatus,
          nextAction,
        }, planText)
      : nonRunningPlanProgress(state.planProgress, repairStatus);
    const retryState = state.repairRetryState?.validation
      ? {
          ...(state.repairRetryState ?? {}),
          validation: {
            ...state.repairRetryState.validation,
            currentRetry: currentRetry ?? state.repairRetryState.validation.currentRetry,
            workflowRetryCount: workflowRetry ?? state.repairRetryState.validation.workflowRetryCount,
            status: repairStatus === "completed" ? "completed" as const : repairStatus === "failed" ? "failed" as const : state.repairRetryState.validation.status === "running" ? "failed" as const : state.repairRetryState.validation.status,
            inProgress: false,
            lastAttempt: retryableInterruptionText(reason),
            history: [...(state.repairRetryState.validation.history ?? []), { timestamp: new Date().toISOString(), retry: currentRetry ?? 0, status: repairStatus === "completed" ? "completed" as const : "failed" as const, failure: compact(reason, 800), nextAction }].slice(-20),
          },
        }
      : state.repairRetryState;
    updateState({
      mode: targetMode,
      activePlanId: kind === "planning" ? state.activePlanId ?? ensureActivePlanId(ctx) : state.activePlanId,
      draftPlan: kind === "planning" ? reason : state.draftPlan,
      lastReviewFailure: kind === "planning" ? reason : kind === "review" ? reason : state.lastReviewFailure,
      reviewerVerdict: state.reviewerVerdict,
      reviewerReport: state.reviewerReport,
      lastReviewRepairStatus: kind === "review" ? "none" : state.lastReviewRepairStatus,
      reviewRepairInProgress: kind === "review" ? false : state.reviewRepairInProgress,
      currentValidationRetry: currentRetry,
      workflowValidationRetryCount: workflowRetry,
      lastRepairStatus: repairStatus,
      lastRepairAttempt: kind === "repair" || kind === "repair_revalidation" ? retryableInterruptionText(reason) : state.lastRepairAttempt,
      repairRetryState: retryState,
      repairHistory: kind === "repair" || kind === "repair_revalidation"
        ? [...(state.repairHistory ?? []), { timestamp: new Date().toISOString(), retry: currentRetry ?? 0, status: repairStatus === "completed" ? "completed" as const : "failed" as const, repairSummary: compact(reason, 800), nextAction }].slice(-20)
        : state.repairHistory,
      planProgress: progress,
      planProgressLastToolStep: undefined,
      planProgressLastToolStatus: undefined,
      planProgressLastToolAt: undefined,
      lastPlanStopSummary: undefined,
    }, ctx);
    pi.setActiveTools(planToolsFor(settings));
    show(pi, `# Plan Workflow Interrupted\n\nA transient connection or model handoff failure interrupted Plan Mode. This is not a semantic workflow block, and no repair should remain marked as running.\n\nPhase: ${workflowDisplayText(kind)}\nReason: ${workflowDisplayText(reason)}\n\nNext: ${workflowDisplayText(nextAction)}.`);
  };

  const recoverMissionTransientHandoffFailure = (ctx: ExtensionContext, kind: TransientMissionFailureKind, reason: string, options: { phase?: WorkflowPendingToolPhase; preserveRetry?: boolean; completedRepair?: boolean } = {}): void => {
    clearTransientPendingPhase(ctx, options.phase, `mission ${kind} transient handoff failure`);
    const settings = loadWorkflowSettings(ctx.cwd);
    const mission = (state.activeMissionId ? loadMissionState(state.activeMissionId) : undefined) ?? activeMission ?? loadMissionState("latest");
    if (!mission) {
      updateState({ mode: "awaiting_mission_input", activeMissionId: undefined }, ctx);
      pi.setActiveTools(planToolsFor(settings));
      show(pi, `# Mission Workflow Interrupted\n\nA transient connection or model handoff failure interrupted Mission Mode, but no active mission state could be loaded. Run /mission status or /workflow recover.\n\nReason: ${workflowDisplayText(reason)}`);
      return;
    }
    const retry = options.preserveRetry && (kind === "repair" || kind === "final_repair") ? Math.max(0, (mission.currentValidationRetry ?? 1) - 1) : mission.currentValidationRetry;
    const missionRetry = options.preserveRetry && kind === "repair" ? Math.max(0, (mission.missionValidationRetryCount ?? 1) - 1) : mission.missionValidationRetryCount;
    const repairStatus = options.completedRepair ? "completed" as const : (kind === "repair" || kind === "final_repair" || kind === "repair_revalidation" ? "failed" as const : mission.lastRepairStatus === "running" ? "failed" as const : mission.lastRepairStatus ?? "none");
    const nextAction = kind === "repair" || kind === "final_repair" ? "Retry mission repair, or run /mission revalidate if edits landed."
      : kind === "repair_revalidation" ? "Run /mission revalidate."
        : kind === "validation" || kind === "revalidation" || kind === "final_validation" ? "Run /mission revalidate."
          : kind === "run" ? "Run /mission resume or /mission continue."
            : kind === "planning" ? "Run /mission resume or rerun /mission plan."
              : "Run /mission review, /mission approve, or /mission resume.";
    if (missionValidationHandoffRetryKind(kind) && queueMissionValidationHandoffRetry(ctx, mission, reason, reason, `mission ${kind} transient handoff failure`, kind === "final_validation")) return;
    if (kind === "run") {
      const activeIndex = mission.currentMilestoneIndex ?? 0;
      const runningMilestones = mission.milestones.map((milestone, index) => index === activeIndex ? { ...milestone, status: "active" as const } : milestone);
      const runNextAction = "Wait for mission_milestone_result from the active executor, or run /mission continue to re-arm execution if no result arrives.";
      const running = saveActiveMission({
        ...mission,
        status: "running",
        milestones: runningMilestones,
        currentValidationRetry: retry,
        missionValidationRetryCount: missionRetry,
        lastRepairStatus: repairStatus,
        lastStopReason: retryableInterruptionText(reason),
        lastBlockReason: "",
        nextAction: runNextAction,
        lastSummary: "Mission run handoff interrupted by a transient failure; execution boundary preserved for typed milestone handoff.",
      });
      checkpointMission(running, `Mission ${kind} interrupted by transient handoff failure; execution boundary preserved. ${compact(reason, 500)}`, runNextAction, running.milestones[activeIndex]?.id, { validationResult: running.lastValidationResult });
      updateState({ mode: "mission_running", activeMissionId: running.id, task: running.goal, originalTask: running.goal, approvedPlan: running.planText }, ctx);
      activeMission = running;
      armWorkflowToolsForPhase(ctx, "Execution", "recover mission run transient handoff failure");
      show(pi, `# Mission Workflow Interrupted\n\nA transient connection or model handoff failure interrupted Mission execution handoff. This is not a semantic mission block; the active milestone execution boundary was preserved so a valid mission_milestone_result can still be accepted.\n\nPhase: ${workflowDisplayText(kind)}\nReason: ${workflowDisplayText(reason)}\n\nNext: ${workflowDisplayText(runNextAction)}.`);
      return;
    }
    const paused = saveActiveMission({
      ...mission,
      status: "paused",
      currentValidationRetry: retry,
      missionValidationRetryCount: missionRetry,
      lastRepairStatus: repairStatus,
      lastRepairAttempt: kind === "repair" || kind === "final_repair" || kind === "repair_revalidation" ? retryableInterruptionText(reason) : mission.lastRepairAttempt,
      lastStopReason: retryableInterruptionText(reason),
      lastBlockReason: "",
      nextAction,
      lastSummary: `Mission ${kind} interrupted by a transient handoff failure; paused for retry.`,
      repairHistory: kind === "repair" || kind === "final_repair" || kind === "repair_revalidation"
        ? [...(mission.repairHistory ?? []), { timestamp: new Date().toISOString(), milestoneId: mission.milestones[mission.currentMilestoneIndex]?.id, retry: retry ?? 0, status: repairStatus === "completed" ? "completed" as const : "failed" as const, repairSummary: compact(reason, 800), nextAction }].slice(-20)
        : mission.repairHistory,
    });
    checkpointMission(paused, `Mission ${kind} interrupted by transient handoff failure. ${compact(reason, 500)}`, nextAction, paused.milestones[paused.currentMilestoneIndex]?.id, { validationResult: paused.lastValidationResult });
    updateState({ mode: "mission_paused", activeMissionId: paused.id }, ctx);
    pi.setActiveTools(planToolsFor(settings));
    show(pi, `# Mission Workflow Interrupted\n\nA transient connection or model handoff failure interrupted Mission Mode. This is not a semantic mission block; the mission has been paused for retry.\n\nPhase: ${workflowDisplayText(kind)}\nReason: ${workflowDisplayText(reason)}\n\nNext: ${workflowDisplayText(nextAction)}.`);
  };

  const buildQueuedFailureRecovery = (ctx: ExtensionContext, recover: (reason: string) => void): WorkflowQueuedTurnOptions => ({
    onFinalFailure: (failure) => recover(transientFailureReason(`Queued workflow turn failed (${failure.customType})`, failure.message)),
  });

  const buildQueuedPhaseRecovery = (ctx: ExtensionContext, phase: WorkflowPendingToolPhase, recover: (reason: string) => void): WorkflowQueuedTurnOptions => ({
    ...buildQueuedFailureRecovery(ctx, recover),
    initialDelayMs: 2000,
    requireIdle: true,
    isIdle: () => ctx.isIdle(),
    onBeforeSend: (customType) => armAndVerifyWorkflowToolsForPhase(ctx, phase, `queued turn before send: ${customType}`),
  });

  const planRoleForQueuedPhase = (phase: WorkflowPendingToolPhase): WorkflowRole => {
    if (phase === "Planning") return "planner";
    if (phase === "Review") return "reviewer";
    if (phase === "Validation") return "validator";
    return "executor";
  };

  const reapplyPlanRouteForQueuedPhase = async (ctx: ExtensionContext, phase: WorkflowPendingToolPhase, customType: string): Promise<void> => {
    const role = planRoleForQueuedPhase(phase);
    const route = await reapplyPlanRouteForRole(ctx, role, false, role === "validator" ? { requireEnabled: false } : {});
    if (!route) {
      const failure = planRoutingFailurePrompt(role, `queued ${phase} turn before send: ${customType}`);
      show(pi, `# Plan Routing Failed\n\n${failure}`);
      throw new WorkflowToolSurfaceAbort(failure);
    }
    armAndVerifyWorkflowToolsForPhase(ctx, phase, `queued Plan ${phase} turn before send: ${customType}`);
  };

  const buildQueuedPlanPhaseRecovery = (ctx: ExtensionContext, phase: WorkflowPendingToolPhase, recover: (reason: string) => void): WorkflowQueuedTurnOptions => ({
    ...buildQueuedFailureRecovery(ctx, recover),
    initialDelayMs: 2000,
    requireIdle: true,
    isIdle: () => ctx.isIdle(),
    onBeforeSend: (customType) => reapplyPlanRouteForQueuedPhase(ctx, phase, customType),
  });

  const buildQueuedMissionValidationRecovery = (ctx: ExtensionContext, recover: (reason: string) => void): WorkflowQueuedTurnOptions => ({
    ...buildQueuedFailureRecovery(ctx, recover),
    initialDelayMs: 2000,
    requireIdle: true,
    isIdle: () => ctx.isIdle(),
    onBeforeSend: async (customType) => {
      const route = await applyMissionModelForRole(pi, ctx, "validator", { requireEnabled: false, cwd: ctx.cwd });
      if (!route) {
        const failure = `Mission validator route could not be applied before queued validation retry: ${customType}.`;
        show(pi, `# Mission Validation Routing Failed\n\n${failure}\n\nConfigure validator routing, then run /mission revalidate.`);
        throw new Error(failure);
      }
      updateState({ modelsUsed: { ...(state.modelsUsed ?? {}), validator: modelLabel(route) } }, ctx);
      armAndVerifyWorkflowToolsForPhase(ctx, "Validation", `queued Mission Validation turn before send: ${customType}`);
    },
  });

  const buildQueuedPlanningRecovery = (ctx: ExtensionContext, recover: (reason: string) => void): WorkflowQueuedTurnOptions =>
    buildQueuedPlanPhaseRecovery(ctx, "Planning", recover);

  function planOutputShowsLateForcedPlanningWorkers(text: string): boolean {
    const planIndex = text.search(/(?:workflow_plan_result:\s*plan|PLAN_DECISION:\s*plan|Approval Gate|Status:\s*READY FOR APPROVAL|Implementation Plan)/i);
    if (planIndex < 0) return false;
    const lateWorkerIndex = text.search(/forced sub-agent policy requires[\s\S]{0,240}(?:dispatching|subagent|workers)/i);
    return lateWorkerIndex > planIndex;
  }

  function queuePlanPlanningHandoffRetry(ctx: ExtensionContext, planText: string, reason: string, source: string): boolean {
    const settings = loadWorkflowSettings(ctx.cwd);
    resetSubagentPhaseUsage("Planning");
    phasePreflightBlocks.Planning = undefined;
    armWorkflowToolsForPhase(ctx, "Planning", `plan planning handoff retry ${source}`);
    const reviewerRepair = planReviewRepairActive(state);
    const priorPlan = reviewerRepair ? state.approvedPlan : undefined;
    const feedback = reviewerRepair
      ? `Reviewer-requested Plan repair is still active.\n\nPrevious repair draft was preserved but not accepted because Planning forced-worker evidence was missing or late:\n${compact(planText, 1600)}\n\nOriginal reviewer failure:\n${state.lastReviewFailure ?? state.reviewerReport ?? "(not recorded)"}`
      : `Previous Plan draft was preserved but not accepted because Planning forced-worker evidence was missing or late:\n${compact(planText, 1600)}`;
    updateState({
      mode: "planning",
      draftPlan: planText,
      approvedPlan: reviewerRepair ? state.approvedPlan : undefined,
      lastReviewAttempt: reviewerRepair ? state.lastReviewAttempt : state.lastReviewAttempt,
      lastReviewRepairStatus: reviewerRepair ? "running" : state.lastReviewRepairStatus,
      reviewRepairInProgress: reviewerRepair ? true : state.reviewRepairInProgress,
      planProgress: workflowPlanProgressEnabled(settings)
        ? mergePlanProgress(
            { ...state, mode: reviewerRepair ? "repairing" : "planning", draftPlan: planText, approvedPlan: reviewerRepair ? state.approvedPlan : undefined },
            settings,
            { lifecycleStatus: reviewerRepair ? "repairing" : "planning", nextAction: reviewerRepair ? "planner repairing for reviewer" : "planning forced-worker retry" },
            reviewerRepair ? state.approvedPlan : undefined,
          )
        : state.planProgress,
    }, ctx);
    queueAgentTurn(
      pi,
      `CRITICAL PLAN PLANNING HANDOFF RETRY: the previous planner output was not accepted because forced Planning worker evidence was missing or arrived after the final plan handoff.\n\nYou are still the parent Plan planner. If Planning policy is forced, call Planning-phase subagents first with workflowPhase=planning, wait for their results, then call workflow_plan_result with decision=plan. Do not output a final repaired plan before the required workers complete. If workflow_plan_result is unavailable, output the parser-safe PLAN_DECISION fallback once and stop; do not call subagent as an acknowledgement after fallback.\n\nBlocker to fix:\n${reason}\n\n${planPrompt(state.task ?? state.originalTask ?? "Repair plan after reviewer feedback", priorPlan, feedback, settings, { feedbackKind: reviewerRepair ? "repair" : "revision", preflightBlock: phasePreflightBlocks.Planning })}`,
      "planning-retry-forced-subagents",
      buildQueuedPlanningRecovery(ctx, (failureReason) => recoverPlanTransientHandoffFailure(ctx, "planning", failureReason, { phase: "Planning" })),
    );
    return true;
  }

  const buildCompletedMissionSummary = (mission: MissionState, settings = loadWorkflowSettings(mission.cwd), handoff: Pick<NonNullable<WorkflowState["lastCompletedMissionSummary"]>, "executionSummary" | "validationReport" | "repairSummary"> = {}): NonNullable<WorkflowState["lastCompletedMissionSummary"]> => {
    const completed = mission.milestones.filter((milestone) => milestone.status === "completed" || milestone.status === "skipped").length;
    return {
      completedAt: mission.completedAt ?? new Date().toISOString(),
      missionId: mission.id,
      status: "completed",
      milestonesCompleted: mission.milestones.length > 0 ? mission.milestones.length : completed,
      milestonesTotal: mission.milestones.length,
      validationResult: mission.lastFinalValidationResult ?? mission.lastValidationResult ?? "PASS",
      repairRetries: mission.missionValidationRetryCount ?? mission.currentValidationRetry ?? 0,
      maxRepairRetries: maxMissionValidationRetries(mission, settings),
      repairStatus: mission.lastRepairStatus === "running" ? "completed" : (mission.lastRepairStatus ?? "none"),
      activeRuntimeMs: missionActiveRuntimeMs(mission),
      elapsedMs: missionWallClockAgeMs(mission),
      nextAction: "ready for new mission",
      ...handoff,
    };
  };

  const finalMissionHandoffReport = (mission: MissionState, summary: NonNullable<WorkflowState["lastCompletedMissionSummary"]>, settings: ReturnType<typeof loadWorkflowSettings>, cwd?: string): string => {
    const milestoneLines = mission.milestones.map((milestone, index) => {
      const checkpointCount = milestone.checkpointIds?.length ?? 0;
      return `- ${milestone.id || `M${index + 1}`}: ${milestone.title || "Untitled"} — ${milestone.status}; objective: ${compact(milestone.objective, 220) || "none recorded"}; checkpoints: ${checkpointCount}`;
    }).join("\n") || "- none recorded";
    const checkpointLines = mission.checkpoints.slice(-8).map((checkpoint) => `- ${checkpoint.id}: ${checkpoint.milestoneId ?? "mission"} — ${checkpoint.validationResult ?? checkpoint.status}; ${compact(checkpoint.summary, 220)}`).join("\n") || "- none recorded";
    const reviewHistoryLines = mission.reviewHistory?.slice(-5).map((entry) => `- ${entry.timestamp}: retry ${entry.retry}, ${entry.status}; ${compact(entry.reviewFailure ?? entry.repairSummary ?? entry.nextAction, 220)}`).join("\n") || "- none recorded";
    const repairHistoryLines = mission.repairHistory?.slice(-5).map((entry) => `- ${entry.timestamp}: ${entry.milestoneId ?? "mission"}, retry ${entry.retry}, ${entry.status}; ${compact(entry.validationFailure ?? entry.repairSummary ?? entry.nextAction, 220)}`).join("\n") || "- none recorded";
    const validationMode = settings.missions.requireValidationPerMilestone === false ? "per-milestone validation skipped" : "per-milestone validation required";
    const finalValidationMode = settings.missions.finalValidationEnabled === true ? `final validation ${mission.lastFinalValidationResult ?? "enabled"}` : "final validation disabled";
    return professionalFinalSummaryMarkdown(`## Final Mission Conclusion
- Mission ID: ${mission.id}
- Final status: ${mission.status}
- Goal: ${compact(mission.goal, 500)}
- Milestones completed: ${summary.milestonesCompleted}/${summary.milestonesTotal}
- Mission plan review: ${mission.reviewerVerdict ?? "not run"}
- Review repairs/retries: ${mission.missionReviewRetryCount ?? 0}/${maxMissionReviewRetries(mission, settings)}; status: ${mission.lastReviewRepairStatus ?? "none"}
- Validation mode: ${validationMode}; ${finalValidationMode}
- Last validation result: ${summary.validationResult}
- Validation repairs/retries: ${summary.repairRetries}/${summary.maxRepairRetries}; status: ${summary.repairStatus}
- Runtime: ${formatDurationMs(summary.activeRuntimeMs)} active / ${formatDurationMs(summary.elapsedMs)} elapsed
- Final conclusion: Mission completed its recorded milestone workflow and is ready for a new mission unless the caveats below require manual follow-up.
- Next: ${summary.nextAction}

${renderHandoffProjectContext(cwd)}

### Milestone Outcomes
${milestoneLines}

### Mission Review Summary
Reviewer verdict: ${mission.reviewerVerdict ?? "not run"}
Latest reviewer report:
${reportExcerpt(mission.reviewerReport, 1600)}

Review History
${reviewHistoryLines}

### Validation And Checkpoint History
${checkpointLines}

### Execution Summary
${reportExcerpt(summary.executionSummary, 2200)}

### Repair Summary
${reportExcerpt(summary.repairSummary, 1600)}

Repair History
${repairHistoryLines}

### Validation Report
${reportExcerpt(summary.validationReport, 2400)}

### Mission Status
${renderMissionProgress(mission, settings)}

### Exact Resume Instructions
- Re-check current mission/workflow state with: /mission status or /workflow status.
- Review mission checkpoints with: /mission checkpoints.
- Before continuing implementation, verify the target repo branch/status and re-read detected project instructions.`);
  };

  const completeMissionToAwaitingInput = (ctx: ExtensionContext, mission: MissionState, validationText: string | undefined, verdict: string | undefined, settings = loadWorkflowSettings(ctx.cwd)) => {
    const repairSummary = mission.lastRepairAttempt ?? mission.repairHistory?.filter((entry) => entry.status === "completed").slice(-1)[0]?.repairSummary;
    const baseSummary = buildCompletedMissionSummary(mission, settings, {
      executionSummary: reportExcerpt(state.executionSummary, 2400),
      validationReport: reportExcerpt(validationText, 2600),
      repairSummary: reportExcerpt(repairSummary, 1800),
    });
    const summary = { ...baseSummary, finalReport: finalMissionHandoffReport(mission, baseSummary, settings, ctx.cwd) };
    pi.setActiveTools(planToolsFor(settings));
    updateState({
      mode: "awaiting_mission_input",
      activeMissionId: mission.id,
      task: undefined,
      originalTask: undefined,
      draftPlan: undefined,
      approvedPlan: undefined,
      executionSummary: undefined,
      validationReport: validationText,
      validationVerdict: verdict === "PASS" || verdict === "PARTIAL PASS" || verdict === "FAIL" || verdict === "UNKNOWN" ? verdict : undefined,
      reviewerReport: undefined,
      reviewerVerdict: undefined,
      modelsUsed: undefined,
      lastCompletedMissionSummary: summary,
      lastMissionStopSummary: { stoppedAt: summary.completedAt, kind: "mission", status: "completed", title: "Mission completed", summary: summary.finalReport ?? finalMissionHandoffReport(mission, baseSummary, settings, ctx.cwd) },
      planProgress: undefined,
    }, ctx);
    queueNativeFinalSummary(pi, nativeMissionFinalDeliverableSummary(summary), "workflow-mission-final-summary");
    return summary;
  };

  const checkpointMission = (mission: MissionState, summary: string, nextAction: string, milestoneId?: string, details: { filesChanged?: string[]; validationResult?: string; errors?: string[] } = {}): MissionState => {
    const withNextAction = touchMissionHeartbeat({ ...mission, nextAction }, true);
    activeMission = addMissionCheckpoint(withNextAction, summary, nextAction, milestoneId, details);
    state = persistWorkflowState({ ...state, activeMissionId: activeMission.id });
    return activeMission;
  };

  function missionResumePriority(status: MissionState["status"]): number {
    if (status === "running") return 0;
    if (status === "paused") return 1;
    if (status === "approved") return 2;
    if (status === "blocked" || status === "failed") return 3;
    if (status === "validating" || status === "revalidating") return 4;
    if (status === "repairing") return 5;
    if (status === "checkpointing") return 6;
    if (status === "stopped") return 7;
    return 9;
  }

  function missionIsResumeCandidate(mission?: MissionState): mission is MissionState {
    if (!mission) return false;
    if (missionResumePriority(mission.status) >= 9) return false;
    // Blocked/failed missions may have 0 milestones (interrupted planning); they are resumable via planning.
    if (mission.milestones.length === 0 && mission.status !== "blocked" && mission.status !== "failed") return false;
    return true;
  }

  function missionMatchesCurrentProject(ctx: ExtensionContext, mission?: MissionState): boolean {
    return Boolean(mission?.cwd && mission.cwd === ctx.cwd);
  }

  function sortMissionResumeCandidates(a: MissionState, b: MissionState): number {
    return missionResumePriority(a.status) - missionResumePriority(b.status) || b.updatedAt.localeCompare(a.updatedAt);
  }

  function resolveActiveMissionForResume(ctx: ExtensionContext): { mission?: MissionState; candidates: MissionState[]; reason?: string; fallbackProject?: boolean } {
    const byState = state.activeMissionId ? loadMissionState(state.activeMissionId) : undefined;
    const loadedActive = activeMission && (!state.activeMissionId || activeMission.id === state.activeMissionId) ? activeMission : undefined;
    const latest = loadMissionState();
    const all = listMissionStates();
    const ordered: MissionState[] = [];
    const add = (mission?: MissionState) => {
      if (mission && !ordered.some((m) => m.id === mission.id)) ordered.push(mission);
    };

    if (byState) {
      add(byState);
      [loadedActive, latest, ...all]
        .filter((mission): mission is MissionState => missionIsResumeCandidate(mission) && mission.id !== byState.id)
        .sort((a, b) => Number(missionMatchesCurrentProject(ctx, b)) - Number(missionMatchesCurrentProject(ctx, a)) || sortMissionResumeCandidates(a, b))
        .forEach(add);
      const inactiveReason = missionIsResumeCandidate(byState) ? undefined : `Current mission is ${(byState as MissionState).status}.`;
      return { mission: byState, candidates: ordered, reason: inactiveReason };
    }

    const currentProject = [loadedActive, latest, ...all]
      .filter((mission): mission is MissionState => missionIsResumeCandidate(mission) && missionMatchesCurrentProject(ctx, mission))
      .sort(sortMissionResumeCandidates);
    const otherProject = [loadedActive, latest, ...all]
      .filter((mission): mission is MissionState => missionIsResumeCandidate(mission) && !missionMatchesCurrentProject(ctx, mission))
      .sort(sortMissionResumeCandidates);

    currentProject.forEach(add);
    otherProject.forEach(add);

    if (currentProject.length > 0) return { mission: currentProject[0], candidates: ordered };
    if (otherProject.length > 0) return { mission: otherProject[0], candidates: ordered, fallbackProject: true, reason: `No resumable mission found for current project ${basename(ctx.cwd)}; showing saved missions from other projects.` };

    add(loadedActive);
    add(latest);
    if (ordered.length > 0) return { mission: ordered[0], candidates: ordered, reason: `No resumable mission found; selected mission is ${ordered[0].status}.` };
    return { candidates: [], reason: "No mission found. Start one with /mission start <goal>." };
  }

  function missionResumeChoiceLabel(mission: MissionState): string {
    const total = mission.milestones.length;
    const done = mission.milestones.filter((m) => m.status === "completed" || m.status === "skipped").length;
    const percent = total ? Math.round((done / total) * 100) : 0;
    const milestone = total ? `M${Math.min(mission.currentMilestoneIndex + 1, total)}/${total}` : "M0/0";
    return `${mission.id} | ${mission.projectLabel ?? mission.cwd ?? "unknown project"} | ${mission.status} | ${milestone} | ${percent}% | ${compact(mission.goal, 80).replace(/\n/g, " ")}`;
  }

  async function chooseMissionFromHistory(ctx: ExtensionContext, missions: MissionState[], title = "Choose a mission"): Promise<MissionState | undefined> {
    if (missions.length === 0) return undefined;
    if (missions.length === 1 || !ctx.hasUI) return missions[0];
    const choices = missions.map(missionResumeChoiceLabel);
    show(pi, `# Mission Resume\n\nChoose a mission.\n\n${choices.map((choice, i) => `${i + 1}. ${choice}`).join("\n")}`);
    const choice = await withWorkflowCommandLock(ctx, "mission", "history-select", () => ctx.ui.select(title, [...choices, "Cancel"]));
    if (!choice || choice === "Cancel") return undefined;
    const id = choice.split(" | ")[0];
    return missions.find((mission) => mission.id === id);
  }

  async function chooseResumeMission(ctx: ExtensionContext, resolved: { mission?: MissionState; candidates: MissionState[]; reason?: string; fallbackProject?: boolean }, action: "resume" | "continue" | "next" | "retry" | "repair" | "revalidate" = "resume"): Promise<MissionState | undefined> {
    const currentProjectRequired = action === "retry" || action === "repair" || action === "revalidate";
    const candidates = currentProjectRequired ? resolved.candidates.filter((mission) => missionMatchesCurrentProject(ctx, mission)) : resolved.candidates;
    const selected = currentProjectRequired && resolved.mission && !missionMatchesCurrentProject(ctx, resolved.mission) ? candidates[0] : resolved.mission;
    if (currentProjectRequired && candidates.length === 0) {
      show(pi, `# Mission ${action[0].toUpperCase()}${action.slice(1)} Refused\n\nNo current-project mission is available for ${action}. Other-project mission history is only available through explicit resume/history selection.`);
      return undefined;
    }
    if (resolved.fallbackProject && !ctx.hasUI) return undefined;
    if (!resolved.fallbackProject && (candidates.length <= 1 || !ctx.hasUI)) return selected ?? candidates[0];
    const title = action === "resume" ? "Mission Resume" : `Mission ${action[0].toUpperCase()}${action.slice(1)}`;
    const verb = action === "resume" ? "use" : action;
    const choices = candidates.map(missionResumeChoiceLabel);
    const intro = currentProjectRequired
      ? `Choose the current-project mission to ${action}. Other-project mission history is hidden for repair/revalidate safety.`
      : resolved.fallbackProject
      ? (resolved.reason ?? "Only saved missions from other projects were found. Choose explicitly before continuing.")
      : action === "resume"
      ? "Choose which mission to use."
      : `I found more than one mission that can ${action}. Choose which one to use.`;
    show(pi, `# ${title}\n\n${intro}\n\n${choices.map((choice, i) => `${i + 1}. ${choice}`).join("\n")}`);
    const choice = await withWorkflowCommandLock(ctx, "mission", action, () => ctx.ui.select(`Choose a mission to ${verb}:`, [...choices, "Cancel"]));
    if (!choice || choice === "Cancel") return undefined;
    const id = choice.split(" | ")[0];
    return candidates.find((m) => m.id === id) ?? selected;
  }

  function prepareMissionRetry(mission: MissionState): MissionState {
    const index = mission.currentMilestoneIndex;
    const milestones = mission.milestones.map((m, i) => i === index && (m.status === "failed" || m.status === "active") ? { ...m, status: "pending" as const } : m);
    return saveActiveMission({ ...mission, status: "approved", milestones, lastBlockReason: "", lastStopReason: "", nextAction: "Retry current milestone through /mission continue.", lastSummary: "Mission retry prepared by /mission resume." });
  }

  function missionWorkflowModeForStatus(status: MissionState["status"]): WorkflowState["mode"] {
    const map: Record<MissionState["status"], WorkflowState["mode"]> = {
      draft: "mission_draft",
      planning: "mission_planning",
      awaiting_clarification: "mission_awaiting_clarification",
      planned: "mission_plan_ready",
      approved: "mission_approved",
      running: "mission_running",
      paused: "mission_paused",
      checkpointing: "mission_checkpointing",
      validating: "mission_validating",
      repairing: "mission_repairing",
      revalidating: "mission_revalidating",
      completed: "mission_completed",
      failed: "mission_failed",
      blocked: "mission_blocked",
      stopped: "mission_stopped",
    };
    return map[status];
  }

  function missionActiveGateMode(mission: MissionState): WorkflowState["mode"] | undefined {
    if (mission.status === "validating") return mission.currentStep === "final validator" ? "mission_final_validating" : "mission_validating";
    if (mission.status === "revalidating") return mission.lastFinalValidationFailure ? "mission_final_validating" : "mission_revalidating";
    if (mission.status === "repairing") return "mission_repairing";
    return undefined;
  }

  async function missionActiveGatePrompt(ctx: ExtensionContext, mission: MissionState, mode: WorkflowState["mode"], systemPrompt: string): Promise<{ systemPrompt: string } | undefined> {
    const settings = loadWorkflowSettings(ctx.cwd);
    if (mode === "mission_validating" || mode === "mission_revalidating") {
      const route = await applyMissionModelForRole(pi, ctx, "validator", { requireEnabled: false, cwd: ctx.cwd });
      if (!route) return { systemPrompt: `${systemPrompt}\n\nPI WORKFLOW MISSION VALIDATION BLOCKED: validator model is disabled, unavailable, or not configured. Do not execute Mission work. Report that Mission validation must be re-entered after validator routing is fixed.` };
      pi.setActiveTools(validationToolsFor(settings));
      updateState({ mode, activeMissionId: mission.id, ...(!state.validationRunId || state.validationMissionId !== mission.id || state.validationScope !== "mission" ? missionValidationContextPatch(ctx, mission) : {}), modelsUsed: { ...(state.modelsUsed ?? {}), validator: modelLabel(route) } }, ctx);
      const surfaceBlock = verifyWorkflowToolSurface(ctx, "Validation", "mission active validation gate", mode);
      if (surfaceBlock) return { systemPrompt: `${systemPrompt}\n\nPI WORKFLOW MISSION VALIDATION BLOCKED: ${surfaceBlock}\n\nDo not validate the mission. Run /mission revalidate after the tool surface is repaired.` };
      return { systemPrompt: `${systemPrompt}\n\n${missionValidationPrompt(mission, settings, missionExecutionSummaryForValidation(mission), phasePreflightBlocks.Validation, state)}` };
    }
    if (mode === "mission_final_validating") {
      const route = await applyMissionModelForRole(pi, ctx, "validator", { requireEnabled: false, cwd: ctx.cwd });
      if (!route) return { systemPrompt: `${systemPrompt}\n\nPI WORKFLOW MISSION FINAL VALIDATION BLOCKED: validator model is disabled, unavailable, or not configured. Do not execute Mission work. Report that final validation must be re-entered after validator routing is fixed.` };
      pi.setActiveTools(validationToolsFor(settings));
      updateState({ mode, activeMissionId: mission.id, ...(!state.validationRunId || state.validationMissionId !== mission.id || state.validationScope !== "mission_final" ? missionValidationContextPatch(ctx, mission, true) : {}), modelsUsed: { ...(state.modelsUsed ?? {}), validator: modelLabel(route) } }, ctx);
      const surfaceBlock = verifyWorkflowToolSurface(ctx, "Validation", "mission active final validation gate", mode);
      if (surfaceBlock) return { systemPrompt: `${systemPrompt}\n\nPI WORKFLOW MISSION FINAL VALIDATION BLOCKED: ${surfaceBlock}\n\nDo not validate the mission. Run /mission revalidate after the tool surface is repaired.` };
      return { systemPrompt: `${systemPrompt}\n\n${missionFinalValidationPrompt(mission, settings, state.executionSummary, phasePreflightBlocks.Validation, state)}` };
    }
    if (mode === "mission_repairing") {
      const route = await applyMissionModelForRole(pi, ctx, "executor", { cwd: ctx.cwd });
      if (!route) return { systemPrompt: `${systemPrompt}\n\nPI WORKFLOW MISSION REPAIR BLOCKED: executor model is disabled, unavailable, or not configured. Do not validate or continue Mission execution. Report that Mission repair must be re-entered after executor routing is fixed.` };
      pi.setActiveTools(missionRepairToolsFor(settings));
      updateState({ mode, activeMissionId: mission.id, modelsUsed: { ...(state.modelsUsed ?? {}), executor: modelLabel(route) } }, ctx);
      const surfaceBlock = verifyWorkflowToolSurface(ctx, "Repair", "mission active repair gate", mode);
      if (surfaceBlock) return { systemPrompt: `${systemPrompt}\n\nPI WORKFLOW MISSION REPAIR BLOCKED: ${surfaceBlock}\n\nDo not repair the mission. Run /mission repair or /mission resume after the tool surface is repaired.` };
      return { systemPrompt: `${systemPrompt}\n\n${missionRepairPrompt(mission, settings, phasePreflightBlocks.Repair)}` };
    }
    return undefined;
  }

  function missionMilestoneAdvanceDecision(mission: MissionState, settings: ReturnType<typeof loadWorkflowSettings>, done: boolean, nextMilestoneId: string | undefined): {
    shouldPause: boolean;
    fullAutoBlocked: boolean;
    nextStatus: MissionState["status"];
    nextMode: WorkflowState["mode"];
    stopReason: string;
    blockReason: string;
    nextAction: string;
    shouldAutoRunNext: boolean;
  } {
    const shouldPause = mission.autonomy === "manual" || mission.pauseBetweenMilestones === true || mission.continueAcrossMilestones === false;
    const fullAutoBlocked = mission.autonomy === "full_auto" && !missionAllowsFullAuto(mission, settings);
    const nextStatus = done ? "completed" : fullAutoBlocked ? "blocked" : shouldPause ? "paused" : "approved";
    const nextMode = done ? "awaiting_mission_input" : fullAutoBlocked ? "mission_blocked" : shouldPause ? "mission_paused" : "mission_approved";
    const stopReason = done ? "" : shouldPause ? (mission.autonomy === "manual" ? "Mission paused because manual mode pauses after each milestone." : "Mission paused because pauseBetweenMilestones=true or continueAcrossMilestones=false.") : "";
    const blockReason = fullAutoBlocked ? "Cannot continue: full auto requested but allowFullAuto=false." : "";
    const nextAction = done ? "Mission completed all milestones." : blockReason || (shouldPause ? "Run /mission continue, /mission next, or /mission resume when ready." : `Mission continuing automatically to milestone ${nextMilestoneId ?? "next"}.`);
    return { shouldPause, fullAutoBlocked, nextStatus, nextMode, stopReason, blockReason, nextAction, shouldAutoRunNext: !done && !shouldPause && !fullAutoBlocked };
  }

  const missionValidationProseBoolean = (text: string, label: string): boolean | undefined => {
    const match = text.match(new RegExp(`${label}\\s*:?\\s*(yes|no|true|false)`, "i"));
    if (!match) return undefined;
    return /^(yes|true)$/i.test(match[1] ?? "");
  };

  const parseMissionValidationPassFallback = (text: string, final = false): { report: string; verdict: "PASS"; concreteRepairableIssue?: boolean; evidenceGap?: boolean; manualVerificationRequired?: boolean } | undefined => {
    const report = text.trim();
    if (!report) return undefined;
    const missionValidationShape = final
      ? /(?:Final Mission Validation Report|Mission.*final.*validation|Final Status[\s\S]{0,300}mission)/i
      : /(?:Mission Milestone Revalidation Summary|Mission Milestone Validation Summary|#\s*Validation Report|Mission.*(?:validation|revalidation))/i;
    if (!missionValidationShape.test(report)) return undefined;
    const verdict = normalizeValidationVerdict(extractVerdict(report), report);
    if (verdict !== "PASS") return undefined;
    return {
      report,
      verdict,
      concreteRepairableIssue: missionValidationProseBoolean(report, "Concrete Repairable Issue"),
      evidenceGap: missionValidationProseBoolean(report, "Evidence Gap"),
      manualVerificationRequired: missionValidationProseBoolean(report, "Manual Verification Required"),
    };
  };

  async function completeMissionValidationPassFromProse(ctx: ExtensionContext, mission: MissionState, text: string, final = false): Promise<boolean> {
    const parsed = parseMissionValidationPassFallback(text, final);
    if (!parsed) return false;
    if (validationTextLooksWrongMissionContext(ctx, mission, parsed.report)) return false;
    const settings = loadWorkflowSettings(ctx.cwd);
    const missionWithBooleans = { ...mission, concreteRepairableIssue: parsed.concreteRepairableIssue, manualVerificationRequired: parsed.manualVerificationRequired, evidenceGap: parsed.evidenceGap };
    if (final) {
      const completed = saveActiveMission({ ...missionWithBooleans, status: "completed", completedAt: new Date().toISOString(), lastFinalValidationResult: parsed.verdict, lastFinalValidationFailure: "", lastValidationResult: parsed.verdict, lastValidationFailure: "", lastBlockReason: "", lastStopReason: "", nextAction: "Mission completed all milestones and final comprehensive validation.", lastSummary: "Final comprehensive mission validation PASS recovered from visible validation summary." });
      checkpointMission(completed, `Final mission validation ${parsed.verdict} recovered from visible validation summary. ${compact(parsed.report, 500)}`, "Mission completed after final comprehensive validation.", undefined, { validationResult: parsed.verdict });
      completeMissionToAwaitingInput(ctx, completed, parsed.report, parsed.verdict, settings);
      recordWorkflowInternalEvent(ctx, "Mission final validation PASS recovered from visible validation summary without typed handoff.");
      return true;
    }
    const index = mission.currentMilestoneIndex;
    const milestone = mission.milestones[index];
    const milestones = mission.milestones.map((m, i) => i === index ? { ...m, status: "completed" as const } : m);
    const nextIndex = Math.min(index + 1, Math.max(0, milestones.length - 1));
    const done = index >= milestones.length - 1;
    if (done && settings.missions.finalValidationEnabled === true) {
      const finalMission = saveActiveMission({ ...missionWithBooleans, status: "validating", milestones, currentMilestoneIndex: index, currentValidationRetry: 0, lastValidationResult: parsed.verdict, lastValidationFailure: "", lastBlockReason: "", lastStopReason: "", lastRepairStatus: mission.lastRepairStatus === "running" || mission.lastRepairStatus === "completed" ? "completed" : (mission.lastRepairStatus ?? "none"), nextAction: "Run final comprehensive mission validation.", lastSummary: `Milestone ${milestone?.id ?? "current"} PASS recovered from visible validation summary; final comprehensive validation queued.` });
      checkpointMission(finalMission, `Milestone ${milestone?.id ?? "current"} validation ${parsed.verdict} recovered from visible validation summary; final mission validation queued. ${compact(parsed.report, 500)}`, "Run final comprehensive validation for the whole mission.", milestone?.id, { validationResult: parsed.verdict });
      updateState({ mode: "mission_final_validating", activeMissionId: finalMission.id, validationReport: parsed.report, validationVerdict: parsed.verdict, concreteRepairableIssue: parsed.concreteRepairableIssue, evidenceGap: parsed.evidenceGap, manualVerificationRequired: parsed.manualVerificationRequired, lastWorkflowHandoff: undefined }, ctx);
      await beginMissionFinalValidation(ctx, activeMission ?? finalMission, true);
      return true;
    }
    const advance = missionMilestoneAdvanceDecision(missionWithBooleans, settings, done, milestones[nextIndex]?.id);
    const nextMission = saveActiveMission({ ...missionWithBooleans, status: advance.nextStatus, milestones, currentMilestoneIndex: nextIndex, currentValidationRetry: 0, lastValidationResult: parsed.verdict, lastValidationFailure: "", lastBlockReason: advance.blockReason, lastStopReason: advance.stopReason, lastRepairStatus: mission.lastRepairStatus === "running" || mission.lastRepairStatus === "completed" ? "completed" : (mission.lastRepairStatus ?? "none"), nextAction: advance.nextAction, lastSummary: `Milestone ${milestone?.id ?? "current"} PASS recovered from visible validation summary.` });
    checkpointMission(nextMission, `Milestone ${milestone?.id ?? "current"} validation ${parsed.verdict} recovered from visible validation summary. ${compact(parsed.report, 500)}`, advance.nextAction, milestone?.id, { validationResult: parsed.verdict });
    if (done) {
      completeMissionToAwaitingInput(ctx, nextMission, parsed.report, parsed.verdict, settings);
    } else {
      updateState({ mode: advance.nextMode, activeMissionId: nextMission.id, validationReport: parsed.report, validationVerdict: parsed.verdict, concreteRepairableIssue: parsed.concreteRepairableIssue, evidenceGap: parsed.evidenceGap, manualVerificationRequired: parsed.manualVerificationRequired, lastWorkflowHandoff: undefined }, ctx);
    }
    recordWorkflowInternalEvent(ctx, "Mission validation PASS recovered from visible validation summary without typed handoff.");
    if (advance.shouldAutoRunNext) await beginMissionRun(ctx, activeMission ?? nextMission, "continue", true);
    return true;
  }

  function missionValidationHandoffRetryKind(kind: TransientMissionFailureKind): boolean {
    return kind === "validation" || kind === "revalidation" || kind === "final_validation";
  }

  function maxMissionValidationHandoffRetries(settings: ReturnType<typeof loadWorkflowSettings>): number {
    const workflowSettings = settings.workflow as typeof settings.workflow & { maxValidationHandoffRetries?: number };
    return Math.max(1, Math.min(2, state.maxValidationHandoffRetries ?? workflowSettings.maxValidationHandoffRetries ?? 1));
  }

  function queueMissionValidationHandoffRetry(ctx: ExtensionContext, mission: MissionState, report: string, reason: string, source: string, final = false): boolean {
    const settings = loadWorkflowSettings(ctx.cwd);
    const maxRetries = maxMissionValidationHandoffRetries(settings);
    const currentRetry = Math.max(0, state.currentValidationHandoffRetry ?? 0);
    if (currentRetry >= maxRetries) return false;
    const nextRetry = currentRetry + 1;
    const finalValidation = final || state.mode === "mission_final_validating";
    const revalidate = !finalValidation && state.mode === "mission_revalidating";
    const retryReason = `Mission Validation handoff incomplete: ${reason}`;
    const retryMode = finalValidation ? "mission_final_validating" as const : revalidate ? "mission_revalidating" as const : "mission_validating" as const;
    const retryStatus = revalidate ? "revalidating" as const : "validating" as const;
    const retryMission = saveActiveMission({
      ...mission,
      status: retryStatus,
      currentStep: finalValidation ? "final validator" : "validator",
      lastStopReason: "",
      lastBlockReason: "",
      nextAction: finalValidation ? "Retry final Mission validation handoff." : revalidate ? "Retry Mission revalidation handoff." : "Retry Mission validation handoff.",
      lastSummary: `Mission validator is retrying the validation handoff ${nextRetry}/${maxRetries}.`,
    });
    clearPendingWorkflowToolPhase(ctx, "Validation", "mission validation handoff retry");
    clearTypedHandoff(ctx, "Mission validation handoff retry");
    resetSubagentPhaseUsage("Validation");
    phasePreflightBlocks.Validation = undefined;
    activeMission = retryMission;
    updateState({
      mode: retryMode,
      activeMissionId: retryMission.id,
      validationReport: report,
      validationVerdict: "UNKNOWN",
      currentValidationHandoffRetry: nextRetry,
      maxValidationHandoffRetries: maxRetries,
      lastValidationHandoffFailure: retryReason,
      lastValidationFailure: retryReason,
    }, ctx);
    const prompt = finalValidation
      ? missionFinalValidationPrompt(retryMission, settings, state.executionSummary, phasePreflightBlocks.Validation, state)
      : missionValidationPrompt(retryMission, settings, missionExecutionSummaryForValidation(retryMission), phasePreflightBlocks.Validation, state);
    queueAgentTurn(
      pi,
      `CRITICAL MISSION VALIDATION HANDOFF RETRY ${nextRetry}/${maxRetries}: the previous Mission Validation turn was not accepted because the structured workflow_validation_result handoff was incomplete or the validator turn was interrupted.\n\nYou are still the parent Mission Validator. Do not repair, do not execute, and do not advance the Mission directly. If Validation policy is forced, call Validation-phase sub-agents first with workflowPhase=validation, wait for their results, then call workflow_validation_result with scope=mission and verdict PASS, PARTIAL PASS, FAIL, or UNKNOWN.\n\nBlocker to fix:\n${reason}\n\nPrevious validator report or interruption reason:\n${compact(report, 1600)}\n\n${prompt}`,
      finalValidation ? "mission-final-validation-retry-handoff" : revalidate ? "mission-revalidation-retry-handoff" : "mission-validation-retry-handoff",
      buildQueuedMissionValidationRecovery(ctx, (failureReason) => recoverMissionTransientHandoffFailure(ctx, finalValidation ? "final_validation" : revalidate ? "revalidation" : "validation", failureReason, { phase: "Validation" })),
    );
    return true;
  }

  function blockMissionMissingValidationHandoff(ctx: ExtensionContext, mission: MissionState, text: string, final = false): void {
    const milestone = mission.milestones[mission.currentMilestoneIndex];
    const reason = final
      ? "Mission final validation did not submit workflow_validation_result; final validation prose was preserved but cannot advance or complete the Mission."
      : "Mission validation did not submit workflow_validation_result; validation prose was preserved but cannot advance the Mission.";
    if (queueMissionValidationHandoffRetry(ctx, mission, text, reason, "missing typed Mission validation handoff", final)) return;
    const paused = saveActiveMission({
      ...mission,
      status: "paused",
      lastStopReason: reason,
      nextAction: final ? "Run /mission revalidate after fixing validator typed handoff." : `Run /mission revalidate after fixing validator typed handoff for ${milestone?.id ?? "current milestone"}.`,
      lastSummary: reason,
    });
    checkpointMission(paused, `${reason} ${compact(text, 500)}`, paused.nextAction ?? "Re-enter Mission validation.", milestone?.id, { validationResult: "UNKNOWN" });
    updateState({ mode: "mission_paused", activeMissionId: paused.id, validationReport: text, validationVerdict: "UNKNOWN", lastWorkflowHandoff: undefined }, ctx);
    queueMissionTerminalSummary(ctx, paused, "blocked", final ? "Mission final validation handoff missing" : "Mission validation handoff missing", { validationText: text, verdict: "UNKNOWN", reason });
  }

  async function resumeMissionThroughCurrentGate(ctx: ExtensionContext, mission: MissionState, settings: ReturnType<typeof loadWorkflowSettings>): Promise<void> {
    if (mission.status === "blocked" && mission.milestones.length === 0) {
      await beginMissionPlanning(ctx, mission, { forceReason: "Mission planning resumed from blocked Mission Resume." });
      return;
    }
    if (mission.status === "draft" && mission.milestones.length === 0) {
      await beginMissionPlanning(ctx, mission, { forceReason: "Mission planning resumed from draft Mission Resume." });
      return;
    }
    if (mission.status === "draft") {
      await showMissionPlanMenu(ctx, mission);
      return;
    }
    if (mission.status === "planned") {
      await showMissionPlanMenu(ctx, mission);
      return;
    }
    if (mission.status === "awaiting_clarification") {
      await beginMissionPlanning(ctx, mission, { forceReason: "Mission clarification resumed." });
      return;
    }
    if (mission.status === "blocked" || mission.status === "failed") {
      const retryMission = prepareMissionRetry(mission);
      const checkpointed = checkpointMission(retryMission, "Mission resume requested from resume menu.", "Resume current mission milestone in Mission Mode.");
      await beginMissionRun(ctx, checkpointed, "resume");
      return;
    }
    if (mission.status === "paused" || mission.status === "stopped") {
      if (missionRepairCompletedPendingRevalidation(mission)) {
        const revalidating = saveActiveMission({ ...mission, status: "revalidating", lastRepairStatus: mission.lastRepairStatus === "blocked" ? "completed" : (mission.lastRepairStatus ?? "completed"), lastStopReason: "", nextAction: `Revalidate ${mission.milestones[mission.currentMilestoneIndex]?.id ?? "current milestone"} after completed repair.`, lastSummary: "Mission resumed to revalidation after completed repair." });
        checkpointMission(revalidating, "Mission resume detected completed repair pending revalidation.", "Resume current mission revalidation gate.", mission.milestones[mission.currentMilestoneIndex]?.id, { validationResult: revalidating.lastValidationResult });
        await beginMissionValidation(ctx, true, true);
        return;
      }
      const approved = saveActiveMission({ ...mission, status: "approved", lastStopReason: "", nextAction: "Run /mission continue to proceed.", lastSummary: "Mission resumed by user." });
      const checkpointed = checkpointMission(approved, "Mission resume requested from resume menu.", "Resume current mission milestone in Mission Mode.");
      await beginMissionRun(ctx, checkpointed, "resume");
      return;
    }
    if (mission.status === "approved") {
      const checkpointed = checkpointMission(mission, "Mission resume requested from resume menu.", "Resume current mission milestone in Mission Mode.");
      await beginMissionRun(ctx, checkpointed, "resume");
      return;
    }
    if (mission.status === "validating") {
      checkpointMission(mission, "Mission validation resume requested from resume menu.", "Resume current mission validation gate.", mission.milestones[mission.currentMilestoneIndex]?.id, { validationResult: mission.lastValidationResult });
      await beginMissionValidation(ctx, true, false);
      return;
    }
    if (mission.status === "revalidating") {
      checkpointMission(mission, "Mission revalidation resume requested from resume menu.", "Resume current mission revalidation gate.", mission.milestones[mission.currentMilestoneIndex]?.id, { validationResult: mission.lastValidationResult });
      await beginMissionValidation(ctx, true, true);
      return;
    }
    if (mission.status === "repairing") {
      const repairCompleted = missionRepairCompletedPendingRevalidation(mission);
      if (repairCompleted) {
        await beginMissionValidation(ctx, true, true);
        return;
      }
      const interrupted = missionRepairGateInterrupted(mission, settings);
      const stale = interrupted || missionIsStale(mission, settings);
      const guidance = interrupted
        ? "This repair appears interrupted. Use Repair / Retry Mission or /mission repair to explicitly start a manual repair retry; prior retry counters and repair history will remain visible."
        : stale
          ? "This repair appears stale. Use /mission revalidate if the repair actually completed, or /mission repair to explicitly start a manual repair retry."
          : "Mission repair is already marked active. Wait for the repair result, or use /mission status to inspect the gate.";
      return show(pi, `# Mission Repair ${stale ? "Stale" : "Active"}\n\n${guidance}\n\n${renderMissionStatus(mission)}`);
    }
    if (mission.status === "running" || mission.status === "checkpointing") {
      const checkpointed = checkpointMission(mission, "Mission resume re-triggering execution from active state.", "Execute current mission milestone, then run mission validation.");
      await beginMissionRun(ctx, checkpointed, "resume");
      return;
    }
    return show(pi, `# Mission Resume\n\nNo safe automatic resume route exists for mission status: ${mission.status}.\n\n${renderMissionStatus(mission)}`);
  }

  async function handleMissionResume(ctx: ExtensionContext) {
    const resolved = resolveActiveMissionForResume(ctx);
    let selected = resolved.mission;
    const allMissions = listMissionStates().sort((a, b) => Number(missionMatchesCurrentProject(ctx, b)) - Number(missionMatchesCurrentProject(ctx, a)) || b.updatedAt.localeCompare(a.updatedAt));
    if (!selected && allMissions.length > 0) selected = allMissions[0];
    if (!selected) return show(pi, `# Mission Resume

${resolved.reason ?? "No mission found. Use /mission list to see saved missions."}`);
    const settings = loadWorkflowSettings(ctx.cwd);

    const activateSelectedMission = (mission: MissionState): MissionState => {
      const next = saveActiveMission(mission, true);
      updateState({ mode: missionWorkflowModeForStatus(next.status), activeMissionId: next.id, task: next.goal, originalTask: next.goal, approvedPlan: next.milestones.length ? missionRunPlan(next) : undefined, draftPlan: undefined, executionSummary: undefined, validationReport: undefined, validationVerdict: undefined, reviewerReport: undefined, lastWorkflowHandoff: undefined, reviewHandoffSuppression: undefined }, ctx);
      return next;
    };

    const resumeSelectedMission = async (mission: MissionState): Promise<void> => {
      const resume = missionResumeReason(mission, settings);
      if (!resume.available) return show(pi, `# Mission Resume

Cannot resume selected mission: ${resume.reason}

${renderMissionStatus(mission)}`);
      const active = activateSelectedMission(mission);
      await resumeMissionThroughCurrentGate(ctx, active, settings);
    };

    const showSelectedMissionMenu = async (mission: MissionState, selectedFromHistory = false): Promise<void> => {
      const resume = missionResumeReason(mission, settings);
      if (!ctx.hasUI) {
        return show(pi, `# ${selectedFromHistory ? "Selected Mission" : "Mission Resume"}

Mission: ${mission.id}
Project: ${mission.projectLabel ?? mission.cwd ?? "unknown project"}
Status: ${missionPhaseFromStatus(mission.status)}
Current Milestone: ${mission.milestones.length ? `M${Math.min(mission.currentMilestoneIndex + 1, mission.milestones.length)}/${mission.milestones.length}` : "M0/0"}
Resume Available: ${resume.available ? "yes" : "no"}
Reason: ${workflowDisplayText(resume.reason)}

Use /mission status, /mission resume, /mission continue, or /mission retry.`);
      }
      const canResume = resume.available;
      const reviewRepairAvailable = missionReviewRepairRecoveryAvailable(mission);
      const validationRepairAvailable = missionValidationRepairRetryAvailable(mission, settings);
      const choices = [
        ...(canResume ? ["Resume Mission"] : []),
        "List Mission Status",
        ...(reviewRepairAvailable ? ["Review Repair / Recover Notes"] : []),
        ...(validationRepairAvailable ? ["Repair / Retry Mission"] : []),
        ...(mission.status === "completed" || mission.status === "stopped" || mission.status === "draft" || mission.status === "planned" || mission.status === "awaiting_clarification" ? ["Reuse Mission", "Amend Mission"] : []),
        ...(!selectedFromHistory && allMissions.some((m) => m.id !== mission.id) ? ["Choose Another Mission"] : []),
        "List Checkpoints",
        "List Missions",
        ...(mission.status !== "completed" && mission.status !== "stopped" ? ["Stop Mission"] : []),
        "Cancel",
      ];
      const choice = await ctx.ui.select(selectedFromHistory ? "Selected Mission" : "Mission Resume", choices);
      if (choice === "Resume Mission") await resumeSelectedMission(mission);
      else if (choice === "Review Repair / Recover Notes") { activateSelectedMission(mission); await handleMissionReviewRepairRecovery(ctx, mission, "resume"); }
      else if (choice === "Repair / Retry Mission") { activateSelectedMission(mission); await handleMissionRetryCommand(ctx, "repair"); }
      else if (choice === "Reuse Mission") await startMissionFromGoal(ctx, mission.goal);
      else if (choice === "Amend Mission") await startMissionFromGoal(ctx, `Amend prior mission ${mission.id}: ${mission.goal}`);
      else if (choice === "Choose Another Mission") {
        const other = await chooseMissionFromHistory(ctx, allMissions.filter((m) => m.id !== mission.id), "Choose a mission to resume:");
        if (other) await showSelectedMissionMenu(other, true);
      } else if (choice === "List Mission Status") show(pi, renderMissionStatus(mission));
      else if (choice === "List Checkpoints") show(pi, renderMissionCheckpoints(mission));
      else if (choice === "List Missions") show(pi, renderMissionList(allMissions));
      else if (choice === "Stop Mission") {
        const active = activateSelectedMission(mission);
        const stopped = saveActiveMission({ ...active, status: "stopped", lastStopReason: "Mission stopped from resume menu.", nextAction: "No further mission action queued.", lastSummary: "Mission stopped from resume menu." });
        checkpointMission(stopped, "Mission stopped from resume menu.", "No further mission action queued.");
        updateState({ mode: "mission_stopped", activeMissionId: stopped.id, task: stopped.goal, originalTask: stopped.goal }, ctx);
        show(pi, renderMissionStatus(activeMission ?? stopped));
      }
    };

    await showSelectedMissionMenu(selected, false);
  }

  async function enterMissionModeAwaitingInput(ctx: ExtensionContext) {
    stopStartupVisual(ctx);
    const settings = loadWorkflowSettings(ctx.cwd);
    if (!settings.missions.enabled) return show(pi, "# Mission Mode Disabled\n\nEnable with `/workflow-settings set missions enabled true`.");
    pi.setActiveTools(planToolsFor(settings));
    updateState({
      mode: "awaiting_mission_input",
      task: undefined,
      originalTask: undefined,
      draftPlan: undefined,
      approvedPlan: undefined,
      executionSummary: undefined,
      validationReport: undefined,
      validationVerdict: undefined,
      reviewerReport: undefined,
      modelsUsed: undefined,
    }, ctx);
  }

  async function startMissionFromGoal(ctx: ExtensionContext, goal: string) {
    stopStartupVisual(ctx);
    const settings = loadWorkflowSettings(ctx.cwd);
    if (!settings.missions.enabled) return show(pi, "# Mission Mode Disabled\n\nEnable with `/workflow-settings set missions enabled true`.");
    const autonomy = normalizeMissionAutonomy(settings);
    if (autonomy === "full_auto" && settings.missions.allowFullAuto !== true) {
      return show(pi, `# Mission Start Blocked\n\n${fullAutoBlockedMessage()}\n\nDefault Autonomy: full_auto\nAllow Full Auto: disabled\n\nUse /workflow-settings set missions allowFullAuto true, or /workflow-settings set missions defaultAutonomy supervised_auto.`);
    }
    activeMission = createMissionState(goal, {
      cwd: ctx.cwd,
      autonomy,
      autonomySource: "settings at mission creation",
      allowFullAutoAtCreation: settings.missions.allowFullAuto === true,
      continueAcrossMilestones: settings.missions.continueAcrossMilestones !== false,
      pauseBetweenMilestones: settings.missions.pauseBetweenMilestones === true,
      maxValidationRetriesPerMilestone: settings.missions.maxValidationRetriesPerMilestone ?? 2,
      maxValidationRetriesPerMission: settings.missions.maxValidationRetriesPerMission ?? 8,
    });
    activeMission = saveActiveMission(activeMission);
    updateState({ mode: "mission_draft", activeMissionId: activeMission.id, task: goal, originalTask: goal, draftPlan: undefined, approvedPlan: undefined, executionSummary: undefined, validationReport: undefined, validationVerdict: undefined, clarifyingQuestions: undefined, clarifyingAnswers: undefined, modelsUsed: undefined, lastCompletedMissionSummary: undefined }, ctx);
    checkpointMission(activeMission, "Mission created from user goal.", "Generate milestone plan or answer mission clarification questions.");
    await beginMissionPlanning(ctx, activeMission);
  }

  async function beginMissionPlanning(ctx: ExtensionContext, mission: MissionState, options: { forceClarification?: boolean; forceAdditionalClarification?: boolean; forceReason?: string; planningPreflightSatisfied?: boolean; reviewFeedback?: string; revisionFeedback?: string } = {}) {
    stopStartupVisual(ctx);
    const settings = loadWorkflowSettings(ctx.cwd);
    clearTypedHandoff(ctx, "Mission planning");
    if (!settings.missions.enabled) return show(pi, "# Mission Mode Disabled\n\nEnable with `/workflow-settings set missions enabled true`.");
    pi.setActiveTools(planToolsFor(settings));
    updateState({
      mode: "mission_planning",
      activeMissionId: mission.id,
      task: mission.goal,
      originalTask: mission.goal,
      draftPlan: undefined,
      approvedPlan: undefined,
      lastCompletedMissionSummary: undefined,
    }, ctx);
    const planningOverride = { policy: missionSubagentPolicy(settings), workers: missionPlanningWorkerCount(settings), label: "Mission Planning", task: mission.goal };
    if (!options.planningPreflightSatisfied && !beginForcedSubagentPhase(ctx, "Planning", settings, planningOverride)) {
      const blocked = saveActiveMission({ ...mission, status: "blocked", lastBlockReason: "Mission planning blocked by forced sub-agent policy availability gate.", nextAction: "Fix mission planning sub-agent policy blocker, then run /mission resume or /mission plan.", lastSummary: "Mission planning blocked before planner handoff." });
      checkpointMission(blocked, "Mission planning blocked before planner handoff.", "Fix mission planning sub-agent policy blocker, then run /mission resume or /mission plan.");
      updateState({ mode: "mission_blocked", activeMissionId: blocked.id, task: blocked.goal, originalTask: blocked.goal, draftPlan: blocked.planText, approvedPlan: undefined }, ctx);
      return;
    }
    const route = await applyMissionModelForRole(pi, ctx, "planner", { cwd: ctx.cwd });
    if (!route) {
      const milestones = fallbackMissionMilestones(mission.goal);
      const next = saveActiveMission({ ...mission, status: "planned", milestones, planText: "Fallback conservative milestone plan created because planner model was unavailable.", modelsUsed: { ...(mission.modelsUsed ?? {}), planner: "fallback: planner unavailable" }, lastSummary: "Fallback milestone plan created because planner model was unavailable.", nextAction: "Review with /mission latest, then /mission approve." });
      checkpointMission(next, "Fallback mission milestone plan created.", "Review with /mission latest, then /mission approve.");
      updateState({ mode: "mission_plan_ready", activeMissionId: next.id, task: next.goal, originalTask: next.goal, draftPlan: next.planText, clarificationQualityRetryCount: undefined }, ctx);
      show(pi, `# Mission Plan Created\n\nMission ID: ${next.id}\nMilestones: ${milestones.length}\nPlanner unavailable; conservative fallback milestones were saved.\n\nUse /mission approve before running.`);
      return;
    }
    pi.setActiveTools(planToolsFor(settings));
    const revisionFeedback = options.revisionFeedback?.trim() || mission.lastRevisionFeedback?.trim();
    const pending = saveActiveMission({ ...mission, status: "planning", lastRevisionFeedback: revisionFeedback || undefined, modelsUsed: { ...(mission.modelsUsed ?? {}), planner: modelLabel(route) }, lastSummary: revisionFeedback ? "Mission plan revision requested from planner model." : "Mission planning requested from planner model.", nextAction: "Mission planner is active; wait for the milestone plan or stop the turn." });
    const hasAnswers = Boolean(pending.clarificationAnswers?.length);
    const answerSummary = hasAnswers ? formatAnswersForPlanner(pending.clarificationQuestions ?? [], pending.clarificationAnswers ?? []) : undefined;
    const forceClarification = options.forceAdditionalClarification === true
      ? options.forceClarification === true
      : !hasAnswers && options.forceClarification === true;
    updateState({
      mode: "mission_planning",
      activeMissionId: pending.id,
      task: pending.goal,
      originalTask: pending.goal,
      clarifyingQuestions: pending.clarificationQuestions,
      clarifyingAnswers: pending.clarificationAnswers,
      clarificationRequiredBeforePlan: forceClarification || undefined,
      clarificationRequirementReason: forceClarification ? options.forceReason : undefined,
      modelsUsed: { ...(state.modelsUsed ?? {}), planner: modelLabel(route) },
    }, ctx);
    queueWorkflowPrompt(
      pi,
      missionPlanPrompt(pending, settings, { forceClarification, forceAdditionalClarification: options.forceAdditionalClarification, forceReason: forceClarification ? options.forceReason : undefined, answerSummary, revisionFeedback, reviewFeedback: options.reviewFeedback }),
      buildQueuedFailureRecovery(ctx, (reason) => recoverMissionTransientHandoffFailure(ctx, "planning", reason)),
    );
  }

  function createFallbackMissionPlan(ctx: ExtensionContext, mission: MissionState): MissionState {
    const settings = loadWorkflowSettings(ctx.cwd);
    const milestones = fallbackMissionMilestones(mission.goal);
    const next = saveActiveMission({
      ...mission,
      status: "planned",
      milestones,
      planText: mission.planText ?? "Conservative fallback milestone plan.",
      modelsUsed: { ...(mission.modelsUsed ?? {}), planner: mission.modelsUsed?.planner ?? modelLabel(settings.models.planner) },
      lastSummary: `Mission milestone plan saved with ${milestones.length} milestone${milestones.length === 1 ? "" : "s"}.`,
      nextAction: "Review with /mission latest, then /mission approve.",
    });
    return checkpointMission(next, "Mission milestone plan saved.", "Review with /mission latest, then /mission approve.");
  }

  function appendMissionReviewHistory(mission: MissionState, entry: NonNullable<WorkflowState["reviewHistory"]>[number]): WorkflowState["reviewHistory"] {
    return [...(mission.reviewHistory ?? []), entry].slice(-20);
  }

  function missionReviewRetryCount(mission: MissionState): number {
    return Math.max(0, mission.missionReviewRetryCount ?? 0);
  }

  function recoverMissionReviewRepairAsNotes(ctx: ExtensionContext, mission: MissionState, source: string): MissionState | undefined {
    const report = mission.reviewerReport?.trim() || mission.lastReviewFailure?.trim();
    if (!report) return undefined;
    const verdict = mission.reviewerVerdict && mission.reviewerVerdict !== "UNKNOWN" ? mission.reviewerVerdict : extractReviewVerdict(report);
    const control = verdict === "NEEDS REPAIR"
      ? normalizeMissionReviewVerdictForControl(verdict, report)
      : (verdict === "PASS" || verdict === "NOTES" ? { verdict, report, originalVerdict: verdict, downgraded: false } satisfies PlanReviewControlVerdict : undefined);
    if (!control || (control.verdict !== "PASS" && control.verdict !== "NOTES")) return undefined;
    const recoveredStatus: MissionState["status"] = mission.status === "blocked" || mission.status === "failed" ? "planned" : mission.status;
    const reviewed = saveActiveMission({
      ...mission,
      status: recoveredStatus,
      reviewerReport: control.report,
      reviewerVerdict: control.verdict,
      currentReviewRetry: 0,
      lastReviewFailure: "",
      lastReviewAttempt: control.downgraded ? control.reason : `${source}: recovered Mission reviewer verdict ${control.verdict}.`,
      lastReviewRepairStatus: "none",
      reviewRepairInProgress: false,
      currentStep: undefined,
      lastBlockReason: mission.status === "blocked" ? "" : mission.lastBlockReason,
      nextAction: recoveredStatus === "approved" ? "Mission review recovered as notes; continue or revalidate if needed." : "Mission review recovered as notes; approve or rerun review if needed.",
      lastSummary: `Mission reviewer repair state recovered as ${control.verdict}.`,
      reviewHistory: appendMissionReviewHistory(mission, {
        timestamp: new Date().toISOString(),
        retry: mission.currentReviewRetry ?? 0,
        status: "completed",
        reviewFailure: compact(report, 800),
        nextAction: control.downgraded ? control.reason : `Recovered reviewer verdict ${control.verdict}.`,
      }),
    });
    activeMission = reviewed;
    updateState({
      mode: missionWorkflowModeForStatus(reviewed.status),
      activeMissionId: reviewed.id,
      task: reviewed.goal,
      originalTask: reviewed.goal,
      draftPlan: reviewed.planText,
      approvedPlan: reviewed.status === "approved" && reviewed.milestones.length ? missionRunPlan(reviewed) : undefined,
      reviewerReport: undefined,
      reviewerVerdict: undefined,
      validationReport: undefined,
      validationVerdict: undefined,
    }, ctx);
    return reviewed;
  }

  async function handleMissionReviewRepairRecovery(ctx: ExtensionContext, mission: MissionState, action: "retry" | "repair" | "resume"): Promise<boolean> {
    if (!missionReviewRepairRecoveryAvailable(mission)) return false;
    const recovered = recoverMissionReviewRepairAsNotes(ctx, mission, `Mission ${action}`);
    if (recovered) {
      show(pi, `# Mission Review Recovered\n\nThe saved Mission reviewer report now normalizes to ${recovered.reviewerVerdict}. Reviewer repair markers were cleared without using validation repair.\n\n${renderMissionStatus(recovered)}`);
      return true;
    }
    if (missionReviewRepairActive(mission)) {
      show(pi, `# Mission Review Repair Active\n\nReviewer-requested Mission plan repair is already running. Wait for planner repair and reviewer rerun before using /mission ${action === "resume" ? "resume" : action}.\n\n${renderMissionStatus(mission)}`);
      return true;
    }
    const report = mission.reviewerReport?.trim() || mission.lastReviewFailure?.trim() || "Mission reviewer requested repair.";
    const verdict = mission.reviewerVerdict && mission.reviewerVerdict !== "UNKNOWN" ? mission.reviewerVerdict : extractReviewVerdict(report);
    if (!reviewVerdictNeedsRepairRecovery(verdict, report)) return false;
    if (!mission.planText?.trim()) {
      show(pi, `# Mission Review Repair Blocked\n\nCannot repair reviewer findings: Mission plan repair context is unavailable.\n\n${renderMissionStatus(mission)}`);
      return true;
    }
    await handleMissionReviewFailure(ctx, mission, verdict === "UNKNOWN" ? "NEEDS REPAIR" : verdict, report, { manualOverride: true });
    return true;
  }

  async function beginMissionReview(ctx: ExtensionContext, mission: MissionState, auto = false): Promise<boolean> {
    if (!mission.milestones.length || mission.status !== "planned") {
      show(pi, "# Mission Reviewer Refused\n\nNo planned mission milestone plan exists. Run `/mission plan` first.");
      return false;
    }
    const settings = loadWorkflowSettings(ctx.cwd);
    clearTypedHandoff(ctx, "Mission review");
    armWorkflowToolsForPhase(ctx, "Review", "mission review start");
    const reviewing = saveActiveMission({ ...mission, currentStep: "reviewer", lastSummary: "Mission reviewer is checking the milestone plan before approval.", nextAction: "Wait for Mission reviewer verdict before approval." });
    activeMission = reviewing;
    updateState({ mode: "mission_plan_ready", activeMissionId: reviewing.id, task: reviewing.goal, originalTask: reviewing.goal, draftPlan: reviewing.planText, approvedPlan: undefined, modelsUsed: { ...(state.modelsUsed ?? {}), planner: reviewing.modelsUsed?.planner } }, ctx);
    if (!beginForcedSubagentPhase(ctx, "Review", settings)) return false;
    const route = await applyMissionModelForRole(pi, ctx, "reviewer", { cwd: ctx.cwd });
    if (!route) {
      show(pi, "# Mission Reviewer Blocked\n\nReviewer is enabled but its model could not be applied. Check /workflow-settings list, provider availability, and credentials, then run /mission review or /mission approve.");
      return false;
    }
    const withModel = saveActiveMission({ ...reviewing, modelsUsed: { ...(reviewing.modelsUsed ?? {}), reviewer: modelLabel(route) } });
    activeMission = withModel;
    updateState({ activeMissionId: withModel.id, modelsUsed: { ...(state.modelsUsed ?? {}), reviewer: modelLabel(route) } }, ctx);
    if (!ensureMissionReviewToolSurface(ctx, withModel, "mission review queued after model routing")) return false;
    if (auto) queueAgentTurn(pi, "Review the Mission milestone plan before approval begins.", "mission-review-trigger", buildQueuedPhaseRecovery(ctx, "Review", (reason) => recoverMissionTransientHandoffFailure(ctx, "review", reason, { phase: "Review" })));
    else queueWorkflowPrompt(pi, missionReviewPrompt(withModel, settings, phasePreflightBlocks.Review), buildQueuedPhaseRecovery(ctx, "Review", (reason) => recoverMissionTransientHandoffFailure(ctx, "review", reason, { phase: "Review" })));
    return true;
  }

  async function continueBeforeMissionApproval(ctx: ExtensionContext, mission: MissionState, auto = false): Promise<"approved" | "blocked"> {
    mission = loadMissionState(mission.id) ?? activeMission ?? mission;
    const reviewBlock = missionReviewContinuationBlock(mission);
    if (reviewBlock) {
      show(pi, `# Mission Approval Blocked\n\n${reviewBlock}\n\n${renderMissionStatus(mission)}`);
      return "blocked";
    }
    const settings = loadWorkflowSettings(ctx.cwd);
    if (missionModelAvailable(settings, "reviewer")) {
      if (settings.missions.autoRunReviewerBeforeApprove === true && mission.reviewerVerdict !== "PASS" && mission.reviewerVerdict !== "NOTES") {
        return (await beginMissionReview(ctx, mission, auto)) ? "blocked" : "blocked";
      }
      if (settings.missions.offerReviewerBeforeApprove === true && ctx.hasUI && !auto && mission.reviewerVerdict !== "PASS" && mission.reviewerVerdict !== "NOTES") {
        const choice = await ctx.ui.select("Reviewer is available. Run reviewer before mission approval?", ["Run Reviewer", "Skip Reviewer", "Back"]);
        if (choice === "Run Reviewer") return (await beginMissionReview(ctx, mission, false)) ? "blocked" : "blocked";
        if (choice === "Back") return "blocked";
      }
    } else if (missionModelEnabled(settings, "reviewer") && settings.missions.autoRunReviewerBeforeApprove === true) {
      show(pi, "# Mission Reviewer Not Configured\n\nMission reviewer is enabled but no effective reviewer model is configured. Configure reviewer, disable Mission reviewer, or turn off Mission reviewer auto-run.");
      return "blocked";
    }
    return "approved";
  }

  async function handleMissionReviewFailure(ctx: ExtensionContext, mission: MissionState, verdict: ReviewVerdict, reviewText: string, _options: { manualOverride?: boolean } = {}): Promise<void> {
    const settings = loadWorkflowSettings(ctx.cwd);
    const retry = mission.currentReviewRetry ?? 0;
    const missionRetry = missionReviewRetryCount(mission);
    const config = missionRepairRetryConfig(settings, "review");
    const maxRetries = Math.max(config.maxRetriesPerItem, maxMissionReviewRetries(mission, settings), retry + 1);
    const failure = `Reviewer ${verdict}. ${compact(reviewText, 1200)}`;
    const canRepairPlan = Boolean(mission.planText?.trim()) && (verdict === "NEEDS REPAIR" || verdict === "FAIL" || verdict === "BLOCKED");
    if (!canRepairPlan) {
      const reason = "Mission review repair context unavailable.";
      const saved = saveActiveMission({ ...mission, reviewerReport: reviewText, reviewerVerdict: verdict, currentStep: undefined, lastReviewFailure: failure, lastReviewAttempt: reason, lastReviewRepairStatus: "none", reviewRepairInProgress: false, nextAction: "Review Mission plan context, then rerun /mission review or /mission plan.", lastSummary: "Mission reviewer repair could not start because plan context was unavailable." });
      activeMission = saved;
      updateState({ mode: "mission_plan_ready", activeMissionId: saved.id, task: saved.goal, originalTask: saved.goal, draftPlan: saved.planText }, ctx);
      show(pi, `# Mission Reviewer Repair Unavailable\n\nVerdict: ${verdict}\nReason: ${reason}\n\nNo reviewer dead-block was written.`);
      return;
    }
    const nextRetry = retry + 1;
    clearPendingWorkflowToolPhase(ctx, "Execution", "mission reviewer repair");
    const attemptLabel = `Reviewer-triggered mission plan repair ${nextRetry}/${maxRetries}.`;
    const repairing = saveActiveMission({ ...mission, status: "planned", milestones: missionMilestonesForReviewRepair(mission), reviewerReport: reviewText, reviewerVerdict: verdict, currentStep: undefined, currentReviewRetry: nextRetry, missionReviewRetryCount: missionRetry + 1, maxReviewRetriesPerMission: maxRetries, lastReviewFailure: failure, lastReviewAttempt: attemptLabel, lastReviewRepairStatus: "running", reviewRepairInProgress: true, reviewHistory: appendMissionReviewHistory(mission, { timestamp: new Date().toISOString(), retry: nextRetry, status: "running", reviewFailure: compact(failure, 800), nextAction: "Repair mission milestone plan, then rerun reviewer before approval." }), nextAction: "Repair mission milestone plan, then rerun reviewer before approval." });
    activeMission = repairing;
    updateState({ mode: "mission_planning", activeMissionId: repairing.id, task: repairing.goal, originalTask: repairing.goal, draftPlan: repairing.planText }, ctx);
    await beginMissionPlanning(ctx, repairing, { reviewFeedback: `Reviewer verdict: ${verdict}\n\nReviewer report:\n${reviewText}` });
  }

  async function recoverLateMissionReviewReport(ctx: ExtensionContext, text: string): Promise<boolean> {
    if (!looksLikeWorkflowReviewReport(text)) return false;
    const verdict = extractReviewVerdict(text);
    if (verdict === "UNKNOWN") return false;
    if (!isMissionWorkflowMode(state)) return false;
    if (!(state.mode === "mission_plan_ready" || state.mode === "mission_awaiting_clarification" || state.mode === "mission_draft")) return false;
    const mission = (state.activeMissionId ? loadMissionState(state.activeMissionId) : undefined) ?? activeMission ?? loadMissionState("latest");
    if (!mission?.planText?.trim()) return false;
    const missionReview = normalizeMissionReviewVerdictForControl(verdict, text);
    if (missionReview.verdict === "PASS" || missionReview.verdict === "NOTES") {
      saveMissionReviewProseFallback(ctx, mission, missionReview, missionReview.downgraded ? missionReview.reason ?? "Late Mission reviewer prose fallback normalized to NOTES." : "Late Mission reviewer prose fallback saved; typed workflow_review_result was missing.");
      return true;
    }
    clearPendingWorkflowToolPhase(ctx, "Execution", "late mission reviewer failure");
    recordWorkflowInternalEvent(ctx, "Recovered late Mission reviewer report after out-of-phase review handoff; routing to mission plan repair.");
    await handleMissionReviewFailure(ctx, mission, missionReview.verdict, missionReview.report);
    return true;
  }

  async function recoverLatePlanReviewReport(ctx: ExtensionContext, text: string): Promise<boolean> {
    if (!looksLikeWorkflowReviewReport(text)) return false;
    const verdict = extractReviewVerdict(text);
    if (!reviewVerdictRequiresRepair(verdict)) return false;
    if (!isPlanWorkflowUiMode(state) || !(state.mode === "plan_approved" || state.mode === "reviewed")) return false;
    if (!state.approvedPlan?.trim()) return false;
    clearPendingWorkflowToolPhase(ctx, "Execution", "late plan reviewer failure");
    const planReview = normalizePlanReviewVerdictForControl(verdict, text);
    if (planReview.verdict === "PASS" || planReview.verdict === "NOTES") {
      updateState({ mode: "reviewed", reviewerReport: planReview.report, reviewerVerdict: planReview.verdict, currentReviewRetry: 0, lastReviewFailure: "", lastReviewAttempt: planReview.downgraded ? planReview.reason : planReview.verdict, lastReviewRepairStatus: state.lastReviewRepairStatus === "running" ? "completed" : (state.lastReviewRepairStatus ?? "none"), reviewRepairInProgress: false, repairRetryState: { ...(state.repairRetryState ?? {}), review: state.repairRetryState?.review ? { ...state.repairRetryState.review, status: state.repairRetryState.review.status === "running" ? "completed" : state.repairRetryState.review.status, inProgress: false, lastAttempt: planReview.downgraded ? planReview.reason : planReview.verdict } : undefined }, planProgress: workflowPlanProgressEnabled(loadWorkflowSettings(ctx.cwd)) ? mergePlanProgress({ ...state, mode: "reviewed" }, loadWorkflowSettings(ctx.cwd), { lifecycleStatus: "reviewed", nextAction: "executor" }, state.approvedPlan) : state.planProgress }, ctx);
      setPendingWorkflowToolPhase(ctx, "Execution", "late plan reviewer notes recovered");
      recordWorkflowInternalEvent(ctx, "Recovered late Plan reviewer report after out-of-phase review handoff; normalized to Plan reviewer notes.");
      deferWorkflowAction(pi, "begin execution after late reviewer notes", async () => {
        const started = await beginExecution(ctx, true);
        if (!started) {
          clearPendingWorkflowToolPhase(ctx, "Execution", "late plan reviewer notes did not start execution");
          recoverPlanTransientHandoffFailure(ctx, "execution", "Late Plan review normalized to notes but execution handoff did not start.", { phase: "Execution" });
        }
      }, { onFailure: (error) => recoverPlanTransientHandoffFailure(ctx, "execution", transientFailureReason("Late Plan review normalized to notes but execution handoff failed", error instanceof Error ? error.message : String(error)), { phase: "Execution" }) });
      return true;
    }
    recordWorkflowInternalEvent(ctx, "Recovered late Plan reviewer report after out-of-phase review handoff; routing to plan repair.");
    await handleWorkflowReviewFailure(ctx, planReview.verdict, planReview.report);
    return true;
  }

  function approveMission(ctx: ExtensionContext, mission: MissionState, force = false): MissionState | undefined {
    stopStartupVisual(ctx);
    mission = loadMissionState(mission.id) ?? activeMission ?? mission;
    const reviewBlock = missionReviewContinuationBlock(mission, force);
    if (reviewBlock) {
      show(pi, `# Mission Approval Refused\n\n${reviewBlock}\n\nTo override, use /mission approve --force.\n\n${renderMissionStatus(mission)}`);
      return undefined;
    }
    if (!mission.milestones.length) {
      show(pi, "# Mission Approval Refused\n\nNo milestones exist yet. Run `/mission plan` first.");
      return undefined;
    }
    if (mission.planText?.trim()) {
      const parsedMilestones = parseMissionMilestones(mission.planText);
      const milestonesMatchPlan = missionMilestonesMatchPlan(parsedMilestones, mission.milestones);
      if (!milestonesMatchPlan) {
        show(pi, "# Mission Approval Refused\n\nMission milestones do not match the current mission plan text. Regenerate the mission plan so approval uses the current parsed milestones.");
        return undefined;
      }
    }
    const settings = loadWorkflowSettings(ctx.cwd);
    const autoAction = mission.autonomy !== "manual" && settings.missions.autoRunAfterApproval === true ? "Mission approved; starting current milestone automatically." : "Mission approved; choose Run Mission Now from the action menu or use /mission continue.";
    const next = saveActiveMission({ ...mission, status: "approved", approvalRequired: false, lastReviewRepairStatus: mission.lastReviewRepairStatus === "running" ? "completed" : (mission.lastReviewRepairStatus ?? "none"), reviewRepairInProgress: false, lastSummary: "Mission plan approved; dynamic handoff is ready.", nextAction: autoAction, lastStopReason: "", lastBlockReason: "" });
    updateState({
      mode: "mission_approved",
      activeMissionId: next.id,
      task: next.goal,
      originalTask: next.goal,
      draftPlan: undefined,
      approvedPlan: missionRunPlan(next),
      executionSummary: undefined,
      validationReport: undefined,
      validationVerdict: undefined,
      reviewerReport: undefined,
    }, ctx);
    const approved = checkpointMission(next, "Mission plan approved.", autoAction);
    updateState({ mode: "mission_approved", activeMissionId: approved.id, task: approved.goal, originalTask: approved.goal, approvedPlan: missionRunPlan(approved) }, ctx);
    return approved;
  }

  function missionRuntimeBudgetBlock(mission: MissionState, settings: ReturnType<typeof loadWorkflowSettings>): string | undefined {
    const maxHours = settings.missions.maxRuntimeHours;
    if (!Number.isFinite(maxHours) || maxHours <= 0) return undefined;
    const activeMs = missionActiveRuntimeMs(mission);
    const maxMs = maxHours * 3_600_000;
    if (activeMs < maxMs) return undefined;
    return `Mission active runtime budget reached. Active Runtime: ${formatDurationMs(activeMs)}. Max Runtime Hours: ${maxHours}. Elapsed: ${formatDurationMs(missionWallClockAgeMs(mission))}.`;
  }

  function missionContinuationBlock(mission: MissionState, settings: ReturnType<typeof loadWorkflowSettings>, action: "run" | "continue" | "next" | "resume", force = false): string | undefined {
    const reviewBlock = missionReviewContinuationBlock(mission, force);
    if (reviewBlock) return reviewBlock;
    if (action !== "resume") {
      const runtimeBlocked = missionRuntimeBudgetBlock(mission, settings);
      if (runtimeBlocked) return runtimeBlocked;
    }
    if (mission.autonomy === "full_auto" && !missionAllowsFullAuto(mission, settings)) return "Cannot continue: full auto requested but allowFullAuto=false.";
    if (mission.status === "draft") return action === "resume" ? undefined
      : mission.milestones.length === 0
        ? "Cannot continue: mission is draft and has no approved milestone plan. Run /mission plan, then /mission approve, then /mission continue."
        : "Cannot continue: mission is draft and not approved. Run /mission approve, then /mission continue.";
    if (mission.status === "planned") return action === "resume" ? undefined : "Cannot continue: mission plan is not approved. Run /mission approve, then /mission continue.";
    if (mission.status === "awaiting_clarification") return action === "resume" ? undefined : "Cannot continue: mission is waiting for clarification. Use /mission clarify, then /mission plan, /mission approve, and /mission continue.";
    if (mission.status === "completed") return "Cannot continue: no remaining milestones.";
    if (mission.status === "stopped") return "Cannot continue: mission is stopped.";
    if (mission.status === "failed" || mission.status === "blocked") return `Cannot continue: validation failed on ${mission.milestones[mission.currentMilestoneIndex]?.id ?? "current milestone"}.`;
    if ((mission.status === "running" || mission.status === "validating" || mission.status === "repairing" || mission.status === "revalidating" || mission.status === "checkpointing") && action !== "resume") return `Cannot continue: mission is currently ${mission.status}; wait for the active gate or use /mission pause.`;
    if (mission.status === "repairing" || mission.status === "revalidating") return `Cannot resume execution: mission is currently ${mission.status}; use /mission revalidate or /mission status instead of restarting execution.`;
    if (!mission.milestones.length) return "Cannot continue: no remaining milestones.";
    if (mission.currentMilestoneIndex >= mission.milestones.length) return "Cannot continue: no remaining milestones.";
    const current = mission.milestones[mission.currentMilestoneIndex];
    if (!current) return "Cannot continue: no remaining milestones.";
    if (current.status === "completed" && !mission.milestones.some((m) => m.status === "pending")) return "Cannot continue: no remaining milestones.";
    if (action === "next" && mission.currentMilestoneIndex >= mission.milestones.length - 1 && current.status === "completed") return "Cannot continue: no remaining milestones.";
    return undefined;
  }

  async function beginMissionRun(ctx: ExtensionContext, mission: MissionState, action: "run" | "continue" | "next" | "resume" = "run", auto = false, force = false) {
    stopStartupVisual(ctx);
    mission = loadMissionState(mission.id) ?? activeMission ?? mission;
    const settings = loadWorkflowSettings(ctx.cwd);
    clearTypedHandoff(ctx, "Mission run");
    const blocked = missionContinuationBlock(mission, settings, action, force);
    if (blocked) {
      const runtimeBudgetBlocked = blocked.startsWith("Mission active runtime budget reached.");
      if (!runtimeBudgetBlocked) {
        return show(pi, `# Mission Cannot Continue\n\n${blocked}\n\n${renderMissionStatus({ ...mission, lastBlockReason: blocked, nextAction: blocked, lastSummary: blocked })}`);
      }
      const blockedMission = saveActiveMission({ ...mission, status: "paused", lastStopReason: blocked, lastBlockReason: blocked, nextAction: blocked, lastSummary: blocked });
      updateState({ mode: "mission_paused", activeMissionId: blockedMission.id }, ctx);
      return show(pi, `# Mission Cannot Continue\n\n${blocked}\n\n${renderMissionStatus(blockedMission)}`);
    }
    const startIndex = mission.milestones.findIndex((m, i) => i >= mission.currentMilestoneIndex && m.status !== "completed" && m.status !== "skipped");
    const index = startIndex >= 0 ? startIndex : mission.currentMilestoneIndex;
    const milestone = mission.milestones[index];
    if (!milestone) return show(pi, "# Mission Cannot Continue\n\nCannot continue: no remaining milestones.");
    const runningMilestones = mission.milestones.map((m, i) => i === index ? { ...m, status: "active" as const } : m.status === "active" ? { ...m, status: "pending" as const } : m);
    const running = saveActiveMission({
      ...mission,
      status: "running",
      currentMilestoneIndex: index,
      milestones: runningMilestones,
      currentStep: milestone.steps?.[0] ?? "milestone start",
      lastStopReason: mission.lastStopReason ? `Previous stop reason: ${mission.lastStopReason}` : "",
      lastBlockReason: "",
      nextAction: "Execute current mission milestone, then run mission validation.",
      lastSummary: `Running approved milestone ${milestone.id}.`,
    });
    checkpointMission(running, `Starting approved milestone ${milestone.id}: ${milestone.title}.`, "Execute current mission milestone, then run mission validation.", milestone.id);
    pi.setActiveTools(missionExecutionToolsFor(settings));
    updateState({ mode: "mission_running", activeMissionId: running.id, task: running.goal, originalTask: running.goal, approvedPlan: missionRunPlan(running), draftPlan: undefined, executionSummary: undefined, validationReport: undefined, validationVerdict: undefined, reviewerReport: undefined, modelsUsed: { ...(state.modelsUsed ?? {}), planner: running.modelsUsed?.planner }, missionTokensUsed: 0 }, ctx);
    if (!auto) show(pi, `# MISSION MODE ACTIVE\n\n# Mission Run Started\n\nMission ID: ${running.id}\nStatus: executing\nMilestone: ${milestone.id} — ${milestone.title}\nAutonomy: ${workflowDisplayValue(running.autonomy)}\n\n${renderMissionProgress(running, settings)}`);
    if (!beginForcedSubagentPhase(ctx, "Execution", settings)) {
      const blocked = saveActiveMission({ ...running, status: "blocked", lastBlockReason: "Mission execution blocked by forced sub-agent policy availability gate.", nextAction: "Fix sub-agent policy blocker, then run /mission continue.", lastSummary: "Mission execution blocked before runtime prompt." });
      updateState({ mode: "mission_blocked", activeMissionId: blocked.id, lastMissionStopSummary: buildMissionStopSummary(ctx, blocked, "blocked", "Mission blocked", { reason: blocked.lastBlockReason }) }, ctx);
      queueMissionTerminalSummary(ctx, blocked, "blocked", "Mission blocked", { reason: blocked.lastBlockReason });
      return;
    }
    const route = await applyMissionModelForRole(pi, ctx, "executor", { cwd: ctx.cwd });
    if (!route) {
      const paused = saveActiveMission({ ...running, status: "paused", lastStopReason: "Mission paused because executor model is unavailable.", nextAction: "Configure executor, then run /mission continue.", lastSummary: "Mission execution could not start because executor model was unavailable." });
      updateState({ mode: "mission_paused", activeMissionId: paused.id }, ctx);
      return;
    }
    updateState({ modelsUsed: { ...(state.modelsUsed ?? {}), executor: modelLabel(route), planner: running.modelsUsed?.planner } }, ctx);
    saveActiveMission({ ...running, modelsUsed: { ...(running.modelsUsed ?? {}), executor: modelLabel(route) } });
    queueAgentTurn(pi, missionRuntimePrompt(running, settings, phasePreflightBlocks.Execution), auto ? "mission-run-trigger" : "mission-run-manual-trigger", buildQueuedPhaseRecovery(ctx, "Execution", (reason) => recoverMissionTransientHandoffFailure(ctx, "run", reason, { phase: "Execution" })));
  }

  async function handleMissionApprovalHandoff(ctx: ExtensionContext, mission: MissionState, source: "menu" | "command" = "command") {
    stopStartupVisual(ctx);
    const gate = await continueBeforeMissionApproval(ctx, mission, false);
    if (gate !== "approved") return;
    mission = loadMissionState(mission.id) ?? (activeMission?.id === mission.id ? activeMission : mission);
    const reviewBlock = missionReviewContinuationBlock(mission);
    if (reviewBlock) return show(pi, `# Mission Approval Blocked\n\n${reviewBlock}\n\n${renderMissionStatus(mission)}`);
    const approved = approveMission(ctx, mission);
    if (!approved) return;
    const settings = loadWorkflowSettings(ctx.cwd);
    if (settings.missions.autoRunAfterApproval === true) {
      await beginMissionRun(ctx, approved, "run", true);
      return;
    }
    const menuTitle = "Mission Approved";
    const choices = ["Run Mission Now", "List Mission Status", "List Checkpoints", "Pause Mission", "Stop Mission", "Cancel"];
    const summary = `# Mission Approved\n\nMission ID: ${approved.id}\nStatus: ${approved.status}\nAuto Run After Approval: disabled\n\nChoose next action:\n${choices.map((choice) => `- ${choice}`).join("\n")}`;
    show(pi, summary);
    if (!ctx.hasUI) return;
    let current = approved;
    while (ctx.hasUI) {
      const choice = await ctx.ui.select(menuTitle, choices);
      if (!choice || choice === "Cancel") return;
      if (choice === "Run Mission Now") {
        await beginMissionRun(ctx, current, "run");
        return;
      }
      if (choice === "List Mission Status") {
        show(pi, renderMissionStatus(current));
        continue;
      }
      if (choice === "List Checkpoints") {
        show(pi, renderMissionCheckpoints(current));
        continue;
      }
      if (choice === "Pause Mission") {
        const reason = source === "menu" ? "Mission paused after approval from approval menu." : "Mission paused after approval.";
        const paused = saveActiveMission({ ...current, status: "paused", lastStopReason: reason, nextAction: "Use /mission resume, /mission continue, or /mission run.", lastSummary: `${reason} No milestone execution started.` });
        current = checkpointMission(paused, reason, "Use /mission resume, /mission continue, or /mission run.");
        updateState({ mode: "mission_paused", activeMissionId: current.id, task: current.goal, originalTask: current.goal }, ctx);
        show(pi, `# Mission Paused\n\n${renderMissionStatus(current)}`);
        return;
      }
      if (choice === "Stop Mission") {
        const reason = source === "menu" ? "Mission stopped after approval from approval menu." : "Mission stopped after approval.";
        const stopped = saveActiveMission({ ...current, status: "stopped", lastStopReason: reason, nextAction: "Use /mission resume or /mission continue if you intentionally want to continue this mission.", lastSummary: reason });
        current = checkpointMission(stopped, reason, "Use /mission resume or /mission continue if you intentionally want to continue this mission.");
        updateState({ mode: "mission_stopped", activeMissionId: current.id, task: current.goal, originalTask: current.goal }, ctx);
        show(pi, `# Mission Stopped\n\n${renderMissionStatus(current)}`);
        return;
      }
    }
  }

  const isRecord = (value: unknown): value is Record<string, unknown> => Boolean(value) && typeof value === "object";

  const subagentUsageTokensFromResult = (result: unknown): number => {
    if (!isRecord(result)) return 0;
    const details = isRecord(result.details) ? result.details : undefined;
    const results = details && Array.isArray(details.results) ? details.results : [];
    if (results.length > 0) {
      return results.reduce((sum, item) => {
        if (!isRecord(item) || !isRecord(item.usage)) return sum;
        return sum + (Number(item.usage.input) || 0) + (Number(item.usage.output) || 0);
      }, 0);
    }
    const usage = isRecord(result.usage) ? result.usage : undefined;
    return usage ? (Number(usage.input) || 0) + (Number(usage.output) || 0) : 0;
  };

  const extractSubagentObservations = (args: Record<string, unknown>, prefix = "top"): SubagentNameObservation[] => {
    const observations: SubagentNameObservation[] = [];
    if (typeof args.agent === "string" && args.agent.trim()) observations.push({ name: args.agent.trim(), key: `${prefix}:agent:0:${args.agent.trim()}` });
    if (Array.isArray(args.tasks)) {
      args.tasks.forEach((task, index) => {
        if (isRecord(task) && typeof task.agent === "string" && task.agent.trim()) observations.push({ name: task.agent.trim(), key: `${prefix}:tasks:${index}:${task.agent.trim()}` });
      });
    }
    if (Array.isArray(args.chain)) {
      args.chain.forEach((step, index) => {
        if (isRecord(step) && typeof step.agent === "string" && step.agent.trim()) observations.push({ name: step.agent.trim(), key: `${prefix}:chain:${index}:${step.agent.trim()}` });
      });
    }
    return observations;
  };

  const extractSubagentNames = (args: Record<string, unknown>): string[] => extractSubagentObservations(args).map((observation) => observation.name);

  const extractSuccessfulSubagentObservations = (resultValue: unknown, prefix = "result"): SubagentNameObservation[] => {
    const details = isRecord(resultValue) ? resultValue.details : undefined;
    const results = isRecord(details) && Array.isArray(details.results) ? details.results : [];
    const observations: SubagentNameObservation[] = [];
    results.forEach((result, index) => {
      if (!isRecord(result) || result.exitCode !== 0 || typeof result.agent !== "string" || !result.agent.trim()) return;
      observations.push({ name: result.agent.trim(), key: `${prefix}:${index}:${result.agent.trim()}` });
    });
    return observations;
  };

  const extractNestedSubagentObservations = (partialResult: unknown): SubagentNameObservation[] => {
    const details = isRecord(partialResult) ? partialResult.details : undefined;
    const results = isRecord(details) && Array.isArray(details.results) ? details.results : [];
    const observations: SubagentNameObservation[] = [];
    results.forEach((result, resultIndex) => {
      const messages = isRecord(result) && Array.isArray(result.messages) ? result.messages : [];
      messages.forEach((message, messageIndex) => {
        const parts = isRecord(message) && Array.isArray(message.content) ? message.content : [];
        parts.forEach((part, partIndex) => {
          if (!isRecord(part) || part.type !== "toolCall" || part.name !== "subagent") return;
          const nestedArgs = isRecord(part.arguments) ? part.arguments : isRecord(part.args) ? part.args : undefined;
          if (!nestedArgs) return;
          observations.push(...extractSubagentObservations(nestedArgs, `nested:${resultIndex}:${messageIndex}:${partIndex}`));
        });
      });
    });
    return observations;
  };

  const subagentUsageByPhase: Record<SubagentPhase, number> = { Planning: 0, Execution: 0, Repair: 0, Review: 0, Validation: 0 };
  const subagentNamesByPhase: Record<SubagentPhase, Set<string>> = { Planning: new Set(), Execution: new Set(), Repair: new Set(), Review: new Set(), Validation: new Set() };
  const successfulSubagentEvidenceByPhase: Record<SubagentPhase, Map<string, string>> = { Planning: new Map(), Execution: new Map(), Repair: new Map(), Review: new Map(), Validation: new Map() };

  const syncSubagentPhaseUsage = (phase: SubagentPhase): void => {
    const evidence = successfulSubagentEvidenceByPhase[phase];
    const distinctNames = new Set(Array.from(evidence.values()));
    subagentUsageByPhase[phase] = evidence.size;
    subagentNamesByPhase[phase] = distinctNames;
  };

  const recordSuccessfulSubagentEvidence = (phase: SubagentPhase, observations: SubagentNameObservation[]): void => {
    for (const observation of observations) successfulSubagentEvidenceByPhase[phase].set(observation.key, observation.name);
    syncSubagentPhaseUsage(phase);
  };

  const restoreSuccessfulSubagentEvidence = (phase: SubagentPhase, count: number, names: Set<string>, prefix: string): void => {
    const evidence = successfulSubagentEvidenceByPhase[phase];
    evidence.clear();
    const restoredNames = Array.from(names);
    restoredNames.forEach((name, index) => evidence.set(`${prefix}:name:${index}:${name}`, name));
    for (let index = evidence.size; index < count; index += 1) evidence.set(`${prefix}:unknown:${index}`, `worker-${index + 1}`);
    syncSubagentPhaseUsage(phase);
  };

  const phaseForWorkflowMode = (mode: WorkflowState["mode"]): SubagentPhase | undefined => {
    if (mode === "standard") return state.standardActivePhase ?? "Planning";
    if (mode === "planning" || mode === "mission_planning") return "Planning";
    if (mode === "executing" || mode === "mission_running") return "Execution";
    if (mode === "repairing" || mode === "mission_repairing") return "Repair";
    if (mode === "reviewing" || mode === "reviewed" || mode === "mission_plan_ready") return "Review";
    if (mode === "validating" || mode === "revalidating" || mode === "mission_validating" || mode === "mission_revalidating" || mode === "mission_final_validating") return "Validation";
    return undefined;
  };

  const subagentModelModeForWorkflowMode = (mode: WorkflowState["mode"]): WorkflowSubagentModelMode | undefined => {
    if (mode === "standard") return "standard";
    if (mode.startsWith("mission_")) return "mission";
    if (isPlanWorkflowMode({ ...state, mode })) return "plan";
    return undefined;
  };

  const subagentModelBucketForPhase = (phase: SubagentPhase): WorkflowSubagentModelBucket => phase.toLowerCase() as WorkflowSubagentModelBucket;

  const routedSubagentTaskFields = (settings: ReturnType<typeof loadWorkflowSettings>, phase: SubagentPhase): Partial<WorkflowSubagentTask> => {
    const route = resolveWorkflowSubagentModelRoute(settings, subagentModelModeForWorkflowMode(state.mode), subagentModelBucketForPhase(phase));
    return route.model ? { model: route.model, thinkingLevel: route.thinkingLevel } : {};
  };

  const forcedSubagentGuardLabel = (phase: SubagentPhase): string => {
    if (state.mode === "standard") return `Standard ${phase}`;
    if (state.mode === "mission_planning" && phase === "Planning") return "Mission Planning";
    if (state.mode === "mission_running" && phase === "Execution") return "Mission Execution";
    if (state.mode === "mission_repairing" && phase === "Repair") return "Mission Repair";
    if (state.mode === "mission_plan_ready" && phase === "Review") return "Mission Review";
    if ((state.mode === "mission_validating" || state.mode === "mission_revalidating") && phase === "Validation") return "Mission Validation";
    if (state.mode === "mission_final_validating" && phase === "Validation") return "Mission Final Validation";
    return phase;
  };

  const resetSubagentPhaseUsage = (phase: SubagentPhase) => {
    successfulSubagentEvidenceByPhase[phase].clear();
    syncSubagentPhaseUsage(phase);
  };
  const resetStandardSubagentUsage = () => {
    (["Planning", "Execution", "Repair", "Review", "Validation"] as SubagentPhase[]).forEach(resetSubagentPhaseUsage);
  };

  const snapshotSubagentPhaseUsage = (phase: SubagentPhase) => ({
    count: subagentUsageByPhase[phase] ?? 0,
    names: new Set(subagentNamesByPhase[phase]),
    evidence: new Map(successfulSubagentEvidenceByPhase[phase]),
  });

  const restoreSubagentPhaseUsage = (phase: SubagentPhase, snapshot: { count: number; names: Set<string>; evidence?: Map<string, string> }) => {
    if (snapshot.evidence) successfulSubagentEvidenceByPhase[phase] = new Map(snapshot.evidence);
    else restoreSuccessfulSubagentEvidence(phase, snapshot.count, snapshot.names, `restored:${phase}`);
    syncSubagentPhaseUsage(phase);
  };

  type SubagentPhasePolicyOverride = { policy?: SubagentPolicyValue; workers?: { deep: number; maximum: number }; label?: string; task?: string; kind?: WorkflowState["standardWorkKind"] };

  const recordSubagentPolicyDecision = (ctx: ExtensionContext, decision: Omit<SubagentPolicyDecision, "createdAt">): SubagentPolicyDecision => {
    const fullDecision: SubagentPolicyDecision = { ...decision, createdAt: new Date().toISOString() };
    updateState({
      subagentPolicyDecisions: {
        ...(state.subagentPolicyDecisions ?? {}),
        [decision.phase]: fullDecision,
      },
    }, ctx);
    return fullDecision;
  };

  const phasePolicyForCurrentMode = (settings: ReturnType<typeof loadWorkflowSettings>, phase: SubagentPhase): SubagentPolicyValue => {
    return state.mode === "standard" ? standardPhasePolicy(settings, phase) : phasePolicy(settings, phase);
  };

  const workersForCurrentMode = (settings: ReturnType<typeof loadWorkflowSettings>, phase: SubagentPhase): { deep: number; maximum: number } => {
    return state.mode === "standard" ? standardWorkerCount(settings, phase) : workerCount(settings, phase);
  };

  const forcedTrivialExemptionDecision = (ctx: ExtensionContext, phase: SubagentPhase, policy: SubagentPolicyValue, workers: { deep: number; maximum: number }, task?: string, kind?: WorkflowState["standardWorkKind"]): SubagentPolicyDecision | undefined => {
    if (!subagentPolicyRequiresRequiredEvidence(policy)) return undefined;
    const reason = trivialSubagentSkipReason(phase, task, kind);
    if (!reason) return undefined;
    return recordSubagentPolicyDecision(ctx, {
      phase,
      policy,
      outcome: "exempt_trivial",
      reason,
      task,
      required: workerTargetForPolicy(policy, workers),
      observed: 0,
      background: false,
    });
  };

  const rememberAdvisorySubagentDecision = (ctx: ExtensionContext, phase: SubagentPhase, policy: SubagentPolicyValue, outcome: "auto_delegate" | "auto_skip_trivial" | "auto_skip_no_useful_parallel_work" | "unavailable", reason: string, task?: string, workers = workerCount(loadWorkflowSettings(ctx.cwd), phase)): void => {
    if (!subagentPolicyNeedsInternalDecision(policy)) return;
    recordSubagentPolicyDecision(ctx, {
      phase,
      policy,
      outcome,
      reason,
      task,
      required: workerTargetForPolicy(policy, workers),
      observed: subagentUsageByPhase[phase] ?? 0,
      background: false,
    });
  };

  const advisoryWorkerTargetForPolicy = (policy: SubagentPolicyValue, workers: { deep: number; maximum: number }): number => {
    if (policy === "auto") return Math.max(1, workers.deep);
    return Math.max(1, workerTargetForPolicy(policy, workers));
  };

  const advisorySubagentUnavailableReason = (ctx: ExtensionContext, phase: SubagentPhase, policy: SubagentPolicyValue, workers: { deep: number; maximum: number }, label: string): string | undefined => {
    if (!subagentPolicyNeedsInternalDecision(policy)) return undefined;
    const target = advisoryWorkerTargetForPolicy(policy, workers);
    if (target <= 0) return undefined;
    const settings = loadWorkflowSettings(ctx.cwd);
    if (settings.subagents.enabled === false) return "subagents.enabled=false";
    if (!phaseAutoUseAllowed(settings, phase)) return `subagents.autoUseDuring${phase}=false`;
    if (!phaseParallelAllowed(settings, phase)) return `subagents.allowParallel${phase}=false`;
    const candidates = chooseForcedSubagents(phase, Math.min(target, 8), label, listEffectiveAgents(ctx.cwd));
    if (candidates.length === 0) return `no suitable ${phase.toLowerCase()} sub-agent workers are available`;
    return undefined;
  };

  const rememberStandardAdvisorySubagentDecisionForWork = (ctx: ExtensionContext, settings: ReturnType<typeof loadWorkflowSettings>, work: { phase: SubagentPhase; kind: NonNullable<WorkflowState["standardWorkKind"]> }, task?: string): void => {
    if (!task?.trim()) return;
    const policy = standardPhasePolicy(settings, work.phase);
    if (!subagentPolicyNeedsInternalDecision(policy)) return;
    const workers = standardWorkerCount(settings, work.phase);
    const unavailable = advisorySubagentUnavailableReason(ctx, work.phase, policy, workers, `Standard ${work.phase}`);
    if (unavailable) {
      rememberAdvisorySubagentDecision(ctx, work.phase, policy, "unavailable", unavailable, task, workers);
      return;
    }
    const advisory = advisorySubagentPolicyDecision(work.phase, policy, task, work.kind);
    rememberAdvisorySubagentDecision(ctx, work.phase, policy, advisory.outcome, advisory.reason, task, workers);
  };

  const priorSubagentUsageSatisfiesForced = (phase: SubagentPhase, snapshot: { count: number; names: Set<string> }, settings: ReturnType<typeof loadWorkflowSettings>, override?: SubagentPhasePolicyOverride): boolean => {
    const policy = override?.policy ?? phasePolicy(settings, phase);
    if (!subagentPolicyRequiresRequiredEvidence(policy)) return false;
    const required = workerTargetForPolicy(policy, override?.workers ?? workerCount(settings, phase));
    return snapshot.count >= required;
  };

  const beginForcedSubagentPhase = (ctx: ExtensionContext, phase: SubagentPhase, settings: ReturnType<typeof loadWorkflowSettings>, override?: SubagentPhasePolicyOverride): boolean => {
    resetSubagentPhaseUsage(phase);
    phasePreflightBlocks[phase] = undefined;
    const policy = override?.policy ?? phasePolicy(settings, phase);
    const workers = override?.workers ?? workerCount(settings, phase);
    const task = override?.task ?? state.task ?? state.originalTask;
    if (subagentPolicyNeedsInternalDecision(policy)) {
      const advisory = advisorySubagentPolicyDecision(phase, policy, task, override?.kind);
      rememberAdvisorySubagentDecision(ctx, phase, policy, advisory.outcome, advisory.reason, task, workers);
    }
    const exemption = forcedTrivialExemptionDecision(ctx, phase, policy, workers, task, override?.kind);
    if (exemption) {
      phasePreflightBlocks[phase] = formatSubagentPolicyDecision(exemption);
      return true;
    }
    const reason = forcedSubagentUnavailableReason(settings, phase, ctx.cwd, policy, workers);
    if (!reason) return true;
    if (subagentPolicyRequiresRequiredEvidence(policy)) {
      recordSubagentPolicyDecision(ctx, {
        phase,
        policy,
        outcome: "unavailable",
        reason,
        task,
        required: workerTargetForPolicy(policy, workers),
        observed: subagentUsageByPhase[phase] ?? 0,
        background: false,
      });
    }
    showInternal(pi, `# Sub-Agent Policy Blocked\n\n${forcedSubagentMessage(phase, reason, override?.label)}`);
    return false;
  };

  const forcedSubagentUsageSatisfied = (ctx: ExtensionContext, phase: SubagentPhase, override?: SubagentPhasePolicyOverride): string | undefined => {
    const settings = loadWorkflowSettings(ctx.cwd);
    const policy = override?.policy ?? phasePolicy(settings, phase);
    if (!subagentPolicyRequiresRequiredEvidence(policy)) return undefined;
    if (forcedTrivialExemptionDecision(ctx, phase, policy, override?.workers ?? workerCount(settings, phase), override?.task ?? state.task ?? state.originalTask, override?.kind)) return undefined;
    const required = workerTargetForPolicy(policy, override?.workers ?? workerCount(settings, phase));
    const observed = subagentUsageByPhase[phase] ?? 0;
    if (observed >= required) return undefined;
    const label = override?.label ?? phase;
    return `${label} stopped because ${label} Policy is forced. Required ${label.toLowerCase()} sub-agent workers: ${required}. Observed: ${observed}. Validation or the next workflow phase will not start until the forced worker requirement is satisfied. Change this in Workflow Sub-agents / Workers, or rerun with the required workers.`;
  };

  const blockIfForcedSubagentsMissing = (ctx: ExtensionContext, phase: SubagentPhase, override?: SubagentPhasePolicyOverride): boolean => {
    const reason = forcedSubagentUsageSatisfied(ctx, phase, override);
    if (!reason) return false;
    showInternal(pi, `# Sub-Agent Policy Blocked\n\n${forcedSubagentMessage(phase, reason, override?.label)}`);
    return true;
  };

  type ForcedSubagentPreflightContext = {
    label?: string;
    task?: string;
    approvedPlan?: string;
    mission?: MissionState;
    validationFailure?: string;
    executionSummary?: string;
    revalidate?: boolean;
  };

  const forcedAgentProfile = (agent: AgentInfo) => ({ name: agent.name, source: agent.source, tools: agent.tools });

  const chooseForcedSubagents = (phase: SubagentPhase, required: number, label: string, availableAgents: AgentInfo[]): AgentInfo[] => {
    const mission = /mission/i.test(label);
    const preferred = phase === "Planning"
      ? mission ? ["workflow-orchestrator", "implementation-planning", "codebase-research", "general-worker", "quality-validation"] : ["implementation-planning", "codebase-research", "general-worker", "quality-validation"]
      : phase === "Execution"
        ? ["general-worker", "implementation-planning", "codebase-research", "quality-validation"]
        : phase === "Repair"
          ? ["general-worker", "implementation-planning", "quality-validation", "codebase-research"]
          : phase === "Review"
            ? ["quality-validation", "implementation-planning", "general-worker", "codebase-research"]
            : ["quality-validation", "general-worker", "codebase-research", "implementation-planning"];
    const suitableAgents = availableAgents.filter((agent) => subagentSuitableForForcedPhase(forcedAgentProfile(agent), phase, label));
    const picked: AgentInfo[] = [];
    for (const name of preferred) {
      if (picked.length >= required) break;
      const agent = suitableAgents.find((candidate) => candidate.name === name);
      if (agent && !picked.some((candidate) => candidate.name === agent.name)) picked.push(agent);
    }
    for (const agent of suitableAgents) {
      if (picked.length >= required) break;
      if (!picked.some((candidate) => candidate.name === agent.name)) picked.push(agent);
    }
    return picked.slice(0, required);
  };

  const forcedSubagentTaskText = (phase: SubagentPhase, agent: string, index: number, required: number, context: ForcedSubagentPreflightContext): string => {
    const label = context.label ?? phase;
    const mission = context.mission;
    const repoLock = loadWorkflowSettings().safety.repoLockEnabled === true ? " Repo Lock is enabled: keep project work inside the current repository. Project .pi files and narrow read-only instruction resources may be read for context, but do not edit protected .pi control/config paths through normal tools. Do not inspect sibling repositories, unrelated home-directory paths, settings, credentials, logs, or unrelated tool state." : "";
    const base = `Forced ${label} sub-agent preflight worker ${index + 1}/${required}. You are running before the main ${label} agent. Stay read-only unless your agent contract explicitly allows otherwise; do not edit, commit, push, deploy, mutate databases, or touch secrets/runtime state.${repoLock} Return concise findings for the main ${label} agent.`;
    if (phase === "Planning") return `${base}\n\nPlanning target:\n${context.task ?? mission?.goal ?? state.task ?? state.originalTask ?? "(not recorded)"}\n\n${mission ? `Mission ID: ${mission.id}\nAutonomy: ${mission.autonomy}\nExisting milestones: ${mission.milestones.length}\n` : ""}\nFocus for ${agent}: identify project rules, likely files/systems, ambiguity, risks, validation needs, off-limits files, and specific recommendations for the final plan.`;
    if (phase === "Execution") {
      const settings = loadWorkflowSettings();
      const stepGated = settings.workflow.validateAfterEachStep === true || settings.workflow.requireApprovalPerStep === true;
      const progress = state.planProgress;
      const stepIndex = progress?.currentStepIndex ?? state.planExecutionStepIndex ?? 0;
      const step = progress?.steps?.[stepIndex];
      const stepBoundary = step ? `\n\nCurrent Plan step boundary:\nStep ${stepIndex + 1}: ${step.title}\nInspect and reason within this current/open step boundary first${stepGated ? ". Do not complete later Plan steps until the current step passes its gate" : "; do not inspect or work on future unrelated Plan steps unless the current task directly requires it"}. Report exactly: Plan Step ${stepIndex + 1} Progress: completed | blocked | incomplete, with evidence.` : "";
      const reviewerFindings = state.reviewerReport?.trim();
      const reviewerBlock = reviewerFindings || state.reviewerVerdict || state.lastReviewFailure
        ? `\n\nReviewer findings to account for before broad worker fanout:\n${state.reviewerVerdict ? `Reviewer verdict: ${state.reviewerVerdict}\n` : ""}${reviewerFindings ? `Reviewer report:\n${compact(reviewerFindings, 1800)}\n` : ""}${state.lastReviewFailure ? `Last review failure/blocker:\n${compact(state.lastReviewFailure, 800)}\n` : ""}`
        : "";
      return `${base}\n\nApproved execution contract:\n${context.approvedPlan ?? state.approvedPlan ?? (mission ? missionRunPlan(mission) : "(not recorded)")}${stepBoundary}${reviewerBlock}\n\nFocus for ${agent}: inspect likely files, identify implementation hazards, perform scoped work allowed by your configured tools and agent contract, propose safe edit order, surface regression risks, and recommend validation checks. Stay inside the approved Plan scope and current/open step, avoid conflicting parallel edits, account for reviewer findings, and do not mark Plan steps complete for the parent executor.`;
    }
    if (phase === "Repair") return `${base}\n\nApproved scope:\n${context.approvedPlan ?? state.approvedPlan ?? (mission ? missionRunPlan(mission) : "(not recorded)")}\n\nValidation failure / repair target:\n${context.validationFailure ?? state.lastValidationFailure ?? state.validationReport ?? mission?.lastValidationFailure ?? "(not recorded)"}\n\nFocus for ${agent}: identify concrete repair target, files to inspect, safe patch strategy, and revalidation checks. Do not repair directly.`;
    if (phase === "Review") return `${base}\n\nApproved plan to challenge before execution:\n${context.approvedPlan ?? state.approvedPlan ?? "(not recorded)"}\n\nFocus for ${agent}: challenge scope, missing requirements, risks, off-limits files, execution ordering, and validation coverage.`;
    return `${base}\n\nApproved plan / milestone:\n${context.approvedPlan ?? state.approvedPlan ?? (mission ? missionRunPlan(mission) : "(not recorded)")}\n\nExecution summary:\n${context.executionSummary ?? state.executionSummary ?? "(not recorded)"}\n\n${validationRuntimeToolOwnershipGuidance()}\n\nFocus for ${agent}: independently validate requirement coverage, changed-file risks, tests/build evidence, routes/selectors/expected URLs, manual QA caveats, and concrete PASS/PARTIAL PASS/FAIL evidence. Do not attempt parent-only Workflow Suite runtime tools; return exact browser/server/localStorage checks the parent validator should run after worker evidence returns.`;
  };

  const formatForcedSubagentPreflightBlock = (label: string, results: WorkflowSubagentResult[]): string => {
    const succeeded = results.filter((result) => result.exitCode === 0);
    const lines = succeeded.map((result) => {
      const profile = subagentToolProfileLabel({ name: result.agent, source: result.agentSource, tools: result.agentTools });
      return `- ${profile}: ${compact(workflowSubagentResultOutput(result), 1400)}`;
    });
    const failed = results.filter((result) => result.exitCode !== 0);
    return [`Phase: ${label}`, `Observed workers: ${succeeded.length}`, ...lines, ...(failed.length ? ["Failed workers:", ...failed.map((result) => `- ${result.agent} (${result.agentSource}): ${compact(workflowSubagentResultOutput(result), 500)}`)] : [])].join("\n");
  };

  const runForcedSubagentPreflight = async (ctx: ExtensionContext, phase: SubagentPhase, settings: ReturnType<typeof loadWorkflowSettings>, context: ForcedSubagentPreflightContext = {}, override?: SubagentPhasePolicyOverride): Promise<{ ok: boolean; block?: string }> => {
    resetSubagentPhaseUsage(phase);
    phasePreflightBlocks[phase] = undefined;
    const policy = override?.policy ?? phasePolicy(settings, phase);
    const workers = override?.workers ?? workerCount(settings, phase);
    const label = override?.label ?? context.label ?? phase;
    const task = override?.task ?? context.task ?? state.task ?? state.originalTask;
    if (!subagentPolicyRequiresRequiredEvidence(policy)) return { ok: true };
    const exemption = forcedTrivialExemptionDecision(ctx, phase, policy, workers, task, override?.kind);
    if (exemption) {
      const block = formatSubagentPolicyDecision(exemption);
      phasePreflightBlocks[phase] = block;
      return { ok: true, block };
    }
    const reason = forcedSubagentUnavailableReason(settings, phase, ctx.cwd, policy, workers);
    if (reason) {
      recordSubagentPolicyDecision(ctx, {
        phase,
        policy,
        outcome: "unavailable",
        reason,
        task,
        required: workerTargetForPolicy(policy, workers),
        observed: subagentUsageByPhase[phase] ?? 0,
        background: false,
      });
      showInternal(pi, `# Sub-Agent Policy Blocked\n\n${forcedSubagentMessage(phase, reason, label)}`);
      return { ok: false };
    }
    const required = workerTargetForPolicy(policy, workers);
    const effectiveAgents = listEffectiveAgents(ctx.cwd);
    const agents = chooseForcedSubagents(phase, required, label, effectiveAgents);
    const names = agents.map((agent) => agent.name);
    if (agents.length < required) {
      const suitableCount = effectiveAgents.filter((agent) => subagentSuitableForForcedPhase(forcedAgentProfile(agent), phase, label)).length;
      showInternal(pi, `# Sub-Agent Policy Blocked\n\n${forcedSubagentMessage(phase, `only ${suitableCount} suitable configured agent(s) were available for required target ${required}`, label)}`);
      return { ok: false };
    }
    if (settings.subagents.requireApprovalBeforeRun === true) {
      if (!ctx.hasUI) {
        showInternal(pi, `# Sub-Agent Policy Blocked\n\n${forcedSubagentMessage(phase, `subagents.requireApprovalBeforeRun=true but no UI is available to approve forced workers: ${names.join(", ")}`, label)}`);
        return { ok: false };
      }
      const approved = await ctx.ui.confirm("Run required sub-agent preflight?", `Phase: ${label}\nRequired workers: ${required}\nAgents: ${names.join(", ")}`);
      if (!approved) {
        showInternal(pi, `# Sub-Agent Policy Blocked\n\n${forcedSubagentMessage(phase, "user cancelled required sub-agent preflight approval", label)}`);
        return { ok: false };
      }
    }
    const useBackground = settings.subagents.allowBackgroundSubagents === true && (phase === "Planning" || phase === "Review");
    const routeFields = routedSubagentTaskFields(settings, phase);
    const tasks: WorkflowSubagentTask[] = names.map((agent, index) => ({ agent, task: forcedSubagentTaskText(phase, agent, index, required, context), cwd: ctx.cwd, background: useBackground, workflowPhase: phase, ...routeFields }));
    stopStartupVisual(ctx);
    const startedAt = new Date().toISOString();
    const toolCallId = `forced-${phase.toLowerCase()}-${Date.now()}`;
    activeSubagents = tasks.map((task, index) => ({ toolCallId, name: task.agent, instance: index + 1, startedAt, status: "running" as const, background: task.background, model: task.model, thinkingLevel: task.thinkingLevel }));
    beginWorkflowPreflightUi(ctx, label, activeSubagents);
    renderWorkflowSubagentActivity(ctx);
    const limits = settings.subagents as typeof settings.subagents & { subagentTimeoutMinutes?: number; subagentStaleMinutes?: number };
    const isBackground = useBackground && tasks.every((t) => t.background);
    if (isBackground) activeBackgroundSubagentRunId = toolCallId;
    let backgroundSettled = false;
    let run: { results: WorkflowSubagentResult[] } | undefined;
    try {
      run = await runWorkflowSubagents({
        cwd: ctx.cwd,
        tasks,
        agentScope: "user",
        timeoutMinutes: limits.subagentTimeoutMinutes,
        staleMinutes: limits.subagentStaleMinutes,
        background: isBackground,
        onUpdate: (results) => {
          if (isBackground && activeBackgroundSubagentRunId !== toolCallId) {
            traceWorkflowTracking(ctx, "background-subagent-stale-update", { phase, toolCallId, activeBackgroundSubagentRunId });
            return;
          }
          activeSubagents = results.map((result, index) => ({ toolCallId, name: result.agent, instance: index + 1, startedAt, status: result.exitCode === -1 ? "running" as const : result.exitCode === 0 ? "completed" as const : "failed" as const, background: tasks[index]?.background, model: result.model ?? tasks[index]?.model, thinkingLevel: result.thinkingLevel ?? tasks[index]?.thinkingLevel }));
          updateWorkflowPreflightUi(ctx, label, activeSubagents);
          renderWorkflowSubagentActivity(ctx);
          if (isBackground && !backgroundSettled && results.length > 0 && results.every((result) => result.exitCode !== -1)) {
            backgroundSettled = true;
            const succeeded = results.filter((result) => result.exitCode === 0);
            recordSuccessfulSubagentEvidence(phase, succeeded.map((result, index) => ({ name: result.agent, key: `background-forced:${phase}:${toolCallId}:${index}:${result.agent}` })));
            phasePreflightBlocks[phase] = formatForcedSubagentPreflightBlock(label, results);
            const subagentTokens = results.reduce((sum, r) => sum + (r.usage?.input ?? 0) + (r.usage?.output ?? 0), 0);
            if (subagentTokens > 0) accumulateModeTokens(subagentTokens, ctx);
            activeBackgroundSubagentRunId = undefined;
            endWorkflowPreflightUi(ctx);
            setTimeout(() => {
              if (activeBackgroundSubagentRunId === undefined) {
                activeSubagents = activeSubagents.filter((agent) => agent.toolCallId !== toolCallId || agent.status === "running");
                renderWorkflowSubagentActivity(ctx);
              }
            }, 1500);
          }
        },
      });
    } finally {
      if (!isBackground) endWorkflowPreflightUi(ctx);
    }
    if (!run) {
      activeSubagents = activeSubagents.filter(a => a.toolCallId !== toolCallId);
      renderWorkflowSubagentActivity(ctx);
      return { ok: false };
    }
    if (isBackground) {
      // Background execution: agents run independently, phase proceeds immediately
      recordSubagentPolicyDecision(ctx, {
        phase,
        policy,
        outcome: "required",
        reason: "required workers launched as advisory background preflight",
        task,
        required,
        observed: 0,
        background: true,
      });
      return { ok: true };
    }
    const succeeded = run.results.filter((result) => result.exitCode === 0);
    recordSuccessfulSubagentEvidence(phase, succeeded.map((result, index) => ({ name: result.agent, key: `forced:${phase}:${toolCallId}:${index}:${result.agent}` })));
    // 4d: Feed sub-agent tokens into mode-level budget
    const subagentTokens = run.results.reduce((sum, r) => sum + (r.usage?.input ?? 0) + (r.usage?.output ?? 0), 0);
    if (subagentTokens > 0) accumulateModeTokens(subagentTokens, ctx);
    activeSubagents = activeSubagents.filter(a => a.toolCallId !== toolCallId);
    renderWorkflowSubagentActivity(ctx);
    const block = formatForcedSubagentPreflightBlock(label, run.results);
    phasePreflightBlocks[phase] = block;
    if (succeeded.length < required) {
      showInternal(pi, `# Sub-Agent Policy Blocked\n\n${label} forced preflight did not satisfy required workers. Required: ${required}; succeeded: ${succeeded.length}.\n\n${block}`);
      return { ok: false, block };
    }
    recordSubagentPolicyDecision(ctx, {
      phase,
      policy,
      outcome: "required",
      reason: "required workers completed before phase continued",
      task,
      required,
      observed: succeeded.length,
      background: false,
    });
    return { ok: true, block };
  };

  const standardForcedSubagentOverride = (settings: ReturnType<typeof loadWorkflowSettings>, phase: SubagentPhase) => ({
    policy: standardPhasePolicy(settings, phase),
    workers: standardWorkerCount(settings, phase),
    label: `Standard ${phase}`,
    task: state.task ?? state.originalTask ?? "Standard Mode task",
    kind: state.standardWorkKind,
  });

  const standardForcedSubagentSatisfied = (phase: SubagentPhase, settings: ReturnType<typeof loadWorkflowSettings>, task: string): boolean => {
    const override = standardForcedSubagentOverride(settings, phase);
    if (!subagentPolicyRequiresRequiredEvidence(override.policy)) return true;
    if (trivialSubagentSkipReason(phase, task, override.kind)) return true;
    const required = workerTargetForPolicy(override.policy, override.workers);
    const record = state.standardSubagentPreflight?.[phase];
    if (record?.task === task && record.observed >= required) {
      restoreSuccessfulSubagentEvidence(phase, record.observed, new Set(record.agents), `standard:${phase}:${task}`);
      return true;
    }
    return false;
  };

  const forcedSubagentVisibleCallBlock = (ctx: ExtensionContext, phase: SubagentPhase, required: number, observed: number, input: unknown, label: string = phase): string | undefined => {
    const remaining = Math.max(0, required - observed);
    if (remaining <= 0) return undefined;
    const callShape = `Use one parallel tasks call shaped like subagent({ workflowPhase: "${phase.toLowerCase()}", tasks: [...] }). Worker count means task entries, not unique agent names; duplicate suitable roles are valid when useful, and distinct role names are not required. Choose phase-suitable workers by task fit. Do not add filler roles. Do not use subagent chain for forced multi-worker evidence.`;
    const countText = (requested: number, suffix = "") => {
      const shortBy = Math.max(0, remaining - requested);
      const shortage = shortBy > 0 ? `; this call is short by ${shortBy}` : "";
      return `subagent blocked — forced ${label} requires ${required} total worker task${required === 1 ? "" : "s"} before substantive ${phase.toLowerCase()} work; observed ${observed}, requested ${requested}${shortage}.${suffix}`;
    };
    if (!isRecord(input)) return countText(0, " The subagent request could not be inspected.");
    const requestedPhase = parseSubagentWorkflowPhase(input.workflowPhase);
    if (requestedPhase && requestedPhase !== phase) {
      return `subagent blocked — forced ${label} requires ${phase.toLowerCase()} workers, but the call requested workflowPhase=${String(input.workflowPhase)}.`;
    }
    const observations = extractSubagentObservations(input);
    const requested = observations.length;
    const distinctNames = Array.from(new Set(observations.map((observation) => observation.name).filter(Boolean)));
    if (remaining > 1 && !Array.isArray(input.tasks)) {
      const shape = Array.isArray(input.chain) && requested >= remaining
        ? `subagent blocked — forced ${label} requires ${required} total worker task${required === 1 ? "" : "s"} before substantive ${phase.toLowerCase()} work; observed ${observed}, requested ${requested} via chain. The requested count is enough, but chain is sequential and does not satisfy forced multi-worker evidence. ${callShape}`
        : `${countText(requested)} ${callShape}`;
      return shape;
    }
    if (requested < remaining) {
      return countText(requested, "");
    }
    const availableAgents = listEffectiveAgents(ctx.cwd);
    const suitableNames = new Set(availableAgents.filter((agent) => subagentSuitableForForcedPhase(forcedAgentProfile(agent), phase, label)).map((agent) => agent.name));
    const unsuitable = distinctNames.filter((name) => !suitableNames.has(name));
    if (unsuitable.length > 0) {
      return `subagent blocked — forced ${label} requested unsuitable or unavailable worker${unsuitable.length === 1 ? "" : "s"} for ${phase.toLowerCase()}: ${unsuitable.join(", ")}.`;
    }
    return undefined;
  };

  const planForcedSubagentPreflightReconcile = (ctx: ExtensionContext, phase: SubagentPhase): void => {
    const block = phasePreflightBlocks[phase];
    if (!block) return;
    const settings = loadWorkflowSettings(ctx.cwd);
    const policy = phasePolicy(settings, phase);
    if (!subagentPolicyRequiresRequiredEvidence(policy)) return;
    if (/^Policy decision:\s*exempt_trivial\b/im.test(block)) return;
    const observedMatch = block.match(/Observed workers: (\d+)/);
    if (!observedMatch) return;
    const observed = parseInt(observedMatch[1], 10);
    if (observed <= 0) return;
    const current = subagentUsageByPhase[phase] ?? 0;
    if (observed > current) {
      restoreSuccessfulSubagentEvidence(phase, observed, subagentNamesByPhase[phase] ?? new Set(), `preflight:${phase}`);
    }
  };

  const planForcedSubagentPreflightSatisfied = (ctx: ExtensionContext, phase: SubagentPhase, settings: ReturnType<typeof loadWorkflowSettings>): boolean => {
    const policy = phasePolicy(settings, phase);
    if (!subagentPolicyRequiresRequiredEvidence(policy)) return false;
    if (forcedTrivialExemptionDecision(ctx, phase, policy, workerCount(settings, phase), state.task ?? state.originalTask, state.standardWorkKind)) return true;
    planForcedSubagentPreflightReconcile(ctx, phase);
    const required = workerTargetForPolicy(policy, workerCount(settings, phase));
    return (subagentUsageByPhase[phase] ?? 0) >= required;
  };

  const planReviewForcedPolicyBlocked = (): boolean => {
    const nextAction = state.planProgress?.nextAction ?? "";
    return state.mode === "plan_approved"
      && Boolean(state.approvedPlan?.trim())
      && state.planProgress?.lifecycleStatus === "blocked"
      && /review blocked by forced sub-agent policy/i.test(nextAction);
  };

  function saveMissionReviewProseFallback(ctx: ExtensionContext, mission: MissionState, missionReview: PlanReviewControlVerdict, reason: string): MissionState {
    const reviewed = saveActiveMission({
      ...mission,
      reviewerReport: missionReview.report,
      reviewerVerdict: missionReview.verdict,
      lastReviewFailure: "",
      lastReviewAttempt: reason,
      lastReviewRepairStatus: mission.lastReviewRepairStatus === "running" ? "completed" : (mission.lastReviewRepairStatus ?? "none"),
      reviewRepairInProgress: false,
      currentStep: undefined,
      nextAction: "Mission review notes were saved from prose fallback. Run /mission approve to continue or /mission review to rerun typed review.",
      lastSummary: `Mission reviewer prose fallback saved as ${missionReview.verdict}; approval remains pending.`,
      reviewHistory: appendMissionReviewHistory(mission, {
        timestamp: new Date().toISOString(),
        retry: mission.currentReviewRetry ?? 0,
        status: "completed",
        reviewFailure: compact(missionReview.report, 800),
        nextAction: "Mission review notes saved from prose fallback; approval remains pending.",
      }),
    });
    activeMission = reviewed;
    updateState({ mode: "mission_plan_ready", activeMissionId: reviewed.id, task: reviewed.goal, originalTask: reviewed.goal, draftPlan: reviewed.planText }, ctx);
    recordWorkflowInternalEvent(ctx, "Mission reviewer prose fallback saved without automatic approval; typed workflow_review_result is required for automatic Mission approval.");
    return reviewed;
  }

  function queueMissionReviewTypedHandoffRetry(ctx: ExtensionContext, mission: MissionState, report: string, reason: string): boolean {
    const settings = loadWorkflowSettings(ctx.cwd);
    const maxRetries = 1;
    const currentRetry = Math.max(0, mission.currentReviewRetry ?? 0);
    if (currentRetry >= maxRetries) return false;
    const nextRetry = currentRetry + 1;
    const retryReason = `Mission Review typed handoff missing: ${reason}`;
    clearPendingWorkflowToolPhase(ctx, "Execution", "mission review typed handoff retry");
    clearTypedHandoff(ctx, "Mission review typed handoff retry");
    const retryMission = saveActiveMission({
      ...mission,
      currentStep: "reviewer",
      reviewerReport: report,
      reviewerVerdict: "UNKNOWN",
      currentReviewRetry: nextRetry,
      lastReviewFailure: retryReason,
      lastReviewAttempt: `Mission Review typed handoff retry ${nextRetry}/${maxRetries}.`,
      lastReviewRepairStatus: mission.lastReviewRepairStatus === "running" ? "none" : (mission.lastReviewRepairStatus ?? "none"),
      reviewRepairInProgress: false,
      nextAction: "Submit workflow_review_result before Mission approval can continue.",
      lastSummary: "Mission reviewer is retrying the typed review handoff before approval.",
    });
    activeMission = retryMission;
    updateState({ mode: "mission_plan_ready", activeMissionId: retryMission.id, task: retryMission.goal, originalTask: retryMission.goal, draftPlan: retryMission.planText }, ctx);
    if (!ensureMissionReviewToolSurface(ctx, retryMission, "mission review typed handoff retry")) return false;
    queueAgentTurn(
      pi,
      `CRITICAL MISSION REVIEW TYPED HANDOFF RETRY ${nextRetry}/${maxRetries}: the previous Mission Review turn produced reviewer prose but did not call workflow_review_result.\n\nYou are still the parent Mission reviewer. Do not approve, execute, validate, repair, call workflow_plan_result, call mission_plan_result, or call workflow_progress. Use the existing reviewer report below and call workflow_review_result with scope=mission and verdict PASS, NOTES, NEEDS_REPAIR, FAIL, or BLOCKED. If Review policy explicitly requires more Review-phase sub-agents and the preflight says evidence is missing, call Review-phase subagents first with workflowPhase=review, wait for their results, then call workflow_review_result.\n\nReason:\n${reason}\n\nPrevious reviewer report:\n${compact(report, 1800)}\n\n${missionReviewPrompt(retryMission, settings, phasePreflightBlocks.Review)}`,
      "mission-review-retry-typed-handoff",
      buildQueuedPhaseRecovery(ctx, "Review", (failureReason) => recoverMissionTransientHandoffFailure(ctx, "review", failureReason, { phase: "Review" })),
    );
    return true;
  }

  function queueMissionReviewHandoffRetry(ctx: ExtensionContext, mission: MissionState, report: string, reason: string, source: string): boolean {
    const settings = loadWorkflowSettings(ctx.cwd);
    const maxRetries = Math.max(1, maxMissionReviewRetries(mission, settings));
    const currentRetry = Math.max(0, mission.currentReviewRetry ?? 0);
    if (currentRetry >= maxRetries) return false;
    const nextRetry = currentRetry + 1;
    const retryReason = `Mission Review handoff incomplete: ${reason}`;
    clearPendingWorkflowToolPhase(ctx, "Execution", "mission review handoff retry");
    clearTypedHandoff(ctx, "Mission review handoff retry");
    if (!beginForcedSubagentPhase(ctx, "Review", settings)) return false;
    const retryMission = saveActiveMission({
      ...mission,
      currentStep: "reviewer",
      reviewerReport: report,
      reviewerVerdict: "UNKNOWN",
      currentReviewRetry: nextRetry,
      lastReviewFailure: retryReason,
      lastReviewAttempt: `Mission Review handoff retry ${nextRetry}/${maxRetries}.`,
      lastReviewRepairStatus: mission.lastReviewRepairStatus === "running" ? "none" : (mission.lastReviewRepairStatus ?? "none"),
      reviewRepairInProgress: false,
      nextAction: "Wait for Mission reviewer verdict before approval.",
      lastSummary: "Mission reviewer is retrying the review handoff before approval.",
    });
    activeMission = retryMission;
    updateState({ mode: "mission_plan_ready", activeMissionId: retryMission.id, task: retryMission.goal, originalTask: retryMission.goal, draftPlan: retryMission.planText }, ctx);
    if (!ensureMissionReviewToolSurface(ctx, retryMission, `mission review handoff retry ${source}`)) return false;
    queueAgentTurn(
      pi,
      `CRITICAL MISSION REVIEW HANDOFF RETRY ${nextRetry}/${maxRetries}: the previous Mission Review turn was not accepted because forced Review sub-agent evidence was missing or the structured workflow_review_result handoff was incomplete.\n\nYou are still the parent Mission reviewer. Do not approve, execute, validate, or repair the mission directly. If Review policy is forced, call Review-phase subagents first with workflowPhase=review, wait for their results, then call workflow_review_result with PASS, NOTES, NEEDS REPAIR, FAIL, or BLOCKED.\n\nBlocker to fix:\n${reason}\n\nPrevious reviewer report:\n${compact(report, 1600)}\n\n${missionReviewPrompt(retryMission, settings, phasePreflightBlocks.Review)}`,
      "mission-review-retry-forced-subagents",
      buildQueuedPhaseRecovery(ctx, "Review", (failureReason) => recoverMissionTransientHandoffFailure(ctx, "review", failureReason, { phase: "Review" })),
    );
    return true;
  }

  const queuePlanReviewHandoffRetry = (ctx: ExtensionContext, report: string, reason: string, source: string): boolean => {
    const settings = loadWorkflowSettings(ctx.cwd);
    const maxRetries = Math.max(1, state.maxReviewRetriesPerPlan ?? settings.workflow.maxReviewRetriesPerPlan ?? repairRetryGateConfig(settings, "review").maxRetriesPerItem ?? 2);
    const currentRetry = Math.max(0, state.currentReviewRetry ?? 0);
    if (currentRetry >= maxRetries) return false;
    const nextRetry = currentRetry + 1;
    const retryReason = `Plan Review handoff incomplete: ${reason}`;
    clearPendingWorkflowToolPhase(ctx, "Execution", "plan review handoff retry");
    clearTypedHandoff(ctx, "Plan review handoff retry");
    armWorkflowToolsForPhase(ctx, "Review", `plan review handoff retry ${source}`);
    updateState({
      mode: "reviewing",
      reviewerReport: report,
      reviewerVerdict: "UNKNOWN",
      currentReviewRetry: nextRetry,
      maxReviewRetriesPerPlan: maxRetries,
      lastReviewFailure: retryReason,
      lastReviewAttempt: `Plan Review handoff retry ${nextRetry}/${maxRetries}.`,
      lastReviewRepairStatus: state.lastReviewRepairStatus === "running" ? "none" : (state.lastReviewRepairStatus ?? "none"),
      reviewRepairInProgress: false,
      repairRetryState: { ...(state.repairRetryState ?? {}), review: state.repairRetryState?.review ? { ...state.repairRetryState.review, inProgress: false, lastAttempt: retryReason } : undefined },
      planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "reviewing" }, settings, { lifecycleStatus: "reviewing", nextAction: `review handoff retry ${nextRetry}/${maxRetries}` }, state.approvedPlan) : state.planProgress,
    }, ctx);
    const promptState = getState();
    queueAgentTurn(
      pi,
      `CRITICAL PLAN REVIEW HANDOFF RETRY ${nextRetry}/${maxRetries}: the previous Review turn was not accepted because forced Review sub-agent evidence was missing or the structured workflow_review_result handoff was incomplete.\n\nYou are still in the Plan Review phase. Do not execute the plan. Do not claim Planning-phase sub-agents satisfy Review policy. If Review policy is forced, call Review-phase subagents first with workflowPhase=review, wait for their results, then call workflow_review_result with PASS, NOTES, NEEDS REPAIR, FAIL, or BLOCKED.\n\nBlocker to fix:\n${reason}\n\n${reviewerPrompt(promptState, settings, phasePreflightBlocks.Review)}`,
      "review-retry-forced-subagents",
      buildQueuedPlanPhaseRecovery(ctx, "Review", (failureReason) => recoverPlanTransientHandoffFailure(ctx, "review", failureReason, { phase: "Review" })),
    );
    return true;
  };

  const blockPlanValidationHandoff = (ctx: ExtensionContext, report: string, reason: string): void => {
    const settings = loadWorkflowSettings(ctx.cwd);
    clearPendingWorkflowToolPhase(ctx, "Validation", "plan validation handoff blocked");
    clearTypedHandoff(ctx, "Plan validation handoff blocked");
    updateState({
      mode: "validated",
      validationReport: report,
      validationVerdict: "UNKNOWN",
      lastValidationFailure: reason,
      lastValidationHandoffFailure: reason,
      planProgress: workflowPlanProgressEnabled(settings)
        ? mergePlanProgress({ ...state, mode: "validated", validationVerdict: "UNKNOWN" }, settings, { lifecycleStatus: "blocked", validationStatus: "unknown", nextAction: "validation blocked by forced sub-agent policy" })
        : state.planProgress,
    }, ctx);
    queuePlanTerminalSummary(ctx, "blocked", "Plan validation blocked", { validationText: report, verdict: "UNKNOWN", reason });
  };

  const queuePlanValidationHandoffRetry = (ctx: ExtensionContext, report: string, reason: string, source: string): boolean => {
    const settings = loadWorkflowSettings(ctx.cwd);
    const workflowSettings = settings.workflow as typeof settings.workflow & { maxValidationHandoffRetries?: number };
    const maxRetries = Math.max(1, state.maxValidationHandoffRetries ?? workflowSettings.maxValidationHandoffRetries ?? repairRetryGateConfig(settings, "validation").maxRetriesPerItem ?? 2);
    const currentRetry = Math.max(0, state.currentValidationHandoffRetry ?? 0);
    if (currentRetry >= maxRetries) return false;
    const nextRetry = currentRetry + 1;
    const retryReason = `Plan Validation handoff incomplete: ${reason}`;
    const revalidate = state.mode === "revalidating";
    clearPendingWorkflowToolPhase(ctx, "Validation", "plan validation handoff retry");
    clearTypedHandoff(ctx, "Plan validation handoff retry");
    resetSubagentPhaseUsage("Validation");
    phasePreflightBlocks.Validation = undefined;
    armWorkflowToolsForPhase(ctx, "Validation", `plan validation handoff retry ${source}`);
    updateState({
      mode: revalidate ? "revalidating" : "validating",
      validationReport: report,
      validationVerdict: "UNKNOWN",
      currentValidationHandoffRetry: nextRetry,
      maxValidationHandoffRetries: maxRetries,
      lastValidationHandoffFailure: retryReason,
      lastValidationFailure: retryReason,
      planProgress: workflowPlanProgressEnabled(settings)
        ? mergePlanProgress({ ...state, mode: revalidate ? "revalidating" : "validating" }, settings, { lifecycleStatus: revalidate ? "revalidating" : "validating", validationStatus: "running", nextAction: `validation handoff retry ${nextRetry}/${maxRetries}` }, state.approvedPlan)
        : state.planProgress,
    }, ctx);
    const promptState = getState();
    queueAgentTurn(
      pi,
      `CRITICAL PLAN VALIDATION HANDOFF RETRY ${nextRetry}/${maxRetries}: the previous Validation turn was not accepted because forced Validation sub-agent evidence was missing or the structured workflow_validation_result handoff was incomplete.\n\nYou are still the parent Plan Validator. Do not repair, do not execute, and do not call workflow-orchestrator for this forced Plan Validation requirement. If validationPolicy is forced, call Validation-phase subagents first with workflowPhase=validation, preferably quality-validation, general-worker, codebase-research, or implementation-planning. Wait for their results, then call workflow_validation_result with PASS, PARTIAL PASS, FAIL, or UNKNOWN.\n\nBlocker to fix:\n${reason}\n\nPrevious validator report:\n${compact(report, 1600)}\n\n${validatePrompt(promptState, settings, phasePreflightBlocks.Validation)}`,
      "validation-retry-forced-subagents",
      buildQueuedPlanPhaseRecovery(ctx, "Validation", (failureReason) => recoverPlanTransientHandoffFailure(ctx, revalidate ? "revalidation" : "validation", failureReason, { phase: "Validation" })),
    );
    return true;
  };

  const rememberStandardSubagentPreflight = (ctx: ExtensionContext, phase: SubagentPhase, task: string, required: number) => {
    const agents = Array.from(subagentNamesByPhase[phase] ?? []);
    updateState({
      standardSubagentPreflight: {
        ...(state.standardSubagentPreflight ?? {}),
        [phase]: { task, required, observed: subagentUsageByPhase[phase] ?? 0, agents, satisfiedAt: new Date().toISOString() },
      },
    }, ctx);
  };

  const orchestrationWarning = (ctx: ExtensionContext, mode: "plan" | "mission"): string | undefined => {
    const settings = loadWorkflowSettings(ctx.cwd);
    if (!planningNeedsOrchestrator(settings, mode)) return undefined;
    if (subagentNamesByPhase.Planning.has("workflow-orchestrator")) return undefined;
    const label = mode === "mission" ? "Mission planning" : "Plan Mode planning";
    return `${label} expected workflow-orchestrator for deep planning, but it was not observed. Current planning workers: ${Array.from(subagentNamesByPhase.Planning).join(", ") || "none"}.`;
  };

  const orchestrationProblem = (ctx: ExtensionContext, mode: "plan" | "mission"): string | undefined => {
    const settings = loadWorkflowSettings(ctx.cwd);
    const policy = ((settings.subagents as typeof settings.subagents & { planningOrchestrationPolicy?: string }).planningOrchestrationPolicy ?? "orchestrator_first");
    if (policy !== "forced_orchestrated") return undefined;
    return orchestrationWarning(ctx, mode)?.replace("expected workflow-orchestrator for deep planning", "requires workflow-orchestrator before accepting this forced-orchestrated planning result");
  };

  const observedSubagentKeysByToolCall = new Map<string, Set<string>>();
  const standardPhaseByToolCall = new Map<string, SubagentPhase>();

  const parseSubagentWorkflowPhase = (value: unknown): SubagentPhase | undefined => {
    if (typeof value !== "string") return undefined;
    const normalized = value.trim().toLowerCase();
    if (normalized === "planning" || normalized === "plan" || normalized === "research") return "Planning";
    if (normalized === "execution" || normalized === "execute") return "Execution";
    if (normalized === "repair") return "Repair";
    if (normalized === "review") return "Review";
    if (normalized === "validation" || normalized === "validate") return "Validation";
    return undefined;
  };

  const registerSubagentObservations = (toolCallId: string, observations: SubagentNameObservation[], ctx: ExtensionContext, countUnknown = false) => {
    const seenKeys = observedSubagentKeysByToolCall.get(toolCallId) ?? new Set<string>();
    const newObservations = observations.filter((observation) => !seenKeys.has(observation.key));
    const phase = standardPhaseByToolCall.get(toolCallId) ?? phaseForWorkflowMode(state.mode);
    if (phase && countUnknown && newObservations.length === 0) {
      // Unknown visible sub-agent starts are activity rows only. Successful policy
      // evidence is recorded from final tool results so launched/running workers
      // cannot satisfy forced counts before they complete.
    }
    if (newObservations.length === 0) {
      if (!observedSubagentKeysByToolCall.has(toolCallId)) observedSubagentKeysByToolCall.set(toolCallId, seenKeys);
      return;
    }
    const localCounts = new Map<string, number>();
    const additions = newObservations.map(({ name, key }) => {
      seenKeys.add(key);
      const existingCount = activeSubagents.filter((agent) => agent.name === name && agent.status === "running").length;
      const localCount = (localCounts.get(name) ?? 0) + 1;
      localCounts.set(name, localCount);
      return { toolCallId, name, instance: existingCount + localCount, startedAt: new Date().toISOString(), status: "running" as const };
    });
    observedSubagentKeysByToolCall.set(toolCallId, seenKeys);
    activeSubagents = [...activeSubagents, ...additions];
    syncWorkflowRuntimeForActivity(ctx, "subagent activity observed");
    renderWorkflowSubagentActivity(ctx);
  };

  const beginSubagentActivity = (toolCallId: string, args: Record<string, unknown>, ctx: ExtensionContext) => {
    activeSubagents = activeSubagents.filter((agent) => agent.toolCallId !== toolCallId);
    observedSubagentKeysByToolCall.delete(toolCallId);
    standardPhaseByToolCall.delete(toolCallId);
    const phaseOverride = parseSubagentWorkflowPhase(args.workflowPhase);
    if (phaseOverride) standardPhaseByToolCall.set(toolCallId, phaseOverride);
    const phase = phaseOverride ?? phaseForWorkflowMode(state.mode);
    if (phase) {
      const settings = loadWorkflowSettings(ctx.cwd);
      const policy = phasePolicyForCurrentMode(settings, phase);
      rememberAdvisorySubagentDecision(ctx, phase, policy, "auto_delegate", "visible parent subagent call started", state.task ?? state.originalTask, workersForCurrentMode(settings, phase));
    }
    const observations = extractSubagentObservations(args, `top:${toolCallId}`);
    registerSubagentObservations(toolCallId, observations, ctx, observations.length === 0);
    if (observations.length === 0) renderWorkflowSubagentActivity(ctx);
  };

  const updateSubagentActivity = (toolCallId: string, partialResult: unknown, ctx: ExtensionContext) => {
    const nestedObservations = extractNestedSubagentObservations(partialResult);
    if (nestedObservations.length === 0) return;
    registerSubagentObservations(toolCallId, nestedObservations, ctx);
  };

  const finishSubagentActivity = (toolCallId: string, failed: boolean, ctx: ExtensionContext) => {
    observedSubagentKeysByToolCall.delete(toolCallId);
    standardPhaseByToolCall.delete(toolCallId);
    if (failed) {
      activeSubagents = activeSubagents.map((agent) => agent.toolCallId === toolCallId ? { ...agent, status: "failed" as const } : agent);
      renderWorkflowSubagentActivity(ctx);
      setTimeout(() => {
        activeSubagents = activeSubagents.filter((agent) => agent.toolCallId !== toolCallId);
        observedSubagentKeysByToolCall.delete(toolCallId);
        standardPhaseByToolCall.delete(toolCallId);
        renderWorkflowSubagentActivity(ctx);
        syncWorkflowRuntimeForActivity(ctx, "subagent failed cleanup");
        if (state.mode === "standard") pauseStandardRuntimeIfIdle(ctx, "subagent failed cleanup");
      }, 1500);
      return;
    }
    activeSubagents = activeSubagents.filter((agent) => agent.toolCallId !== toolCallId);
    renderWorkflowSubagentActivity(ctx);
    syncWorkflowRuntimeForActivity(ctx, "subagent finished");
    if (state.mode === "standard") pauseStandardRuntimeIfIdle(ctx, "subagent finished");
  };

  // ── Phase entry ────────────────────────────────────────────────

  function exitPlanModeToIdle(ctx: ExtensionContext): void {
    state = persistWorkflowState(emptyState(), ctx);
    activeMission = undefined;
    pi.setActiveTools(withRuntimeWebTools(BASE_EXECUTE_TOOLS));
    setWorkflowUi(ctx, state, activeSubagents);
  }

  function exitMissionModeToIdle(ctx: ExtensionContext): void {
    state = persistWorkflowState(emptyState(), ctx);
    activeMission = undefined;
    pi.setActiveTools(withRuntimeWebTools(BASE_EXECUTE_TOOLS));
    setWorkflowUi(ctx, state, activeSubagents);
  }

  function exitStandardModeToIdle(ctx: ExtensionContext): void {
    state = persistWorkflowState(emptyState(), ctx);
    activeMission = undefined;
    pi.setActiveTools(withRuntimeWebTools(BASE_EXECUTE_TOOLS));
    setWorkflowUi(ctx, state, activeSubagents);
  }

  async function enterStandardMode(ctx: ExtensionContext, task?: string) {
    stopStartupVisual(ctx);
    const settings = loadWorkflowSettings(ctx.cwd);
    const standardWork = classifyStandardWork(task);
    if (settings.standard.enabled === false) return show(pi, "# Standard Mode Disabled\n\nEnable with `/workflow-settings set standard enabled true`.");
    activeMission = undefined;
    pi.setActiveTools(standardToolsFor(settings));
    const standardRuntimeStartedAt = new Date().toISOString();
    updateState({
      mode: "standard",
      activeMissionId: undefined,
      task: task || undefined,
      originalTask: task || undefined,
      draftPlan: undefined,
      approvedPlan: undefined,
      executionSummary: undefined,
      validationReport: undefined,
      validationVerdict: undefined,
      reviewerReport: undefined,
      reviewerVerdict: undefined,
      currentReviewRetry: 0,
      workflowReviewRetryCount: 0,
      currentValidationRetry: 0,
      workflowValidationRetryCount: 0,
      clarifyingQuestions: undefined,
      clarifyingAnswers: undefined,
      planRuntime: undefined,
      planProgress: undefined,
      standardRuntime: { id: createStandardRuntimeId(ctx.cwd), createdAt: standardRuntimeStartedAt, active: Boolean(task?.trim()), activeRuntimeMs: 0, activeRunStartedAt: task?.trim() ? standardRuntimeStartedAt : null, lastProgressAt: standardRuntimeStartedAt, runtimeCounter: task?.trim() ? "running" : "paused" },
      standardTodo: undefined,
      standardLastAutoCheckAt: undefined,
      standardLastClarificationDecision: undefined,
      standardLastClarificationReason: undefined,
      standardClarificationPending: undefined,
      standardClarificationStage: undefined,
      standardActivePhase: task?.trim() ? standardWork.phase : undefined,
      standardWorkKind: task?.trim() ? standardWork.kind : undefined,
      standardClarificationTask: undefined,
      standardClarificationAnswer: undefined,
      standardClarificationRequirementReason: undefined,
      standardClarifyingQuestions: undefined,
      standardClarifyingAnswers: undefined,
      standardSubagentPreflight: undefined,
      standardLastTodoDecision: undefined,
      standardLastTodoReason: undefined,
      modelsUsed: undefined,
      standardTokensUsed: 0,
    }, ctx);
    if (task?.trim()) queueWorkflowPrompt(pi, task.trim(), buildQueuedFailureRecovery(ctx, (reason) => recoverStandardTransientHandoffFailure(ctx, reason)));
  }

  async function enterPlanModeAwaitingInput(ctx: ExtensionContext) {
    stopStartupVisual(ctx);
    // Do not switch/apply the planner model here. Entering ready state must be
    // side-effect-light so completion can reset without triggering a stale turn.
    pi.setActiveTools(planToolsFor(loadWorkflowSettings(ctx.cwd)));
    activeMission = undefined;
    updateState({
      mode: "awaiting_plan_input",
      activeMissionId: undefined,
      task: undefined, originalTask: undefined, draftPlan: undefined, approvedPlan: undefined,
      executionSummary: undefined, validationReport: undefined, validationVerdict: undefined,
      reviewerReport: undefined, reviewerVerdict: undefined, currentReviewRetry: 0, workflowReviewRetryCount: 0, maxReviewRetriesPerPlan: undefined, maxReviewRetriesPerWorkflow: undefined, lastReviewFailure: undefined, lastReviewAttempt: undefined, lastReviewRepairStatus: "none", reviewHistory: undefined, reviewRepairInProgress: undefined, repairRetryState: undefined, clarifyingQuestions: undefined, clarifyingAnswers: undefined,
      clarificationAlreadyAsked: undefined, clarificationRequiredBeforePlan: undefined, clarificationRequirementReason: undefined, clarificationSkipReason: undefined, clarificationQualityRetryCount: undefined, planningDepth: undefined, clarificationMode: undefined,
      modelsUsed: undefined,
      currentValidationRetry: 0,
      workflowValidationRetryCount: 0,
      maxValidationRetriesPerPlan: undefined,
      maxValidationRetriesPerWorkflow: undefined,
      lastValidationFailure: undefined,
      lastRepairAttempt: undefined,
      repairHistory: undefined,
      lastRepairStatus: "none",
      planStepValidationIndex: undefined,
      planExecutionStepIndex: undefined,
      planRuntime: undefined,
      planProgress: undefined,
      planHistoryId: undefined,
      approvedPlanHistoryId: undefined,
    }, ctx);
  }

  type PlanApprovalContinuation = "configured" | "execute" | "review";

  async function approveCurrentPlan(ctx: ExtensionContext, saveReason: string, continuation: PlanApprovalContinuation = "configured"): Promise<boolean> {
    const planText = state.draftPlan ?? state.approvedPlan;
    if (!planText?.trim()) {
      show(pi, "# No draft plan. Run `/plan <task>` first.");
      return false;
    }
    const settings = loadWorkflowSettings(ctx.cwd);
    const approvalSteps = extractApprovedPlanSteps(planText);
    if (approvalSteps.length === 0) {
      show(pi, "# Plan Approval Refused\n\nNo parser-safe implementation steps were found in the current plan. Revise/regenerate the plan so it includes `## Implementation Steps` with numbered steps before approval.");
      return false;
    }
    updateState({
      mode: "plan_approved",
      approvedPlan: planText,
      executionSummary: undefined,
      validationReport: undefined,
      validationVerdict: undefined,
      reviewerReport: undefined,
      reviewerVerdict: undefined,
      currentReviewRetry: 0,
      workflowReviewRetryCount: 0,
      maxReviewRetriesPerPlan: undefined,
      maxReviewRetriesPerWorkflow: undefined,
      lastReviewFailure: undefined,
      lastReviewAttempt: undefined,
      lastReviewRepairStatus: "none",
      reviewHistory: undefined,
      reviewRepairInProgress: undefined,
      repairRetryState: undefined,
      currentValidationRetry: 0,
      workflowValidationRetryCount: 0,
      maxValidationRetriesPerPlan: undefined,
      maxValidationRetriesPerWorkflow: undefined,
      lastValidationFailure: undefined,
      lastRepairAttempt: undefined,
      repairHistory: undefined,
      lastRepairStatus: "none",
      planStepValidationIndex: undefined,
      planExecutionStepIndex: undefined,
      planProgress: workflowPlanProgressEnabled(settings) ? createPlanProgress(planText, settings, "approved") : undefined,
    }, ctx);
    persistCurrentPlan(ctx, "approved", saveReason);
    pi.setActiveTools(executionToolsFor(settings));
    let started = false;
    try {
      if (continuation === "review") started = await beginReview(ctx, true);
      else if (continuation === "execute") started = await beginExecution(ctx, true);
      else started = await continueAfterPlanApproval(ctx, true);
    } catch (error) {
      const phase = continuation === "review" ? "Review" : "Execution";
      recoverPlanTransientHandoffFailure(ctx, continuation === "review" ? "review" : "execution", transientFailureReason(continuation === "review" ? "Approved-plan reviewer handoff failed" : "Approved-plan handoff failed", error instanceof Error ? error.message : String(error)), { phase });
      return true;
    }
    if (!started) {
      const next = continuation === "review"
        ? "Plan was approved, but reviewer could not start. Configure reviewer or run /plan continue to execute without reviewer."
        : "Plan was approved, but execution could not start. Use /plan continue after fixing the issue.";
      show(pi, `# Handoff Paused\n\n${next}`);
    }
    return true;
  }

  async function beginPlanning(ctx: ExtensionContext, task: string, priorPlan?: string, feedback?: string, options: { feedbackKind?: "clarification" | "revision" | "repair" | "resume"; clarifyPriorPlan?: boolean; planningPreflightSatisfied?: boolean } = {}) {
    stopStartupVisual(ctx);
    const settings = loadWorkflowSettings(ctx.cwd);
    clearTypedHandoff(ctx, "Plan planning");
    const feedbackKind = options.feedbackKind ?? (feedback ? "revision" : undefined);
    pi.setActiveTools(planToolsFor(settings));
    const reviewerRepair = planReviewRepairActive(state);
    const activePlanId = reviewerRepair || options.feedbackKind === "resume" ? state.activePlanId ?? ensureActivePlanId(ctx) : createWorkflowPlanId(ctx.cwd);
    const initialPlanProgress = !workflowPlanProgressEnabled(settings) ? undefined : reviewerRepair
      ? mergePlanProgress({ ...state, mode: "repairing", task, approvedPlan: state.approvedPlan }, settings, { lifecycleStatus: "repairing", nextAction: "planner repairing for reviewer" }, state.approvedPlan)
      : mergePlanProgress({ ...state, mode: "planning", task }, settings, { lifecycleStatus: "planning", nextAction: "planner", steps: [], currentStepIndex: 0 }, undefined);
    updateState({
      mode: "planning",
      activePlanId,
      task,
      originalTask: state.originalTask ?? task,
      draftPlan: undefined,
      approvedPlan: reviewerRepair ? state.approvedPlan : undefined,
      lastCompletedPlanSummary: undefined,
      planningDepth: settings.planning.depth,
      clarificationMode: settings.planning.clarificationMode,
      clarificationQualityRetryCount: feedback ? state.clarificationQualityRetryCount : undefined,
      currentReviewRetry: reviewerRepair ? state.currentReviewRetry : 0,
      workflowReviewRetryCount: reviewerRepair ? state.workflowReviewRetryCount : 0,
      maxReviewRetriesPerPlan: reviewerRepair ? state.maxReviewRetriesPerPlan : undefined,
      maxReviewRetriesPerWorkflow: reviewerRepair ? state.maxReviewRetriesPerWorkflow : undefined,
      lastReviewFailure: reviewerRepair ? state.lastReviewFailure : undefined,
      lastReviewAttempt: reviewerRepair ? state.lastReviewAttempt : undefined,
      lastReviewRepairStatus: reviewerRepair ? state.lastReviewRepairStatus : "none",
      reviewHistory: reviewerRepair ? state.reviewHistory : undefined,
      repairRetryState: reviewerRepair ? state.repairRetryState : undefined,
      planProgress: initialPlanProgress,
    }, ctx);
    if (!options.planningPreflightSatisfied && !beginForcedSubagentPhase(ctx, "Planning", settings, { task })) {
      pi.setActiveTools(planToolsFor(settings));
      updateState({ mode: "plan_draft", activePlanId, draftPlan: "Planning blocked before the planner could run: forced planning sub-agent requirements are unavailable.", approvedPlan: undefined, lastReviewFailure: "Forced planning sub-agent requirements are unavailable.", executionSummary: undefined, validationReport: undefined, validationVerdict: undefined, reviewerReport: undefined, reviewerVerdict: undefined, currentReviewRetry: 0, workflowReviewRetryCount: 0, maxReviewRetriesPerPlan: undefined, maxReviewRetriesPerWorkflow: undefined, lastReviewAttempt: undefined, lastReviewRepairStatus: "none", reviewHistory: undefined, reviewRepairInProgress: undefined, repairRetryState: undefined, currentValidationRetry: 0, workflowValidationRetryCount: 0, lastRepairStatus: "none", planStepValidationIndex: undefined, planExecutionStepIndex: undefined, planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "validated", draftPlan: undefined, approvedPlan: undefined }, settings, { lifecycleStatus: "blocked", nextAction: "fix planning sub-agent policy or revise planning", steps: [] }, undefined) : undefined, lastCompletedPlanSummary: undefined }, ctx);
      return;
    }
    const route = await applyPlanModelForRole(pi, ctx, "planner", { cwd: ctx.cwd });
    if (!route) {
      updateState({ mode: "plan_draft", activePlanId, draftPlan: "Planning blocked before the planner could run: planner model is disabled, unavailable, or not configured.", approvedPlan: undefined, lastReviewFailure: "Planner model is disabled, unavailable, or not configured.", planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "validated", draftPlan: undefined, approvedPlan: undefined }, settings, { lifecycleStatus: "blocked", nextAction: "configure planner or revise planning", steps: [] }, undefined) : undefined }, ctx);
      return;
    }
    pi.setActiveTools(planToolsFor(settings));
    const feedbackIsClarification = feedbackKind === "clarification";
    const syntheticFreeformAnswer: ClarificationAnswer[] | undefined = feedbackIsClarification && feedback?.trim() && !state.clarifyingAnswers?.length
      ? [{ index: 1, letter: "D", custom: feedback.trim() }]
      : undefined;
    const hasAnswers = Boolean(state.clarifyingAnswers?.length) || Boolean(syntheticFreeformAnswer?.length);
    const gate = clarificationGate(task, settings, hasAnswers, Boolean(priorPlan), { clarifyPriorPlan: options.clarifyPriorPlan === true });
    if (gate.skipReason && settings.planning.clarificationMode === "always_for_nontrivial" && !priorPlan) recordWorkflowInternalEvent(ctx, "Internal workflow lifecycle event suppressed.");
    const planningApprovedPlan = reviewerRepair ? state.approvedPlan : undefined;
    const planningNextAction = reviewerRepair ? "planner repairing for reviewer" : "planner";
    const planningProgress = !workflowPlanProgressEnabled(settings) ? undefined : reviewerRepair
      ? mergePlanProgress({ ...state, mode: "repairing", task, approvedPlan: planningApprovedPlan }, settings, { lifecycleStatus: "repairing", nextAction: planningNextAction }, planningApprovedPlan)
      : mergePlanProgress({ ...state, mode: "planning", task, draftPlan: undefined, approvedPlan: undefined }, settings, { lifecycleStatus: "planning", nextAction: planningNextAction, steps: [], currentStepIndex: 0 }, undefined);
    updateState({
      mode: "planning", task, originalTask: state.originalTask ?? task,
      approvedPlan: planningApprovedPlan,
      clarifyingQuestions: priorPlan ? state.clarifyingQuestions : undefined,
      clarifyingAnswers: hasAnswers ? (state.clarifyingAnswers?.length ? state.clarifyingAnswers : syntheticFreeformAnswer) : undefined,
      clarificationAlreadyAsked: gate.force ? true : state.clarificationAlreadyAsked,
      clarificationRequiredBeforePlan: gate.force || undefined,
      clarificationRequirementReason: gate.forceReason,
      clarificationSkipReason: gate.skipReason,
      clarificationQualityRetryCount: feedback ? state.clarificationQualityRetryCount : undefined,
      planningDepth: settings.planning.depth,
      clarificationMode: settings.planning.clarificationMode,
      planProgress: planningProgress,
      currentReviewRetry: reviewerRepair ? state.currentReviewRetry : 0,
      workflowReviewRetryCount: reviewerRepair ? state.workflowReviewRetryCount : 0,
      maxReviewRetriesPerPlan: reviewerRepair ? state.maxReviewRetriesPerPlan : undefined,
      maxReviewRetriesPerWorkflow: reviewerRepair ? state.maxReviewRetriesPerWorkflow : undefined,
      lastReviewFailure: reviewerRepair ? state.lastReviewFailure : undefined,
      lastReviewAttempt: reviewerRepair ? state.lastReviewAttempt : undefined,
      lastReviewRepairStatus: reviewerRepair ? state.lastReviewRepairStatus : "none",
      reviewHistory: reviewerRepair ? state.reviewHistory : undefined,
      repairRetryState: reviewerRepair ? state.repairRetryState : undefined,
      lastCompletedPlanSummary: undefined,
      modelsUsed: { ...(state.modelsUsed ?? {}), planner: modelLabel(route) },
    }, ctx);
    queueWorkflowPrompt(
      pi,
      planPrompt(task, priorPlan, feedback, settings, { forceClarification: gate.force, forceReason: gate.forceReason, feedbackKind, preflightBlock: phasePreflightBlocks.Planning }),
      buildQueuedPlanningRecovery(ctx, (reason) => recoverPlanTransientHandoffFailure(ctx, "planning", reason, { phase: "Planning" })),
    );
  }

  async function beginExecution(ctx: ExtensionContext, auto = false): Promise<boolean> {
    if (!state.approvedPlan) {
      show(pi, "# Execute Refused\n\nNo approved plan exists. Run `/plan <task>` first.");
      return false;
    }
    const reviewBlock = planReviewContinuationBlock();
    if (reviewBlock) {
      clearPendingWorkflowToolPhase(ctx, "Execution", "plan reviewer repair blocks execution");
      const settings = loadWorkflowSettings(ctx.cwd);
      updateState({ mode: state.mode === "executing" ? "plan_approved" : state.mode, planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "plan_approved" }, settings, { lifecycleStatus: "blocked", nextAction: "review repair before execution" }, state.approvedPlan) : state.planProgress }, ctx);
      show(pi, `# Execute Refused\n\n${reviewBlock}`);
      return false;
    }
    const settings = loadWorkflowSettings(ctx.cwd);
    clearTypedHandoff(ctx, "Plan execution");
    if (extractApprovedPlanSteps(state.approvedPlan).length === 0) {
      show(pi, "# Execute Refused\n\nThe approved plan has no parser-safe implementation steps. Revise/regenerate the plan so progress can track the current approved plan.");
      return false;
    }
    const previousMode = state.mode;
    clearPendingWorkflowToolPhase(ctx, "Execution", "beginExecution");
    armWorkflowToolsForPhase(ctx, "Execution", "beginExecution");
    const currentProgress = mergePlanProgress({ ...state, mode: "executing" }, settings, { lifecycleStatus: "executing", validationStatus: "pending", repairStatus: state.lastRepairStatus ?? "none", nextAction: "validator" }, state.approvedPlan);
    const baseSteps = currentProgress.steps.length && !currentProgress.steps.some((step) => step.status === "active" || step.status === "completed")
      ? currentProgress.steps.map((step, index) => index === 0 ? { ...step, status: "active" as PlanStepStatus } : step)
      : currentProgress.steps;
    const activeIndex = currentStepIndexForSteps(baseSteps, currentProgress.currentStepIndex);
    const steps = settings.workflow.validateAfterEachStep === true || settings.workflow.requireApprovalPerStep === true
      ? baseSteps.map((step, index) => index === activeIndex ? { ...step, status: "active" as PlanStepStatus } : step.status === "active" ? { ...step, status: "pending" as PlanStepStatus } : step)
      : baseSteps;
    const execStepIndex = currentStepIndexForSteps(steps, activeIndex);
    const progressProofClear = clearPlanProgressToolProofPatch();
    const executionState: WorkflowState = { ...state, mode: "executing", planExecutionStepIndex: activeIndex, planProgress: { ...currentProgress, steps, currentStepIndex: execStepIndex }, ...progressProofClear, planTokensUsed: 0 };
    updateState(executionState, ctx);
    traceWorkflowTracking(ctx, "plan-execution-progress-required", { step: execStepIndex + 1, status: "active" });
    const executionPreflightExists = phasePreflightBlocks.Execution != null;
    if (!executionPreflightExists && !beginForcedSubagentPhase(ctx, "Execution", settings)) {
      const reason = "Execution blocked by forced sub-agent policy availability gate.";
      pi.setActiveTools(planToolsFor(settings));
      updateState({ mode: previousMode === "reviewed" ? "reviewed" : "plan_approved", planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: previousMode === "reviewed" ? "reviewed" : "plan_approved" }, settings, { lifecycleStatus: "blocked", nextAction: "fix execution policy blocker" }, state.approvedPlan) : state.planProgress }, ctx);
      queuePlanTerminalSummary(ctx, "blocked", "Plan execution blocked", { reason });
      return false;
    }
    const route = isMissionWorkflowMode(state) ? await applyMissionModelForRole(pi, ctx, "executor", { cwd: ctx.cwd }) : await applyPlanModelForRole(pi, ctx, "executor", { cwd: ctx.cwd });
    if (!route) {
      pi.setActiveTools(planToolsFor(settings));
      // Fix C2: include planProgress update when reverting mode so lifecycleStatus stays consistent.
      const revertMode = previousMode === "reviewed" ? "reviewed" as const : "plan_approved" as const;
      updateState({ mode: revertMode, planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: revertMode }, settings, { lifecycleStatus: revertMode === "reviewed" ? "reviewed" : "approved", nextAction: "executor" }, state.approvedPlan) : state.planProgress }, ctx);
      show(pi, "# Execution Blocked\n\nExecutor is enabled for this workflow path but its model could not be applied. Check /workflow-settings list, provider availability, and credentials, then run /plan continue.");
      return false;
    }
    updateState({ modelsUsed: { ...(state.modelsUsed ?? {}), executor: modelLabel(route) } }, ctx);
    armWorkflowToolsForPhase(ctx, "Execution", "beginExecution prompt queued");
    const executionSurfaceBlock = verifyWorkflowToolSurface(ctx, "Execution", "beginExecution prompt queued");
    if (executionSurfaceBlock) {
      return false;
    }
    queueAgentTurn(pi, executePrompt(executionState, settings, phasePreflightBlocks.Execution), auto ? "workflow-execute-trigger" : "workflow-execute-manual-trigger", buildQueuedPlanPhaseRecovery(ctx, "Execution", (reason) => recoverPlanTransientHandoffFailure(ctx, "execution", reason, { phase: "Execution" })));
    return true;
  }

  async function beginReview(ctx: ExtensionContext, auto = false): Promise<boolean> {
    if (!state.approvedPlan) {
      show(pi, "# Reviewer Refused\n\nNo approved plan exists.");
      return false;
    }
    const settings = loadWorkflowSettings(ctx.cwd);
    clearTypedHandoff(ctx, "Plan review");
    clearPendingWorkflowToolPhase(ctx, "Review", "beginReview");
    armWorkflowToolsForPhase(ctx, "Review", "beginReview");
    updateState({ mode: "reviewing", planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "reviewing" }, settings, { lifecycleStatus: "reviewing", nextAction: "executor" }, state.approvedPlan) : state.planProgress }, ctx);
    if (!beginForcedSubagentPhase(ctx, "Review", settings)) {
      const reason = "Review blocked by forced sub-agent policy availability gate.";
      updateState({ mode: "plan_approved", planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "plan_approved" }, settings, { lifecycleStatus: "blocked", nextAction: "fix review policy blocker" }, state.approvedPlan) : state.planProgress }, ctx);
      queuePlanTerminalSummary(ctx, "blocked", "Plan review blocked", { reason });
      return false;
    }
    const route = isMissionWorkflowMode(state) ? await applyMissionModelForRole(pi, ctx, "reviewer", { cwd: ctx.cwd }) : await applyPlanModelForRole(pi, ctx, "reviewer", { cwd: ctx.cwd });
    if (!route) {
      updateState({ mode: "plan_approved" }, ctx);
      show(pi, "# Reviewer Blocked\n\nReviewer is enabled but its model could not be applied. Check /workflow-settings list, provider availability, and credentials, then run /plan continue.");
      return false;
    }
    updateState({ modelsUsed: { ...(state.modelsUsed ?? {}), reviewer: modelLabel(route) } }, ctx);
    armWorkflowToolsForPhase(ctx, "Review", "beginReview prompt queued");
    if (auto) {
      queueAgentTurn(pi, reviewerPrompt(getState(), settings, phasePreflightBlocks.Review), "workflow-review-trigger", buildQueuedPlanPhaseRecovery(ctx, "Review", (reason) => recoverPlanTransientHandoffFailure(ctx, "review", reason, { phase: "Review" })));
    } else {
      queueWorkflowPrompt(pi, reviewerPrompt(state, settings), buildQueuedPlanPhaseRecovery(ctx, "Review", (reason) => recoverPlanTransientHandoffFailure(ctx, "review", reason, { phase: "Review" })));
    }
    return true;
  }

  async function continueAfterPlanApproval(ctx: ExtensionContext, auto = false): Promise<boolean> {
    if (!state.approvedPlan) {
      show(pi, "# Workflow Handoff Failed\n\nNo approved plan exists. Run `/plan <task>` to create and approve a new plan.");
      updateState({ mode: "awaiting_plan_input" }, ctx);
      return false;
    }
    const reviewBlock = planReviewContinuationBlock();
    if (reviewBlock) {
      clearPendingWorkflowToolPhase(ctx, "Execution", "plan review blocks continuation");
      show(pi, `# Workflow Handoff Paused\n\n${reviewBlock}`);
      return false;
    }
    const settings = loadWorkflowSettings(ctx.cwd);
    if (planModelAvailable(settings, "reviewer")) {
      if (settings.workflow.autoRunReviewerBeforeExecute === true
          && state.reviewerVerdict !== "PASS"
          && state.reviewerVerdict !== "NOTES") {
        return await beginReview(ctx, auto);
      }
      if (settings.workflow.offerReviewerBeforeExecute === true && ctx.hasUI && !auto
          && state.reviewerVerdict !== "PASS"
          && state.reviewerVerdict !== "NOTES") {
        const choice = await ctx.ui.select("Reviewer is available. Run reviewer before execution?", ["Run Reviewer", "Skip Reviewer", "Back"]);
        if (choice === "Run Reviewer") return await beginReview(ctx, false);
        if (choice === "Back") return false;
      }
    } else if (planModelEnabled(settings, "reviewer") && !planModelAvailable(settings, "reviewer") && settings.workflow.autoRunReviewerBeforeExecute === true) {
      show(pi, "# Reviewer Not Configured\n\nReviewer is enabled but no reviewer model is configured. Configure reviewer, disable reviewer, or turn off reviewer auto-run.");
      return false;
    }
    return await beginExecution(ctx, auto);
  }

  async function beginValidation(ctx: ExtensionContext, auto = false, revalidate = false, delivery: "queued" | "immediate" = "queued"): Promise<boolean> {
    if (!state.approvedPlan) {
      show(pi, "# Validate Refused\n\nNo approved plan exists.");
      return false;
    }
    if (isMissionWorkflowMode(state) && (activeMission ?? loadMissionState(state.activeMissionId ?? "latest"))) {
      await beginMissionValidation(ctx, auto, revalidate);
      return true;
    }
    const settings = loadWorkflowSettings(ctx.cwd);
    if (!planValidationBoundaryReached(state, settings)) {
      const reason = "Approved Plan execution is incomplete. Continue execution and complete the remaining Plan steps before validation.";
      updateState({
        mode: "reviewed",
        validationReport: undefined,
        validationVerdict: undefined,
        lastValidationFailure: undefined,
        lastRepairStatus: "none",
        lastRepairAttempt: undefined,
        planStepValidationIndex: undefined,
        planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "reviewed" }, settings, { lifecycleStatus: "reviewed", validationStatus: "pending", repairStatus: "none", nextAction: "continue execution" }, state.approvedPlan) : state.planProgress,
      }, ctx);
      show(pi, `# Plan Validation Refused\n\n${reason}\n\nUse /plan continue.`);
      return false;
    }
    const route = await applyPlanModelForRole(pi, ctx, "validator", { requireEnabled: false, cwd: ctx.cwd });
    if (!route) {
      const reason = "Plan validator model is disabled, unavailable, or not configured.";
      updateState({ mode: "validated", lastWorkflowHandoff: undefined, validationReport: reason, validationVerdict: "UNKNOWN", lastRepairStatus: revalidate ? "blocked" : (state.lastRepairStatus ?? "none"), planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "validated", validationVerdict: "UNKNOWN", lastRepairStatus: revalidate ? "blocked" : (state.lastRepairStatus ?? "none") }, settings, { lifecycleStatus: "blocked", validationStatus: "unknown", repairStatus: revalidate ? "blocked" : (state.lastRepairStatus ?? "none"), nextAction: "configure validator then revalidate" }) : state.planProgress, lastRepairAttempt: revalidate ? reason : state.lastRepairAttempt }, ctx);
      clearPendingWorkflowToolPhase(ctx, "Validation", revalidate ? "beginRevalidation validator unavailable" : "beginValidation validator unavailable");
      queuePlanTerminalSummary(ctx, "blocked", "Plan validation blocked", { reason });
      show(pi, `# Plan Validation Blocked\n\n${reason}\n\nWorkflow did not complete. Configure validator, then run /plan revalidate.`);
      showBlockedPlanRecoveryMenu(ctx);
      return false;
    }
    const validationMode = revalidate ? "revalidating" as const : "validating" as const;
    const validationState = { ...state, mode: validationMode, modelsUsed: { ...(state.modelsUsed ?? {}), validator: modelLabel(route) } };
    updateState({
      mode: validationMode,
      modelsUsed: validationState.modelsUsed,
      ...planValidationContextPatch(ctx),
      currentValidationHandoffRetry: undefined,
      maxValidationHandoffRetries: undefined,
      lastValidationHandoffFailure: undefined,
      planProgress: workflowPlanProgressEnabled(settings)
        ? mergePlanProgress(validationState, settings, { lifecycleStatus: revalidate ? "revalidating" : "validating", validationStatus: "running", nextAction: "validation result" }, state.approvedPlan)
        : state.planProgress,
    }, ctx);
    clearTypedHandoff(ctx, revalidate ? "Plan revalidation" : "Plan validation");
    clearPendingWorkflowToolPhase(ctx, "Validation", revalidate ? "beginRevalidation" : "beginValidation");
    armWorkflowToolsForPhase(ctx, "Validation", revalidate ? "beginRevalidation" : "beginValidation");
    if (!beginForcedSubagentPhase(ctx, "Validation", settings)) {
      const reason = "Validation blocked by forced sub-agent policy availability gate.";
      updateState({ mode: "validated", lastRepairStatus: revalidate ? "blocked" : (state.lastRepairStatus ?? "none"), planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "validated" }, settings, { lifecycleStatus: "blocked", validationStatus: "unknown", nextAction: "fix validation policy blocker then /plan revalidate" }, state.approvedPlan) : state.planProgress, lastRepairAttempt: revalidate ? reason : state.lastRepairAttempt }, ctx);
      queuePlanTerminalSummary(ctx, "blocked", "Plan validation blocked", { reason });
      return false;
    }
    const promptState = getState();
    armWorkflowToolsForPhase(ctx, "Validation", revalidate ? "beginRevalidation prompt queued" : "beginValidation prompt queued");
    if (auto) {
      const customType = revalidate ? "workflow-revalidate-trigger" : "workflow-validate-trigger";
      const prompt = validatePrompt(promptState, settings, phasePreflightBlocks.Validation);
      const options = buildQueuedPlanPhaseRecovery(ctx, "Validation", (reason) => recoverPlanTransientHandoffFailure(ctx, revalidate ? "revalidation" : "validation", reason, { phase: "Validation" }));
      if (delivery === "immediate") sendAgentTurnNowOrQueue(pi, prompt, customType, options);
      else queueAgentTurn(pi, prompt, customType, options);
    } else {
      queueWorkflowPrompt(pi, validatePrompt(promptState, settings, phasePreflightBlocks.Validation), buildQueuedPlanPhaseRecovery(ctx, "Validation", (reason) => recoverPlanTransientHandoffFailure(ctx, revalidate ? "revalidation" : "validation", reason, { phase: "Validation" })));
    }
    return true;
  }

  async function completeMissionRepairAndStartRevalidation(ctx: ExtensionContext, mission: MissionState, summary: string, typedSafetyBlock?: string) {
    const settings = loadWorkflowSettings(ctx.cwd);
    const milestone = mission.milestones[mission.currentMilestoneIndex];
    const repairSafetyBlock = typedSafetyBlock ?? repairSummaryRequiresApproval(summary, settings);
    if (repairSafetyBlock) {
      const blocked = saveActiveMission({ ...mission, status: "blocked", lastRepairStatus: "blocked", lastRepairAttempt: compact(summary, 1200), lastBlockReason: `Repair stopped for approval: ${repairSafetyBlock}`, nextAction: "Review the repair summary and approve safe next steps before retrying.", lastSummary: `Mission repair stopped for approval on ${milestone?.id ?? "current milestone"}.`, repairHistory: appendRepairHistory(mission, { timestamp: new Date().toISOString(), milestoneId: milestone?.id, retry: mission.currentValidationRetry ?? 0, status: "blocked", repairSummary: compact(summary, 800), nextAction: "Review repair summary and approve safe next steps before retrying." }) });
      checkpointMission(blocked, `Repair stopped for approval on ${milestone?.id ?? "current milestone"}: ${repairSafetyBlock}. ${compact(summary, 500)}`, "Review repair summary and approve safe next steps before retrying.", milestone?.id, { validationResult: blocked.lastValidationResult });
      updateState({ mode: "mission_blocked", activeMissionId: blocked.id, executionSummary: summary, lastMissionStopSummary: buildMissionStopSummary(ctx, blocked, "blocked", "Mission blocked", { reason: blocked.lastBlockReason }) }, ctx);
      recordWorkflowInternalEvent(ctx, "Internal workflow lifecycle event suppressed.");
      showBlockedMissionRecoveryMenu(ctx);
      return;
    }
    const repaired = saveActiveMission({
      ...mission,
      status: "revalidating",
      lastRepairStatus: "completed",
      lastRepairAttempt: compact(summary, 1200),
      nextAction: `Revalidate ${milestone?.id ?? "current milestone"} after repair retry ${mission.currentValidationRetry ?? 0}.`,
      lastSummary: `Repair completed for mission milestone ${milestone?.id ?? "current"}.`,
      repairHistory: appendRepairHistory(mission, { timestamp: new Date().toISOString(), milestoneId: milestone?.id, retry: mission.currentValidationRetry ?? 0, status: "completed", repairSummary: compact(summary, 800), nextAction: "Revalidate repaired milestone." }),
    });
    checkpointMission(repaired, `Repair completed for ${milestone?.id ?? "current milestone"}. Retry ${repaired.currentValidationRetry ?? 0}/${maxValidationRetries(repaired, settings)}. ${compact(summary, 500)}`, "Revalidation started after repair.", milestone?.id, { validationResult: repaired.lastValidationResult });
    updateState({ mode: "mission_revalidating", activeMissionId: repaired.id, executionSummary: summary }, ctx);
    if (repaired.lastFinalValidationFailure) {
      deferWorkflowAction(pi, "begin final mission validation after repair", () => beginMissionFinalValidation(ctx, activeMission ?? repaired, true), { timeoutMs: workflowDeferredPhaseTimeoutMs(ctx, "Validation"), onFailure: (error) => recoverMissionTransientHandoffFailure(ctx, "repair_revalidation", transientFailureReason("Mission repair completed but final validation handoff failed", error instanceof Error ? error.message : String(error)), { phase: "Validation", completedRepair: true }) });
      return;
    }
    deferWorkflowAction(pi, "begin mission revalidation after repair", () => beginMissionValidation(ctx, true, true), { timeoutMs: workflowDeferredPhaseTimeoutMs(ctx, "Validation"), onFailure: (error) => recoverMissionTransientHandoffFailure(ctx, "repair_revalidation", transientFailureReason("Mission repair completed but revalidation handoff failed", error instanceof Error ? error.message : String(error)), { phase: "Validation", completedRepair: true }) });
  }

  async function beginMissionValidation(ctx: ExtensionContext, auto = false, revalidate = false) {
    const mission = (state.activeMissionId ? loadMissionState(state.activeMissionId) : undefined) ?? activeMission ?? loadMissionState("latest");
    if (!mission) return show(pi, "# Mission Validate Refused\n\nNo active mission found.");
    const settings = loadWorkflowSettings(ctx.cwd);
    const executionSummary = missionExecutionSummaryForValidation(mission);
    if (!executionSummary?.trim()) {
      const milestone = mission.milestones[mission.currentMilestoneIndex];
      show(pi, `# Mission Validation Refused\n\nCannot validate ${milestone?.id ?? "current milestone"} because no same-mission milestone execution summary is available. Resume or rerun the current milestone before revalidating.`);
      return;
    }
    clearTypedHandoff(ctx, revalidate ? "Mission revalidation" : "Mission validation");
    const status = revalidate ? "revalidating" as const : "validating" as const;
    const mode = revalidate ? "mission_revalidating" as const : "mission_validating" as const;
    const validating = saveActiveMission({ ...mission, status, currentStep: "validator", nextAction: revalidate ? "Revalidate current mission milestone after repair." : "Validate current mission milestone.", lastSummary: `${revalidate ? "Revalidating" : "Validating"} mission milestone ${mission.milestones[mission.currentMilestoneIndex]?.id ?? "current"}.` });
    checkpointMission(validating, `${revalidate ? "Revalidation" : "Validation"} started for mission milestone ${mission.milestones[mission.currentMilestoneIndex]?.id ?? "current"}. Retry ${validating.currentValidationRetry ?? 0}/${maxValidationRetries(validating, settings)}.`, revalidate ? "Rerun validator after repair." : "Run validator for current milestone.", mission.milestones[mission.currentMilestoneIndex]?.id);
    pi.setActiveTools(validationToolsFor(settings));
    updateState({ mode, activeMissionId: validating.id, ...missionValidationContextPatch(ctx, validating), currentValidationHandoffRetry: undefined, maxValidationHandoffRetries: undefined, lastValidationHandoffFailure: undefined }, ctx);
    if (!beginForcedSubagentPhase(ctx, "Validation", settings, { label: "Mission Validation" })) {
      const paused = saveActiveMission({ ...validating, status: "paused", lastStopReason: "Mission validation blocked by forced sub-agent policy availability gate.", nextAction: "Fix sub-agent policy blocker, then run /mission revalidate or /mission continue.", lastSummary: "Mission validation blocked before validator prompt." });
      checkpointMission(paused, "Mission validation blocked by forced sub-agent policy availability gate.", "Fix sub-agent policy blocker, then run /mission revalidate or /mission continue.", mission.milestones[mission.currentMilestoneIndex]?.id);
      updateState({ mode: "mission_paused", activeMissionId: paused.id }, ctx);
      queueMissionTerminalSummary(ctx, paused, "blocked", "Mission validation paused", { reason: paused.lastStopReason });
      return;
    }
    const runtimeBlocked = missionRuntimeBudgetBlock(validating, settings);
    if (runtimeBlocked) {
      const milestone = mission.milestones[mission.currentMilestoneIndex];
      const paused = saveActiveMission({ ...mission, status: "paused", lastStopReason: runtimeBlocked, nextAction: "Mission active runtime budget reached. Review status before continuing.", lastSummary: runtimeBlocked });
      checkpointMission(paused, runtimeBlocked, "Mission active runtime budget reached. Review status before continuing.", milestone?.id);
      updateState({ mode: "mission_paused", activeMissionId: paused.id }, ctx);
      queueMissionTerminalSummary(ctx, paused, "blocked", "Mission runtime budget reached", { reason: runtimeBlocked });
      return show(pi, `# Mission Runtime Budget Reached\n\n${runtimeBlocked}\n\n${renderMissionStatus(activeMission ?? paused)}`);
    }
    const route = await applyMissionModelForRole(pi, ctx, "validator", { requireEnabled: false, cwd: ctx.cwd });
    if (!route) {
      const milestone = mission.milestones[mission.currentMilestoneIndex];
      const paused = saveActiveMission({ ...mission, status: "paused", lastStopReason: "Mission paused because validator model is disabled, unavailable, or not configured.", nextAction: "Configure validator, then run /mission resume or /mission continue. Mission will not advance without validation.", lastSummary: "Mission validation could not start; paused before milestone advancement." });
      checkpointMission(paused, "Mission validation could not start because validator model is disabled, unavailable, or not configured.", "Configure validator, then run /mission resume or /mission continue. Mission will not advance without validation.", milestone?.id);
      updateState({ mode: "mission_paused", activeMissionId: paused.id }, ctx);
      queueMissionTerminalSummary(ctx, paused, "blocked", "Mission validation paused", { reason: "Validator is unavailable." });
      show(pi, `# Mission Validation Paused\n\nValidator is unavailable. Mission did not advance.\n\n${renderMissionStatus(activeMission ?? paused)}`);
      return;
    }
    updateState({ modelsUsed: { ...(state.modelsUsed ?? {}), validator: modelLabel(route) } }, ctx);
    saveActiveMission({ ...validating, modelsUsed: { ...(validating.modelsUsed ?? {}), validator: modelLabel(route) } });
    const prompt = missionValidationPrompt(validating, settings, executionSummary, phasePreflightBlocks.Validation, state);
    if (auto) {
      queueAgentTurn(pi, prompt, revalidate ? "mission-revalidate-trigger" : "mission-validate-trigger", buildQueuedPhaseRecovery(ctx, "Validation", (reason) => recoverMissionTransientHandoffFailure(ctx, revalidate ? "revalidation" : "validation", reason, { phase: "Validation" })));
    } else queueWorkflowPrompt(pi, prompt, buildQueuedPhaseRecovery(ctx, "Validation", (reason) => recoverMissionTransientHandoffFailure(ctx, revalidate ? "revalidation" : "validation", reason, { phase: "Validation" })));
  }

  function appendWorkflowRepairHistory(entry: NonNullable<WorkflowState["repairHistory"]>[number]): WorkflowState["repairHistory"] {
    return [...(state.repairHistory ?? []), entry].slice(-20);
  }

  function showBlockedPlanRecoveryMenu(ctx: ExtensionContext): void {
    settleWorkflowRuntimeForUserWait(ctx, "blocked plan recovery menu");
    deferWorkflowMenuAction(pi, "show plan resume after blocked plan stop", () => handlePlanResume(ctx), {
      countsAsWorkflowWork: false,
      onSettled: () => settleWorkflowRuntimeForUserWait(ctx, "blocked plan recovery menu settled"),
    });
  }

  function showBlockedMissionRecoveryMenu(ctx: ExtensionContext): void {
    settleWorkflowRuntimeForUserWait(ctx, "blocked mission recovery menu");
    deferWorkflowMenuAction(pi, "show mission resume menu after blocked stop", () => handleMissionResume(ctx), {
      countsAsWorkflowWork: false,
      onSettled: () => settleWorkflowRuntimeForUserWait(ctx, "blocked mission recovery menu settled"),
    });
  }

  function repairTextIndicatesRevalidationReady(text: string | undefined): boolean {
    return /\brepair(?:ed)?\s+(?:completed|complete)\b|\brevalidation readiness\b|\bready for revalidation\b|\bsubmit for .*validation\b/i.test(text ?? "");
  }

  function planRepairCompletedPendingRevalidation(): boolean {
    if (state.mode === "executing" || state.mode === "validating" || state.mode === "repairing" || state.mode === "revalidating") return false;
    if (state.validationVerdict === "PASS") return false;
    const validationCompletedAt = state.lastValidationCompletedAt
      ?? (state.lastWorkflowHandoff?.type === "workflow_validation_result" ? state.lastWorkflowHandoff.createdAt : undefined);
    if (validationCompletedAt) {
      const latestCompletedRepair = [...(state.repairHistory ?? [])].reverse().find((entry) => entry.status === "completed");
      if (latestCompletedRepair?.timestamp && validationCompletedAt > latestCompletedRepair.timestamp) return false;
    }
    const typedRepairHandoff = state.lastWorkflowHandoff?.type === WORKFLOW_REPAIR_RESULT_TOOL && state.lastWorkflowHandoff.payload && typeof state.lastWorkflowHandoff.payload === "object"
      ? workflowTypedRepairDetails(state.lastWorkflowHandoff.payload as Record<string, unknown>)
      : undefined;
    const typedRepairAfterValidation = !validationCompletedAt || !state.lastWorkflowHandoff?.createdAt || state.lastWorkflowHandoff.createdAt > validationCompletedAt;
    if (typedRepairAfterValidation && typedRepairHandoff?.status === "completed" && !typedRepairHandoff.safetyBlocked) return true;
    const latestRepair = [...(state.repairHistory ?? [])].reverse().find((entry) => entry.status === "completed" || entry.status === "blocked" || entry.status === "running");
    return state.lastRepairStatus === "completed"
      || latestRepair?.status === "completed"
      || repairTextIndicatesRevalidationReady(state.lastRepairAttempt);
  }

  function missionRepairCompletedPendingRevalidation(mission: MissionState): boolean {
    const settings = loadWorkflowSettings(mission.cwd);
    if (mission.status === "running" || mission.status === "validating" || mission.status === "revalidating") return false;
    if (mission.status === "repairing" && !missionRepairGateInterrupted(mission, settings)) return false;
    if (mission.lastValidationResult === "PASS") return false;
    if (!(mission.lastValidationResult === "FAIL" || mission.lastValidationResult === "PARTIAL PASS" || mission.lastValidationFailure || mission.lastBlockReason)) return false;
    const verdict = mission.lastValidationResult === "FAIL" || mission.lastValidationResult === "PARTIAL PASS" || mission.lastValidationResult === "UNKNOWN" ? mission.lastValidationResult : "UNKNOWN";
    const failure = mission.lastValidationFailure || mission.lastBlockReason || "";
    if (mission.lastValidationResult === "PARTIAL PASS" && classifyValidationFailure(verdict, failure, {
      concreteRepairableIssue: mission.concreteRepairableIssue,
      manualVerificationRequired: mission.manualVerificationRequired,
      evidenceGap: mission.evidenceGap,
    }) !== "repairable") return false;
    const latestRepair = currentMissionRepairEntry(mission);
    return latestRepair?.status === "completed"
      || repairTextIndicatesRevalidationReady(latestRepair?.repairSummary)
      || repairTextIndicatesRevalidationReady(latestRepair?.nextAction)
      || repairTextIndicatesRevalidationReady(currentMissionRepairAttempt(mission));
  }

  async function startWorkflowRepair(ctx: ExtensionContext, source: "auto" | "user" = "auto") {
    if (!state.approvedPlan) return show(pi, "# Plan Repair Refused\n\nNo approved plan exists.");
    const settings = loadWorkflowSettings(ctx.cwd);
    if (!planValidationBoundaryReached(state, settings)) {
      const reason = "Approved Plan execution is incomplete. Repair is only available after a valid validation failure.";
      updateState({
        mode: "reviewed",
        validationReport: undefined,
        validationVerdict: undefined,
        lastValidationFailure: undefined,
        lastRepairStatus: "none",
        lastRepairAttempt: undefined,
        planStepValidationIndex: undefined,
        planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "reviewed" }, settings, { lifecycleStatus: "reviewed", validationStatus: "pending", repairStatus: "none", nextAction: "continue execution" }, state.approvedPlan) : state.planProgress,
      }, ctx);
      return show(pi, `# Plan Repair Refused\n\n${reason}\n\nUse /plan continue.`);
    }
    if (state.concreteRepairableIssue === false) {
      const reason = "No concrete repairable issue — validation recorded notes or manual follow-up only.";
      updateState({ mode: "validated", lastRepairStatus: "none", lastRepairAttempt: reason, planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "validated", lastRepairStatus: "none" }, settings, { lifecycleStatus: "completed", repairStatus: "none", nextAction: "accept notes or revalidate" }) : state.planProgress }, ctx);
      settleWorkflowRuntimeForUserWait(ctx, "plan repair not needed");
      show(pi, `# Repair Not Needed\n\n${reason}\n\nUse /plan revalidate after accepting notes/manual follow-up or /plan revise to update scope.`);
      return;
    }
    clearTypedHandoff(ctx, "Plan repair");
    const failure = state.lastValidationFailure || state.validationReport || "No validation failure details recorded.";
    const currentRetry = state.currentValidationRetry ?? 0;
    const maxRetries = workflowMaxValidationRetries(state, settings);
    const workflowRetry = workflowValidationRetryCount(state);
    const maxWorkflowRetries = workflowMaxValidationRetriesTotal(state, settings);
    const repairClass = classifyValidationFailure(state.validationVerdict ?? "UNKNOWN", failure, {
      concreteRepairableIssue: state.concreteRepairableIssue,
      manualVerificationRequired: state.manualVerificationRequired,
      evidenceGap: state.evidenceGap,
    });
    if (repairClass !== "repairable") {
      const reason = repairClass === "manual_only"
        ? "Validation recorded pass-with-notes or manual follow-up only; no concrete repair target is available."
        : "Validation needs clearer evidence before repair; run revalidation with the correct context instead of repairing.";
      updateState({ mode: "validated", lastRepairStatus: "none", lastRepairAttempt: reason, planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "validated", lastRepairStatus: "none" }, settings, { lifecycleStatus: "completed", repairStatus: "none", nextAction: "revalidate with clearer evidence or accept notes" }) : state.planProgress }, ctx);
      settleWorkflowRuntimeForUserWait(ctx, "plan repair refused no concrete target");
      show(pi, `# Plan Repair Refused\n\n${reason}\n\nUse /plan revalidate, /plan complete, or /plan revise <feedback>.`);
      return;
    }
    const decision = resolveRepairRetryDecision({ gate: "validation", verdict: state.validationVerdict ?? "FAIL", report: failure, settings, state, itemRetry: currentRetry, workflowRetry, requiredContextAvailable: Boolean(state.approvedPlan), manualOverride: source !== "auto" });
    if (!decision.allowed) {
      const reason = decision.reason ?? "repair requires approval or safety gate.";
      updateState({ mode: "validated", lastRepairStatus: "blocked", lastValidationFailure: failure, planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "validated", lastRepairStatus: "blocked" }, settings, { lifecycleStatus: "blocked", repairStatus: "blocked", nextAction: "manual repair or revise plan" }) : state.planProgress, lastRepairAttempt: reason, repairRetryState: { ...(state.repairRetryState ?? {}), validation: { currentRetry, workflowRetryCount: workflowRetry, maxRetriesPerItem: decision.maxRetriesPerItem, maxRetriesPerWorkflow: decision.maxRetriesPerWorkflow, lastFailure: failure, lastAttempt: reason, status: "blocked", inProgress: false, history: state.repairRetryState?.validation?.history } }, repairHistory: appendWorkflowRepairHistory({ timestamp: new Date().toISOString(), retry: currentRetry, status: "blocked", validationFailure: compact(failure, 800), nextAction: reason }) }, ctx);
      settleWorkflowRuntimeForUserWait(ctx, "plan repair policy blocked");
      recordWorkflowInternalEvent(ctx, "Internal workflow lifecycle event suppressed.");
      showBlockedPlanRecoveryMenu(ctx);
      return;
    }
    const repairPreflightExists = phasePreflightBlocks.Repair != null;
    if (!repairPreflightExists && !beginForcedSubagentPhase(ctx, "Repair", settings)) {
      const reason = "Repair blocked by forced sub-agent policy availability gate.";
      updateState({ mode: "validated", lastRepairStatus: "blocked", lastRepairAttempt: reason, lastValidationFailure: failure, planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "validated", lastRepairStatus: "blocked" }, settings, { lifecycleStatus: "blocked", repairStatus: "blocked", nextAction: reason }) : state.planProgress, repairHistory: appendWorkflowRepairHistory({ timestamp: new Date().toISOString(), retry: currentRetry, status: "blocked", validationFailure: compact(failure, 800), nextAction: reason }) }, ctx);
      settleWorkflowRuntimeForUserWait(ctx, "plan repair sub-agent policy blocked");
      queuePlanTerminalSummary(ctx, "blocked", "Plan repair blocked", { validationText: failure, reason });
      showBlockedPlanRecoveryMenu(ctx);
      return;
    }
    const route = await applyPlanModelForRole(pi, ctx, "executor", { cwd: ctx.cwd });
    if (!route) {
      updateState({ mode: "validated", lastRepairStatus: "blocked", lastRepairAttempt: "Repair executor model unavailable.", lastValidationFailure: failure }, ctx);
      settleWorkflowRuntimeForUserWait(ctx, "plan repair executor unavailable");
      showBlockedPlanRecoveryMenu(ctx);
      return;
    }
    const manualOverride = decision.manualOverride === true;
    const verdict = state.validationVerdict ?? "UNKNOWN";
    if (!manualOverride && verdict !== "FAIL" && !validationReportHasRepairableIssue(state.validationReport ?? state.lastValidationFailure ?? "")) {
      const reason = "No concrete repairable issue found; validation recorded notes or manual follow-up, not a repair task.";
      updateState({ mode: "validated", lastRepairStatus: "blocked", lastRepairAttempt: reason, lastValidationFailure: failure, planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "validated", lastRepairStatus: "blocked" }, settings, { lifecycleStatus: "blocked", repairStatus: "blocked", nextAction: reason }) : state.planProgress, repairHistory: appendWorkflowRepairHistory({ timestamp: new Date().toISOString(), retry: currentRetry, status: "blocked", validationFailure: compact(failure, 800), nextAction: reason }) }, ctx);
      settleWorkflowRuntimeForUserWait(ctx, "plan repair no concrete issue");
      queuePlanTerminalSummary(ctx, "blocked", "Plan repair blocked", { validationText: failure, reason });
      show(pi, `# Plan Repair Blocked\n\n${reason}\n\nNo repair retry was consumed. Use:\n- /plan complete (accept as done)\n- /plan revalidate\n- /plan revise <feedback>`);
      showBlockedPlanRecoveryMenu(ctx);
      return;
    }
    const retry = currentRetry + 1;
    const totalRetry = workflowRetry + 1;
    const effectiveMaxRetries = Math.max(maxRetries, retry);
    const effectiveMaxWorkflow = Math.max(maxWorkflowRetries, totalRetry);
    const repairProgress = workflowPlanProgressEnabled(settings)
      ? mergePlanProgress({ ...state, mode: "repairing", currentValidationRetry: retry, lastRepairStatus: "running" }, settings, { lifecycleStatus: "repairing", validationStatus: "fail", repairRetry: retry, maxRepairRetries: effectiveMaxRetries, repairStatus: "running", nextAction: "repair executor then validator" }, state.approvedPlan)
      : state.planProgress;
    const repairBaseSteps = repairProgress?.steps ?? [];
    const repairActiveIndex = currentStepIndexForSteps(repairBaseSteps, repairProgress?.currentStepIndex ?? 0);
    const repairSteps = repairBaseSteps.length
      ? repairBaseSteps.map((step, index) => index === repairActiveIndex && step.status !== "completed" && step.status !== "skipped" ? { ...step, status: "active" as PlanStepStatus } : step.status === "active" ? { ...step, status: "pending" as PlanStepStatus } : step)
      : repairBaseSteps;
    const repairProgressWithActiveStep = repairProgress ? { ...repairProgress, steps: repairSteps, currentStepIndex: currentStepIndexForSteps(repairSteps, repairActiveIndex) } : repairProgress;
    const repairProgressProofClear = clearPlanProgressToolProofPatch();
    updateState({
      mode: "repairing",
      currentValidationRetry: retry,
      workflowValidationRetryCount: totalRetry,
      maxValidationRetriesPerPlan: effectiveMaxRetries,
      maxValidationRetriesPerWorkflow: effectiveMaxWorkflow,
      lastRepairStatus: "running",
      repairRetryState: { ...(state.repairRetryState ?? {}), validation: { currentRetry: retry, workflowRetryCount: totalRetry, maxRetriesPerItem: effectiveMaxRetries, maxRetriesPerWorkflow: effectiveMaxWorkflow, lastFailure: failure, lastAttempt: `${manualOverride ? "Manual repair retry override" : `Plan repair retry`} ${retry}/${effectiveMaxRetries}; workflow retry ${totalRetry}/${effectiveMaxWorkflow} started by ${source}.`, status: "running", inProgress: true, history: [...(state.repairRetryState?.validation?.history ?? []), { timestamp: new Date().toISOString(), retry, status: "running" as const, failure: compact(failure, 800), nextAction: "Repair approved-plan validation failure, then revalidate." }].slice(-20) } },
      planProgress: repairProgressWithActiveStep,
      ...repairProgressProofClear,
      lastRepairAttempt: `${manualOverride ? "Manual repair retry override" : `Plan repair retry`} ${retry}/${effectiveMaxRetries}; workflow retry ${totalRetry}/${effectiveMaxWorkflow} started by ${source}.`,
      lastValidationFailure: failure,
      repairHistory: appendWorkflowRepairHistory({ timestamp: new Date().toISOString(), retry, status: "running", validationFailure: compact(failure, 800), nextAction: "Repair approved-plan validation failure, then revalidate." }),
      lastPlanStopSummary: undefined,
      modelsUsed: { ...(state.modelsUsed ?? {}), executor: modelLabel(route) },
    }, ctx);
    traceWorkflowTracking(ctx, "plan-repair-progress-required", { step: (repairProgressWithActiveStep?.currentStepIndex ?? repairActiveIndex) + 1, status: "active" });
    pi.setActiveTools(executionToolsFor(settings));
    if (source !== "auto") show(pi, manualOverride
      ? `# Plan Repair Started (Manual Override)\n\nRetry: ${retry} (capped at ${maxRetries}) per plan\nWorkflow Retry: ${totalRetry} (capped at ${maxWorkflowRetries}) total\n\nManual override bypassed automatic retry limits. Repairing only the approved-plan validation failure.`
      : `# Plan Repair Started\n\nRetry: ${retry} of ${effectiveMaxRetries} per plan\nWorkflow Retry: ${totalRetry} of ${effectiveMaxWorkflow} total\n\nRepairing only the approved-plan validation failure.`);
    queueWorkflowPrompt(pi, workflowRepairPrompt(state, settings, phasePreflightBlocks.Repair), buildQueuedPlanPhaseRecovery(ctx, "Repair", (reason) => recoverPlanTransientHandoffFailure(ctx, "repair", reason, { phase: "Repair", preserveRetry: true })));
  }

  async function handleWorkflowRetryCommand(ctx: ExtensionContext, action: "retry" | "repair" | "revalidate") {
    const settings = loadWorkflowSettings(ctx.cwd);
    if (action === "revalidate") {
      if (!state.approvedPlan && (state.mode === "idle" || state.mode === "cancelled" || state.mode === "awaiting_plan_input")) {
        const latest = latestRecoverablePlan();
        if (latest) recoverPlanFromHistory(ctx, latest);
      }
      if (state.approvedPlan && !planValidationBoundaryReached(state, settings)) {
        const reason = "Approved Plan execution is incomplete. Continue execution and complete the remaining Plan steps before validation.";
        updateState({
          mode: "reviewed",
          validationReport: undefined,
          validationVerdict: undefined,
          lastValidationFailure: undefined,
          lastRepairStatus: "none",
          lastRepairAttempt: undefined,
          planStepValidationIndex: undefined,
          planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "reviewed" }, settings, { lifecycleStatus: "reviewed", validationStatus: "pending", repairStatus: "none", nextAction: "continue execution" }, state.approvedPlan) : state.planProgress,
        }, ctx);
        return show(pi, `# Plan Revalidate Refused\n\n${reason}\n\nUse /plan continue.`);
      }
      return beginValidation(ctx, true, true);
    }
    if (await handlePlanReviewRepairRecovery(ctx, action)) return;
    if (state.approvedPlan && !planValidationBoundaryReached(state, settings)) {
      const reason = "Approved Plan execution is incomplete. Repair is only available after a valid validation failure.";
      updateState({
        mode: "reviewed",
        validationReport: undefined,
        validationVerdict: undefined,
        lastValidationFailure: undefined,
        lastRepairStatus: "none",
        lastRepairAttempt: undefined,
        planStepValidationIndex: undefined,
        planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "reviewed" }, settings, { lifecycleStatus: "reviewed", validationStatus: "pending", repairStatus: "none", nextAction: "continue execution" }, state.approvedPlan) : state.planProgress,
      }, ctx);
      return show(pi, `# Plan ${action}\n\n${reason}\n\nUse /plan continue.`);
    }
    if (state.mode === "executing" || state.mode === "validating" || state.mode === "repairing" || state.mode === "revalidating") return show(pi, `# Plan ${action}\n\nCannot ${action}: workflow is currently ${state.mode}. Wait for the active gate first.`);
    const hasValidationFailure = Boolean(state.lastValidationFailure || state.validationReport || state.validationVerdict === "FAIL" || state.validationVerdict === "PARTIAL PASS");
    if (!hasValidationFailure) return show(pi, `# Plan ${action}\n\nCannot ${action}: no validation failure is recorded.`);
    if (action === "retry" && planRepairCompletedPendingRevalidation()) {
      return beginValidation(ctx, true, true);
    }
    await startWorkflowRepair(ctx, "user");
  }

  function latestRecoverablePlan(): SavedWorkflowPlan | undefined {
    const latest = loadWorkflowPlan("latest");
    if (latest?.finalPlan?.trim() && (latest.approvalStatus === "approved" || latest.approvalStatus === "revised")) return latest;
    return listWorkflowPlans().find((plan) => plan.finalPlan?.trim() && (plan.approvalStatus === "approved" || plan.approvalStatus === "revised"));
  }

  function recoverablePlanDetails(plan: SavedWorkflowPlan): string {
    const task = compact(plan.originalTask || "Recovered approved plan", 180).replace(/\n/g, " ");
    return `Plan ID: ${plan.id}\nStatus: ${plan.approvalStatus}\nTimestamp: ${plan.timestamp ?? "unknown"}\nProject: ${plan.projectLabel ?? plan.projectPath ?? "unknown"}\nTask: ${task}`;
  }

  function planIdentityMatchesSavedPlan(candidate: WorkflowState, plan: SavedWorkflowPlan): boolean {
    if (candidate.planHistoryId === plan.id || candidate.approvedPlanHistoryId === plan.id || candidate.activePlanId === plan.id) return true;
    return Boolean(candidate.approvedPlan?.trim() && plan.finalPlan?.trim() && candidate.approvedPlan.trim() === plan.finalPlan.trim());
  }

  function completedPlanProgressStepCount(candidate: WorkflowState): number {
    return candidate.planProgress?.steps.filter((step) => step.status === "completed").length ?? 0;
  }

  function advancedPlanRuntimeSnapshotScore(candidate: WorkflowState): number {
    if (isMissionWorkflowMode(candidate) || !candidate.approvedPlan?.trim()) return -1;
    const completedSteps = completedPlanProgressStepCount(candidate);
    const allStepsCompleted = Boolean(candidate.planProgress?.steps.length && completedSteps === candidate.planProgress.steps.length);
    const validationPending = candidate.planProgress?.validationStatus === "pending" || candidate.planProgress?.nextAction === "validator";
    if (candidate.mode === "validated") return 700 + completedSteps;
    if (candidate.mode === "validating" || candidate.mode === "revalidating") return 650 + completedSteps;
    if (candidate.mode === "executed" && (candidate.executionSummary?.trim() || allStepsCompleted || validationPending)) return 600 + completedSteps;
    if (candidate.mode === "executing" && completedSteps > 0) return 400 + completedSteps;
    return -1;
  }

  function workflowStateFromSessionEntry(entry: unknown): WorkflowState | undefined {
    if (!isPlainRecord(entry) || entry.type !== "custom") return undefined;
    if (entry.customType !== workflowSessionStateEntryType && entry.customType !== legacyWorkflowSessionStateEntryType) return undefined;
    const data = isPlainRecord(entry.data) ? entry.data : undefined;
    if (!data || typeof data.mode !== "string") return undefined;
    return reconcileRestoredWorkflowState({ ...emptyState(), ...(data as Partial<WorkflowState>), version: 1 });
  }

  function projectSessionDirectoryName(cwd: string): string {
    return `--${cwd.replace(/^\/+/, "").replace(/[\\/]/g, "-")}--`;
  }

  function workflowStateSnapshotsFromProjectSessionFiles(ctx: ExtensionContext, plan: SavedWorkflowPlan): WorkflowState[] {
    const dir = join(USER_SESSIONS_DIR, projectSessionDirectoryName(ctx.cwd));
    if (!existsSync(dir)) return [];
    let files: string[] = [];
    try {
      files = readdirSync(dir)
        .filter((file) => file.endsWith(".jsonl"))
        .sort((a, b) => b.localeCompare(a))
        .slice(0, 8);
    } catch {
      return [];
    }
    const snapshots: WorkflowState[] = [];
    for (const file of files) {
      let text = "";
      try {
        text = readFileSync(join(dir, file), "utf8");
      } catch {
        continue;
      }
      for (const line of text.split(/\n/)) {
        if (!line.includes(workflowSessionStateEntryType) && !line.includes(legacyWorkflowSessionStateEntryType)) continue;
        if (plan.id !== "active" && !line.includes(plan.id) && !line.includes("executionSummary")) continue;
        try {
          const candidate = workflowStateFromSessionEntry(JSON.parse(line));
          if (candidate && planIdentityMatchesSavedPlan(candidate, plan)) snapshots.push(candidate);
        } catch {
          // Ignore malformed or truncated session lines.
        }
      }
    }
    return snapshots;
  }

  function findAdvancedPlanRuntimeSnapshot(ctx: ExtensionContext, plan: SavedWorkflowPlan): WorkflowState | undefined {
    let best: { state: WorkflowState; score: number; index: number } | undefined;
    let branch: unknown[] = [];
    try {
      branch = [...ctx.sessionManager.getBranch()];
    } catch {
      branch = [];
    }
    branch.forEach((entry, index) => {
      const candidate = workflowStateFromSessionEntry(entry);
      if (!candidate || !planIdentityMatchesSavedPlan(candidate, plan)) return;
      const score = advancedPlanRuntimeSnapshotScore(candidate);
      if (score < 0) return;
      if (!best || score > best.score || (score === best.score && index > best.index)) best = { state: candidate, score, index };
    });
    workflowStateSnapshotsFromProjectSessionFiles(ctx, plan).forEach((candidate, offset) => {
      const score = advancedPlanRuntimeSnapshotScore(candidate);
      if (score < 0) return;
      const index = branch.length + offset;
      if (!best || score > best.score || (score === best.score && index > best.index)) best = { state: candidate, score, index };
    });
    return best?.state;
  }

  function currentPlanForRuntimeRecovery(ctx: ExtensionContext): SavedWorkflowPlan | undefined {
    const planId = state.approvedPlanHistoryId ?? state.planHistoryId;
    const byId = planId ? loadWorkflowPlan(planId) : undefined;
    if (byId?.finalPlan?.trim()) return byId;
    const latest = loadWorkflowPlan("latest");
    if (latest?.finalPlan?.trim() && planIdentityMatchesSavedPlan(state, latest)) return latest;
    const matching = listWorkflowPlans().find((plan) => plan.finalPlan?.trim() && planIdentityMatchesSavedPlan(state, plan));
    if (matching) return matching;
    if (!state.approvedPlan?.trim()) return undefined;
    return {
      id: planId ?? state.activePlanId ?? "active",
      timestamp: state.updatedAt ?? new Date().toISOString(),
      projectPath: ctx.cwd,
      projectLabel: basename(ctx.cwd),
      planningMode: state.mode,
      originalTask: state.originalTask ?? state.task,
      finalPlan: state.approvedPlan,
      approvalStatus: "approved",
      saveReason: "active runtime recovery",
    };
  }

  function findAdvancedPlanRuntimeSnapshotForCurrentState(ctx: ExtensionContext): WorkflowState | undefined {
    const plan = currentPlanForRuntimeRecovery(ctx);
    if (!plan) return undefined;
    const snapshot = findAdvancedPlanRuntimeSnapshot(ctx, plan);
    if (!snapshot) return undefined;
    return advancedPlanRuntimeSnapshotScore(snapshot) > advancedPlanRuntimeSnapshotScore(state) ? snapshot : undefined;
  }

  function restorePlanRuntimeSnapshot(ctx: ExtensionContext, snapshot: WorkflowState): void {
    activeMission = undefined;
    const restored = reconcileRestoredWorkflowState({ ...emptyState(), ...snapshot, activeMissionId: undefined, version: 1 });
    state = persistWorkflowState(restored, ctx);
    setWorkflowUi(ctx, state, activeSubagents);
    syncWorkflowUiClockTicker(ctx);
  }

  function restorePlanRuntimeSnapshotForResume(ctx: ExtensionContext, snapshot: WorkflowState): void {
    restorePlanRuntimeSnapshot(ctx, snapshot);
  }

  function planValidationRuntimeIsStale(ctx: ExtensionContext): boolean {
    if (state.mode !== "validating" && state.mode !== "revalidating") return false;
    if (state.lastWorkflowHandoff?.type === WORKFLOW_VALIDATION_RESULT_TOOL) return false;
    if (state.validationVerdict || state.validationReport?.trim()) return false;
    return !workflowHasActiveOrPendingValidationWork(ctx);
  }

  function planActiveRuntimePhase(mode = state.mode): WorkflowPendingToolPhase | undefined {
    if (mode === "reviewing") return "Review";
    if (mode === "executing") return "Execution";
    if (mode === "validating" || mode === "revalidating") return "Validation";
    if (mode === "repairing") return "Repair";
    return undefined;
  }

  function requiredPlanRuntimePhaseTools(phase: WorkflowPendingToolPhase, settings: ReturnType<typeof loadWorkflowSettings>): string[] {
    if (phase === "Execution") return requiredPlanExecutionTools(settings);
    if (phase === "Review") return [WORKFLOW_REVIEW_RESULT_TOOL];
    if (phase === "Validation") return [WORKFLOW_VALIDATION_RESULT_TOOL];
    if (phase === "Repair") return ["edit", "write", "bash", WORKFLOW_PROGRESS_TOOL, WORKFLOW_REPAIR_RESULT_TOOL];
    return [WORKFLOW_PLAN_RESULT_TOOL];
  }

  function missingPlanRuntimePhaseTools(phase: WorkflowPendingToolPhase, settings: ReturnType<typeof loadWorkflowSettings>): string[] {
    const active = new Set(pi.getActiveTools());
    return requiredPlanRuntimePhaseTools(phase, settings).filter((tool) => !active.has(tool));
  }

  function workflowRuntimeIsIdle(ctx: ExtensionContext): boolean {
    try { return ctx.isIdle(); } catch { return false; }
  }

  function planActiveRuntimeHasPendingWork(ctx: ExtensionContext): boolean {
    return workflowActiveToolExecutions > 0
      || workflowScheduledAgentTurns > 0
      || runningSubagentActivity()
      || Boolean(pendingWorkflowToolPhase)
      || workflowHasQueuedMessages(ctx)
      || !workflowRuntimeIsIdle(ctx);
  }

  function planActiveRuntimeIsRecoverablyStale(ctx: ExtensionContext): boolean {
    const phase = planActiveRuntimePhase();
    if (!phase) return false;
    if (state.mode === "validating" || state.mode === "revalidating") return planValidationRuntimeIsStale(ctx);
    if (planActiveRuntimeHasPendingWork(ctx)) return false;
    return true;
  }

  function planActiveRuntimeStaleReason(ctx: ExtensionContext): string {
    const settings = loadWorkflowSettings(ctx.cwd);
    const phase = planActiveRuntimePhase();
    const missing = phase ? missingPlanRuntimePhaseTools(phase, settings) : [];
    const missingText = missing.length ? ` Missing active ${phase} tools: ${missing.join(", ")}.` : "";
    return `Persisted Plan mode is ${state.mode}, but no active or queued workflow work is present.${missingText}`;
  }

  async function resumeInterruptedPlanValidation(ctx: ExtensionContext, title: string): Promise<boolean> {
    const settings = loadWorkflowSettings(ctx.cwd);
    const revalidate = state.mode === "revalidating";
    if (!planValidationBoundaryReached(state, settings)) {
      show(pi, `# ${title}\n\nRecovered interrupted Plan validation runtime, but approved Plan execution is incomplete. Re-arming executor for the current incomplete step.`);
      updateState({
        mode: "reviewed",
        validationReport: undefined,
        validationVerdict: undefined,
        lastValidationFailure: undefined,
        lastRepairStatus: "none",
        lastRepairAttempt: undefined,
        planStepValidationIndex: undefined,
        planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "reviewed" }, settings, { lifecycleStatus: "reviewed", validationStatus: "pending", repairStatus: "none", nextAction: "executor" }, state.approvedPlan) : state.planProgress,
      }, ctx);
      await beginExecution(ctx, true);
      return true;
    }
    if (!planValidationGateActive(settings)) {
      show(pi, `# ${title}\n\nRecovered interrupted Plan validation runtime. Validation is disabled or unavailable for this workflow.`);
      await completePlanWithoutValidation(ctx, "Validation skipped: validation gate is disabled for this workflow.");
      return true;
    }
    show(pi, `# ${title}\n\nRecovered interrupted Plan validation runtime. Re-running validator.`);
    const started = await beginValidation(ctx, true, revalidate, "immediate");
    if (!started && (state.mode === "validating" || state.mode === "revalidating")) {
      markPlanValidationHandoffDidNotStart(ctx, settings, "Recovered Plan validation runtime could not restart. Fix the validation blocker, then run /plan revalidate.");
    }
    return true;
  }

  async function resumeInterruptedPlanExecution(ctx: ExtensionContext, title: string): Promise<boolean> {
    const reason = planActiveRuntimeStaleReason(ctx);
    recordWorkflowInternalEvent(ctx, `Recovered stale Plan execution runtime. ${reason}`);
    show(pi, `# ${title}\n\nRecovered interrupted Plan execution runtime. Re-arming executor for the current active step.\n\n${workflowDisplayText(reason)}`);
    await beginExecution(ctx, true);
    return true;
  }

  async function resumeInterruptedPlanReview(ctx: ExtensionContext, title: string): Promise<boolean> {
    const reason = planActiveRuntimeStaleReason(ctx);
    recordWorkflowInternalEvent(ctx, `Recovered stale Plan review runtime. ${reason}`);
    show(pi, `# ${title}\n\nRecovered interrupted Plan review runtime. Re-running reviewer.\n\n${workflowDisplayText(reason)}`);
    await beginReview(ctx, true);
    return true;
  }

  async function resumeInterruptedPlanRepair(ctx: ExtensionContext, title: string): Promise<boolean> {
    const reason = planActiveRuntimeStaleReason(ctx);
    const settings = loadWorkflowSettings(ctx.cwd);
    const route = await applyPlanModelForRole(pi, ctx, "executor", { cwd: ctx.cwd });
    if (!route) {
      show(pi, `# ${title}\n\nRecovered interrupted Plan repair runtime, but the executor model could not be applied. Configure executor, then run /plan repair or /plan retry.\n\n${workflowDisplayText(reason)}`);
      return true;
    }
    clearPendingWorkflowToolPhase(ctx, "Repair", "resumeInterruptedPlanRepair");
    armWorkflowToolsForPhase(ctx, "Repair", "resumeInterruptedPlanRepair");
    updateState({
      mode: "repairing",
      lastRepairStatus: "running",
      modelsUsed: { ...(state.modelsUsed ?? {}), executor: modelLabel(route) },
      planProgress: workflowPlanProgressEnabled(settings)
        ? mergePlanProgress({ ...state, mode: "repairing", lastRepairStatus: "running" }, settings, { lifecycleStatus: "repairing", repairStatus: "running", nextAction: "repair executor then validator" }, state.approvedPlan)
        : state.planProgress,
    }, ctx);
    recordWorkflowInternalEvent(ctx, `Recovered stale Plan repair runtime. ${reason}`);
    show(pi, `# ${title}\n\nRecovered interrupted Plan repair runtime. Re-arming repair executor.\n\n${workflowDisplayText(reason)}`);
    queueWorkflowPrompt(pi, workflowRepairPrompt(state, settings, phasePreflightBlocks.Repair), buildQueuedPlanPhaseRecovery(ctx, "Repair", (failureReason) => recoverPlanTransientHandoffFailure(ctx, "repair", failureReason, { phase: "Repair", preserveRetry: true })));
    return true;
  }

  async function continueRestoredPlanRuntime(ctx: ExtensionContext, title: string, snapshot: WorkflowState): Promise<boolean> {
    restorePlanRuntimeSnapshot(ctx, snapshot);
    const settings = loadWorkflowSettings(ctx.cwd);
    const validationAvailable = planValidationGateActive(settings);
    if ((state.mode === "executed" || state.mode === "validated" || state.mode === "validating" || state.mode === "revalidating") && planExecutionIncomplete(state, settings)) {
      show(pi, `# ${title}\n\nRecovered Plan runtime from session history, but approved Plan execution is incomplete. Continuing execution from the current incomplete step.`);
      updateState({
        mode: "reviewed",
        validationReport: undefined,
        validationVerdict: undefined,
        lastValidationFailure: undefined,
        lastRepairStatus: "none",
        lastRepairAttempt: undefined,
        planStepValidationIndex: undefined,
        planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "reviewed" }, settings, { lifecycleStatus: "reviewed", validationStatus: "pending", repairStatus: "none", nextAction: "executor" }, state.approvedPlan) : state.planProgress,
      }, ctx);
      await beginExecution(ctx, true);
      return true;
    }
    if (state.mode === "executed" && validationAvailable) {
      show(pi, `# ${title}\n\nRecovered executed Plan runtime from session history. Continuing to validation.`);
      await beginValidation(ctx, true, false, "immediate");
      return true;
    }
    if (state.mode === "executed") {
      show(pi, `# ${title}\n\nRecovered executed Plan runtime from session history. Validation is disabled or unavailable for this workflow.`);
      await completePlanWithoutValidation(ctx, "Validation skipped: validation gate is disabled for this workflow.");
      return true;
    }
    if (state.mode === "validating" || state.mode === "revalidating") {
      if (planValidationRuntimeIsStale(ctx)) return resumeInterruptedPlanValidation(ctx, title);
      show(pi, `# ${title}\n\nRecovered active Plan validation runtime from session history. Wait for validation result.`);
      return true;
    }
    if (state.mode === "validated") {
      show(pi, `# ${title}\n\nRecovered validated Plan runtime from session history. Run /plan continue to complete or recover according to the validation result.`);
      return true;
    }
    if (state.mode === "executing") {
      if (planActiveRuntimeIsRecoverablyStale(ctx)) return resumeInterruptedPlanExecution(ctx, title);
      show(pi, `# ${title}\n\nRecovered active Plan execution runtime from session history. Wait for execution completion.`);
      return true;
    }
    if (state.mode === "reviewing") {
      if (planActiveRuntimeIsRecoverablyStale(ctx)) return resumeInterruptedPlanReview(ctx, title);
      show(pi, `# ${title}\n\nRecovered active Plan review runtime from session history. Wait for reviewer completion.`);
      return true;
    }
    if (state.mode === "repairing") {
      if (planActiveRuntimeIsRecoverablyStale(ctx)) return resumeInterruptedPlanRepair(ctx, title);
      show(pi, `# ${title}\n\nRecovered active Plan repair runtime from session history. Wait for repair completion.`);
      return true;
    }
    return false;
  }

  function recoverPlanFromHistory(ctx: ExtensionContext, plan: SavedWorkflowPlan): void {
    const settings = loadWorkflowSettings(ctx.cwd);
    activeMission = undefined;
    const hasPersistedProgress = plan.planProgress && plan.planProgress.steps.some((s) => s.status === "completed" || s.status === "active");
    updateState({
      mode: "plan_approved",
      activeMissionId: undefined,
      task: plan.originalTask ?? "Recovered approved plan",
      originalTask: plan.originalTask ?? "Recovered approved plan",
      draftPlan: undefined,
      approvedPlan: plan.finalPlan,
      planHistoryId: plan.id,
      approvedPlanHistoryId: plan.id,
      validationReport: undefined,
      validationVerdict: undefined,
      executionSummary: undefined,
      reviewerReport: undefined,
      reviewerVerdict: undefined,
      currentReviewRetry: 0,
      workflowReviewRetryCount: plan.reviewHistory?.length ?? 0,
      maxReviewRetriesPerPlan: undefined,
      maxReviewRetriesPerWorkflow: undefined,
      lastReviewFailure: undefined,
      lastReviewAttempt: undefined,
      lastReviewRepairStatus: "none",
      reviewHistory: plan.reviewHistory,
      reviewRepairInProgress: undefined,
      lastValidationFailure: undefined,
      lastRepairAttempt: undefined,
      repairHistory: plan.repairHistory,
      lastRepairStatus: "none",
      currentValidationRetry: plan.currentValidationRetry ?? 0,
      workflowValidationRetryCount: plan.workflowValidationRetryCount ?? 0,
      planStepValidationIndex: plan.planStepValidationIndex,
      planExecutionStepIndex: plan.planExecutionStepIndex,
      planRuntime: plan.planRuntime,
      repairRetryState: plan.repairRetryState,
      planProgress: hasPersistedProgress ? plan.planProgress : (workflowPlanProgressEnabled(settings) ? createPlanProgress(plan.finalPlan, settings, "approved") : undefined),
    }, ctx);
  }

  function planRecoveryGuidance(current: WorkflowState, validationAvailable: boolean, activeRuntimeStale = false, settings = loadWorkflowSettings()): string {
    if ((current.mode === "executed" || current.mode === "validated" || current.mode === "validating" || current.mode === "revalidating") && planExecutionIncomplete(current, settings)) {
      return "Approved Plan execution is incomplete. Next action: /plan continue to complete the remaining steps before validation or repair.";
    }
    if (current.mode === "idle" || current.mode === "cancelled" || current.mode === "awaiting_plan_input") {
      const latest = latestRecoverablePlan();
      if (latest) return `No active Plan Mode workflow is loaded. Recoverable approved plan found.\n\n${recoverablePlanDetails(latest)}\n\nNext action: /plan resume to restore it, /plan continue to run it, or /p <task> to start a new plan.`;
      return current.mode === "awaiting_plan_input" ? "Plan Mode is ready and waiting for a planning request. Next action: enter a task with /p <task> or type the request as a normal message." : "No active Plan Mode workflow found. Start one with /p <task> or enter ready state with /p.";
    }
    if (current.mode === "planning") return "Planner is already running. Wait for the draft plan or clarification request.";
    if (current.mode === "awaiting_clarification") return "Plan is waiting for clarification answers. Next action: reply with choices like 1A, 2C, or use /clarify questions.";
    if (current.mode === "plan_draft") return "Draft plan is ready. Next action: /plan approve, /plan revise <feedback>, or /plan cancel.";
    if (current.mode === "plan_approved") return "Approved plan is loaded. Next action: /plan continue, /plan revalidate, /plan revise <feedback>, or /plan cancel.";
    if (current.mode === "reviewing") return activeRuntimeStale ? "Reviewer appears interrupted. Next action: /plan continue to rearm reviewer." : "Reviewer is already running. Wait for reviewer completion.";
    if (current.mode === "reviewed") return "Reviewer is complete. Next action: /plan continue to execute.";
    if (current.mode === "executing") return activeRuntimeStale ? "Execution appears interrupted. Next action: /plan continue to rearm executor." : "Executor is already running. Wait for execution completion.";
    if (current.mode === "executed") return validationAvailable ? "Execution is complete. Next action: /plan continue to validate." : "Execution is complete and validation is not active for this workflow. Next action: /plan continue to finish.";
    if (current.mode === "validating" || current.mode === "revalidating") return activeRuntimeStale ? "Validation appears interrupted. Next action: /plan continue to rearm validator." : "Validator is already running. Wait for validation result.";
    if (current.mode === "repairing") return activeRuntimeStale ? "Repair appears interrupted. Next action: /plan continue to rearm repair executor." : "Executor is already running in repair mode. Revalidation will start after repair completes.";
    if (current.mode === "validated" && current.validationVerdict === "PASS") return "Validation passed. Next action: /plan continue to complete and return to ready state.";
    if (current.mode === "validated" && current.validationVerdict === "PARTIAL PASS") return classifyValidationFailure(current.validationVerdict, current.validationReport ?? current.lastValidationFailure ?? "", { concreteRepairableIssue: current.concreteRepairableIssue, manualVerificationRequired: current.manualVerificationRequired, evidenceGap: current.evidenceGap }) === "repairable" ? "Validation partially passed with repairable issues. Next actions: /plan repair, /plan retry, /plan revalidate, or /plan revise <feedback>." : "Validation partially passed with notes. Next action: accept, revalidate, or revise if scope changed.";
    if (current.mode === "validated" && (current.validationVerdict === "FAIL" || current.lastValidationFailure)) return "Validation failed. Next actions: /plan repair, /plan retry, /plan revalidate, or /plan revise <feedback>.";
    if (current.mode === "validated" && current.approvedPlan && validationAvailable) return "Validation status is unknown. Next action: /plan revalidate.";
    return `No safe automatic continuation is available for state: ${current.mode}.`;
  }

  function planMatchesCurrentProject(ctx: ExtensionContext, plan?: SavedWorkflowPlan): boolean {
    return Boolean(plan?.projectPath && plan.projectPath === ctx.cwd);
  }

  function resolveActivePlanForResume(ctx: ExtensionContext): { plan?: SavedWorkflowPlan; candidates: SavedWorkflowPlan[]; source: "active" | "history" | "fallback" | "none"; reason?: string } {
    const candidates = listWorkflowPlans()
      .filter((plan) => plan.finalPlan?.trim() && (plan.approvalStatus === "approved" || plan.approvalStatus === "revised"))
      .sort((a, b) => (b.timestamp ?? "").localeCompare(a.timestamp ?? ""));
    const latest = loadWorkflowPlan("latest");
    const ordered: SavedWorkflowPlan[] = [];
    const add = (plan?: SavedWorkflowPlan) => {
      if (plan?.finalPlan?.trim() && (plan.approvalStatus === "approved" || plan.approvalStatus === "revised") && !ordered.some((p) => p.id === plan.id)) ordered.push(plan);
    };
    const currentProject = [latest, ...candidates]
      .filter((plan): plan is SavedWorkflowPlan => Boolean(plan?.finalPlan?.trim()) && (plan.approvalStatus === "approved" || plan.approvalStatus === "revised") && planMatchesCurrentProject(ctx, plan))
      .sort((a, b) => (b.timestamp ?? "").localeCompare(a.timestamp ?? ""));
    const otherProject = [latest, ...candidates]
      .filter((plan): plan is SavedWorkflowPlan => Boolean(plan?.finalPlan?.trim()) && (plan.approvalStatus === "approved" || plan.approvalStatus === "revised") && !planMatchesCurrentProject(ctx, plan))
      .sort((a, b) => (b.timestamp ?? "").localeCompare(a.timestamp ?? ""));
    currentProject.forEach(add);
    otherProject.forEach(add);
    if (state.approvedPlan?.trim() && !isMissionWorkflowMode(state)) return { candidates: ordered, source: "active", reason: "Active approved plan is already loaded." };
    if (currentProject.length > 0) return { plan: currentProject[0], candidates: ordered, source: "history" };
    if (otherProject.length > 0) return { plan: otherProject[0], candidates: ordered, source: "fallback", reason: `No recoverable Plan Mode workflow found for current project ${basename(ctx.cwd)}; showing saved plans from other projects.` };
    return { candidates: [], source: "none", reason: "No active or recoverable approved Plan Mode workflow found." };
  }

  function restorePlanFromStopSnapshot(ctx: ExtensionContext): boolean {
    const snapshot = state.lastPlanStopSummary?.blockedPlanSnapshot;
    if (!snapshot?.approvedPlan?.trim()) return false;
    const settings = loadWorkflowSettings(ctx.cwd);
    const restoredRepairStatus = nonRunningRepairStatus(snapshot.lastRepairStatus);
    const restoredProgress = nonRunningPlanProgress(snapshot.planProgress, restoredRepairStatus);
    updateState({
      mode: "plan_approved",
      activeMissionId: undefined,
      task: snapshot.task ?? "Recovered blocked plan",
      originalTask: snapshot.originalTask ?? "Recovered blocked plan",
      approvedPlan: snapshot.approvedPlan,
      planHistoryId: snapshot.planHistoryId,
      approvedPlanHistoryId: snapshot.approvedPlanHistoryId,
      executionSummary: snapshot.executionSummary,
      validationReport: snapshot.validationReport,
      validationVerdict: snapshot.validationVerdict,
      lastValidationFailure: snapshot.lastValidationFailure,
      lastRepairAttempt: snapshot.lastRepairAttempt,
      repairHistory: snapshot.repairHistory,
      lastRepairStatus: restoredRepairStatus,
      currentValidationRetry: snapshot.currentValidationRetry,
      workflowValidationRetryCount: snapshot.workflowValidationRetryCount,
      planRuntime: snapshot.planRuntime,
      planProgress: restoredProgress ?? (workflowPlanProgressEnabled(settings) ? createPlanProgress(snapshot.approvedPlan, settings, "approved") : undefined),
      reviewerReport: snapshot.reviewerReport,
      reviewerVerdict: snapshot.reviewerVerdict,
      reviewHistory: snapshot.reviewHistory,
      currentReviewRetry: snapshot.currentReviewRetry,
      workflowReviewRetryCount: snapshot.workflowReviewRetryCount,
      lastReviewFailure: snapshot.lastReviewFailure,
      lastReviewAttempt: snapshot.lastReviewAttempt,
      lastReviewRepairStatus: snapshot.lastReviewRepairStatus,
      reviewRepairInProgress: snapshot.reviewRepairInProgress,
      repairRetryState: snapshot.repairRetryState,
      concreteRepairableIssue: snapshot.concreteRepairableIssue,
      manualVerificationRequired: snapshot.manualVerificationRequired,
      evidenceGap: snapshot.evidenceGap ?? false,
      planTokensUsed: snapshot.planTokensUsed,
      modelsUsed: snapshot.modelsUsed,
      // Clear fields that are not in the snapshot to prevent stale state bleed
      draftPlan: undefined,
      planStepValidationIndex: undefined,
      planExecutionStepIndex: undefined,
      lastPlanStopSummary: undefined,
    }, ctx);
    return true;
  }

  function planResumeChoiceLabel(plan: SavedWorkflowPlan): string {
    return `${plan.id} | ${plan.projectLabel ?? plan.projectPath ?? "unknown project"} | ${plan.approvalStatus} | ${plan.planningMode} | ${compact(plan.originalTask || "Saved plan", 80).replace(/\n/g, " ")}`;
  }

  function planResumeCanContinueCurrent(current: WorkflowState): boolean {
    if (!current.approvedPlan?.trim() || isMissionWorkflowMode(current)) return false;
    return current.mode === "plan_approved"
      || current.mode === "reviewing"
      || current.mode === "reviewed"
      || current.mode === "executing"
      || current.mode === "executed"
      || current.mode === "validating"
      || current.mode === "revalidating"
      || current.mode === "repairing"
      || current.mode === "validated";
  }

  async function chooseSavedPlanForResume(ctx: ExtensionContext, plans: SavedWorkflowPlan[], title = "Choose a plan to resume:"): Promise<SavedWorkflowPlan | undefined> {
    const selectable = plans.filter((plan) => plan.finalPlan?.trim());
    if (selectable.length === 0) return undefined;
    if (selectable.length === 1 || !ctx.hasUI) return selectable[0];
    const choices = selectable.map(planResumeChoiceLabel);
    show(pi, `# Plan Resume\n\nChoose a plan.\n\n${choices.map((choice, i) => `${i + 1}. ${choice}`).join("\n")}`);
    const choice = await withWorkflowCommandLock(ctx, "plan", "history-select", () => ctx.ui.select(title, [...choices, "Cancel"]));
    if (!choice || choice === "Cancel") return undefined;
    const id = choice.split(" | ")[0];
    return selectable.find((plan) => plan.id === id);
  }

  async function choosePlanForContinueWhenNoCurrentPlan(ctx: ExtensionContext, resolved: { plan?: SavedWorkflowPlan; candidates: SavedWorkflowPlan[]; source: "active" | "history" | "fallback" | "none"; reason?: string }, action: "resume" | "continue" = "resume"): Promise<SavedWorkflowPlan | undefined> {
    if (resolved.source === "active") return undefined;
    if (resolved.source === "fallback" && !ctx.hasUI) return undefined;
    if (resolved.source !== "fallback" && (resolved.candidates.length <= 1 || !ctx.hasUI)) return resolved.plan;
    const title = action === "resume" ? "Plan Resume" : "Plan Continue";
    const choices = resolved.candidates.map(planResumeChoiceLabel);
    const intro = resolved.source === "fallback"
      ? (resolved.reason ?? "Only saved plans from other projects were found. Choose explicitly before continuing.")
      : action === "resume"
      ? "Choose which plan to use."
      : "I found more than one saved plan. Choose which one to continue.";
    show(pi, `# ${title}\n\n${intro}\n\n${choices.map((choice, i) => `${i + 1}. ${choice}`).join("\n")}`);
    const choice = await withWorkflowCommandLock(ctx, "plan", action, () => ctx.ui.select(`Choose a plan to ${action}:`, [...choices, "Cancel"]));
    if (!choice || choice === "Cancel") return undefined;
    const id = choice.split(" | ")[0];
    return resolved.candidates.find((plan) => plan.id === id) ?? resolved.plan;
  }

  async function handlePlanResume(ctx: ExtensionContext) {
    const settings = loadWorkflowSettings(ctx.cwd);
    const validationAvailable = planValidationGateActive(settings);
    const currentAdvancedSnapshot = findAdvancedPlanRuntimeSnapshotForCurrentState(ctx);
    if (currentAdvancedSnapshot) restorePlanRuntimeSnapshotForResume(ctx, currentAdvancedSnapshot);
    const resolved = resolveActivePlanForResume(ctx);
    const allPlans = listWorkflowPlans().filter((plan) => plan.finalPlan?.trim()).sort((a, b) => Number(planMatchesCurrentProject(ctx, b)) - Number(planMatchesCurrentProject(ctx, a)) || (b.timestamp ?? "").localeCompare(a.timestamp ?? ""));
    const activeRuntimeStale = planActiveRuntimeIsRecoverablyStale(ctx);
    if (resolved.source === "none" && allPlans.length === 0) return show(pi, `# Plan Resume\n\n${resolved.reason ?? planRecoveryGuidance(state, validationAvailable, activeRuntimeStale, settings)}\n\nUse /workflow plans list to see saved plans.\n\n${renderWorkflowStatus(state, pi.getActiveTools(), ctx.cwd)}`);
    let selected = resolved.plan;
    if (resolved.source === "history" && selected) {
      const advancedSnapshot = findAdvancedPlanRuntimeSnapshot(ctx, selected);
      if (advancedSnapshot) restorePlanRuntimeSnapshotForResume(ctx, advancedSnapshot);
      else {
        const restoredFromSnapshot = restorePlanFromStopSnapshot(ctx);
        if (!restoredFromSnapshot) recoverPlanFromHistory(ctx, selected);
      }
    }

    const reusePlan = async (plan: SavedWorkflowPlan, amend: boolean): Promise<void> => {
      activeMission = undefined;
      updateState({ mode: "awaiting_plan_input", activeMissionId: undefined, task: plan.originalTask ?? "Reuse saved plan", originalTask: plan.originalTask ?? "Reuse saved plan", draftPlan: undefined, approvedPlan: undefined, validationReport: undefined, validationVerdict: undefined, executionSummary: undefined, reviewerReport: undefined, clarifyingQuestions: undefined, clarifyingAnswers: undefined, clarificationAlreadyAsked: undefined, clarificationRequiredBeforePlan: undefined, clarificationRequirementReason: undefined, clarificationSkipReason: undefined, clarificationQualityRetryCount: undefined, planHistoryId: undefined, approvedPlanHistoryId: undefined, planStepValidationIndex: undefined, planExecutionStepIndex: undefined, planRuntime: undefined, planProgress: undefined }, ctx);
      await beginPlanning(ctx, plan.originalTask ?? "Reuse saved plan", plan.finalPlan, amend ? "Amend this saved plan into a new approval-ready plan. Keep what still applies and update what should change." : "Reuse this saved plan as the starting point for a new approval-ready plan.");
    };

    // Secondary surface for a saved plan chosen through "Choose Another Plan".
    const showSelectedSavedPlanResumeMenu = async (plan: SavedWorkflowPlan): Promise<void> => {
      const canContinue = plan.approvalStatus === "approved" || plan.approvalStatus === "revised";
      const canRevalidatePlan = canContinue && planValidationBoundaryReached({
        ...state,
        approvedPlan: plan.finalPlan,
        planProgress: plan.planProgress,
        planStepValidationIndex: plan.planStepValidationIndex,
      }, settings);
      const summary = `# Selected Plan\n\n${recoverablePlanDetails(plan)}\n\nStatus: ${plan.approvalStatus}`;
      show(pi, `${summary}\n\nChoose what to do.`);
      if (!ctx.hasUI) return;
      const choices = [...(canContinue ? ["Continue Plan"] : []), ...(canRevalidatePlan ? ["Revalidate Plan"] : []), "Reuse Plan", "Amend Plan", "List Plan Status", "List Plans", "Cancel"];
      const choice = await withWorkflowCommandLock(ctx, "plan", "selected-plan", () => ctx.ui.select("Selected Plan", choices));
      if (choice === "Continue Plan") {
        const advancedSnapshot = findAdvancedPlanRuntimeSnapshot(ctx, plan);
        if (advancedSnapshot && await continueRestoredPlanRuntime(ctx, "Plan Continue", advancedSnapshot)) return;
        recoverPlanFromHistory(ctx, plan);
        await handlePlanContinue(ctx);
      }
      else if (choice === "Revalidate Plan") {
        const advancedSnapshot = findAdvancedPlanRuntimeSnapshot(ctx, plan);
        if (advancedSnapshot) restorePlanRuntimeSnapshot(ctx, advancedSnapshot);
        else recoverPlanFromHistory(ctx, plan);
        await beginValidation(ctx, true, true);
      }
      else if (choice === "Reuse Plan") await reusePlan(plan, false);
      else if (choice === "Amend Plan") await reusePlan(plan, true);
      else if (choice === "List Plan Status") show(pi, renderSavedPlan(plan));
      else if (choice === "List Plans") show(pi, renderPlanList(listWorkflowPlans()));
    };

    // Primary /plan resume surface: restore state, then let the user choose.
    const showActivePlanResumeActionMenu = async (currentPlan?: SavedWorkflowPlan): Promise<void> => {
      const details = currentPlan ? `\n\n${recoverablePlanDetails(currentPlan)}` : "";
      const summary = `# Plan Resume\n\n${currentPlan ? state.approvedPlan ? "Plan loaded from saved history." : "Saved plan is available." : state.approvedPlan ? "Current plan is loaded." : "No current plan is loaded."}${details}\n\n${resolved.source === "fallback" ? `${resolved.reason}\n\n` : ""}${planRecoveryGuidance(state, validationAvailable, planActiveRuntimeIsRecoverablyStale(ctx), settings)}\n\n${renderWorkflowStatus(state, pi.getActiveTools(), ctx.cwd)}`;
      show(pi, `${summary}\n\nChoose what to do.`);
      if (!ctx.hasUI) return;
      const hasAlternatives = allPlans.some((plan) => plan.id !== currentPlan?.id);
      const canContinueCurrent = planResumeCanContinueCurrent(state);
      const reviewRepairAvailable = planReviewRepairRecoveryAvailable(state);
      const validationBoundaryReached = planValidationBoundaryReached(state, settings);
      const validationRepairClass = state.validationVerdict
        ? classifyValidationFailure(state.validationVerdict, state.validationReport ?? state.lastValidationFailure ?? "", {
          concreteRepairableIssue: state.concreteRepairableIssue,
          manualVerificationRequired: state.manualVerificationRequired,
          evidenceGap: state.evidenceGap,
        })
        : undefined;
      const validationRepairAvailable = validationBoundaryReached && Boolean(state.lastValidationFailure || state.validationReport || state.validationVerdict === "FAIL" || state.validationVerdict === "PARTIAL PASS")
        && (state.validationVerdict === "FAIL" || state.validationVerdict === "UNKNOWN" || validationRepairClass === "repairable" || (!state.validationVerdict && state.concreteRepairableIssue !== false));
      const choice = await withWorkflowCommandLock(ctx, "plan", "resume", () => ctx.ui.select("Plan Resume", [
        ...(reviewRepairAvailable ? ["Review Repair / Recover Notes"] : []),
        ...(state.approvedPlan && validationRepairAvailable ? ["Repair / Retry"] : []),
        ...(state.approvedPlan && validationBoundaryReached ? ["Revalidate"] : []),
        ...(canContinueCurrent ? ["Continue Current Plan"] : []),
        ...(hasAlternatives ? ["Choose Another Plan"] : []),
        "List Plan Status", "List Plans", "Cancel",
      ]));
      if (choice === "Review Repair / Recover Notes") await handlePlanReviewRepairRecovery(ctx, "resume");
      else if (choice === "Repair / Retry") await handleWorkflowRetryCommand(ctx, "repair");
      else if (choice === "Revalidate") await beginValidation(ctx, true, true);
      else if (choice === "Continue Current Plan") await handlePlanContinue(ctx);
      else if (choice === "Choose Another Plan") {
        const other = await chooseSavedPlanForResume(ctx, allPlans.filter((plan) => plan.id !== currentPlan?.id), "Choose a plan to resume:");
        if (other) await showSelectedSavedPlanResumeMenu(other);
      } else if (choice === "List Plan Status") show(pi, renderWorkflowStatus(state, pi.getActiveTools(), ctx.cwd));
      else if (choice === "List Plans") show(pi, renderPlanList(listWorkflowPlans()));
    };

    await showActivePlanResumeActionMenu(selected);
  }

  function recoverPlanAcceptedReviewVerdictFromReport(ctx: ExtensionContext, settings: ReturnType<typeof loadWorkflowSettings>): ReviewVerdict | undefined {
    if (!state.reviewerReport?.trim()) return undefined;
    if (state.reviewerVerdict && state.reviewerVerdict !== "UNKNOWN") return undefined;
    const recoveredReviewVerdict = extractReviewVerdict(state.reviewerReport);
    if (recoveredReviewVerdict !== "PASS" && recoveredReviewVerdict !== "NOTES") return undefined;
    updateState({
      mode: "reviewed",
      reviewerVerdict: recoveredReviewVerdict,
      lastReviewFailure: "",
      lastReviewAttempt: `Recovered prior reviewer verdict: ${recoveredReviewVerdict}`,
      lastReviewRepairStatus: state.lastReviewRepairStatus === "running" ? "completed" : (state.lastReviewRepairStatus ?? "none"),
      reviewRepairInProgress: false,
      planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "reviewed" }, settings, { lifecycleStatus: "reviewed", nextAction: "executor" }, state.approvedPlan) : state.planProgress,
    }, ctx);
    return recoveredReviewVerdict;
  }

  function refreshActivePlanStateForContinue(ctx: ExtensionContext): void {
    if (state.approvedPlan && state.mode !== "idle" && state.mode !== "cancelled" && state.mode !== "awaiting_plan_input") return;
    let active: WorkflowState;
    try {
      active = reconcileRestoredWorkflowState(loadState());
    } catch {
      return;
    }
    if (!active.approvedPlan) return;
    if (active.mode !== "plan_approved" && active.mode !== "reviewing" && active.mode !== "reviewed" && active.mode !== "executing" && active.mode !== "executed" && active.mode !== "validating" && active.mode !== "revalidating" && active.mode !== "repairing" && active.mode !== "validated") return;
    state = persistWorkflowState(active, ctx);
  }

  async function handlePlanContinue(ctx: ExtensionContext) {
    const title = "Plan Continue";
    const settings = loadWorkflowSettings(ctx.cwd);
    refreshActivePlanStateForContinue(ctx);
    const currentAdvancedSnapshot = findAdvancedPlanRuntimeSnapshotForCurrentState(ctx);
    if (currentAdvancedSnapshot && await continueRestoredPlanRuntime(ctx, title, currentAdvancedSnapshot)) return;
    const validationAvailable = planValidationGateActive(settings);
    const status = renderWorkflowStatus(state, pi.getActiveTools(), ctx.cwd);

    if (!state.approvedPlan && (state.mode === "idle" || state.mode === "cancelled" || state.mode === "awaiting_plan_input")) {
      const resolved = resolveActivePlanForResume(ctx);
      const selected = await choosePlanForContinueWhenNoCurrentPlan(ctx, resolved, "continue");
      if (!selected) return show(pi, `# ${title}\n\n${resolved.reason ?? "No plan selected. Continue cancelled."}\n\nUse /workflow plans list to see saved plans.\n\n${status}`);
      const advancedSnapshot = findAdvancedPlanRuntimeSnapshot(ctx, selected);
      if (advancedSnapshot && await continueRestoredPlanRuntime(ctx, title, advancedSnapshot)) return;
      const restoredFromSnapshot = restorePlanFromStopSnapshot(ctx);
      if (!restoredFromSnapshot) {
        recoverPlanFromHistory(ctx, selected);
        show(pi, `# ${title}\n\nRecovered approved plan from history.\n\n${recoverablePlanDetails(selected)}\n\nContinuing through configured workflow gates.`);
      } else {
        show(pi, `# ${title}\n\nRestored blocked Plan from the saved stop snapshot.\n\nContinuing through configured workflow gates.`);
      }
    }

    if (state.mode === "awaiting_plan_input") return show(pi, `# ${title}\n\nPlan Mode is ready and waiting for a planning request. Next action: enter a task with /p <task> or type the request as a normal message.\n\n${renderWorkflowStatus(state, pi.getActiveTools(), ctx.cwd)}`);
    if (state.mode === "idle" || state.mode === "cancelled") return show(pi, `# ${title}\n\nNo active Plan Mode workflow found. Start one with /p <task> or enter ready state with /p.\n\n${renderWorkflowStatus(state, pi.getActiveTools(), ctx.cwd)}`);
    if (state.mode === "planning") return show(pi, `# ${title}\n\nPlanner is already running. Wait for the draft plan or clarification request.\n\n${status}`);
    if (state.mode === "awaiting_clarification") return show(pi, `# ${title}\n\nPlan is waiting for clarification answers. Next action: reply with choices like 1A, 2C, or use /clarify questions.\n\n${status}`);
    if (state.mode === "plan_draft") return show(pi, `# ${title}\n\nDraft plan is ready. Next action: /plan approve, /plan revise <feedback>, or /plan cancel.\n\n${status}`);
    if (state.mode === "reviewing") {
      if (planActiveRuntimeIsRecoverablyStale(ctx)) {
        await resumeInterruptedPlanReview(ctx, title);
        return;
      }
      return show(pi, `# ${title}\n\nReviewer is already running. Wait for reviewer completion.\n\n${status}`);
    }
    if (state.mode === "executing") {
      if (planActiveRuntimeIsRecoverablyStale(ctx)) {
        await resumeInterruptedPlanExecution(ctx, title);
        return;
      }
      return show(pi, `# ${title}\n\nExecutor is already running. Wait for execution completion.\n\n${status}`);
    }
    if (state.mode === "validating" || state.mode === "revalidating") {
      if (planValidationRuntimeIsStale(ctx)) {
        await resumeInterruptedPlanValidation(ctx, title);
        return;
      }
      return show(pi, `# ${title}\n\nValidator is already running. Wait for validation result.\n\n${status}`);
    }
    if (state.mode === "repairing") {
      if (planActiveRuntimeIsRecoverablyStale(ctx)) {
        await resumeInterruptedPlanRepair(ctx, title);
        return;
      }
      return show(pi, `# ${title}\n\nExecutor is already running in repair mode. Revalidation will start after repair completes.\n\n${status}`);
    }

    if (state.mode === "plan_approved") {
      if (planReviewForcedPolicyBlocked()) {
        show(pi, `# ${title}\n\nThe approved Plan is blocked because forced Review sub-agent evidence was not completed. Re-running Plan Review in the Review phase before execution.`);
        await beginReview(ctx, true);
        return;
      }
      const recoveredReviewVerdict = recoverPlanAcceptedReviewVerdictFromReport(ctx, settings);
      if (recoveredReviewVerdict) {
        show(pi, `# ${title}\n\nRecovered the previous reviewer verdict (${recoveredReviewVerdict}) from the saved report. Continuing directly to execution instead of re-running review.`);
        await beginExecution(ctx, true);
        return;
      }
      show(pi, `# ${title}\n\nContinuing approved plan through the configured workflow gates.`);
      await continueAfterPlanApproval(ctx, true);
      return;
    }
    if (state.mode === "reviewed") {
      const recoveredReviewVerdict = recoverPlanAcceptedReviewVerdictFromReport(ctx, settings);
      if (recoveredReviewVerdict) show(pi, `# ${title}\n\nRecovered the previous reviewer verdict (${recoveredReviewVerdict}) from the saved report. Continuing to execution.`);
      else show(pi, `# ${title}\n\nReviewer is complete. Continuing to execution.`);
      await beginExecution(ctx, true);
      return;
    }
    if ((state.mode === "executed" || state.mode === "validated") && planExecutionIncomplete(state, settings)) {
      show(pi, `# ${title}\n\nApproved Plan execution is incomplete. Continuing execution from the current incomplete step.`);
      updateState({
        mode: "reviewed",
        validationReport: undefined,
        validationVerdict: undefined,
        lastValidationFailure: undefined,
        lastRepairStatus: "none",
        lastRepairAttempt: undefined,
        planStepValidationIndex: undefined,
        planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "reviewed" }, settings, { lifecycleStatus: "reviewed", validationStatus: "pending", repairStatus: "none", nextAction: "executor" }, state.approvedPlan) : state.planProgress,
      }, ctx);
      await beginExecution(ctx, true);
      return;
    }
    if (state.mode === "executed") {
      if (validationAvailable) {
        show(pi, `# ${title}\n\nExecution is complete. Continuing to validation.`);
        await beginValidation(ctx, true);
        return;
      }
      await completePlanWithoutValidation(ctx, "Validation skipped: validation gate is disabled for this workflow.");
      return;
    }
    if (state.mode === "validated") {
      if (state.validationVerdict === "PASS") {
        await completePlanWorkflow(ctx, state.validationReport, "PASS");
        return;
      }
      if (state.validationVerdict === "PARTIAL PASS") {
        if (classifyValidationFailure(state.validationVerdict, state.validationReport ?? state.lastValidationFailure ?? "", {
          concreteRepairableIssue: state.concreteRepairableIssue,
          manualVerificationRequired: state.manualVerificationRequired,
          evidenceGap: state.evidenceGap,
        }) === "repairable") {
          show(pi, `# ${title}\n\nValidation partially passed but includes concrete repairable issues. Starting safe repair under the configured validation repair policy.`);
          await startWorkflowRepair(ctx, "user");
          return;
        }
        await completePlanWorkflow(ctx, state.validationReport ?? state.lastValidationFailure ?? "", state.validationVerdict);
        return;
      }
      if (state.validationVerdict === "FAIL" || state.lastValidationFailure) {
        return show(pi, `# ${title}\n\nValidation failed. Continue will not automatically repair a failed plan.\n\nNext actions:\n- /plan repair\n- /plan retry\n- /plan revalidate\n- /plan revise <feedback>\n\nRun /plan status to view full workflow details.`);
      }
      if (state.approvedPlan && validationAvailable) {
        show(pi, `# ${title}\n\nValidation status is unknown. Revalidating the approved plan.`);
        await beginValidation(ctx, true, true);
        return;
      }
    }

    return show(pi, `# ${title}\n\nNo safe automatic continuation is available for state: ${state.mode}.\n\nRun /plan status to view full workflow details.`);
  }

  function appendWorkflowReviewHistory(entry: NonNullable<WorkflowState["reviewHistory"]>[number]): WorkflowState["reviewHistory"] {
    return [...(state.reviewHistory ?? []), entry].slice(-20);
  }

  function recoverPlanReviewRepairAsNotes(ctx: ExtensionContext, source: string): ReviewVerdict | undefined {
    const report = state.reviewerReport?.trim() || state.lastReviewFailure?.trim();
    if (!report) return undefined;
    const verdict = state.reviewerVerdict && state.reviewerVerdict !== "UNKNOWN" ? state.reviewerVerdict : extractReviewVerdict(report);
    const control = verdict === "NEEDS REPAIR"
      ? normalizePlanReviewVerdictForControl(verdict, report)
      : (verdict === "PASS" || verdict === "NOTES" ? { verdict, report, originalVerdict: verdict, downgraded: false } satisfies PlanReviewControlVerdict : undefined);
    if (!control || (control.verdict !== "PASS" && control.verdict !== "NOTES")) return undefined;
    updateState({
      mode: "reviewed",
      reviewerReport: control.report,
      reviewerVerdict: control.verdict,
      currentReviewRetry: 0,
      lastReviewFailure: "",
      lastReviewAttempt: control.downgraded ? control.reason : `${source}: recovered Plan reviewer verdict ${control.verdict}.`,
      lastReviewRepairStatus: "none",
      reviewRepairInProgress: false,
      repairRetryState: {
        ...(state.repairRetryState ?? {}),
        review: state.repairRetryState?.review
          ? { ...state.repairRetryState.review, currentRetry: 0, status: "completed", inProgress: false, lastAttempt: control.downgraded ? control.reason : `Recovered reviewer verdict ${control.verdict}.` }
          : undefined,
      },
      reviewHistory: appendWorkflowReviewHistory({
        timestamp: new Date().toISOString(),
        retry: state.currentReviewRetry ?? 0,
        status: "completed",
        reviewFailure: compact(report, 800),
        nextAction: control.downgraded ? control.reason : `Recovered reviewer verdict ${control.verdict}.`,
      }),
      planProgress: workflowPlanProgressEnabled(loadWorkflowSettings(ctx.cwd))
        ? mergePlanProgress({ ...state, mode: "reviewed" }, loadWorkflowSettings(ctx.cwd), { lifecycleStatus: "reviewed", nextAction: "executor" }, state.approvedPlan)
        : state.planProgress,
    }, ctx);
    return control.verdict;
  }

  async function handlePlanReviewRepairRecovery(ctx: ExtensionContext, action: "retry" | "repair" | "resume"): Promise<boolean> {
    if (!planReviewRepairRecoveryAvailable(state)) return false;
    const recovered = recoverPlanReviewRepairAsNotes(ctx, `Plan ${action}`);
    if (recovered) {
      show(pi, `# Plan Review Recovered\n\nThe saved Plan reviewer report now normalizes to ${recovered}. Reviewer repair markers were cleared without using validation repair.\n\n${renderWorkflowStatus(state, pi.getActiveTools(), ctx.cwd)}`);
      return true;
    }
    if (planReviewRepairActive(state)) {
      show(pi, `# Plan Review Repair Active\n\nReviewer-requested Plan repair is already running. Wait for planner repair and reviewer rerun before using /plan ${action === "resume" ? "resume" : action}.\n\n${renderWorkflowStatus(state, pi.getActiveTools(), ctx.cwd)}`);
      return true;
    }
    const report = state.reviewerReport?.trim() || state.lastReviewFailure?.trim() || "Plan reviewer requested repair.";
    const verdict = state.reviewerVerdict && state.reviewerVerdict !== "UNKNOWN" ? state.reviewerVerdict : extractReviewVerdict(report);
    if (!reviewVerdictNeedsRepairRecovery(verdict, report)) return false;
    if (!state.approvedPlan?.trim()) {
      show(pi, `# Plan Review Repair Blocked\n\nCannot repair reviewer findings: approved Plan context is unavailable.\n\n${renderWorkflowStatus(state, pi.getActiveTools(), ctx.cwd)}`);
      return true;
    }
    await handleWorkflowReviewFailure(ctx, verdict === "UNKNOWN" ? "NEEDS REPAIR" : verdict, report, { manualOverride: true });
    return true;
  }

  async function handleWorkflowReviewFailure(ctx: ExtensionContext, verdict: ReviewVerdict, reviewText: string, _options: { manualOverride?: boolean } = {}) {
    const settings = loadWorkflowSettings(ctx.cwd);
    const retry = state.currentReviewRetry ?? 0;
    const workflowRetry = workflowReviewRetryCount(state);
    const failure = `Reviewer ${verdict}. ${compact(reviewText, 1200)}`;
    const canRepairPlan = Boolean(state.approvedPlan) && settings.workflow.allowPlanRevisionBeforeExecute !== false && (verdict === "NEEDS REPAIR" || verdict === "FAIL" || verdict === "BLOCKED");
    const decision = resolveRepairRetryDecision({ gate: "review", verdict, report: failure, settings, state, itemRetry: retry, workflowRetry, requiredContextAvailable: canRepairPlan, manualOverride: true });
    if (!canRepairPlan || !decision.allowed) {
      const reason = !canRepairPlan ? "Plan review repair context unavailable." : (decision.reason ?? "Plan review repair could not start.");
      updateState({ mode: "plan_approved", reviewerReport: reviewText, reviewerVerdict: verdict, lastReviewFailure: failure, lastReviewAttempt: reason, lastReviewRepairStatus: "none", reviewRepairInProgress: false, repairRetryState: { ...(state.repairRetryState ?? {}), review: state.repairRetryState?.review ? { ...state.repairRetryState.review, status: "none", inProgress: false, lastAttempt: reason } : undefined }, planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "plan_approved" }, settings, { lifecycleStatus: "approved", nextAction: "review repair unavailable" }, state.approvedPlan) : state.planProgress, reviewHistory: appendWorkflowReviewHistory({ timestamp: new Date().toISOString(), retry, status: "failed", reviewFailure: compact(failure, 800), nextAction: reason }) }, ctx);
      return show(pi, `# Plan Reviewer Repair Unavailable\n\nVerdict: ${verdict}\nReason: ${reason}\n\nNo reviewer dead-block was written.`);
    }
    const nextRetry = retry + 1;
    const nextWorkflowRetry = workflowRetry + 1;
    const attemptLabel = `Reviewer-triggered plan repair ${nextRetry}/${decision.maxRetriesPerItem}.`;
    clearPendingWorkflowToolPhase(ctx, "Execution", "plan reviewer repair");
    updateState({ mode: "planning", reviewerReport: reviewText, reviewerVerdict: verdict, currentReviewRetry: nextRetry, workflowReviewRetryCount: nextWorkflowRetry, maxReviewRetriesPerPlan: decision.maxRetriesPerItem, maxReviewRetriesPerWorkflow: decision.maxRetriesPerWorkflow, lastReviewFailure: failure, lastReviewAttempt: attemptLabel, lastReviewRepairStatus: "running", reviewRepairInProgress: true, repairRetryState: { ...(state.repairRetryState ?? {}), review: { currentRetry: nextRetry, workflowRetryCount: nextWorkflowRetry, maxRetriesPerItem: decision.maxRetriesPerItem, maxRetriesPerWorkflow: decision.maxRetriesPerWorkflow, lastFailure: failure, lastAttempt: attemptLabel, status: "running", inProgress: true, history: [...(state.repairRetryState?.review?.history ?? []), { timestamp: new Date().toISOString(), retry: nextRetry, status: "running" as const, failure: compact(failure, 800), nextAction: "Repair approved plan, then rerun reviewer before execution." }].slice(-20) } }, reviewHistory: appendWorkflowReviewHistory({ timestamp: new Date().toISOString(), retry: nextRetry, status: "running", reviewFailure: compact(failure, 800), nextAction: "Repair approved plan, then rerun reviewer before execution." }), planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "repairing" }, settings, { lifecycleStatus: "repairing", nextAction: "planner repairing for reviewer" }, state.approvedPlan) : state.planProgress }, ctx);
    await beginPlanning(ctx, state.task ?? state.originalTask ?? "Repair plan after reviewer feedback", state.approvedPlan, `Reviewer verdict: ${verdict}\n\nReviewer report:\n${reviewText}\n\nRepair the plan only. Do not execute. Return an approval-ready repaired plan that addresses the reviewer feedback.`);
  }

  async function handleWorkflowValidationFailure(ctx: ExtensionContext, verdict: WorkflowState["validationVerdict"], validationText: string) {
    const settings = loadWorkflowSettings(ctx.cwd);
    const maxRetries = workflowMaxValidationRetries(state, settings);
    const maxWorkflowRetries = workflowMaxValidationRetriesTotal(state, settings);
    const retry = state.currentValidationRetry ?? 0;
    const workflowRetry = workflowValidationRetryCount(state);
    const failure = `Validation ${verdict}. ${compact(validationText, 1200)}`;
    const failureClass = classifyValidationFailure(verdict, validationText, {
      concreteRepairableIssue: state.concreteRepairableIssue,
      manualVerificationRequired: state.manualVerificationRequired,
      evidenceGap: state.evidenceGap,
    });
    if (failureClass === "manual_only") {
      const reason = "Validation recorded pass-with-notes or manual follow-up without a concrete repairable issue; automatic repair is not appropriate.";
      const validationStatus = planValidationStatusForVerdict(verdict);
      updateState({ mode: "validated", validationReport: validationText, validationVerdict: verdict, lastValidationCompletedAt: new Date().toISOString(), lastPlanStopSummary: undefined, lastValidationFailure: "", lastRepairStatus: "none", lastRepairAttempt: reason, maxValidationRetriesPerPlan: maxRetries, maxValidationRetriesPerWorkflow: maxWorkflowRetries, repairRetryState: { ...(state.repairRetryState ?? {}), validation: { currentRetry: retry, workflowRetryCount: workflowRetry, maxRetriesPerItem: maxRetries, maxRetriesPerWorkflow: maxWorkflowRetries, lastFailure: "", lastAttempt: reason, status: "completed", inProgress: false, history: state.repairRetryState?.validation?.history } }, planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "validated", validationVerdict: verdict }, settings, { lifecycleStatus: "completed", validationStatus, lastValidationStatus: validationStatus, repairStatus: "none", nextAction: "accept notes, revalidate, or revise" }) : state.planProgress }, ctx);
      settleWorkflowRuntimeForUserWait(ctx, "plan validation manual-only");
      queuePlanTerminalSummary(ctx, "completed", "Plan validation pass-with-notes", { validationText, verdict, reason });
      show(pi, `# Plan Validation - Pass With Notes\n\nVerdict: ${verdict}\nReason: ${reason}\n\nNo repair retry was consumed.\n\nChoose from the action menu, or use:\n- /plan complete (accept as done)\n- /plan revalidate\n- /plan revise <feedback>`);
      deferWorkflowMenuAction(pi, "show plan resume after manual-only validation", () => handlePlanResume(ctx));
      return;
    }
    if (failureClass !== "repairable") {
      const reason = "Validation result is ambiguous and no concrete repairable issue was identified; automatic repair is not appropriate until clearer evidence is available.";
      const validationStatus = planValidationStatusForVerdict(verdict);
      updateState({ mode: "validated", validationReport: validationText, validationVerdict: verdict, lastValidationCompletedAt: new Date().toISOString(), lastPlanStopSummary: undefined, lastValidationFailure: failure, lastRepairStatus: "none", lastRepairAttempt: reason, maxValidationRetriesPerPlan: maxRetries, maxValidationRetriesPerWorkflow: maxWorkflowRetries, repairRetryState: { ...(state.repairRetryState ?? {}), validation: { currentRetry: retry, workflowRetryCount: workflowRetry, maxRetriesPerItem: maxRetries, maxRetriesPerWorkflow: maxWorkflowRetries, lastFailure: failure, lastAttempt: reason, status: "failed", inProgress: false, history: state.repairRetryState?.validation?.history } }, planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "validated", validationVerdict: verdict }, settings, { lifecycleStatus: "blocked", validationStatus, lastValidationStatus: validationStatus, repairStatus: "none", nextAction: "revalidate with clearer evidence, manually verify, or revise" }) : state.planProgress }, ctx);
      settleWorkflowRuntimeForUserWait(ctx, "plan validation ambiguous");
      show(pi, `# Plan Validation Needs Clearer Evidence\n\nVerdict: ${verdict}\nReason: ${reason}\n\nNo repair retry was consumed. Use /plan revalidate after gathering clearer evidence, /plan revise <feedback>, or /plan repair only after confirming a concrete repairable issue.`);
      deferWorkflowMenuAction(pi, "show plan resume after ambiguous validation", () => handlePlanResume(ctx));
      return;
    }
    const validationStatus = planValidationStatusForVerdict(verdict);
    const decision = resolveRepairRetryDecision({ gate: "validation", verdict: verdict ?? "UNKNOWN", report: failure, settings, state, itemRetry: retry, workflowRetry, requiredContextAvailable: Boolean(state.approvedPlan) });
    updateState({ mode: "validated", validationReport: validationText, validationVerdict: verdict, lastPlanStopSummary: buildPlanStopSummary(ctx, "blocked", "Plan validation blocked", { validationText, verdict, reason: failure }), lastValidationFailure: failure, maxValidationRetriesPerPlan: maxRetries, maxValidationRetriesPerWorkflow: maxWorkflowRetries, repairRetryState: { ...(state.repairRetryState ?? {}), validation: { currentRetry: retry, workflowRetryCount: workflowRetry, maxRetriesPerItem: decision.maxRetriesPerItem, maxRetriesPerWorkflow: decision.maxRetriesPerWorkflow, lastFailure: failure, lastAttempt: decision.reason, status: decision.allowed ? "none" : "blocked", inProgress: false, history: state.repairRetryState?.validation?.history } }, planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "validated", validationVerdict: verdict }, settings, { lifecycleStatus: "blocked", validationStatus, lastValidationStatus: validationStatus, nextAction: "repair/revalidate or revise" }) : state.planProgress }, ctx);
    show(pi, `# Plan Validation Result\n\nVerdict: ${verdict}\n${verdict === "PARTIAL PASS" ? `Concrete repairable issue found. Repair policy: ${decision.allowed ? "auto-repair starting" : decision.reason ?? "repair blocked"}.` : `Repair policy: ${decision.allowed ? "auto-repair starting" : decision.reason ?? "repair blocked"}.`}\n\n${compact(validationText, 800)}`);
    if (!decision.allowed) {
      const reason = decision.reason ?? "repair requires approval or safety gate.";
      updateState({ mode: "validated", lastPlanStopSummary: buildPlanStopSummary(ctx, "blocked", "Plan repair blocked", { validationText, verdict, reason }), lastRepairStatus: "blocked", planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "validated", lastRepairStatus: "blocked" }, settings, { lifecycleStatus: "blocked", validationStatus, repairStatus: "blocked", nextAction: reason }) : state.planProgress, lastRepairAttempt: reason, lastValidationFailure: failure }, ctx);
      settleWorkflowRuntimeForUserWait(ctx, "plan validation repair blocked");
      queuePlanTerminalSummary(ctx, "blocked", "Plan repair blocked", { validationText, verdict, reason });
      show(pi, `# Plan Validation Failed\n\nVerdict: ${verdict}\nReason: ${reason}\n\nChoose from the action menu, or use:\n- /plan repair\n- /plan retry\n- /plan revalidate\n- /plan revise <feedback>`);
      showBlockedPlanRecoveryMenu(ctx);
      return;
    }
    await startWorkflowRepair(ctx, "auto");
  }

  function appendRepairHistory(mission: MissionState, entry: NonNullable<MissionState["repairHistory"]>[number]): MissionState["repairHistory"] {
    return [...(mission.repairHistory ?? []), entry].slice(-20);
  }

  async function startMissionFinalRepair(ctx: ExtensionContext, mission: MissionState, source: "auto" | "user" = "auto") {
    const settings = loadWorkflowSettings(ctx.cwd);
    clearTypedHandoff(ctx, "Mission final repair");
    const failure = mission.lastFinalValidationFailure || mission.lastValidationFailure || mission.lastBlockReason || "No final validation failure details recorded.";
    const unsafe = validationFailureRequiresApproval(failure, settings, {
      concreteRepairableIssue: mission.concreteRepairableIssue,
      evidenceGap: mission.evidenceGap,
    });
    if (unsafe) {
      const blocked = saveActiveMission({ ...mission, status: "blocked", lastRepairStatus: "blocked", lastBlockReason: `Final repair requires approval: ${unsafe}`, nextAction: "Inspect final validation failure or approve broader repair before retrying.", lastSummary: `Mission final repair blocked: ${unsafe}` });
      checkpointMission(blocked, `Mission final repair blocked before attempt. Reason: ${unsafe}`, "Inspect final validation failure or approve broader repair before retrying.", undefined, { validationResult: blocked.lastFinalValidationResult ?? blocked.lastValidationResult });
      updateState({ mode: "mission_blocked", activeMissionId: blocked.id, lastMissionStopSummary: buildMissionStopSummary(ctx, blocked, "blocked", "Mission blocked", { reason: blocked.lastBlockReason }) }, ctx);
      queueMissionTerminalSummary(ctx, blocked, "blocked", "Mission blocked", { reason: blocked.lastBlockReason });
      recordWorkflowInternalEvent(ctx, "Internal workflow lifecycle event suppressed.");
      showBlockedMissionRecoveryMenu(ctx);
      return;
    }
    if (!beginForcedSubagentPhase(ctx, "Repair", settings)) {
      const blocked = saveActiveMission({ ...mission, status: "blocked", lastRepairStatus: "blocked", lastBlockReason: "Mission final repair blocked by forced sub-agent policy availability gate.", nextAction: "Fix sub-agent policy blocker, then run /mission repair or /mission revalidate.", lastSummary: "Mission final repair blocked before repair prompt." });
      checkpointMission(blocked, "Mission final repair blocked by forced sub-agent policy availability gate.", "Fix sub-agent policy blocker, then run /mission repair or /mission revalidate.", undefined, { validationResult: blocked.lastFinalValidationResult ?? blocked.lastValidationResult });
      updateState({ mode: "mission_blocked", activeMissionId: blocked.id, lastMissionStopSummary: buildMissionStopSummary(ctx, blocked, "blocked", "Mission blocked", { reason: blocked.lastBlockReason }) }, ctx);
      queueMissionTerminalSummary(ctx, blocked, "blocked", "Mission blocked", { reason: blocked.lastBlockReason });
      showBlockedMissionRecoveryMenu(ctx);
      return;
    }
    const route = await applyMissionModelForRole(pi, ctx, "executor", { cwd: ctx.cwd });
    if (!route) {
      const paused = saveActiveMission({ ...mission, status: "paused", lastRepairStatus: "blocked", lastStopReason: "Mission final repair paused because executor model is disabled, unavailable, or not configured.", lastBlockReason: "Mission final repair executor unavailable.", nextAction: "Configure executor, then run /mission repair or /mission revalidate.", lastSummary: "Mission final repair could not start; paused before repair prompt." });
      checkpointMission(paused, "Mission final repair could not start because executor is unavailable.", "Configure executor, then run /mission repair or /mission revalidate.", undefined, { validationResult: paused.lastFinalValidationResult ?? paused.lastValidationResult });
      updateState({ mode: "mission_paused", activeMissionId: paused.id }, ctx);
      queueMissionTerminalSummary(ctx, paused, "blocked", "Mission final repair paused", { reason: paused.lastStopReason });
      return show(pi, `# Mission Final Repair Paused\n\nExecutor is unavailable. Mission did not advance.\n\n${renderMissionStatus(activeMission ?? paused)}`);
    }
    const retry = missionFinalValidationRetryCount(mission);
    const maxRetries = missionMaxFinalValidationRetries(mission, settings);
    const repairing = saveActiveMission({
      ...mission,
      status: "repairing",
      maxFinalValidationRetries: maxRetries,
      lastRepairStatus: "running",
      lastRepairAttempt: `Final validation repair retry ${retry}/${maxRetries} started by ${source}.`,
      nextAction: "Repair final validation failure, then revalidate the whole mission.",
      lastSummary: `Mission final validation repair retry ${retry}/${maxRetries} started.`,
      repairHistory: appendRepairHistory(mission, { timestamp: new Date().toISOString(), retry, status: "running", validationFailure: compact(failure, 800), nextAction: "Repair final validation failure, then revalidate." }),
    });
    checkpointMission(repairing, `Final validation repair started. Retry ${retry}/${maxRetries}. Failure: ${compact(failure, 500)}`, "Repair final validation failure, then revalidate.", undefined, { validationResult: repairing.lastFinalValidationResult ?? repairing.lastValidationResult });
    pi.setActiveTools(missionRepairToolsFor(settings));
    updateState({ mode: "mission_repairing", activeMissionId: repairing.id, modelsUsed: { ...(state.modelsUsed ?? {}), executor: modelLabel(route) } }, ctx);
    saveActiveMission({ ...repairing, modelsUsed: { ...(repairing.modelsUsed ?? {}), executor: modelLabel(route) } });
    if (source !== "auto") show(pi, `# Mission Final Repair Started\n\nRetry: ${retry} of ${maxRetries}\n\n${renderMissionProgress(repairing, settings)}`);
    queueWorkflowPrompt(pi, missionRepairPrompt(repairing, settings, phasePreflightBlocks.Repair), buildQueuedPhaseRecovery(ctx, "Repair", (reason) => recoverMissionTransientHandoffFailure(ctx, "final_repair", reason, { phase: "Repair", preserveRetry: true })));
  }

  async function startMissionRepair(ctx: ExtensionContext, mission: MissionState, source: "auto" | "user" = "auto") {
    const settings = loadWorkflowSettings(ctx.cwd);
    clearTypedHandoff(ctx, "Mission repair");
    const runtimeBlocked = missionRuntimeBudgetBlock(mission, settings);
    if (runtimeBlocked) {
      const milestone = mission.milestones[mission.currentMilestoneIndex];
      const paused = saveActiveMission({ ...mission, status: "paused", lastStopReason: runtimeBlocked, nextAction: "Mission active runtime budget reached. Review status before repairing.", lastSummary: runtimeBlocked });
      checkpointMission(paused, runtimeBlocked, "Mission active runtime budget reached. Review status before repairing.", milestone?.id, { validationResult: mission.lastValidationResult });
      updateState({ mode: "mission_paused", activeMissionId: paused.id }, ctx);
      queueMissionTerminalSummary(ctx, paused, "blocked", "Mission runtime budget reached", { reason: runtimeBlocked });
      return show(pi, `# Mission Runtime Budget Reached\n\n${runtimeBlocked}\n\n${renderMissionStatus(activeMission ?? paused)}`);
    }
    const failure = mission.lastValidationFailure || mission.lastBlockReason || "No validation failure details recorded.";
    if (validationTextLooksWrongMissionContext(ctx, mission, failure)) {
      const milestone = mission.milestones[mission.currentMilestoneIndex];
      const quarantined = saveActiveMission({ ...mission, lastValidationFailure: "", lastBlockReason: "", lastRepairStatus: "none", lastRepairAttempt: "Ignored wrong-context validation failure.", nextAction: `Run /mission revalidate to validate ${milestone?.id ?? "current milestone"} with current project context.`, lastSummary: "Wrong-context validation failure ignored; repair was not started." });
      updateState({ mode: missionWorkflowModeForStatus(quarantined.status), activeMissionId: quarantined.id, lastWorkflowHandoff: undefined }, ctx);
      return show(pi, `# Mission Repair Refused\n\nThe saved validation failure does not belong to the active mission/project, so repair was not started.\n\nRun /mission revalidate to regenerate validation for ${milestone?.id ?? "current milestone"}.`);
    }
    const verdict = mission.lastValidationResult === "FAIL" || mission.lastValidationResult === "PARTIAL PASS" || mission.lastValidationResult === "UNKNOWN" ? mission.lastValidationResult : "UNKNOWN";
    const repairClass = classifyValidationFailure(verdict, failure, {
      concreteRepairableIssue: mission.concreteRepairableIssue,
      manualVerificationRequired: mission.manualVerificationRequired,
      evidenceGap: mission.evidenceGap,
    });
    if (repairClass !== "repairable") {
      const milestone = mission.milestones[mission.currentMilestoneIndex];
      const reason = repairClass === "manual_only"
        ? "Mission validation recorded pass-with-notes or manual follow-up only; no concrete repair target is available."
        : "Mission validation needs clearer evidence before repair; revalidate with the current context instead of repairing.";
      const saved = saveActiveMission({ ...mission, lastRepairStatus: "none", lastRepairAttempt: reason, nextAction: `Run /mission revalidate for ${milestone?.id ?? "current milestone"} or continue if pass-with-notes is acceptable.`, lastSummary: "Mission repair refused because no concrete repair target exists." });
      updateState({ mode: missionWorkflowModeForStatus(saved.status), activeMissionId: saved.id }, ctx);
      return show(pi, `# Mission Repair Refused\n\n${reason}\n\nNo repair retry was consumed.`);
    }
    const unsafe = validationFailureRequiresApproval(failure, settings, {
      concreteRepairableIssue: mission.concreteRepairableIssue,
      evidenceGap: mission.evidenceGap,
    });
    if (unsafe) {
      const milestone = mission.milestones[mission.currentMilestoneIndex];
      const blocked = saveActiveMission({ ...mission, status: "blocked", lastRepairStatus: "blocked", lastBlockReason: `Repair requires approval: ${unsafe}`, nextAction: "Inspect validation failure or approve broader repair before retrying.", lastSummary: `Mission repair blocked: ${unsafe}` });
      checkpointMission(blocked, `Mission repair blocked before attempt. Retry ${blocked.currentValidationRetry ?? 0}/${maxValidationRetries(blocked, settings)}. Reason: ${unsafe}`, "Inspect validation failure or approve broader repair before retrying.", milestone?.id, { validationResult: blocked.lastValidationResult });
      updateState({ mode: "mission_blocked", activeMissionId: blocked.id, lastMissionStopSummary: buildMissionStopSummary(ctx, blocked, "blocked", "Mission blocked", { reason: blocked.lastBlockReason }) }, ctx);
      queueMissionTerminalSummary(ctx, blocked, "blocked", "Mission blocked", { reason: blocked.lastBlockReason });
      recordWorkflowInternalEvent(ctx, "Internal workflow lifecycle event suppressed.");
      showBlockedMissionRecoveryMenu(ctx);
      return;
    }
    const currentRetry = mission.currentValidationRetry ?? 0;
    const maxRetries = maxValidationRetries(mission, settings);
    const missionRetryCount = missionValidationRetryCount(mission);
    const maxMissionRetries = maxMissionValidationRetries(mission, settings);
    if (currentRetry >= maxRetries && source === "auto") {
      const milestone = mission.milestones[mission.currentMilestoneIndex];
      const blockedMilestones = mission.milestones.map((m, i) => i === mission.currentMilestoneIndex ? { ...m, status: "failed" as const } : m);
      const blocked = saveActiveMission({ ...mission, status: "blocked", milestones: blockedMilestones, lastRepairStatus: "blocked", lastBlockReason: "milestone repair retry limit exhausted", nextAction: "Inspect failure, adjust settings, or manually approve broader repair.", lastSummary: `Mission blocked: milestone repair retry limit exhausted (${currentRetry}/${maxRetries} per milestone).` });
      checkpointMission(blocked, `Mission blocked: milestone repair retry limit exhausted (${currentRetry}/${maxRetries} per milestone).`, "Inspect failure, adjust settings, or manually approve broader repair.", milestone?.id, { validationResult: blocked.lastValidationResult });
      updateState({ mode: "mission_blocked", activeMissionId: blocked.id, lastMissionStopSummary: buildMissionStopSummary(ctx, blocked, "blocked", "Mission blocked", { reason: blocked.lastBlockReason }) }, ctx);
      recordWorkflowInternalEvent(ctx, "Mission automatic repair blocked by milestone retry limit.");
      showBlockedMissionRecoveryMenu(ctx);
      return;
    }
    const milestone = mission.milestones[mission.currentMilestoneIndex];
    if (!beginForcedSubagentPhase(ctx, "Repair", settings)) {
      const blocked = saveActiveMission({ ...mission, status: "blocked", lastRepairStatus: "blocked", lastBlockReason: "Mission repair blocked by forced sub-agent policy availability gate.", nextAction: "Fix sub-agent policy blocker, then run /mission repair or /mission retry.", lastSummary: "Mission repair blocked before repair prompt." });
      checkpointMission(blocked, "Mission repair blocked by forced sub-agent policy availability gate.", "Fix sub-agent policy blocker, then run /mission repair or /mission retry.", milestone?.id, { validationResult: blocked.lastValidationResult });
      updateState({ mode: "mission_blocked", activeMissionId: blocked.id, lastMissionStopSummary: buildMissionStopSummary(ctx, blocked, "blocked", "Mission blocked", { reason: blocked.lastBlockReason }) }, ctx);
      queueMissionTerminalSummary(ctx, blocked, "blocked", "Mission blocked", { reason: blocked.lastBlockReason });
      showBlockedMissionRecoveryMenu(ctx);
      return;
    }
    const route = await applyMissionModelForRole(pi, ctx, "executor", { cwd: ctx.cwd });
    if (!route) {
      const paused = saveActiveMission({ ...mission, status: "paused", lastRepairStatus: "blocked", lastStopReason: "Mission repair paused because executor model is disabled, unavailable, or not configured.", lastBlockReason: "Mission repair executor unavailable.", nextAction: "Configure executor, then run /mission repair or /mission retry. Mission will not advance until repair can run.", lastSummary: "Mission repair could not start; paused before repair prompt." });
      checkpointMission(paused, "Mission repair could not start because executor is unavailable.", "Configure executor, then run /mission repair or /mission retry.", milestone?.id, { validationResult: paused.lastValidationResult });
      updateState({ mode: "mission_paused", activeMissionId: paused.id }, ctx);
      queueMissionTerminalSummary(ctx, paused, "blocked", "Mission repair paused", { reason: paused.lastStopReason });
      return show(pi, `# Mission Repair Paused

Executor is unavailable. Mission did not advance.

${renderMissionStatus(activeMission ?? paused)}`);
    }
    const manualRetryOverride = source !== "auto" && currentRetry >= maxRetries;
    const retry = currentRetry + 1;
    const missionRetry = missionRetryCount + 1;
    const repairingMilestones = mission.milestones.map((m, i) => i === mission.currentMilestoneIndex ? { ...m, status: "active" as const } : m);
    const repairing = saveActiveMission({
      ...mission,
      status: "repairing",
      milestones: repairingMilestones,
      currentValidationRetry: retry,
      missionValidationRetryCount: missionRetry,
      maxValidationRetriesPerMilestone: maxRetries,
      maxValidationRetriesPerMission: maxMissionRetries,
      lastRepairStatus: "running",
      lastRepairAttempt: `${manualRetryOverride ? "Manual repair retry override" : "Repair retry"} ${retry}/${maxRetries} per milestone; mission retry ${missionRetry}/${maxMissionRetries} total started by ${source}.`,
      nextAction: `Repair validation failure, then revalidate ${milestone?.id ?? "current milestone"}.`,
      lastSummary: `${manualRetryOverride ? "Manual mission repair retry override" : "Mission repair retry"} ${retry}/${maxRetries} per milestone; mission retry ${missionRetry}/${maxMissionRetries} total started for ${milestone?.id ?? "current milestone"}.`,
      repairHistory: appendRepairHistory(mission, { timestamp: new Date().toISOString(), milestoneId: milestone?.id, retry, status: "running", validationFailure: compact(failure, 800), nextAction: "Repair current validation failure, then revalidate." }),
    });
    checkpointMission(repairing, `${manualRetryOverride ? "Manual repair retry override" : "Repair started"} for ${milestone?.id ?? "current milestone"}. Retry ${retry}/${maxRetries} per milestone; mission retry ${missionRetry}/${maxMissionRetries} total. Failure: ${compact(failure, 500)}`, "Repair current validation failure, then revalidate.", milestone?.id, { validationResult: repairing.lastValidationResult });
    pi.setActiveTools(missionRepairToolsFor(settings));
    updateState({ mode: "mission_repairing", activeMissionId: repairing.id, modelsUsed: { ...(state.modelsUsed ?? {}), executor: modelLabel(route) } }, ctx);
    saveActiveMission({ ...repairing, modelsUsed: { ...(repairing.modelsUsed ?? {}), executor: modelLabel(route) } });
    if (source !== "auto") show(pi, `# Mission Repair Started\n\nRetry: ${retry} of ${maxRetries} per milestone\nMission Retry: ${missionRetry} of ${maxMissionRetries} total\nMilestone: ${milestone?.id ?? "current"} — ${milestone?.title ?? "unknown"}\n\n${renderMissionProgress(repairing, settings)}`);
    if (source === "auto") queueAgentTurn(pi, "Repair the current mission milestone validation failure, then submit workflow_repair_result.", "mission-repair-trigger", buildQueuedPhaseRecovery(ctx, "Repair", (reason) => recoverMissionTransientHandoffFailure(ctx, "repair", reason, { phase: "Repair", preserveRetry: true })));
    else queueWorkflowPrompt(pi, missionRepairPrompt(repairing, settings, phasePreflightBlocks.Repair), buildQueuedPhaseRecovery(ctx, "Repair", (reason) => recoverMissionTransientHandoffFailure(ctx, "repair", reason, { phase: "Repair", preserveRetry: true })));
  }

  async function handleMissionRetryCommand(ctx: ExtensionContext, action: "retry" | "repair" | "revalidate") {
    const mission = (state.activeMissionId ? loadMissionState(state.activeMissionId) : undefined) ?? activeMission ?? loadMissionState("latest");
    if (!mission) return show(pi, `# Mission ${action}\n\nCannot ${action}: no active mission found.`);
    const current = mission.milestones[mission.currentMilestoneIndex];
    if (!current) return show(pi, `# Mission ${action}\n\nCannot ${action}: no current milestone.`);
    if (action === "revalidate") {
      if (!mission.milestones.length) return show(pi, "# Mission Revalidate\n\nCannot revalidate: no current milestone.");
      if (mission.lastFinalValidationFailure || state.mode === "mission_final_validating") {
        await beginMissionFinalValidation(ctx, mission, true);
        return;
      }
      await beginMissionValidation(ctx, true, true);
      return;
    }
    if (await handleMissionReviewRepairRecovery(ctx, mission, action)) return;
    const failure = mission.lastValidationFailure || mission.lastBlockReason || "";
    if (action === "repair" && validationTextLooksWrongMissionContext(ctx, mission, failure)) {
      const quarantined = saveActiveMission({ ...mission, lastValidationFailure: "", lastBlockReason: "", lastRepairStatus: "none", lastRepairAttempt: "Ignored wrong-context validation failure.", nextAction: `Run /mission revalidate to validate ${current.id} with current project context.`, lastSummary: "Wrong-context validation failure ignored; repair was not started." });
      updateState({ mode: missionWorkflowModeForStatus(quarantined.status), activeMissionId: quarantined.id, lastWorkflowHandoff: undefined }, ctx);
      return show(pi, `# Mission Repair Refused\n\nThe saved validation failure belongs to another mission/project. It was ignored for repair.\n\nRun /mission revalidate to validate ${current.id} in the current project context.`);
    }
    const verdict = mission.lastValidationResult === "FAIL" || mission.lastValidationResult === "PARTIAL PASS" || mission.lastValidationResult === "UNKNOWN" ? mission.lastValidationResult : "UNKNOWN";
    const failureClass = classifyValidationFailure(verdict, failure, {
      concreteRepairableIssue: mission.concreteRepairableIssue,
      manualVerificationRequired: mission.manualVerificationRequired,
      evidenceGap: mission.evidenceGap,
    });
    const hasValidationFailure = Boolean(mission.lastValidationFailure || mission.lastBlockReason || mission.lastValidationResult === "FAIL" || mission.lastValidationResult === "PARTIAL PASS")
      && (verdict !== "PARTIAL PASS" || failureClass === "repairable");
    if (!hasValidationFailure) {
      return show(pi, `# Mission ${action}\n\nCannot ${action}: no validation failure found for ${current.id}.`);
    }
    if (action === "retry" && missionRepairCompletedPendingRevalidation(mission)) {
      if (mission.lastRepairStatus === "blocked") saveActiveMission({ ...mission, lastRepairStatus: "completed", nextAction: `Revalidate ${current.id} after completed repair.`, lastSummary: "Repair completed; revalidation requested." });
      await beginMissionValidation(ctx, true, true);
      return;
    }
    const settings = loadWorkflowSettings(ctx.cwd);
    if (mission.status === "repairing" && missionRepairGateInterrupted(mission, settings)) {
      await startMissionRepair(ctx, mission, "user");
      return;
    }
    if (mission.status === "running" || mission.status === "validating" || mission.status === "repairing" || mission.status === "revalidating") {
      return show(pi, `# Mission ${action}\n\nCannot ${action}: mission is currently ${mission.status}. Wait for the active gate or pause first.`);
    }
    await startMissionRepair(ctx, mission, "user");
  }

  async function beginMissionFinalValidation(ctx: ExtensionContext, mission: MissionState, auto = false) {
    const settings = loadWorkflowSettings(ctx.cwd);
    clearTypedHandoff(ctx, "Mission final validation");
    const validating = saveActiveMission({ ...mission, status: "validating", currentStep: "final validator", nextAction: "Run comprehensive final mission validation.", lastSummary: "Running final comprehensive mission validation." });
    checkpointMission(validating, `Final mission validation started. Retry ${missionFinalValidationRetryCount(validating)}/${missionMaxFinalValidationRetries(validating, settings)}.`, "Run final comprehensive validation for the whole mission.");
    pi.setActiveTools(validationToolsFor(settings));
    updateState({ mode: "mission_final_validating", activeMissionId: validating.id, ...missionValidationContextPatch(ctx, validating, true), currentValidationHandoffRetry: undefined, maxValidationHandoffRetries: undefined, lastValidationHandoffFailure: undefined }, ctx);
    if (!beginForcedSubagentPhase(ctx, "Validation", settings, { label: "Mission Final Validation" })) {
      const paused = saveActiveMission({ ...validating, status: "paused", lastStopReason: "Mission final validation blocked by forced sub-agent policy availability gate.", nextAction: "Fix sub-agent policy blocker, then run /mission revalidate.", lastSummary: "Mission final validation blocked before validator prompt." });
      checkpointMission(paused, "Mission final validation blocked by forced sub-agent policy availability gate.", "Fix sub-agent policy blocker, then run /mission revalidate.");
      updateState({ mode: "mission_paused", activeMissionId: paused.id }, ctx);
      queueMissionTerminalSummary(ctx, paused, "blocked", "Mission final validation paused", { reason: paused.lastStopReason });
      return;
    }
    const route = await applyMissionModelForRole(pi, ctx, "validator", { requireEnabled: false, cwd: ctx.cwd });
    if (!route) {
      const paused = saveActiveMission({ ...mission, status: "paused", lastStopReason: "Mission paused because final validator model is disabled, unavailable, or not configured.", nextAction: "Configure validator, then run /mission revalidate.", lastSummary: "Mission final validation could not start." });
      checkpointMission(paused, "Mission final validation could not start because validator is unavailable.", "Configure validator, then run /mission revalidate.");
      updateState({ mode: "mission_paused", activeMissionId: paused.id }, ctx);
      queueMissionTerminalSummary(ctx, paused, "blocked", "Mission final validation paused", { reason: "Final validator is unavailable." });
      return show(pi, `# Mission Final Validation Paused\n\nValidator is unavailable.\n\n${renderMissionStatus(activeMission ?? paused)}`);
    }
    updateState({ modelsUsed: { ...(state.modelsUsed ?? {}), validator: modelLabel(route) } }, ctx);
    const prompt = missionFinalValidationPrompt(validating, settings, state.executionSummary, phasePreflightBlocks.Validation, state);
    if (auto) {
      queueAgentTurn(pi, prompt, "mission-final-validate-trigger", buildQueuedPhaseRecovery(ctx, "Validation", (reason) => recoverMissionTransientHandoffFailure(ctx, "final_validation", reason, { phase: "Validation" })));
    }
    else queueWorkflowPrompt(pi, prompt, buildQueuedPhaseRecovery(ctx, "Validation", (reason) => recoverMissionTransientHandoffFailure(ctx, "final_validation", reason, { phase: "Validation" })));
  }

  async function handleMissionFinalValidationFailure(ctx: ExtensionContext, mission: MissionState, verdict: WorkflowState["validationVerdict"], validationText: string) {
    const settings = loadWorkflowSettings(ctx.cwd);
    const failureClass = classifyValidationFailure(verdict, validationText, {
      concreteRepairableIssue: mission.concreteRepairableIssue,
      manualVerificationRequired: mission.manualVerificationRequired,
      evidenceGap: mission.evidenceGap,
    });
    if (failureClass === "manual_only") {
      if (settings.missions.finalValidationRequiresPass === true && verdict !== "PASS") {
        const failure = `Final mission validation ${verdict}. ${compact(validationText, 1200)}`;
        const reason = "Final validation recorded pass-with-notes, but missions.finalValidationRequiresPass=true requires a strict PASS before completion.";
        const paused = saveActiveMission({ ...mission, status: "paused", lastFinalValidationResult: verdict ?? "UNKNOWN", lastFinalValidationFailure: failure, lastValidationResult: verdict, lastValidationFailure: "", lastStopReason: reason, lastBlockReason: "", lastRepairStatus: "none", nextAction: "Run /mission revalidate for a strict PASS, or change finalValidationRequiresPass if accepting notes.", lastSummary: `Final mission validation ${verdict} recorded pass-with-notes; strict PASS still required.` });
        checkpointMission(paused, `${reason} ${compact(validationText, 500)}`, paused.nextAction ?? "Run final validation again for strict PASS.", undefined, { validationResult: verdict });
        updateState({ mode: "mission_paused", activeMissionId: paused.id, validationReport: validationText, validationVerdict: verdict, concreteRepairableIssue: false, manualVerificationRequired: mission.manualVerificationRequired === true, evidenceGap: false }, ctx);
        show(pi, `# Mission Final Validation Pass With Notes\n\n${reason}\n\nNo repair retry was consumed.\n\n${renderMissionStatus(activeMission ?? paused)}`);
        return;
      }
      const completed = saveActiveMission({ ...mission, status: "completed", completedAt: new Date().toISOString(), lastFinalValidationResult: verdict, lastFinalValidationFailure: "", lastValidationResult: verdict, lastValidationFailure: "", lastBlockReason: "", nextAction: "Mission completed all milestones and final validation (no concrete repairable issues).", lastSummary: `Final mission validation ${verdict} — no concrete repairable issue, completing.` });
      checkpointMission(completed, `Final mission validation ${verdict} — no concrete repairable issue. ${compact(validationText, 500)}`, "Mission completed after final validation.", undefined, { validationResult: verdict });
      completeMissionToAwaitingInput(ctx, completed, validationText, verdict, settings);
      recordWorkflowInternalEvent(ctx, "Internal workflow lifecycle event suppressed.");
      return;
    }
    if (failureClass !== "repairable") {
      const failure = `Final mission validation ${verdict}. ${compact(validationText, 1200)}`;
      const reason = "Final mission validation is ambiguous and no concrete repairable issue was identified; automatic final repair is not appropriate until clearer evidence is available.";
      const paused = saveActiveMission({ ...mission, status: "paused", lastFinalValidationResult: verdict ?? "UNKNOWN", lastFinalValidationFailure: failure, lastValidationFailure: failure, lastStopReason: reason, lastBlockReason: "", lastRepairStatus: "none", nextAction: "Run /mission revalidate after gathering clearer evidence, or revise the mission scope before repair.", lastSummary: `Final mission validation ${verdict} was ambiguous; paused without repair.` });
      checkpointMission(paused, `${reason} ${compact(validationText, 500)}`, paused.nextAction ?? "Revalidate mission with clearer evidence.", undefined, { validationResult: verdict });
      updateState({ mode: "mission_paused", activeMissionId: paused.id, validationReport: validationText, validationVerdict: verdict, concreteRepairableIssue: mission.concreteRepairableIssue, manualVerificationRequired: mission.manualVerificationRequired, evidenceGap: mission.evidenceGap }, ctx);
      show(pi, `# Mission Final Validation Paused\n\n${reason}\n\n${renderMissionStatus(activeMission ?? paused)}`);
      return;
    }
    const retry = missionFinalValidationRetryCount(mission);
    const maxRetries = missionMaxFinalValidationRetries(mission, settings);
    const failure = `Final mission validation ${verdict}. ${compact(validationText, 1200)}`;
    const unsafe = validationFailureRequiresApproval(failure, settings, {
      concreteRepairableIssue: mission.concreteRepairableIssue,
      evidenceGap: mission.evidenceGap,
    });
    const nextRetry = retry + 1;
    const failed = saveActiveMission({ ...mission, status: "validating", finalValidationRetryCount: nextRetry, maxFinalValidationRetries: maxRetries, lastFinalValidationResult: verdict ?? "UNKNOWN", lastFinalValidationFailure: failure, lastValidationFailure: failure, lastBlockReason: "", nextAction: "Final mission validation failed; evaluating safe repair retry.", lastSummary: `Final mission validation ${verdict}.` });
    checkpointMission(failed, `Final mission validation failed. Retry ${retry}/${maxRetries}. ${compact(validationText, 500)}`, "Evaluate safe final repair retry before completion.", undefined, { validationResult: verdict });
    const shouldBlock = settings.missions.autoRepairFinalValidationFailures !== true || retry >= maxRetries || Boolean(unsafe);
    if (shouldBlock) {
      const reason = settings.missions.autoRepairFinalValidationFailures !== true ? "missions.autoRepairFinalValidationFailures=false."
        : retry >= maxRetries ? "final mission validation repair retry limit exhausted"
        : unsafe ?? "final mission repair requires approval or safety gate.";
      const blocked = saveActiveMission({ ...failed, status: "blocked", lastRepairStatus: unsafe ? "blocked" : (failed.lastRepairStatus ?? "none"), lastBlockReason: reason, nextAction: "Inspect final validation failure, repair manually if needed, then run /mission revalidate.", lastSummary: "Mission blocked after final validation failure." });
      checkpointMission(blocked, `Mission blocked after final validation failure. Reason: ${reason}`, blocked.nextAction ?? "Inspect final validation failure.", undefined, { validationResult: verdict });
      updateState({ mode: "mission_blocked", activeMissionId: blocked.id, validationReport: validationText, validationVerdict: verdict, concreteRepairableIssue: mission.concreteRepairableIssue, manualVerificationRequired: mission.manualVerificationRequired, evidenceGap: mission.evidenceGap, lastMissionStopSummary: buildMissionStopSummary(ctx, blocked, "blocked", "Mission blocked", { validationText, verdict, reason }) }, ctx);
      queueMissionTerminalSummary(ctx, blocked, "blocked", "Mission blocked", { validationText, verdict, reason });
      recordWorkflowInternalEvent(ctx, "Mission final validation failure card suppressed from transcript.");
      showBlockedMissionRecoveryMenu(ctx);
      return;
    }
    updateState({ mode: "mission_final_validating", activeMissionId: failed.id, validationReport: validationText, validationVerdict: verdict, concreteRepairableIssue: mission.concreteRepairableIssue, manualVerificationRequired: mission.manualVerificationRequired, evidenceGap: mission.evidenceGap }, ctx);
    await startMissionFinalRepair(ctx, activeMission ?? failed, "auto");
  }

  async function handleMissionValidationFailure(ctx: ExtensionContext, mission: MissionState, verdict: WorkflowState["validationVerdict"], validationText: string) {
    const settings = loadWorkflowSettings(ctx.cwd);
    const index = mission.currentMilestoneIndex;
    const milestone = mission.milestones[index];
    const maxRetries = maxValidationRetries(mission, settings);
    const maxMissionRetries = maxMissionValidationRetries(mission, settings);
    const retry = mission.currentValidationRetry ?? 0;
    const missionRetry = missionValidationRetryCount(mission);
    const failure = `Validation ${verdict} for ${milestone?.id ?? "current milestone"}. ${compact(validationText, 1200)}`;
    const failureClass = classifyValidationFailure(verdict, validationText, {
      concreteRepairableIssue: mission.concreteRepairableIssue,
      manualVerificationRequired: mission.manualVerificationRequired,
      evidenceGap: mission.evidenceGap,
    });
    if (failureClass === "manual_only") {
      const milestones = mission.milestones.map((m, i) => i === index ? { ...m, status: "completed" as const } : m);
      const nextIndex = Math.min(index + 1, Math.max(0, milestones.length - 1));
      const done = index >= milestones.length - 1;
      if (done && settings.missions.finalValidationEnabled === true) {
        const finalMission = saveActiveMission({ ...mission, status: "validating", milestones, currentMilestoneIndex: index, currentValidationRetry: 0, lastValidationResult: verdict, lastValidationFailure: "", concreteRepairableIssue: false, manualVerificationRequired: mission.manualVerificationRequired === true, evidenceGap: false, nextAction: "Run final comprehensive mission validation.", lastSummary: `Milestone ${milestone?.id ?? "current"} ${verdict} — pass-with-notes; final validation queued.` });
        checkpointMission(finalMission, `Milestone ${milestone?.id ?? "current"} ${verdict} — no concrete repairable issue; final mission validation queued. ${compact(validationText, 500)}`, "Run final comprehensive validation for the whole mission.", milestone?.id, { validationResult: verdict });
        updateState({ mode: "mission_final_validating", activeMissionId: finalMission.id, validationReport: validationText, validationVerdict: verdict }, ctx);
        deferWorkflowAction(pi, "begin final mission validation after no-defect partial pass", async () => {
          await beginMissionFinalValidation(ctx, activeMission ?? finalMission, true);
        }, { timeoutMs: workflowDeferredPhaseTimeoutMs(ctx, "Validation") });
        return;
      }
      const shouldPause = mission.autonomy === "manual" || mission.pauseBetweenMilestones === true || mission.continueAcrossMilestones === false;
      const nextStatus = done ? "completed" : shouldPause ? "paused" : "approved";
      const nextMode = done ? "awaiting_mission_input" : shouldPause ? "mission_paused" : "mission_approved";
      const nextAction = done ? "Mission completed all milestones." : shouldPause ? "Run /mission continue, /mission next, or /mission resume when ready." : `Mission continuing automatically to milestone ${milestones[nextIndex]?.id ?? nextIndex + 1}.`;
      const nextMission = saveActiveMission({ ...mission, status: nextStatus, milestones, currentMilestoneIndex: nextIndex, currentValidationRetry: 0, lastValidationResult: verdict, lastValidationFailure: "", lastRepairStatus: done ? mission.lastRepairStatus : "none", lastRepairAttempt: done ? mission.lastRepairAttempt : "", concreteRepairableIssue: false, manualVerificationRequired: mission.manualVerificationRequired === true, evidenceGap: false, nextAction, lastSummary: `Milestone ${milestone?.id ?? "current"} ${verdict} — pass-with-notes, advancing.` });
      checkpointMission(nextMission, `Milestone ${milestone?.id ?? "current"} ${verdict} — no concrete repairable issue. ${compact(validationText, 500)}`, nextAction, milestone?.id, { validationResult: verdict });
      if (done) completeMissionToAwaitingInput(ctx, nextMission, validationText, verdict, settings);
      else updateState({ mode: nextMode, activeMissionId: nextMission.id, validationReport: validationText, validationVerdict: verdict }, ctx);
      if (!done && !shouldPause) {
        await beginMissionRun(ctx, activeMission ?? nextMission, "continue", true);
      }
      return;
    }
    if (failureClass !== "repairable") {
      const reason = "Mission validation is ambiguous and no concrete repairable issue was identified; automatic repair is not appropriate until clearer evidence is available.";
      const paused = saveActiveMission({ ...mission, status: "paused", lastValidationResult: verdict ?? "UNKNOWN", lastValidationFailure: failure, lastStopReason: reason, lastBlockReason: "", lastRepairStatus: "none", nextAction: `Run /mission revalidate after gathering clearer evidence for ${milestone?.id ?? "current milestone"}, or revise the mission scope before repair.`, lastSummary: `Mission validation ${verdict} for ${milestone?.id ?? "current milestone"} was ambiguous; paused without repair.` });
      checkpointMission(paused, `${reason} ${compact(validationText, 500)}`, paused.nextAction ?? "Revalidate mission with clearer evidence.", milestone?.id, { validationResult: verdict });
      updateState({ mode: "mission_paused", activeMissionId: paused.id, validationReport: validationText, validationVerdict: verdict }, ctx);
      show(pi, `# Mission Validation Paused\n\n${reason}\n\n${renderMissionStatus(activeMission ?? paused)}`);
      return;
    }
    const failedMilestones = mission.milestones.map((m, i) => i === index ? { ...m, status: "active" as const } : m);
    const failed = saveActiveMission({
      ...mission,
      status: "validating",
      milestones: failedMilestones,
      currentMilestoneIndex: index,
      maxValidationRetriesPerMilestone: maxRetries,
      maxValidationRetriesPerMission: maxMissionRetries,
      lastValidationResult: verdict ?? "UNKNOWN",
      lastValidationFailure: failure,
      lastBlockReason: "",
      nextAction: "Validation failed; evaluating safe repair retry.",
      lastSummary: `Validation ${verdict} for mission milestone ${milestone?.id ?? "current"}.`,
    });
    checkpointMission(failed, `Validation failed for ${milestone?.id ?? "current milestone"}. Retry ${retry}/${maxRetries} per milestone; mission retry ${missionRetry}/${maxMissionRetries} total. ${compact(validationText, 500)}`, "Evaluate safe repair retry before blocking or advancing.", milestone?.id, { validationResult: verdict });
    const unsafe = validationFailureRequiresApproval(failure, settings, {
      concreteRepairableIssue: mission.concreteRepairableIssue,
      evidenceGap: mission.evidenceGap,
    });
    const shouldBlock = mission.autonomy === "manual"
      || settings.missions.autoRepairValidationFailures === false
      || settings.missions.pauseAfterValidationFailure === true
      || retry >= maxRetries
      || Boolean(unsafe)
      || (mission.autonomy === "full_auto" && !missionAllowsFullAuto(mission, settings));
    if (shouldBlock) {
      const reason = mission.autonomy === "manual" ? "manual autonomy pauses after validation failure."
        : settings.missions.autoRepairValidationFailures === false ? "autoRepairValidationFailures=false."
        : settings.missions.pauseAfterValidationFailure === true ? "pauseAfterValidationFailure=true."
        : retry >= maxRetries ? "milestone repair retry limit exhausted"
        : unsafe ?? "repair requires approval or safety gate.";
      const blockedMilestones = failed.milestones.map((m, i) => i === index ? { ...m, status: "failed" as const } : m);
      const repairCompleted = missionRepairCompletedPendingRevalidation(failed);
      const nextAction = repairCompleted
        ? `Repair completed; run /mission retry or /mission revalidate to validate ${milestone?.id ?? "current milestone"}.`
        : reason === "mission repair retry limit exhausted" ? "Inspect failure or manually approve broader repair."
        : reason === "milestone repair retry limit exhausted" ? "Inspect failure, adjust settings, or manually approve broader repair."
        : "Inspect validation failure, approve broader repair if safe, or run /mission repair after addressing the blocker.";
      const blocked = saveActiveMission({ ...failed, status: "blocked", milestones: blockedMilestones, lastRepairStatus: repairCompleted && !unsafe ? "completed" : unsafe ? "blocked" : (failed.lastRepairStatus ?? "none"), lastBlockReason: reason, nextAction, lastSummary: "Mission blocked after validation failure." });
      checkpointMission(blocked, `Mission blocked after validation failure. Reason: ${reason}`, nextAction, milestone?.id, { validationResult: verdict });
      updateState({ mode: "mission_blocked", activeMissionId: blocked.id, validationReport: validationText, validationVerdict: verdict, lastMissionStopSummary: buildMissionStopSummary(ctx, blocked, "blocked", "Mission blocked", { validationText, verdict, reason }) }, ctx);
      queueMissionTerminalSummary(ctx, blocked, "blocked", "Mission blocked", { validationText, verdict, reason });
      recordWorkflowInternalEvent(ctx, "Mission validation failure card suppressed from transcript.");
      showBlockedMissionRecoveryMenu(ctx);
      return;
    }
    updateState({ mode: "mission_validating", activeMissionId: failed.id, validationReport: validationText, validationVerdict: verdict }, ctx);
    await startMissionRepair(ctx, activeMission ?? failed, "auto");
  }

  // ── Clarification interactive flow ─────────────────────────────

  /**
   * Run the structured clarification flow using Pi's ctx.ui.select()
   * for each question. Returns the answers, or undefined if cancelled.
   */
  async function runClarificationSelect(ctx: ExtensionContext, questions: ClarificationQuestion[]): Promise<ClarificationAnswer[] | undefined> {
    const answers: ClarificationAnswer[] = [];

    for (let i = 0; i < questions.length; i++) {
      const q = questions[i];
      const title = `Question ${i + 1} of ${questions.length}: ${q.question}`;
      const hasCustomOption = q.options.some(o => /^D\./i.test(o));
      const options = [...q.options, ...(hasCustomOption ? [] : ["D. Other: type your own answer"]), "Skip this question", "Stop and answer later"];
      const choice = await ctx.ui.select(title, options);
      if (!choice || choice === "Stop and answer later") return undefined;

      if (choice === "Skip this question") {
        answers.push({ index: q.index, letter: "S", skipped: true });
        continue;
      }

      const letterMatch = choice.match(/^([A-D])\./);
      const letter = letterMatch ? letterMatch[1] : "A";

      if (letter === "D") {
        const custom = await ctx.ui.input("Your custom answer:", "Type your answer");
        answers.push({ index: q.index, letter: "D", custom: custom?.trim() || "custom answer" });
      } else {
        answers.push({ index: q.index, letter });
      }
    }

    return answers;
  }

  /**
   * Apply clarification answers and re-run planning.
   */
  async function applyClarificationAnswers(ctx: ExtensionContext, answers: ClarificationAnswer[]) {
    const questions = state.clarifyingQuestions ?? [];
    const answerSummary = formatAnswersForPlanner(questions, answers);
    const settings = loadWorkflowSettings(ctx.cwd);
    const priorPlanning = snapshotSubagentPhaseUsage("Planning");
    if (!beginForcedSubagentPhase(ctx, "Planning", settings, { task: state.task ?? "Plan with clarification answers" })) {
      updateState({ mode: "planning", clarifyingAnswers: answers, draftPlan: state.draftPlan, approvedPlan: undefined, planProgress: workflowPlanProgressEnabled(settings) ? mergePlanProgress({ ...state, mode: "planning", draftPlan: state.draftPlan, approvedPlan: undefined }, settings, { lifecycleStatus: "blocked", nextAction: "fix forced planning sub-agent policy or rerun planning", steps: [] }, undefined) : state.planProgress }, ctx);
      return;
    }
    const planningPreflightSatisfied = priorSubagentUsageSatisfiesForced("Planning", priorPlanning, settings);
    if (planningPreflightSatisfied) restoreSubagentPhaseUsage("Planning", priorPlanning);
    updateState({
      mode: "planning",
      clarifyingAnswers: answers,
      lastWorkflowHandoff: undefined,
    }, ctx);
    await beginPlanning(ctx, state.task ?? "Plan with clarification answers", state.approvedPlan, answerSummary, { feedbackKind: "clarification", planningPreflightSatisfied });
  }

  async function runStandardClarificationSelect(ctx: ExtensionContext, questions: ClarificationQuestion[]): Promise<ClarificationAnswer[] | undefined> {
    const answers: ClarificationAnswer[] = [];
    for (let i = 0; i < questions.length; i++) {
      const q = questions[i];
      const hasCustomOption = q.options.some(o => /^D\./i.test(o));
      const choice = await ctx.ui.select(`Standard Question ${i + 1} of ${questions.length}: ${q.question}`, [...q.options, ...(hasCustomOption ? [] : ["D. Other: type your own answer"]), "Skip this question", "Stop and answer later"]);
      if (!choice || choice === "Stop and answer later") return undefined;
      if (choice === "Skip this question") {
        answers.push({ index: q.index, letter: "S", skipped: true });
        continue;
      }
      const letter = choice.match(/^([A-D])\./)?.[1] ?? "A";
      if (letter === "D") {
        const custom = await ctx.ui.input("Your custom answer:", "Type your answer");
        answers.push({ index: q.index, letter: "D", custom: custom?.trim() || "custom answer" });
      } else {
        answers.push({ index: q.index, letter });
      }
    }
    return answers;
  }

  function recordStandardClarificationAnswer(ctx: ExtensionContext, answerSummary: string, answers?: ClarificationAnswer[]) {
    updateState({
      standardClarificationPending: false,
      standardClarificationStage: "answered",
      standardClarificationAnswer: answerSummary,
      standardClarifyingAnswers: answers,
      standardLastAutoCheckAt: undefined,
      standardLastClarificationDecision: undefined,
      standardLastClarificationReason: undefined,
    }, ctx);
  }

  async function applyStandardClarificationAnswers(ctx: ExtensionContext, answerSummary: string, answers?: ClarificationAnswer[], options: { showRecorded?: boolean } = {}) {
    const task = state.standardClarificationTask ?? state.task ?? state.originalTask ?? "Continue Standard Mode task after clarification";
    const work = classifyStandardWork(task, answerSummary);
    resetStandardSubagentUsage();
    recordStandardClarificationAnswer(ctx, answerSummary, answers);
    updateState({ task, originalTask: task, standardActivePhase: work.phase, standardWorkKind: work.kind, lastWorkflowHandoff: undefined }, ctx);
    queueWorkflowPrompt(pi, standardClarificationAnsweredPrompt(task, answerSummary), buildQueuedFailureRecovery(ctx, (reason) => recoverStandardTransientHandoffFailure(ctx, reason)));
  }

  function standardClarificationAnswerSummary(input: string): { summary: string; answers?: ClarificationAnswer[] } {
    const questions = state.standardClarifyingQuestions ?? [];
    const parsed = parseShorthandAnswers(input);
    if (questions.length > 0 && parsed.length > 0) return { summary: formatAnswersForPlanner(questions, parsed), answers: parsed };
    return { summary: input.trim() };
  }


  async function applyMissionClarificationAnswers(ctx: ExtensionContext, answers: ClarificationAnswer[]) {
    const mission = activeMission ?? (state.activeMissionId ? loadMissionState(state.activeMissionId) : undefined) ?? loadMissionState();
    if (!mission) return show(pi, "# Mission Clarification Error\n\nNo active mission found.");
    if (mission.status !== "draft" && mission.status !== "awaiting_clarification" && mission.status !== "planned") {
      return show(pi, `# Mission Clarification Refused\n\nMission ${mission.id} is ${mission.status}. Clarification answers can only revise a draft/planned mission before approval.`);
    }
    const questions = mission.clarificationQuestions?.length ? mission.clarificationQuestions : (state.clarifyingQuestions ?? []);
    const settings = loadWorkflowSettings(ctx.cwd);
    const planningOverride = { policy: missionSubagentPolicy(settings), workers: missionPlanningWorkerCount(settings), label: "Mission Planning", task: mission.goal };
    const priorPlanning = snapshotSubagentPhaseUsage("Planning");
    if (!beginForcedSubagentPhase(ctx, "Planning", settings, planningOverride)) {
      const blocked = saveActiveMission({ ...mission, status: "blocked", clarificationQuestions: questions, clarificationAnswers: answers, lastBlockReason: "Mission clarification resume blocked by forced Mission Planning sub-agent policy.", nextAction: "Fix Mission Planning sub-agent workers, then run /mission resume or /mission plan.", lastSummary: "Mission clarification answers recorded, but forced Mission Planning availability gate did not pass." });
      checkpointMission(blocked, "Mission clarification resume blocked by forced Mission Planning sub-agent policy.", "Fix Mission Planning sub-agent workers, then run /mission resume or /mission plan.");
      updateState({ mode: "mission_blocked", activeMissionId: blocked.id, task: blocked.goal, originalTask: blocked.goal, clarifyingQuestions: questions, clarifyingAnswers: answers, draftPlan: blocked.planText, approvedPlan: undefined }, ctx);
      return;
    }
    const planningPreflightSatisfied = priorSubagentUsageSatisfiesForced("Planning", priorPlanning, settings, planningOverride);
    if (planningPreflightSatisfied) restoreSubagentPhaseUsage("Planning", priorPlanning);
    const next = saveActiveMission({ ...mission, status: "draft", clarificationQuestions: questions, clarificationAnswers: answers, lastSummary: "Mission clarification answered. Resuming milestone planning." });
    checkpointMission(next, "Mission clarification answers recorded.", "Resume dynamic milestone planning with clarification applied.");
    updateState({ mode: "mission_planning", activeMissionId: next.id, task: next.goal, originalTask: next.goal, clarifyingQuestions: questions, clarifyingAnswers: answers, lastWorkflowHandoff: undefined }, ctx);
    await beginMissionPlanning(ctx, { ...next, clarificationQuestions: questions, clarificationAnswers: answers }, { planningPreflightSatisfied });
  }

  function showMissionClarificationFallback(reason: string): void {
    show(pi, `# Mission Clarification Needed\n\n${reason}\n\nUse one of:\n- \`/mission clarify\`\n- \`/mission clarify answer 1A 2C\`\n- \`/mission clarify answer 1D: your text\`\n- reply with shorthand like \`1A, 2C\` or \`1D: your answer\``);
  }

  function missionHandoffCompatible(snapshot: WorkflowHandoffSnapshot, currentMission?: MissionState): boolean {
    if (snapshot.expectedMode && state.mode !== snapshot.expectedMode) return false;
    if (snapshot.activeMissionId && state.activeMissionId && state.activeMissionId !== snapshot.activeMissionId) return false;
    const mission = currentMission ?? (snapshot.activeMissionId ? loadMissionState(snapshot.activeMissionId) : undefined);
    if (snapshot.activeMissionId && !mission) return false;
    if (snapshot.missionUpdatedAt && mission?.updatedAt !== snapshot.missionUpdatedAt) return false;
    if (snapshot.missionPlanFingerprint && mission && missionPlanMenuFingerprint(mission) !== snapshot.missionPlanFingerprint) return false;
    return true;
  }

  async function showMissionClarificationMenu(ctx: ExtensionContext, snapshot: WorkflowHandoffSnapshot) {
    recordWorkflowInternalEvent(ctx, "Internal workflow lifecycle event suppressed.");
    const questions = snapshot.questions ?? [];
    if (!missionHandoffCompatible(snapshot)) {
      showMissionClarificationFallback(snapshot.fallback);
      return;
    }
    const mission = snapshot.activeMissionId ? loadMissionState(snapshot.activeMissionId) : activeMission ?? loadMissionState();
    if (!mission) {
      showMissionClarificationFallback("Mission clarification menu could not open because no active mission was found.");
      return;
    }
    const settings = loadWorkflowSettings(ctx.cwd);
    if (settings.missions.interactiveClarificationEnabled === false || !ctx.hasUI || questions.length === 0) {
      showMissionClarificationFallback(snapshot.fallback);
      return;
    }
    let choice: string | undefined;
    try {
      choice = await ctx.ui.select("Mission clarification requested. Choose how to answer:", ["Answer Questions (guided)", "Type Shorthand (e.g. 1A, 2C, 3B)", "Cancel Mission"]);
    } catch (error) {
      showMissionClarificationFallback(`Interactive mission clarification menu failed to open: ${error instanceof Error ? error.message : String(error)}`);
      return;
    }
    if (choice === "Answer Questions (guided)") {
      const answers = await runClarificationSelect(ctx, questions);
      if (answers) await applyMissionClarificationAnswers(ctx, answers);
    } else if (choice === "Type Shorthand (e.g. 1A, 2C, 3B)") {
      const shorthand = await ctx.ui.input("Type mission clarification choices:", "1A, 2C, 3B");
      const parsed = parseShorthandAnswers(shorthand ?? "");
      if (parsed.length > 0) await applyMissionClarificationAnswers(ctx, parsed);
    } else if (choice === "Cancel Mission") {
      const stopped = saveActiveMission({ ...mission, status: "stopped", lastSummary: "Mission cancelled during clarification." });
      checkpointMission(stopped, "Mission cancelled during clarification.", "No further mission action queued.");
      updateState({ mode: "mission_stopped", activeMissionId: stopped.id, task: stopped.goal, originalTask: stopped.goal }, ctx);
    }
  }

  async function runMissionClarificationFlow(ctx: ExtensionContext, mission: MissionState, questions: ClarificationQuestion[]) {
    const snapshot: WorkflowHandoffSnapshot = {
      kind: "mission_clarification_menu",
      expectedMode: "mission_awaiting_clarification",
      activeMissionId: mission.id,
      questions,
      task: mission.goal,
      fallback: "Mission clarification questions are ready, but the interactive menu is unavailable.",
    };
    await showMissionClarificationMenu(ctx, snapshot);
  }

  async function reviseMissionPlanWithFeedback(ctx: ExtensionContext, mission: MissionState, feedback: string) {
    const revisionFeedback = feedback.trim();
    if (!revisionFeedback) {
      updateState({ mode: "mission_plan_ready", activeMissionId: mission.id, task: mission.goal, originalTask: mission.goal, draftPlan: mission.planText }, ctx);
      return recordWorkflowInternalEvent(ctx, `Mission revision dismissed: ${mission.id}`);
    }
    if (!mission.planText?.trim() && mission.milestones.length === 0) {
      return show(pi, "# Mission Revision Unavailable\n\nNo mission plan is available to revise. Run `/mission plan` first.");
    }
    const revising = saveActiveMission({
      ...mission,
      status: "draft",
      currentStep: undefined,
      reviewerReport: undefined,
      reviewerVerdict: undefined,
      lastReviewFailure: "",
      lastReviewAttempt: "Mission plan revision requested by user.",
      lastReviewRepairStatus: "none",
      reviewRepairInProgress: false,
      lastRevisionFeedback: revisionFeedback,
      lastSummary: "Mission plan revision requested from user feedback.",
      nextAction: "Mission planner is revising the milestone plan from user feedback.",
    });
    checkpointMission(revising, "Mission plan revision requested from user feedback.", "Revise the mission milestone plan before approval.");
    updateState({ mode: "mission_planning", activeMissionId: revising.id, task: revising.goal, originalTask: revising.goal, draftPlan: revising.planText, reviewerReport: undefined, reviewerVerdict: undefined }, ctx);
    await beginMissionPlanning(ctx, revising, { revisionFeedback });
  }

  async function requestMissionPlanRevision(ctx: ExtensionContext, mission: MissionState, feedback?: string) {
    const explicitFeedback = feedback?.trim();
    if (explicitFeedback) return reviseMissionPlanWithFeedback(ctx, mission, explicitFeedback);
    if (!ctx.hasUI) return show(pi, "# Mission Revise\n\nUsage: `/mission revise <feedback>`");
    updateState({ mode: "mission_plan_ready", activeMissionId: mission.id, task: mission.goal, originalTask: mission.goal, draftPlan: mission.planText }, ctx);
    const editorFeedback = await ctx.ui.editor("Mission revision feedback:", "");
    await reviseMissionPlanWithFeedback(ctx, mission, editorFeedback ?? "");
  }

  async function showMissionPlanMenu(ctx: ExtensionContext, mission: MissionState, snapshot?: WorkflowHandoffSnapshot) {
    stopStartupVisual(ctx);
    const handoffSnapshot = snapshot ?? { kind: "mission_plan_menu" as const, expectedMode: "mission_plan_ready", activeMissionId: mission.id, fallback: "Mission plan is ready, but the interactive menu is unavailable." };
    const currentMission = handoffSnapshot.activeMissionId ? loadMissionState(handoffSnapshot.activeMissionId) : undefined;
    if (!missionHandoffCompatible(handoffSnapshot, currentMission)) {
      showMissionPlanMenuFallback("Mission plan menu was skipped because the active mission state changed.");
      return;
    }
    const menuMission = currentMission ?? mission;
    mission = menuMission;
    showMissionPlanReadyCard(mission);
    if (!ctx.hasUI) return;
    const reviewChoice = ["PASS", "NOTES"].includes(mission.reviewerVerdict ?? "") ? [] : ["Review Mission Plan"];
    const choices = mission.autonomy === "manual" || mission.autonomy === "approval_gated"
      ? [...reviewChoice, "Approve Mission", "Revise Mission Plan", "Answer More Clarifications", "Cancel Mission"]
      : [...reviewChoice, "Approve Mission", "Approve And Run Mission", "Revise Mission Plan", "Answer More Clarifications", "Cancel Mission"];
    const choice = await ctx.ui.select("Mission plan ready. Choose next action:", choices);
    if (!choice) {
      updateState({ mode: "mission_plan_ready", activeMissionId: mission.id, task: mission.goal, originalTask: mission.goal, draftPlan: mission.planText }, ctx);
      showMissionPlanMenuFallback("Mission plan menu was dismissed. The mission plan remains ready.");
      return recordWorkflowInternalEvent(ctx, `Mission plan menu dismissed: ${mission.id}`);
    }
    if (choice === "Review Mission Plan") {
      await beginMissionReview(ctx, mission);
    } else if (choice === "Approve Mission") {
      await handleMissionApprovalHandoff(ctx, mission, "menu");
    } else if (choice === "Approve And Run Mission") {
      const gate = await continueBeforeMissionApproval(ctx, mission, false);
      if (gate !== "approved") return;
      const approved = approveMission(ctx, activeMission?.id === mission.id ? activeMission : mission);
      if (approved) await beginMissionRun(ctx, approved);
    } else if (choice === "Revise Mission Plan") {
      await requestMissionPlanRevision(ctx, mission);
    } else if (choice === "Answer More Clarifications") {
      const next = saveActiveMission({ ...mission, status: "draft", lastSummary: "Additional mission clarification requested before approval.", nextAction: "Generate dynamic mission clarification questions before approval." });
      checkpointMission(next, "Additional mission clarification requested before approval.", "Generate dynamic mission-specific clarification questions.");
      recordWorkflowInternalEvent(ctx, "Internal workflow lifecycle event suppressed.");
      await beginMissionPlanning(ctx, next, { forceClarification: true, forceAdditionalClarification: true, forceReason: "user requested additional mission clarification before approval" });
    } else if (choice === "Cancel Mission") {
      const stopped = saveActiveMission({ ...mission, status: "stopped", lastSummary: "Mission cancelled before approval." });
      checkpointMission(stopped, "Mission cancelled before approval.", "No further mission action queued.");
      updateState({ mode: "mission_stopped", activeMissionId: stopped.id, task: stopped.goal, originalTask: stopped.goal }, ctx);
      show(pi, "# Mission Cancelled");
    }
  }

  function showMissionPlanMenuFallback(reason: string): void {
    show(pi, `# Mission Plan Ready\n\n${reason}\n\nUse one of:\n- \`/mission review\`\n- \`/mission approve\`\n- \`/mission revise <feedback>\`\n- \`/mission cancel\``);
  }

  function showMissionPlanReadyCard(mission: MissionState): void {
    const planText = mission.planText?.trim() ? mission.planText : "(none recorded)";
    show(pi, `# Mission Plan Ready\n\n${planText}\n\nChoose an action in the Mission menu, or use:\n- \`/mission review\`\n- \`/mission approve\`\n- \`/mission revise <feedback>\`\n- \`/mission cancel\``);
  }

  // ── Menus ──────────────────────────────────────────────────────

  function showPlanMenuCommandFallback(reason: string): void {
    show(pi, `# Plan Ready\n\n${reason}\n\nUse one of:\n- \`/plan approve\`\n- \`/plan revise <feedback>\`\n- \`/plan cancel\``);
  }

  function showPlanReadyForApprovalCard(snapshot: WorkflowHandoffSnapshot, options: { includePlanText?: boolean } = {}): void {
    const planText = snapshot.draftPlan?.trim()
      ? snapshot.draftPlan
      : state.draftPlan?.trim()
        ? state.draftPlan
        : state.approvedPlan?.trim()
          ? state.approvedPlan
          : "(none recorded)";
    const body = options.includePlanText === true
      ? `${planText}\n\nChoose an action in the approval menu, or use:`
      : "Choose an action in the approval menu. The native plan above is the source of truth, and the saved plan remains recoverable with:";
    show(pi, `# Plan Ready For Approval\n\n${body}\n- \`/plan approve\`\n- \`/plan revise <feedback>\`\n- \`/plan cancel\``);
  }

  function showPlanClarificationFallback(reason: string, questions?: ClarificationQuestion[]): void {
    const rendered = questions?.length ? `\n\n${renderClarificationQuestionsForUser(questions)}` : "";
    show(pi, `# Clarification Needed\n\n${reason}${rendered}\n\nAnswer with: /clarify answer 1A 2C\nSkip with: /clarify answer 1S\nCustom answer: /clarify answer 3D: your text`);
  }

  function planHandoffCompatible(snapshot: WorkflowHandoffSnapshot): boolean {
    if (snapshot.expectedMode && state.mode !== snapshot.expectedMode) return false;
    if (snapshot.activePlanId && state.activePlanId && state.activePlanId !== snapshot.activePlanId) return false;
    return true;
  }

  async function showPlanClarificationMenu(ctx: ExtensionContext, snapshot: WorkflowHandoffSnapshot) {
    if (!planHandoffCompatible(snapshot)) {
      showPlanClarificationFallback(snapshot.fallback, snapshot.questions);
      return;
    }
    const settings = loadWorkflowSettings(ctx.cwd);
    const maxQuestions = Math.max(1, Math.min(5, settings.planning.maxClarificationQuestions ?? 3));
    const questions = (snapshot.questions?.length ? snapshot.questions : state.clarifyingQuestions?.length ? state.clarifyingQuestions : parseClarifyingQuestions(state.draftPlan ?? "")).slice(0, maxQuestions);
    updateState({ clarifyingQuestions: questions.length ? questions : state.clarifyingQuestions }, ctx);
    if (!ctx.hasUI || settings.planning.interactiveClarificationEnabled === false || !questions.length) {
      showPlanClarificationFallback(snapshot.fallback, questions);
      return;
    }
    const choice = await ctx.ui.select("Clarification requested. How would you like to answer?", [
      "Answer Questions (guided)",
      "Type Shorthand (e.g. 1A, 2C, 3B)",
      "Revise Original Request",
      "Cancel Plan",
    ]);
    if (choice === "Answer Questions (guided)") {
      const answers = await runClarificationSelect(ctx, questions);
      if (answers) await applyClarificationAnswers(ctx, answers);
    } else if (choice === "Type Shorthand (e.g. 1A, 2C, 3B)") {
      const shorthand = await ctx.ui.input("Type your choices:", "1A, 2C, 3B");
      const parsed = parseShorthandAnswers(shorthand ?? "");
      if (parsed.length > 0) await applyClarificationAnswers(ctx, parsed);
    } else if (choice === "Revise Original Request") {
      const feedback = await ctx.ui.editor("Revised request:", state.task ?? "");
      if (feedback?.trim()) {
        updateState({ task: feedback.trim(), clarifyingQuestions: undefined, clarifyingAnswers: undefined, lastWorkflowHandoff: undefined }, ctx);
        await beginPlanning(ctx, feedback.trim());
      }
    } else if (choice === "Cancel Plan") {
      exitPlanModeToIdle(ctx);
    }
  }

  async function showPlanApprovalMenu(ctx: ExtensionContext, snapshot: WorkflowHandoffSnapshot) {
    if (!planHandoffCompatible(snapshot)) {
      showPlanMenuCommandFallback(snapshot.fallback);
      return;
    }
    if (!ctx.hasUI) {
      showPlanReadyForApprovalCard(snapshot, { includePlanText: true });
      return;
    }
    showPlanReadyForApprovalCard(snapshot);
    const settings = loadWorkflowSettings(ctx.cwd);
    const reviewerChoiceAvailable = settings.workflow.offerReviewerBeforeExecute === true && planModelAvailable(settings, "reviewer");
    const autoReviewerWillRun = !reviewerChoiceAvailable && planModelAvailable(settings, "reviewer") && settings.workflow.autoRunReviewerBeforeExecute === true;
    const approveLabel = autoReviewerWillRun ? "Approve and Run Workflow" : "Approve and Execute";
    const choices = reviewerChoiceAvailable
      ? ["Approve and Execute", "Run Reviewer", "Revise Plan", "Cancel"]
      : [approveLabel, "Revise Plan", "Cancel"];
    let menuChoice: string | undefined;
    try {
      menuChoice = await ctx.ui.select("Plan ready. Choose next action:", choices);
    } catch (error) {
      showPlanMenuCommandFallback(`Interactive approval menu failed to open: ${error instanceof Error ? error.message : String(error)}`);
      return;
    }
    if (!menuChoice) {
      updateState({ mode: "plan_draft", activePlanId: snapshot.activePlanId ?? state.activePlanId, draftPlan: snapshot.draftPlan ?? state.draftPlan, task: snapshot.task ?? state.task }, ctx);
      showPlanMenuCommandFallback("Plan approval menu was dismissed. The plan remains ready for approval.");
      return;
    }
    if (menuChoice === "Approve and Execute") {
      await approveCurrentPlan(ctx, "plan approved by user", reviewerChoiceAvailable ? "execute" : "configured");
    } else if (menuChoice === "Approve and Run Workflow") {
      await approveCurrentPlan(ctx, "plan approved by user");
    } else if (menuChoice === "Run Reviewer") {
      await approveCurrentPlan(ctx, "plan approved by user for review", "review");
    } else if (menuChoice === "Revise Plan") {
      const feedback = await ctx.ui.editor("Revision feedback:", "");
      if (feedback?.trim()) await beginPlanning(ctx, snapshot.task ?? state.task ?? "Revise plan", snapshot.draftPlan ?? state.draftPlan ?? state.approvedPlan, feedback.trim());
    } else if (menuChoice === "Cancel") {
      exitPlanModeToIdle(ctx);
    }
  }

  async function showPlanMenu(ctx: ExtensionContext) {
    const pendingQuestions = state.mode === "awaiting_clarification" ? (state.clarifyingQuestions ?? parseClarifyingQuestions(state.draftPlan ?? "")) : [];
    if (state.mode === "awaiting_clarification" || pendingQuestions.length > 0) {
      await showPlanClarificationMenu(ctx, { kind: "plan_clarification_menu", expectedMode: "awaiting_clarification", activePlanId: state.activePlanId, questions: pendingQuestions, task: state.task ?? state.originalTask, fallback: "Plan clarification questions are ready, but the interactive menu is unavailable." });
      return;
    }
    if (!ctx.hasUI) {
      showPlanMenuCommandFallback("Interactive approval menu is unavailable in this context.");
      return;
    }
    const settings = loadWorkflowSettings(ctx.cwd);
    const needsClarification = planNeedsClarification(state.draftPlan);

    if (needsClarification) {
      // Parse questions from the planner output
      const questions = parseClarifyingQuestions(state.draftPlan ?? "").slice(0, Math.max(1, Math.min(5, settings.planning.maxClarificationQuestions ?? 3)));
      if (settings.planning.interactiveClarificationEnabled === false) {
        updateState({ clarifyingQuestions: questions.length > 0 ? questions : state.clarifyingQuestions }, ctx);
        return;
      }
      const choice = await ctx.ui.select("Clarification requested. How would you like to answer?", [
        "Answer Questions (guided)",
        "Type Shorthand (e.g. 1A, 2C, 3B)",
        "Revise Original Request",
        "Cancel Plan",
      ]);

      if (choice === "Answer Questions (guided)") {
        if (questions.length === 0) {
          // Fallback: couldn't parse structured questions
          const freeform = await ctx.ui.input("Type your answers (e.g. 1A, 2C, 3B or free text):", "1A, 2C, 3B");
          if (freeform?.trim()) {
            const parsed = parseShorthandAnswers(freeform.trim());
            if (parsed.length > 0) {
              await applyClarificationAnswers(ctx, parsed);
            } else {
              // Freeform text — pass directly as clarification
              await beginPlanning(ctx, state.task ?? "Clarify plan", undefined, freeform.trim(), { feedbackKind: "clarification" });
            }
          }
        } else {
          // Store questions in state for the interactive flow
          updateState({ clarifyingQuestions: questions }, ctx);
          const answers = await runClarificationSelect(ctx, questions);
          if (answers) {
            await applyClarificationAnswers(ctx, answers);
          }
        }
      } else if (choice === "Type Shorthand (e.g. 1A, 2C, 3B)") {
        const shorthand = await ctx.ui.input("Type your choices:", "1A, 2C, 3B");
        if (shorthand?.trim()) {
          const parsed = parseShorthandAnswers(shorthand.trim());
          if (parsed.length > 0) {
            await applyClarificationAnswers(ctx, parsed);
          } else {
            // Couldn't parse as shorthand — use as free text
            await beginPlanning(ctx, state.task ?? "Clarify plan", undefined, shorthand.trim(), { feedbackKind: "clarification" });
          }
        }
      } else if (choice === "Revise Original Request") {
        const feedback = await ctx.ui.editor("Revised request:", state.task ?? "");
        if (feedback?.trim()) {
          updateState({ task: feedback.trim(), clarifyingQuestions: undefined, clarifyingAnswers: undefined }, ctx);
          await beginPlanning(ctx, feedback.trim());
        }
      } else if (choice === "Cancel Plan") {
        exitPlanModeToIdle(ctx);
      }
      return;
    }

    await showPlanApprovalMenu(ctx, {
      kind: "plan_approval_menu",
      expectedMode: "plan_draft",
      activePlanId: state.activePlanId,
      draftPlan: state.draftPlan,
      task: state.task,
      fallback: "Interactive approval menu is unavailable in this context.",
    });
  }

  async function showPostExecutionMenu(ctx: ExtensionContext, validationAvailable = false) {
    if (!ctx.hasUI) return;
    const choices = validationAvailable ? ["Run Validation", "List Summary", "Start New Plan", "End"] : ["List Summary", "Start New Plan", "End"];
    const choice = await ctx.ui.select("Execution complete. Choose next action:", choices);
    if (choice === "Run Validation") await beginValidation(ctx, true);
    else if (choice === "List Summary") show(pi, renderWorkflowSummary(state, ctx.cwd));
    else if (choice === "Start New Plan") await enterPlanModeAwaitingInput(ctx);
    else if (choice === "End") recordWorkflowInternalEvent(ctx, "Plan post-execution validation menu ended by user.");
  }

  async function showFinalMenu(ctx: ExtensionContext) {
    if (!ctx.hasUI) return;
    const settings = loadWorkflowSettings(ctx.cwd);
    const returnToPlan = (settings.workflow as typeof settings.workflow & { returnToPlanModeAfterWorkflow?: boolean }).returnToPlanModeAfterWorkflow !== false;
    const verdict = state.validationVerdict;
    const passed = verdict === "PASS";
    const partial = verdict === "PARTIAL PASS";
    const repairablePartial = partial && classifyValidationFailure(verdict, state.validationReport ?? state.lastValidationFailure ?? "", { concreteRepairableIssue: state.concreteRepairableIssue, manualVerificationRequired: state.manualVerificationRequired, evidenceGap: state.evidenceGap }) === "repairable";
    const failed = verdict === "FAIL" || verdict === "UNKNOWN";
    const title = repairablePartial ? "Validation found repairable issues. Choose next action:" : partial ? "Validation passed with notes. Choose next action:" : failed ? "Validation failed. Choose next action:" : "Validation complete. Choose next action:";
    const choices = [
      ...(failed || repairablePartial ? ["Run Safe Repair"] : []),
      ...(!passed ? ["Revalidate"] : []),
      "List Summary",
      partial && !repairablePartial ? "Revise / Add Manual Verification Feedback" : "Revise / Fix Issues",
      ...(passed && returnToPlan ? ["Start New Plan"] : []),
      "End",
      ...(!passed ? ["Cancel"] : []),
    ];
    const choice = await ctx.ui.select(title, choices);
    if (!choice) return;
    if (choice === "Run Safe Repair") await startWorkflowRepair(ctx, "user");
    else if (choice === "Revalidate") await beginValidation(ctx, true, true);
    else if (choice === "List Summary") show(pi, renderWorkflowSummary(state, ctx.cwd));
    else if (choice === "Revise / Fix Issues" || choice === "Revise / Add Manual Verification Feedback") {
      const feedback = await ctx.ui.editor(choice === "Revise / Add Manual Verification Feedback" ? "Manual verification feedback or scope change?" : "What needs to change?", "");
      if (feedback?.trim()) await beginPlanning(ctx, state.task ?? "Revise/fix after validation", state.approvedPlan, feedback.trim());
    } else if (choice === "End" || choice === "Finish") {
      recordWorkflowInternalEvent(ctx, "Plan final menu ended by user.");
    } else if (choice === "Start New Plan" || (passed && returnToPlan)) {
      await enterPlanModeAwaitingInput(ctx);
    }
  }

  async function configureRoleModel(ctx: ExtensionContext, role: WorkflowRole) {
    const models = ctx.modelRegistry.getAll();
    const providers = [...new Set(models.map((m) => m.provider))].sort();
    const provider = await ctx.ui.select(`Select provider for ${role}:`, providers);
    if (!provider) return;
    const providerModels = models.filter((m) => m.provider === provider).map((m) => m.id).sort();
    const model = await ctx.ui.select(`Select model for ${role}:`, providerModels);
    if (!model) return;
    const result = setModelForRole(role, provider, model, ctx.cwd);
    const plannerReapplied = role === "planner" ? await reapplyPlannerRouteIfPlanMode(ctx, true) : false;
    const standardSettings = loadWorkflowSettings(ctx.cwd);
    const standardReapplied = effectiveStandardModelRole(standardSettings) === role ? await reapplyStandardRouteIfStandardMode(ctx, true) : false;
    workflowUiNotify(ctx, `${role} model set to ${provider}/${model} in ${result.file}${plannerReapplied || standardReapplied ? `\n${activeModelDiagnostic(ctx)}` : ""}`, "info");
  }

  async function configureStandardRoleModel(ctx: ExtensionContext, role: WorkflowRole) {
    const selected = await selectProviderAndModel(ctx, `Standard ${role} model`);
    if (!selected) return;
    const result = setStandardModelForRole(role, selected.provider, selected.model, ctx.cwd);
    await reapplyStandardRouteIfStandardMode(ctx, true);
    workflowUiNotify(ctx, `standard ${role} model set to ${selected.provider}/${selected.model} in ${result.file}`, "info");
  }

  async function inheritStandardRoleModel(ctx: ExtensionContext, role: WorkflowRole) {
    const result = clearStandardModelForRole(role, ctx.cwd);
    const settings = loadWorkflowSettings(ctx.cwd);
    const activeRole = effectiveStandardModelRole(settings);
    let activeNote = "";
    if (isStandardWorkflowMode(state)) {
      if (activeRole === role) {
        const reapplied = await reapplyStandardRouteIfStandardMode(ctx, false);
        activeNote = reapplied ? `\n\nActive Standard Mode ${role} route now inherits Shared.\n${activeModelDiagnostic(ctx)}` : "";
      } else {
        activeNote = `\n\nStandard ${role} route set to inherit Shared. Current Standard role is ${workflowRoleLabel(activeRole)}; ${workflowRoleLabel(role)} will inherit Shared when selected.`;
      }
    }
    workflowUiNotify(ctx, `standard ${role} model set to inherit Shared in ${result.file}${activeNote}`, "info");
  }

