  function renderStandardModelRoutingDetails(ctx: ExtensionContext): string {
    return `# Standard Model Routing\n\n${renderStandardModelStrategy(loadWorkflowSettings(ctx.cwd))}\n\n## Active Pi Session\n${activeModelDiagnostic(ctx)}\n\nStandard Mode can use the current Pi model, shared Workflow Suite models, or Standard-specific models. Standard-specific configuration does not mutate shared Plan/Mission model roles.`;
  }

  async function showStandardModelRoutingMenu(ctx: ExtensionContext) {
    if (!ctx.hasUI) return show(pi, renderStandardModelRoutingDetails(ctx));
    while (ctx.hasUI) {
      const choice = await ctx.ui.select("Standard Model Routing", ["Model Source", "Standard Model Role", "Configure Standard Planner", "Configure Standard Executor", "Configure Standard Reviewer", "Configure Standard Validator", "Inherit Shared Planner", "Inherit Shared Executor", "Inherit Shared Reviewer", "Inherit Shared Validator", "Standard Thinking Levels", "List Effective Standard Models", "Back"]);
      if (!choice || choice === "Back") return;
      if (choice === "Model Source") {
        const source = await ctx.ui.select("Standard model source", ["Current Pi model", "Shared Workflow Models", "Standard-specific Models"]);
        if (!source) continue;
        const result = updateSettings(ctx.cwd, undefined, (s) => {
          if (source === "Current Pi model") {
            s.standard.useSharedExecutorModel = false;
            s.standard.useStandardSpecificModels = false;
            s.standard.modelRole = "current";
          } else if (source === "Shared Workflow Models") {
            s.standard.useSharedExecutorModel = true;
            s.standard.useStandardSpecificModels = false;
            if (!s.standard.modelRole || s.standard.modelRole === "current") s.standard.modelRole = "executor";
          } else {
            s.standard.useSharedExecutorModel = true;
            s.standard.useStandardSpecificModels = true;
            if (!s.standard.modelRole || s.standard.modelRole === "current") s.standard.modelRole = "executor";
          }
        });
        await reapplyStandardRouteIfStandardMode(ctx, true);
        workflowUiNotify(ctx, `Standard model source set to ${source} in ${result.file}`, "info");
      } else if (choice === "Standard Model Role") {
        const role = parseStandardModelRole((await ctx.ui.select("Standard model role", ["Current Pi model", "Planner", "Executor", "Reviewer", "Validator"])) ?? "");
        if (!role) continue;
        const result = updateSettings(ctx.cwd, undefined, (s) => {
          s.standard.modelRole = role;
          if (role === "current") {
            s.standard.useSharedExecutorModel = false;
            s.standard.useStandardSpecificModels = false;
          } else if (s.standard.useSharedExecutorModel === false) {
            s.standard.useSharedExecutorModel = true;
          }
        });
        await reapplyStandardRouteIfStandardMode(ctx, true);
        workflowUiNotify(ctx, `Standard model role set to ${workflowRoleLabel(role)} in ${result.file}`, "info");
      } else if (choice === "Configure Standard Planner") await configureStandardRoleModel(ctx, "planner");
      else if (choice === "Configure Standard Executor") await configureStandardRoleModel(ctx, "executor");
      else if (choice === "Configure Standard Reviewer") await configureStandardRoleModel(ctx, "reviewer");
      else if (choice === "Configure Standard Validator") await configureStandardRoleModel(ctx, "validator");
      else if (choice === "Inherit Shared Planner") await inheritStandardRoleModel(ctx, "planner");
      else if (choice === "Inherit Shared Executor") await inheritStandardRoleModel(ctx, "executor");
      else if (choice === "Inherit Shared Reviewer") await inheritStandardRoleModel(ctx, "reviewer");
      else if (choice === "Inherit Shared Validator") await inheritStandardRoleModel(ctx, "validator");
      else if (choice === "Standard Thinking Levels") await configureStandardThinking(ctx);
      else if (choice === "List Effective Standard Models") show(pi, renderStandardModelRoutingDetails(ctx));
    }
  }

  async function showPlanModelBehaviorMenu(ctx: ExtensionContext) {
    if (!ctx.hasUI) return show(pi, `# Effective Plan Models\n\n${renderPlanModelSettings(loadWorkflowSettings(ctx.cwd))}`);
    while (ctx.hasUI) {
      const settings = loadWorkflowSettings(ctx.cwd);
      const choices = settings.planning.usePlanSpecificModels
        ? ["Model Source", "Configure Plan Planner", "Configure Plan Executor", "Configure Plan Reviewer", "Configure Plan Validator", "Inherit Shared Planner", "Inherit Shared Executor", "Inherit Shared Reviewer", "Inherit Shared Validator", "Plan Thinking Levels", "List Effective Plan Models", "Back"]
        : ["Model Source", "List Effective Plan Models", "Back"];
      const choice = await ctx.ui.select("Plan Models", choices);
      if (!choice || choice === "Back") return;
      if (choice === "Model Source") {
        const source = await ctx.ui.select("Plan model source", ["Shared Workflow Models", "Plan-Specific Models"]);
        if (!source) continue;
        const enabled = source === "Plan-Specific Models";
        const r = updateSettings(ctx.cwd, undefined, (s) => { s.planning.usePlanSpecificModels = enabled; });
        const activeRole = activePlanModelRole();
        const activeNote = activeRole ? await planRouteSavedFeedback(ctx, activeRole, activeRole === "validator" ? { requireEnabled: false } : {}) : "";
        workflowUiNotify(ctx, `planning.usePlanSpecificModels set to ${enabled} in ${r.file}${activeNote}`, "info");
      } else if (choice === "Configure Plan Planner") await configurePlanRoleModel(ctx, "planner");
      else if (choice === "Configure Plan Executor") await configurePlanRoleModel(ctx, "executor");
      else if (choice === "Configure Plan Reviewer") await configurePlanRoleModel(ctx, "reviewer");
      else if (choice === "Configure Plan Validator") await configurePlanRoleModel(ctx, "validator");
      else if (choice === "Inherit Shared Planner") await inheritPlanRoleModel(ctx, "planner");
      else if (choice === "Inherit Shared Executor") await inheritPlanRoleModel(ctx, "executor");
      else if (choice === "Inherit Shared Reviewer") await inheritPlanRoleModel(ctx, "reviewer");
      else if (choice === "Inherit Shared Validator") await inheritPlanRoleModel(ctx, "validator");
      else if (choice === "Plan Thinking Levels") await configurePlanThinking(ctx);
      else if (choice === "List Effective Plan Models") show(pi, `# Effective Plan Models\n\n${renderPlanModelSettings(loadWorkflowSettings(ctx.cwd))}`);
    }
  }

  function subagentModelScopeLabel(scope: WorkflowSubagentModelMode | "shared"): string {
    if (scope === "shared") return "Shared";
    if (scope === "plan") return "Plan";
    if (scope === "standard") return "Standard";
    return "Mission";
  }

  async function chooseSubagentBucket(ctx: ExtensionContext): Promise<WorkflowSubagentModelBucket | undefined> {
    return parseSubagentModelBucket((await ctx.ui.select("Sub-agent phase", ["planning", "execution", "repair", "review", "validation"])) ?? "");
  }

  async function configureSubagentBucketModel(ctx: ExtensionContext, scopeName: WorkflowSubagentModelMode | "shared") {
    const bucket = await chooseSubagentBucket(ctx);
    if (!bucket) return;
    const selected = await selectProviderAndModel(ctx, `${subagentModelScopeLabel(scopeName)} ${bucket} sub-agent model`);
    if (!selected) return;
    const result = setSubagentModelForBucket(scopeName, bucket, selected.provider, selected.model, ctx.cwd);
    workflowUiNotify(ctx, `${subagentModelScopeLabel(scopeName).toLowerCase()} ${bucket} sub-agent model set to ${selected.provider}/${selected.model} in ${result.file}`, "info");
  }

  async function configureSubagentBucketThinking(ctx: ExtensionContext, scopeName: WorkflowSubagentModelMode | "shared") {
    const bucket = await chooseSubagentBucket(ctx);
    if (!bucket) return;
    const level = parseThinkingLevel((await ctx.ui.select("Sub-agent thinking level", ["off", "minimal", "low", "medium", "high", "xhigh"])) ?? "");
    if (!level) return;
    const result = setSubagentThinkingForBucket(scopeName, bucket, level, ctx.cwd);
    workflowUiNotify(ctx, `${subagentModelScopeLabel(scopeName).toLowerCase()} ${bucket} sub-agent thinking set to ${level} in ${result.file}`, "info");
  }

  async function inheritSubagentBucketModel(ctx: ExtensionContext, scopeName: WorkflowSubagentModelMode | "shared") {
    const bucket = await chooseSubagentBucket(ctx);
    if (!bucket) return;
    const result = clearSubagentModelForBucket(scopeName, bucket, ctx.cwd);
    workflowUiNotify(ctx, `${subagentModelScopeLabel(scopeName).toLowerCase()} ${bucket} sub-agent model set to inherit in ${result.file}`, "info");
  }

  async function showSubagentModelRoutingMenu(ctx: ExtensionContext, scopeName: WorkflowSubagentModelMode | "shared") {
    if (!ctx.hasUI) return show(pi, `# ${subagentModelScopeLabel(scopeName)} Sub-agent Models\n\n${renderSubagentModelRouting(loadWorkflowSettings(ctx.cwd), scopeName)}`);
    while (ctx.hasUI) {
      const label = subagentModelScopeLabel(scopeName);
      const choices = ["Enable / Disable Routing", "Configure Phase Model", "Configure Phase Thinking", "Inherit Phase Model", "List Effective Sub-agent Models", "Back"];
      const choice = await ctx.ui.select(`${label} Sub-agent Models`, choices);
      if (!choice || choice === "Back") return;
      if (choice === "Enable / Disable Routing") {
        const enabled = await chooseBool(ctx, `${label} sub-agent model routing?`);
        if (enabled === undefined) continue;
        const result = updateSettings(ctx.cwd, undefined, (s) => {
          if (scopeName === "shared") s.subagents.modelRouting = { ...(s.subagents.modelRouting ?? {}), enabled };
          else if (scopeName === "plan") s.planning.subagentModelRouting = { ...(s.planning.subagentModelRouting ?? {}), enabled };
          else if (scopeName === "standard") s.standard.subagentModelRouting = { ...(s.standard.subagentModelRouting ?? {}), enabled };
          else s.missions.subagentModelRouting = { ...(s.missions.subagentModelRouting ?? {}), enabled };
        });
        workflowUiNotify(ctx, `${label} sub-agent model routing set to ${enabled} in ${result.file}`, "info");
      } else if (choice === "Configure Phase Model") await configureSubagentBucketModel(ctx, scopeName);
      else if (choice === "Configure Phase Thinking") await configureSubagentBucketThinking(ctx, scopeName);
      else if (choice === "Inherit Phase Model") await inheritSubagentBucketModel(ctx, scopeName);
      else if (choice === "List Effective Sub-agent Models") show(pi, `# ${label} Sub-agent Models\n\n${renderSubagentModelRouting(loadWorkflowSettings(ctx.cwd), scopeName)}`);
    }
  }

  async function showWorkflowRepairRetrySettingsMenu(ctx: ExtensionContext) {
    if (!ctx.hasUI) return show(pi, renderFullWorkflowSettings(loadWorkflowSettings(ctx.cwd)));
    while (ctx.hasUI) {
      const setting = await ctx.ui.select("Plan Repair / Validation Retry", ["Auto Repair Validation Failures", "Validation Retry Mode", "Max Retries Per Plan", "Max Retries Per Workflow", "Pause After Validation Failure", "Require Approval For Out-Of-Scope Repair", "Require Approval For Destructive Repair", "Back"]);
      if (!setting || setting === "Back") return;
      if (setting === "Max Retries Per Plan" || setting === "Max Retries Per Workflow") {
        const key = setting === "Max Retries Per Plan" ? "maxValidationRetriesPerPlan" : "maxValidationRetriesPerWorkflow";
        const max = key === "maxValidationRetriesPerPlan" ? 10 : 100;
        const options = key === "maxValidationRetriesPerPlan" ? ["0", "1", "2", "3", "4", "5", "10"] : ["0", "1", "2", "4", "8", "12", "20", "50", "100"];
        const raw = await ctx.ui.select(setting, options);
        const count = raw === undefined ? undefined : Number(raw);
        if (Number.isInteger(count) && count >= 0 && count <= max) { const r = updateSettings(ctx.cwd, undefined, (s) => { (s.workflow as typeof s.workflow & Record<string, number>)[key] = count; }); workflowUiNotify(ctx, `workflow.${key} set to ${count} in ${r.file}`, "info"); }
      } else if (setting === "Validation Retry Mode") {
        const mode = parseValidationRetryMode((await ctx.ui.select("Validation retry mode", ["off", "safe_only", "aggressive_within_scope"])) ?? "");
        if (mode) { const r = updateSettings(ctx.cwd, undefined, (s) => { s.workflow.validationRetryMode = mode; }); workflowUiNotify(ctx, `workflow.validationRetryMode set to ${mode} in ${r.file}`, "info"); }
      } else {
        const keyMap: Record<string, keyof ReturnType<typeof loadWorkflowSettings>["workflow"]> = {
          "Auto Repair Validation Failures": "autoRepairValidationFailures",
          "Pause After Validation Failure": "pauseAfterValidationFailure",
          "Require Approval For Out-Of-Scope Repair": "requireApprovalForOutOfScopeRepair",
          "Require Approval For Destructive Repair": "requireApprovalForDestructiveRepair",
        };
        const key = keyMap[setting];
        const enabled = await chooseBool(ctx, `${String(key)}?`);
        if (enabled !== undefined) { const r = updateSettings(ctx.cwd, undefined, (s) => { (s.workflow as Record<string, unknown>)[String(key)] = enabled; }); workflowUiNotify(ctx, `workflow.${String(key)} set to ${enabled} in ${r.file}`, "info"); }
      }
    }
  }

  async function showPlanModeSettingsMenu(ctx: ExtensionContext) {
    if (!ctx.hasUI) return show(pi, renderFullWorkflowSettings(loadWorkflowSettings(ctx.cwd)));
    while (ctx.hasUI) {
      const choice = await ctx.ui.select("Plan Mode Settings", ["Plan Models", "Planning Depth", "Plan Clarification", "Plan Sub-agents / Workers", "Review / Validation Behavior", "Repair / Validation Retry", "Plan Progress / Runtime", "Plan History", "List Current Settings", "Back"]);
      if (!choice || choice === "Back") return;
      if (choice === "Plan Models") {
        await showPlanModelBehaviorMenu(ctx);
      } else if (choice === "Planning Depth") {
        const depth = parsePlanningDepth((await ctx.ui.select("Planning depth", ["fast", "standard", "deep", "maximum"])) ?? "");
        if (depth) { const r = updateSettings(ctx.cwd, undefined, (s) => { s.planning.depth = depth; }); workflowUiNotify(ctx, `planning.depth set to ${depth} in ${r.file}`, "info"); }
      } else if (choice === "Plan Clarification") {
        const setting = await ctx.ui.select("Plan Clarification", ["Clarification Mode", "Interactive Clarification", "Max Clarification Questions", "Timing", "Quality Gate", "Allow Without Analysis", "Use Sub-agents Before Clarification", "Back"]);
        if (!setting || setting === "Back") continue;
        if (setting === "Clarification Mode") {
          const mode = parseClarificationMode((await ctx.ui.select("Plan clarification mode", ["auto", "always_for_nontrivial", "never"])) ?? "");
          if (mode) { const r = updateSettings(ctx.cwd, undefined, (s) => { s.planning.clarificationMode = mode; }); workflowUiNotify(ctx, `planning.clarificationMode set to ${mode} in ${r.file}`, "info"); }
        } else if (setting === "Interactive Clarification") {
          const enabled = await chooseBool(ctx, "Interactive clarification enabled?");
          if (enabled !== undefined) { const r = updateSettings(ctx.cwd, undefined, (s) => { s.planning.interactiveClarificationEnabled = enabled; }); workflowUiNotify(ctx, `planning.interactiveClarificationEnabled set to ${enabled} in ${r.file}`, "info"); }
        } else if (setting === "Max Clarification Questions") {
          const count = parsePositiveInt((await ctx.ui.select("Max clarification questions", ["1", "2", "3", "4", "5"])) ?? "");
          if (count) { const r = updateSettings(ctx.cwd, undefined, (s) => { s.planning.maxClarificationQuestions = count; }); workflowUiNotify(ctx, `planning.maxClarificationQuestions set to ${count} in ${r.file}`, "info"); }
        } else if (setting === "Timing") {
          const timing = parseClarificationTiming((await ctx.ui.select("Plan clarification timing", ["after_initial_analysis", "immediate"])) ?? "");
          if (timing) { const r = updateSettings(ctx.cwd, undefined, (s) => { s.planning.clarificationTiming = timing; }); workflowUiNotify(ctx, `planning.clarificationTiming set to ${timing} in ${r.file}`, "info"); }
        } else {
          const key = setting === "Quality Gate" ? "clarificationQualityGate" : setting === "Allow Without Analysis" ? "allowClarificationWithoutAnalysis" : "useSubagentsBeforeClarification";
          const enabled = await chooseBool(ctx, `planning.${key}?`);
          if (enabled !== undefined) { const r = updateSettings(ctx.cwd, undefined, (s) => { (s.planning as typeof s.planning & Record<string, boolean | string | number | undefined>)[key] = enabled; }); workflowUiNotify(ctx, `planning.${key} set to ${enabled} in ${r.file}`, "info"); }
        }
      } else if (choice === "Plan Sub-agents / Workers") {
        await showPlanSubagentWorkerSettingsMenu(ctx);
      } else if (choice === "Review / Validation Behavior") {
        const setting = await ctx.ui.select("Review / Validation Behavior", ["Reviewer Enabled", "Validator Enabled", "Auto Run Reviewer", "Auto Run Validation", "Auto Repair Review Failures", "Pause After Review Failure", "Approval Before Execution", "Approval Per Step", "Validate After Each Step", "Validate After Full Execution", "Back"]);
        if (!setting || setting === "Back") continue;
        const enabled = await chooseBool(ctx, `${setting}?`);
        if (enabled === undefined) continue;
        if (setting === "Reviewer Enabled") {
          if (loadWorkflowSettings(ctx.cwd).planning.usePlanSpecificModels) { const r = updateSettings(ctx.cwd, undefined, (s) => { setPlanRoleEnabled(s, "reviewer", enabled); }); workflowUiNotify(ctx, `planning.models.reviewer.enabled set to ${enabled} in ${r.file}`, "info"); }
          else { const r = setRoleEnabled("reviewer", enabled, ctx.cwd); workflowUiNotify(ctx, `reviewer.enabled set to ${enabled} in ${r.file}`, "info"); }
        }
        else if (setting === "Validator Enabled") {
          if (loadWorkflowSettings(ctx.cwd).planning.usePlanSpecificModels) { const r = updateSettings(ctx.cwd, undefined, (s) => { setPlanRoleEnabled(s, "validator", enabled); }); workflowUiNotify(ctx, `planning.models.validator.enabled set to ${enabled} in ${r.file}`, "info"); }
          else { const r = setRoleEnabled("validator", enabled, ctx.cwd); workflowUiNotify(ctx, `validator.enabled set to ${enabled} in ${r.file}`, "info"); }
        }
        else if (setting === "Auto Run Reviewer") { const r = updateSettings(ctx.cwd, undefined, (s) => { s.workflow.autoRunReviewerBeforeExecute = enabled; }); workflowUiNotify(ctx, `workflow.autoRunReviewerBeforeExecute set to ${enabled} in ${r.file}`, "info"); }
        else if (setting === "Auto Run Validation") { const r = updateSettings(ctx.cwd, undefined, (s) => { s.workflow.autoRunValidationAfterExecute = enabled; s.workflow.validateAfterExecution = enabled; }); workflowUiNotify(ctx, `workflow.autoRunValidationAfterExecute and workflow.validateAfterExecution set to ${enabled} in ${r.file}`, "info"); }
        else if (setting === "Auto Repair Review Failures") { const r = updateSettings(ctx.cwd, undefined, (s) => { s.workflow.autoRepairReviewFailures = enabled; }); workflowUiNotify(ctx, `workflow.autoRepairReviewFailures set to ${enabled} in ${r.file}`, "info"); }
        else if (setting === "Pause After Review Failure") { const r = updateSettings(ctx.cwd, undefined, (s) => { s.workflow.pauseAfterReviewFailure = enabled; }); workflowUiNotify(ctx, `workflow.pauseAfterReviewFailure set to ${enabled} in ${r.file}`, "info"); }
        else if (setting === "Approval Before Execution") { const r = updateSettings(ctx.cwd, undefined, (s) => { s.workflow.requireApprovalBeforeExecution = enabled; s.workflow.requirePlanApprovalBeforeExecute = enabled; }); workflowUiNotify(ctx, `workflow.requireApprovalBeforeExecution set to ${enabled} in ${r.file}`, "info"); }
        else if (setting === "Approval Per Step") { const r = updateSettings(ctx.cwd, undefined, (s) => { s.workflow.requireApprovalPerStep = enabled; }); workflowUiNotify(ctx, `workflow.requireApprovalPerStep set to ${enabled} in ${r.file}`, "info"); }
        else if (setting === "Validate After Each Step") { const r = updateSettings(ctx.cwd, undefined, (s) => { s.workflow.validateAfterEachStep = enabled; }); workflowUiNotify(ctx, `workflow.validateAfterEachStep set to ${enabled} in ${r.file}`, "info"); }
        else if (setting === "Validate After Full Execution") { const r = updateSettings(ctx.cwd, undefined, (s) => { s.workflow.validateAfterExecution = enabled; s.workflow.autoRunValidationAfterExecute = enabled; }); workflowUiNotify(ctx, `workflow.validateAfterExecution set to ${enabled} in ${r.file}`, "info"); }
      } else if (choice === "Repair / Validation Retry") {
        await showWorkflowRepairRetrySettingsMenu(ctx);
      } else if (choice === "Plan Progress / Runtime") {
        const setting = await ctx.ui.select("Plan Progress / Runtime", ["Progress Tracking", "Show Runtime Timer", "Progress Bar Display", "Runtime Budget", "Token Budget", "List Current Settings", "Back"]);
        if (!setting || setting === "Back") continue;
        if (setting === "List Current Settings") {
          const s = loadWorkflowSettings(ctx.cwd);
          show(pi, `# Plan Progress / Runtime\n\nProgress Tracking: ${s.workflow.planProgressEnabled !== false ? "enabled" : "disabled"}\nShow Runtime Timer: ${s.workflow.planRuntimeEnabled !== false ? "enabled" : "disabled"}\nProgress Bar Display: ${s.workflow.planShowProgressBar !== false ? "graphical" : "numeric"}\nRuntime Budget: ${(s.planning.maxRuntimeHours ?? 0) === 0 ? "unlimited" : `${s.planning.maxRuntimeHours ?? 0} hours`}\nToken Budget: ${(s.planning.maxTokens ?? 0) === 0 ? "unlimited" : (s.planning.maxTokens ?? 0).toLocaleString()}`);
          continue;
        }
        if (setting === "Token Budget") {
          const current = loadWorkflowSettings(ctx.cwd).planning.maxTokens ?? 0;
          const choice = await ctx.ui.select("Plan Token Budget", ["Default (unlimited)", "Custom..."]);
          if (choice === "Default (unlimited)") {
            const r = updateSettings(ctx.cwd, undefined, (s) => { s.planning.maxTokens = 0; });
            workflowUiNotify(ctx, `planning.maxTokens set to default (unlimited) in ${r.file}`, "info");
          } else if (choice === "Custom...") {
            const count = parsePositiveInt((await ctx.ui.input("Enter custom plan token budget", String(current > 0 ? current : ""))) ?? "");
            if (count !== undefined && count >= 0) { const r = updateSettings(ctx.cwd, undefined, (s) => { s.planning.maxTokens = count; }); workflowUiNotify(ctx, `planning.maxTokens set to ${count === 0 ? "unlimited" : count.toLocaleString()} in ${r.file}`, "info"); }
          }
        } else if (setting === "Runtime Budget") {
          const current = loadWorkflowSettings(ctx.cwd).planning.maxRuntimeHours ?? 0;
          const choice = await ctx.ui.select("Plan Runtime Budget", ["Default (unlimited)", "Custom..."]);
          if (choice === "Default (unlimited)") {
            const r = updateSettings(ctx.cwd, undefined, (s) => { s.planning.maxRuntimeHours = 0; });
            workflowUiNotify(ctx, `planning.maxRuntimeHours set to default (unlimited) in ${r.file}`, "info");
          } else if (choice === "Custom...") {
            const count = parsePositiveInt((await ctx.ui.input("Enter custom plan runtime budget (hours)", String(current > 0 ? current : ""))) ?? "");
            if (count !== undefined && count > 0) { const r = updateSettings(ctx.cwd, undefined, (s) => { s.planning.maxRuntimeHours = count; }); workflowUiNotify(ctx, `planning.maxRuntimeHours set to ${count} hours in ${r.file}`, "info"); }
          }
        } else if (setting === "Progress Bar Display") {
          const enabled = await chooseBool(ctx, "workflow.planShowProgressBar?");
          if (enabled !== undefined) { const r = updateSettings(ctx.cwd, undefined, (s) => { s.workflow.planShowProgressBar = enabled; }); workflowUiNotify(ctx, `workflow.planShowProgressBar set to ${enabled} in ${r.file}`, "info"); }
        } else {
          const key = setting === "Progress Tracking" ? "planProgressEnabled" : "planRuntimeEnabled";
          const enabled = await chooseBool(ctx, `workflow.${key}?`);
          if (enabled !== undefined) { const r = updateSettings(ctx.cwd, undefined, (s) => { (s.workflow as typeof s.workflow & Record<string, boolean>)[key] = enabled; }); workflowUiNotify(ctx, `workflow.${key} set to ${enabled} in ${r.file}`, "info"); }
        }
      } else if (choice === "Plan History") {
        const setting = await ctx.ui.select("Plan History", ["Save Plans", "Save Plan History", "Plan History Limit", "Back"]);
        const workflow = loadWorkflowSettings(ctx.cwd).workflow as ReturnType<typeof loadWorkflowSettings>["workflow"] & { savePlans?: boolean; savePlanHistory?: boolean; planHistoryLimit?: number };
        if (!setting || setting === "Back") continue;
        if (setting === "Plan History Limit") {
          const count = parsePositiveInt((await ctx.ui.input("Plan history limit", String(workflow.planHistoryLimit ?? 50))) ?? "");
          if (count !== undefined && count > 0) { const r = updateSettings(ctx.cwd, undefined, (s) => { s.workflow.planHistoryLimit = count; }); workflowUiNotify(ctx, `workflow.planHistoryLimit set to ${count} in ${r.file}`, "info"); }
        } else {
          const key = setting === "Save Plans" ? "savePlans" : "savePlanHistory";
          const enabled = await chooseBool(ctx, `${key}?`);
          if (enabled !== undefined) { const r = updateSettings(ctx.cwd, undefined, (s) => { (s.workflow as typeof s.workflow & Record<string, boolean>)[key] = enabled; }); workflowUiNotify(ctx, `workflow.${key} set to ${enabled} in ${r.file}`, "info"); }
        }
      } else if (choice === "List Current Settings") {
        const s = loadWorkflowSettings(ctx.cwd);
        const planReviewerEnabled = planModelEnabled(s, "reviewer");
        const planValidatorEnabled = planModelEnabled(s, "validator");
        show(pi, `# Plan Mode Settings\n\n## Plan Models\n${renderPlanModelSettings(s)}\n\n## Plan Mode Flow\nPlanning Depth: ${s.planning.depth}\nProgress Tracking: ${s.workflow.planProgressEnabled !== false ? "enabled" : "disabled"}\nShow Runtime Timer: ${s.workflow.planRuntimeEnabled !== false ? "enabled" : "disabled"}\nProgress Bar Display: ${s.workflow.planShowProgressBar !== false ? "graphical" : "numeric"}\nRuntime Budget: ${(s.planning.maxRuntimeHours ?? 0) === 0 ? "unlimited" : `${s.planning.maxRuntimeHours ?? 0} hours`}\nToken Budget: ${(s.planning.maxTokens ?? 0) === 0 ? "unlimited" : (s.planning.maxTokens ?? 0).toLocaleString()}\nRequire Approval Before Execution: ${s.workflow.requireApprovalBeforeExecution !== false ? "enabled" : "disabled"}\nRequire Approval Per Step: ${s.workflow.requireApprovalPerStep === true ? "enabled" : "disabled"}\nValidate After Each Step: ${s.workflow.validateAfterEachStep !== false ? "enabled" : "disabled"}\nValidate After Full Execution: ${s.workflow.validateAfterExecution !== false ? "enabled" : "disabled"}\n\n## Plan Sub-agents\n${renderPlanSubagentWorkerSettings(s)}\n\n## Plan Clarification\nClarification Mode: ${s.planning.clarificationMode}\nInteractive: ${s.planning.interactiveClarificationEnabled !== false ? "enabled" : "disabled"}\nMax Questions: ${s.planning.maxClarificationQuestions}\n\n## Plan Review / Validation\nReviewer: ${planReviewerEnabled ? "enabled" : "disabled"}\nValidator: ${planValidatorEnabled ? "enabled" : "disabled"}\nAuto Run Reviewer: ${s.workflow.autoRunReviewerBeforeExecute !== false ? "enabled" : "disabled"}\nAuto Run Validation: ${s.workflow.autoRunValidationAfterExecute !== false ? "enabled" : "disabled"}\nAuto Repair Review Failures: ${s.workflow.autoRepairReviewFailures === true ? "enabled" : "disabled"}\nRepair / Retry Master Toggle: ${s.workflow.repairRetry?.enabled !== false ? "enabled" : "disabled"}\nMax Total Retries: ${s.workflow.repairRetry?.maxTotalRetries ?? "unlimited"}\n\n## Plan History\nSave Plans: ${(s.workflow as Record<string, unknown>).savePlans !== false ? "enabled" : "disabled"}\nSave Plan History: ${(s.workflow as Record<string, unknown>).savePlanHistory !== false ? "enabled" : "disabled"}\nPlan History Limit: ${(s.workflow as Record<string, unknown>).planHistoryLimit ?? 50}`);
      }
    }
  }

