  const handleWorkflowCommand = async (args: string, ctx: ExtensionContext): Promise<void> => {
    const parts = args.trim().split(/\s+/).filter(Boolean);
    const section = (parts[0] ?? "help").toLowerCase();
    const rest = parts.slice(1);
    if (section === "help" || section === "") return show(pi, workflowUtilityHelp());
    if (section === "status") return show(pi, `${renderWorkflowStatus(state, pi.getActiveTools(), ctx.cwd)}\n\n${renderMissionStatus(activeMission ?? loadMissionState())}`);
    if (section === "settings") return handleWorkflowSettingsCommand(rest.join(" "), ctx);
    if (section === "presets") {
      const action = rest[0] ?? "select";
      if (action === "configure" || action === "menu") return showWorkflowPresetsMenu(ctx);
      if (action === "apply") return handleWorkflowPresetsCommand(`use ${rest.slice(1).join(" ")}`.trim(), ctx);
      return handleWorkflowPresetsCommand(rest.join(" "), ctx);
    }
    if (section === "models") {
      const action = rest[0] ?? "list";
      if (action === "status") return handleWorkflowModelsCommand("list", ctx);
      if (action === "active") return handleWorkflowModelsCommand("active", ctx);
      if (action === "list" && rest[1] === "active") return handleWorkflowModelsCommand("active", ctx);
      return handleWorkflowModelsCommand(rest.length ? rest.join(" ") : "list", ctx);
    }
    if (section === "subagents") {
      const action = rest[0] ?? "status";
      if (action === "list") return handleWorkflowSubagentsCommand("agents", ctx);
      return handleWorkflowSubagentsCommand(rest.length ? rest.join(" ") : "status", ctx);
    }
    if (section === "widgets") {
      const action = rest[0] ?? "status";
      if (action === "status") return handleWorkflowWidgetsCommand("list", ctx);
      return handleWorkflowWidgetsCommand(rest.length ? rest.join(" ") : "list", ctx);
    }
    if (section === "plans") return handleWorkflowPlansCommand(rest.length ? rest.join(" ") : "list", ctx);
    return show(pi, `${workflowUtilityHelp()}\n\nUnknown workflow utility: ${section}`);
  };

