        updateState({ mode: "plan_draft", draftPlan: text, approvedPlan: undefined, clarificationQualityRetryCount: undefined, lastReviewFailure: reason, planProgress: mergePlanProgress({ ...state, mode: "validated", draftPlan: text, approvedPlan: undefined }, settings, { lifecycleStatus: "blocked", nextAction: "revise planning", steps: [] }, undefined) }, ctx);
